int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To maximize the number, we want to have as many '1's as possible, followed by '0's.
    // Each '1' requires one 'o', one 'n', one 'e'.
    // Each '0' requires one 'z', one 'e', one 'r', one 'o'.

    // The number of '1's is limited by the count of 'n'.
    // Each 'n' can only be used for a '1'.
    int num_ones = count_n;

    // After forming 'num_ones' '1's, we use 'num_ones' 'o's and 'num_ones' 'e's.
    // The remaining 'o's and 'e's, along with 'z's and 'r's, can form '0's.
    // The number of '0's is limited by the count of 'z'.
    // Each 'z' can only be used for a '0'.
    int num_zeros = count_z;

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

