int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        long long min_val = a[0];
        long long operations = 0;

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0), we can copy min_val into it
            // as many times as possible without exceeding k.
            // The current value of a[i] is a[i].
            // Each copy adds min_val.
            // We need a[i] + x * min_val <= k
            // x * min_val <= k - a[i]
            // x <= (k - a[i]) / min_val
            // Since x must be an integer, x = floor((k - a[i]) / min_val)
            if (a[i] < k) { // Only perform operations if there's room
                operations += (k - a[i]) / min_val;
            }
        }
        std::cout << operations << "\n";
    }
    return 0;
}

