#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for both coal and crafting are k * y + k.
        long long total_sticks_needed = k * y + k;

        // We start with 1 stick.
        // Each trade of type 1 (1 stick for x sticks) gives us x-1 net sticks.
        // We need to acquire (total_sticks_needed - 1) additional sticks from our initial 1 stick.
        // The number of trades of type 1 needed is ceil((total_sticks_needed - 1) / (x - 1)).
        // Using integer division: (A + B - 1) / B for ceil(A/B)
        long long trades_for_sticks = (total_sticks_needed - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = trades for sticks + trades for coal.
        // Trades for coal is simply k, as each coal trade gives 1 coal.
        long long total_trades = trades_for_sticks + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

