int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration = total_sum / k;
    std::vector<int> s_values;
    long long current_post_sum = 0;
    int current_post_video_count = 0;
    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_video_count++;

        if (current_post_sum == target_duration) {
            s_values.push_back(current_post_video_count);
            current_post_sum = 0;
            current_post_video_count = 0;
            posts_formed++;
        } else if (current_post_sum > target_duration) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_formed == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "No\n";
    }

    return 0;
}

