int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // Skip a[i][i] which is 0
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is 0, it means all other elements in the row are 0.
        // This can only happen if p[i] is 1 and all other p[j] are also 1,
        // which is not possible in a permutation.
        // Or if p[i] is 1 and all other p[j] are > 1, then min(p[i], p[j]) = 1.
        // So if max_val_in_row is 0, it means p[i] must be 1, and all other p[j] are also 1.
        // This implies that p[i] must be 1, and all other p[j] are also 1.
        // This is only possible if n=1, but n >= 2.
        // The only way max_val_in_row can be 0 is if n=1, but n >= 2.
        // For n >= 2, there must be at least one p[j] > p[i] or p[j] < p[i].
        // If p[i] is 1, then max_val_in_row will be 1 (unless n=1).
        // If p[i] is not 1, then max_val_in_row will be at least 1.
        // The only case where max_val_in_row could be 0 is if n=1, but n >= 2.
        // So max_val_in_row will always be at least 1 for n >= 2.
        // If max_val_in_row is less than n, it means p[i] is max_val_in_row.
        // If max_val_in_row is n-1, it means p[i] could be n.
        // The logic is: if p[i] is not n, then there is some p[k] = n.
        // Then min(p[i], p[k]) = p[i]. So max_val_in_row would be p[i].
        // If p[i] is n, then for all j != i, min(p[i], p[j]) = p[j].
        // So max_val_in_row would be max(p[j] for j != i), which is n-1.
        // So if max_val_in_row is n-1, p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point (cell 0)

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos.
                // The gap is (i+1) - (last_r_pos + 1) + 1 = i - last_r_pos.
                // This is the distance from the previous 'R' cell (or 0) to the current 'R' cell.
                // Example: s = "LRL", n=3
                // i=0, s[0]='L'. last_r_pos = -1.
                // i=1, s[1]='R'. current cell is 2. last_r_pos = -1.
                // Gap is 2 - (-1) = 3. max_gap = max(0, 3) = 3. last_r_pos = 1.
                // i=2, s[2]='L'.
                // After loop, last_r_pos = 1.
                // Final gap to n+1: (n+1) - (last_r_pos + 1) = (3+1) - (1+1) = 4 - 2 = 2.
                // max_gap = max(3, 2) = 3.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After the loop, consider the jump from the last 'R' (or 0 if no 'R's) to n+1.
        // The last 'R' was at index last_r_pos (0-indexed string).
        // This corresponds to cell (last_r_pos + 1).
        // The target is cell (n + 1).
        // The distance is (n + 1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, n - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this element.
        // The presence of 1 or -1 before this index doesn't matter for this specific element,
        // but it might matter for subsequent elements.
        // The has_pos_one and has_neg_one flags are updated based on the original a[i] values.
        // This is correct because the values a[i] that are added to a[j] (j>i) are the *current* values of a[i].
        // However, the problem states "Add a_i to a_j", where a_i is the element at index i.
        // The crucial observation is that an element a[i] can only be changed by elements a[k] where k < i.
        // So, when we are considering operations on a[j], the values a[i] (for i < j) are already fixed
        // to their final values b[i].
        // This means we need to track if there was an original 1 or -1 *before* index i.
        // The current logic correctly tracks if there was an original 1 or -1 at any index k < i.
        // The flags `has_pos_one` and `has_neg_one` are updated based on the *original* `a` values.
        // This is correct because an `a[k]` (k < i) that was originally 1 or -1 can be used to modify `a[i]`.
        // If `a[k]` itself was modified to `b[k]`, then `b[k]` is the value that would be added.
        // However, the problem implies that `a_i` refers to the *original* value of `a_i` or its current value.
        // "Add a_i to a_j" usually means the current value.
        // Let's re-read: "Add a_i to a_j. In other words, j-th element of the array becomes equal to a_i + a_j."
        // This implies the *current* value of a_i.
        // If a_i is changed to b_i, then b_i is what gets added.
        // But b_i can be any integer, not just -1, 0, 1.
        // This would mean we can add any b_i (i < j) to a_j. This is too powerful.
        // The example "if you are given array [1, -1, 0], you can transform it only to [1, -1, -1], [1, 0, 0] and [1, -1, 1] by one operation."
        // This example implies that the *original* values of a_i are used for addition.
        // If a_i refers to the *original* value, then the flags `has_pos_one` and `has_neg_one` should be based on the original `a` array.
        // If a_i refers to the *current* value, then the flags should be updated as we iterate.
        // The problem statement "array a contains only elements from the set {-1, 0, 1}" refers to the initial state.
        // The example transformation `[1, -1, 0] -> [1, -1, -1]` by `(2,3)` means `a_3 = a_3 + a_2` (0 + (-1) = -1).
        // `[1, -1, 0] -> [1, 0, 0]` by `(1,2)` means `a_2 = a_2 + a_1` (-1 + 1 = 0).
        // The example `[1, -1, 0] -> [1, -1, -2] -> [1, 1, -2]`
        // `[1, -1, 0]`
        // `(2,3)` twice: `a_3 = a_3 + a_2` (0 + (-1) = -1), then `a_3 = a_3 + a_2` (-1 + (-1) = -2). Array is `[1, -1, -2]`.
        // `(1,2)` twice: `a_2 = a_2 + a_1` (-1 + 1 = 0), then `a_2 = a_2 + a_1` (0 + 1 = 1). Array is `[1, 1, -2]`.
        // This confirms that `a_i` in `a_j = a_j + a_i` refers to the *current* value of `a_i`.
        // So, if `a[k]` (k < i) was originally 1, and then it was changed to `b[k]`, then `b[k]` is what gets added.
        // This means the `has_pos_one` and `has_neg_one` flags should track if there is *any* `b[k]` (k < i) that is positive or negative.
        // This is a critical distinction.

        // Let's re-evaluate the logic based on `a_i` being the *current* value.
        // We process from left to right. For each `i`:
        // 1. `a[i]` must become `b[i]`.
        // 2. `a[i]` can be modified by `a[k]` for `k < i`.
        // 3. The values `a[k]` (for `k < i`) have already been transformed to `b[k]`.
        // 4. So, `a[i]` can be changed by adding any `b[k]` (for `k < i`) any number of times.
        // 5. To increase `a[i]` to `b[i]`, we need to be able to add a positive value. This means there must exist some `k < i` such that `b[k] > 0`.
        // 6. To decrease `a[i]` to `b[i]`, we need to be able to add a negative value. This means there must exist some `k < i` such that `b[k] < 0`.
        // 7. If `a[i] == b[i]`, no operation is needed.
        // 8. If `a[i] < b[i]`, we need to increase `a[i]`. This is possible if `has_pos_b_before_i` is true.
        // 9. If `a[i] > b[i]`, we need to decrease `a[i]`. This is possible if `has_neg_b_before_i` is true.

        // Let's use `can_add_pos` and `can_add_neg` flags.
        // These flags track if there's any `b[k]` (for `k < i`) that is positive or negative.
        // Initial state: `can_add_pos = false`, `can_add_neg = false`.
        // For `i = 0`: `a[0]` must equal `b[0]`. No operations possible.
        // After processing `i = 0`: if `b[0] > 0`, then `can_add_pos` becomes true for `i = 1`. If `b[0] < 0`, `can_add_neg` becomes true for `i = 1`.

        // The current `has_pos_one` and `has_neg_one` are based on original `a` values.
        // This is the interpretation that makes the problem solvable with simple flags.
        // If `a_i` refers to the *original* value of `a_i` when added, then the flags are correct.
        // The example `[1, -1, 0] -> [1, -1, -2] -> [1, 1, -2]`
        // `a_3 = a_3 + a_2` (0 + (-1) = -1). Here `a_2` is -1.
        // `a_3 = a_3 + a_2` (-1 + (-1) = -2). Here `a_2` is still -1.
        // `a_2 = a_2 + a_1` (-1 + 1 = 0). Here `a_1` is 1.
        // `a_2 = a_2 + a_1` (0 + 1 = 1). Here `a_1` is still 1.
        // This implies that `a_i` in `a_j = a_j + a_i` refers to the *original* value of `a_i`.
        // If `a_i` was changed, its *new* value is not used for subsequent additions.
        // This is a common ambiguity in such problems. Given the constraints and typical competitive programming problem styles,
        // the interpretation that `a_i` refers to the *original* value of `a_i` is more likely.
        // If `a_i` referred to the *current* value, then `b_k` could be added, which would make the problem much harder or trivial.
        // For example, if `b_k` could be added, and `b_k` could be `10^9`, then `a_j` could be changed by `10^9` in one step.
        // The problem statement "array a contains only elements from the set {-1, 0, 1}" for the initial state strongly suggests this.

        // So, the current logic is correct under the interpretation that `a_i` in `a_j = a_j + a_i` refers to the *original* value of `a_i`.
        // The flags `has_pos_one` and `has_neg_one` correctly track if there was an original 1 or -1 at any index `k < i`.
        // These flags are updated *after* checking `a[i]` vs `b[i]`, but they reflect the state *before* `i`.

        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

