#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 is always q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i must be distinct from previous q_j
                // and q_j are the only elements that could be p_j for q_j > q_{j-1}.
                // However, it's good to check for robustness.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be some unused number less than q_i
            // We need to find the largest available number less than q_i to maximize chances
            // of finding numbers for subsequent positions.
            // The numbers available are those from 1 to n that have not been used yet.
            // We need to pick the largest available number that is less than q_i.
            // The largest available number less than q_i is q_i - 1, then q_i - 2, etc.
            // We can iterate downwards from q_i - 1 to find the first unused number.
            // Or, we can use a set of available numbers and find the largest one less than q_i.
            // A more efficient way is to keep track of numbers not yet used.
            // The numbers that are *not* q_j for some j where q_j > q_{j-1} are candidates.
            // Let's find the largest number in [1, n] that is not in used_numbers and is less than q_i.
            // We can pre-populate a set of all numbers [1, n] and remove used_numbers.
            // Or, we can iterate downwards from q_i - 1.

            // Let's use a strategy: fill p_i with the smallest available number that is not yet used.
            // This is not correct. We need to fill p_i with an available number that is <= q_i.
            // The problem states "any possible suitable permutation".
            // To maximize chances for later elements, it's usually best to use the smallest available number.
            // However, for q_i = q_{i-1}, p_i must be < q_i.
            // So, we need to find the largest available number that is less than q_i.
            // This is because if we use a small number, a larger number might be needed later.
            // If we use the largest available number less than q_i, we leave smaller numbers for later.
            // This greedy choice seems more robust.

            // Find the largest number `x` such that `x < q_i` and `x` is not in `used_numbers`.
            int candidate = -1;
            for (int k = q[i] - 1; k >= 1; --k) {
                if (!used_numbers.count(k)) {
                    candidate = k;
                    break;
                }
            }

            if (candidate == -1) {
                possible = false;
                break;
            }
            p[i] = candidate;
            used_numbers.insert(candidate);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        // Final check: ensure all numbers from 1 to n are used exactly once.
        // This is implicitly handled by the logic if `possible` is true.
        // `used_numbers` should contain `n` distinct elements.
        // If `used_numbers.size() != n`, it means some numbers were not found,
        // which would have set `possible = false` earlier.
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

