    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate the first k+1 elements to produce k distinct differences
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // The remaining elements are filled in increasing order
    // This will produce a difference of 1, which is already among the k distinct differences
    // or if k=1, it will produce 1, which is the only distinct difference.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be left, which is i+1
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

