int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for n=1 staircase
        long long sum_of_costs = 0;

        // The costs for nice staircases are 1, 7, 30, 91, 252, ...
        // These are of the form (2^k - 1) * (2^k) / 2 for k=1, 2, 3, ...
        // Or, more generally, for a staircase with (2^k - 1) stairs,
        // the cost is (2^k - 1) * (2^k) / 2.
        // Let m = 2^k - 1. Then the cost is m * (m+1) / 2.
        // The sequence of m values is 1, 3, 7, 15, 31, ...
        // The sequence of costs is 1, 6, 28, 120, 496, ...
        // Wait, the example says n=3 costs 7.
        // Let's re-evaluate the cost of a nice staircase with n stairs.
        // A staircase with n stairs is nice if n = 2^k - 1 for some k >= 1.
        // The number of cells for a staircase with n stairs is n * (n + 1) / 2.
        // So, for n = 2^k - 1, the cost is (2^k - 1) * (2^k - 1 + 1) / 2
        // = (2^k - 1) * 2^k / 2
        // = (2^k - 1) * 2^(k-1).

        // Let's list the costs for k=1, 2, 3, ...
        // k=1: n = 2^1 - 1 = 1. Cost = (2^1 - 1) * 2^(1-1) = 1 * 1 = 1.
        // k=2: n = 2^2 - 1 = 3. Cost = (2^2 - 1) * 2^(2-1) = 3 * 2 = 6.
        // k=3: n = 2^3 - 1 = 7. Cost = (2^3 - 1) * 2^(3-1) = 7 * 4 = 28.
        // k=4: n = 2^4 - 1 = 15. Cost = (2^4 - 1) * 2^(4-1) = 15 * 8 = 120.
        // k=5: n = 2^5 - 1 = 31. Cost = (2^5 - 1) * 2^(5-1) = 31 * 16 = 496.

        // The problem states: "A staircase with 7 stairs is nice".
        // The image shows a staircase with 7 stairs covered by 7 squares.
        // The cost for n=7 is 7 * (7+1) / 2 = 7 * 8 / 2 = 28.
        // The example output for x=8 is 2.
        // This means we can build a staircase with 1 stair (cost 1) and a staircase with 3 stairs (cost 6).
        // Total cost = 1 + 6 = 7. Remaining cells = 1. Total staircases = 2.
        // This matches the costs derived above: 1 and 6.

        // The costs are (2^k - 1) * 2^(k-1).
        // Let's generate these costs and greedily pick them as long as x allows.
        // The costs are 1, 6, 28, 120, 496, ...
        // These are the costs for staircases with 1, 3, 7, 15, 31, ... stairs respectively.

        // The sequence of costs is:
        // C_k = (2^k - 1) * 2^(k-1)
        // C_1 = 1
        // C_2 = 6
        // C_3 = 28
        // C_4 = 120
        // C_5 = 496
        // ...

        // We want to find the maximum number of *different* nice staircases.
        // This means we should always pick the smallest available cost first to maximize the count.
        // The costs are strictly increasing. So, we just iterate through the costs C_1, C_2, C_3, ...
        // and subtract them from x as long as x is sufficient.

        long long current_k_val = 1; // This represents 2^k - 1
        long long current_power_of_2 = 1; // This represents 2^(k-1)

        while (true) {
            long long cost = current_k_val * current_power_of_2;
            if (x >= cost) {
                x -= cost;
                count++;
            } else {
                break;
            }

            // Calculate next k_val and power_of_2
            // For next iteration, k becomes k+1.
            // New k_val = 2^(k+1) - 1 = 2 * (2^k - 1) + 1 = 2 * current_k_val + 1
            // New power_of_2 = 2^((k+1)-1) = 2^k = 2 * current_power_of_2
            current_k_val = 2 * current_k_val + 1;
            current_power_of_2 = 2 * current_power_of_2;

            // Check for overflow before calculating next cost, though x up to 10^18 means costs can be large.
            // The maximum value for x is 10^18.
            // The costs grow very fast.
            // C_6 = (2^6 - 1) * 2^5 = 63 * 32 = 2016
            // C_7 = (2^7 - 1) * 2^6 = 127 * 64 = 8128
            // C_8 = (2^8 - 1) * 2^7 = 255 * 128 = 32640
            // C_9 = (2^9 - 1) * 2^8 = 511 * 256 = 130816
            // C_10 = (2^10 - 1) * 2^9 = 1023 * 512 = 523776
            // C_20 = (2^20 - 1) * 2^19 approx 2^39 approx 5.5 * 10^11
            // C_30 = (2^30 - 1) * 2^29 approx 2^59 approx 5.7 * 10^17
            // C_31 = (2^31 - 1) * 2^30 approx 2^61 approx 2.3 * 10^18
            // C_32 = (2^32 - 1) * 2^31 approx 2^63 approx 9.2 * 10^18
            // So, current_k_val and current_power_of_2 can reach values up to 2^31 or 2^32.
            // Their product can exceed 10^18.
            // `long long` is sufficient for `x` and `cost`.
            // `current_k_val` and `current_power_of_2` will also fit in `long long`.
            // The loop will run at most about 31-32 times.
            if (current_k_val > 2000000000000000000LL / current_power_of_2) { // Prevent overflow for next cost calculation
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

