int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // We can only add a ')' if we have an open bracket to match it
            // AND we still need closing brackets AND adding it won't make balance negative
            // The balance check is implicitly handled by the problem constraints and the greedy choice
            // that we prioritize adding '(' first.
            // We need to ensure we don't add more ')' than k/2.
            // Also, we must ensure balance doesn't drop below 0.
            // Since we add '(' greedily up to k/2, and then add ')' greedily up to k/2,
            // and it's guaranteed a solution exists, this strategy works.
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break; // We have found k/2 open and k/2 close brackets
        }
    }

    std::cout << result << std::endl;

    return 0;
}

