        //
        // Consider the partition:
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // Each class has size n. If n is odd, then the median of C1 is a_{(n-1)/2} and median of C2 is a_{n + (n-1)/2}.
        // This is not the general solution.
        //
        // The problem is simpler than trying to construct the classes.
        // The minimum possible difference between medians of two odd-sized classes
        // will always be the difference between the two middle elements of the *entire* sorted array.
        //
        // Let the sorted array be $a_0, a_1, \dots, a_{2n-1}$.
        // We want to find $\min |M_1 - M_2|$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // We can form $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // Each has size $n$. If $n$ is odd, this is a valid partition.
        // The median of $C_1$ is $a_{(n-1)/2}$. The median of $C_2$ is $a_{n + (n-1)/2}$.
        // The difference is $|a_{n + (n-1)/2} - a_{(n-1)/2}|$.
        //
        // Example 2: n=3, 2n=6. a = [1, 2, 3, 4, 5, 6].
        // a_{n-1} = a_2 = 3. a_n = a_3 = 4.
        // Difference = |4-3| = 1.
        //
        // Example 3: n=5, 2n=10. a = [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // a_{n-1} = a_4 = 8. a_n = a_5 = 13.
        // Difference = |13-8| = 5.
        //
        // This pattern holds for the examples.
        //
        // Why is this always the minimum?
        // Let $m_1$ and $m_2$ be the medians of the two classes $C_1$ and $C_2$.
        // Let $m_1 \le m_2$.
        //
        // $C_1$ has size $2k_1+1$. $m_1$ is the $k_1$-th element (0-indexed) in $C_1$.
        // This means there are at least $k_1$ elements in $C_1$ that are $\le m_1$.
        // And there are at least $k_1$ elements in $C_1$ that are $\ge m_1$.
        //
        // $C_2$ has size $2k_2+1$. $m_2$ is the $k_2$-th element (0-indexed) in $C_2$.
        // This means there are at least $k_2$ elements in $C_2$ that are $\le m_2$.
        // And there are at least $k_2$ elements in $C_2$ that are $\ge m_2$.
        //
        // Total elements $2n$. $k_1+k_2 = n-1$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // The median $m_1$ must be at least $a_{k_1}$.
        // The median $m_2$ must be at least $a_{k_2}$ (if $C_2$ was formed from the smallest elements).
        //
        // More formally, let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$.
        //
        // For $m_1$ to be the median of $C_1$ (size $2k_1+1$), there must be at least $k_1$ elements in $C_1$ that are $\le m_1$.
        // For $m_2$ to be the median of $C_2$ (size $2k_2+1$), there must be at least $k_2+1$ elements in $C_2$ that are $\le m_2$.
        //
        // Total number of elements $\le m_2$ is at least $(k_1+1) + (k_2+1) = k_1+k_2+2 = (n-1)+2 = n+1$.
        // This means $m_2$ must be at least $a_n$ (since $a_n$ is the $(n+1)$-th smallest element, 0-indexed).
        // So $m_2 \ge a_n$.
        //
        // Similarly, for $m_1$ to be the median of $C_1$, there must be at least $k_1+1$ elements in $C_1$ that are $\ge m_1$.
        // For $m_2$ to be the median of $C_2$, there must be at least $k_2$ elements in $C_2$ that are $\ge m_2$.
        //
        // Total number of elements $\ge m_1$ is at least $(k_1+1) + k_2 = k_1+k_2+1 = (n-1)+1 = n$.
        // This means $m_1$ must be at most $a_{2n-1 - (n-1)} = a_n$.
        // This is not quite right.
        //
        // Let's use the property that if $m$ is the median of a set $S$ of size $2k+1$, then there are $k$ elements $\le m$ and $k$ elements $\ge m$ in $S$.
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$.
        //
        // $C_1$ has $k_1$ elements smaller than $m_1$, $m_1$ itself, and $k_1$ elements larger than $m_1$.
        // $C_2$ has $k_2$ elements smaller than $m_2$, $m_2$ itself, and $k_2$ elements larger than $m_2$.
        //
        // Consider the set of all elements $S = C_1 \cup C_2$.
        //
        // The number of elements in $S$ that are $\le m_1$ is at least $k_1+1$.
        // The number of elements in $S$ that are $\le m_2$ is at least $(k_1+1) + (k_2+1) = k_1+k_2+2 = n-1+2 = n+1$.
        // Since there are at least $n+1$ elements $\le m_2$, $m_2$ must be at least $a_n$.
        // (Because $a_n$ is the $(n+1)$-th element in the sorted list $a_0, \dots, a_{2n-1}$).
        // So, $m_2 \ge a_n$.
        //
        // The number of elements in $S$ that are $\ge m_2$ is at least $k_2+1$.
        // The number of elements in $S$ that are $\ge m_1$ is at least $(k_1+1) + (k_2+1) = k_1+k_2+2 = n+1$.
        // This means $m_1$ must be at most $a_{2n-1 - (n)} = a_{n-1}$.
        // (Because $a_{n-1}$ is the $(n)$-th element from the end in the sorted list).
        // So, $m_1 \le a_{n-1}$.
        //
        // Combining these, we have $m_1 \le a_{n-1}$ and $m_2 \ge a_n$.
        // Since $a_{n-1} \le a_n$ (due to sorting), we have $m_1 \le a_{n-1} \le a_n \le m_2$.
        //
        // Therefore, $|m_1 - m_2| = m_2 - m_1 \ge a_n - a_{n-1}$.
        //
        // We can achieve this minimum difference by constructing a partition:
        // Class 1 ($C_1$): Take $a_{n-1}$ as its median.
        // We need $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We can choose $k_1 = n-1$.
        // So $C_1$ has size $2(n-1)+1 = 2n-1$.
        // Elements for $C_1$: $\{a_0, \dots, a_{n-2}\}$ (n-1 elements smaller than $a_{n-1}$)
        //                     $\{a_{n-1}\}$ (the median)
        //                     $\{a_{n+1}, \dots, a_{2n-1}\}$ (n-1 elements larger than $a_{n-1}$)
        // This forms $C_1 = \{a_0, \dots, a_{n-2}, a_{n-1}, a_{n+1}, \dots, a_{2n-1}\}$.
        // The median of $C_1$ is $a_{n-1}$.
        //
        // The remaining student is $a_n$.
        // Class 2 ($C_2$): $\{a_n\}$. This class has size 1 (which is odd).
        // Its median is $a_n$.
        //
        // This partition is valid:
        // $|C_1| = 2n-1$ (odd)
        // $|C_2| = 1$ (odd)
        // $|C_1| + |C_2| = (2n-1) + 1 = 2n$. All students assigned.
        //
        // The absolute difference between medians is $|a_{n-1} - a_n| = a_n - a_{n-1}$.
        //
        // Since we proved that $|m_1 - m_2| \ge a_n - a_{n-1}$, and we found a partition that achieves $a_n - a_{n-1}$,
        // this is indeed the minimum possible absolute difference.
        //
        // So the algorithm is:
        // 1. Read $n$.
        // 2. Read $2n$ skill levels into a vector.
        // 3. Sort the vector.
        // 4. The answer is $a[n] - a[n-1]$.

        std::cout << a[n] - a[n-1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horizontal_moves = std::min(counts['L'], counts['R']);
    int vertical_moves = std::min(counts['U'], counts['D']);

    std::string result = "";
    int total_length = 0;

    if (horizontal_moves == 0 && vertical_moves == 0) {
        // No moves possible
        total_length = 0;
    } else if (horizontal_moves == 0) {
        // Only vertical moves possible, must be U and D.
        // To form a valid path, we need to go U and then D (or D then U).
        // If we have at least one U and one D, we can form "UD" or "DU".
        // If we only have U or only D, we can't return to (0,0).
        // Since vertical_moves > 0, we have at least one U and one D.
        // The path "UD" (or "DU") is valid. Length 2.
        total_length = 2;
        result = "UD";
    } else if (vertical_moves == 0) {
        // Only horizontal moves possible, must be L and R.
        // Similar to vertical, if horizontal_moves > 0, we have at least one L and one R.
        // The path "LR" (or "RL") is valid. Length 2.
        total_length = 2;
        result = "LR";
    } else {
        // Both horizontal and vertical moves are possible.
        // We can form a path like L...LU...UR...RD...D
        // Example: L...L U...U R...R D...D
        // This path visits cells (x,y) where x is from -horizontal_moves to horizontal_moves
        // and y is from -vertical_moves to vertical_moves.
        // The path does not self-intersect except at (0,0) if constructed as:
        // L repeated horizontal_moves times
        // U repeated vertical_moves times
        // R repeated horizontal_moves times
        // D repeated vertical_moves times
        // This forms a rectangle.
        total_length = 2 * horizontal_moves + 2 * vertical_moves;
        for (int i = 0; i < horizontal_moves; ++i) result += 'L';
        for (int i = 0; i < vertical_moves; ++i) result += 'U';
        for (int i = 0; i < horizontal_moves; ++i) result += 'R';
        for (int i = 0; i < vertical_moves; ++i) result += 'D';
    }

    std::cout << total_length << std::endl;
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <string>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For current m, we need to check if the numbers 1 to m form a contiguous subsegment.
        // We maintain min_idx and max_idx for the current set {1, ..., m-1}.
        // When we consider m, we update min_idx and max_idx to include pos[m].
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // If the range [min_idx, max_idx] contains exactly m elements,
        // then the subsegment p[min_idx ... max_idx] contains all numbers from 1 to m.
        // Since it's a permutation, and we've only added numbers 1 to m,
        // this subsegment must contain exactly {1, ..., m}.
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return;
    }

    std::vector<int> result;
    result.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a peak or a valley
        // p[i-1] < p[i] and p[i] > p[i+1] (peak)
        // p[i-1] > p[i] and p[i] < p[i+1] (valley)
        if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
            result.push_back(p[i]);
        }
    }
    result.push_back(p[n-1]);

    std::cout << result.size() << "\n";
    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i] << (i == result.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int i = 0;
    while (i < n) {
        if (a[i] != b[i]) {
            // Found a differing bit at index i
            // Check if the next bit also differs and forms a '01' vs '10' or '10' vs '01' pattern
            // i.e., a[i] != b[i] AND a[i+1] != b[i+1] AND a[i] == b[i+1] AND a[i+1] == b[i]
            // This means a[i] and a[i+1] are swapped relative to b[i] and b[i+1]
            // Example: a = "01", b = "10" (a[i]=0, b[i]=1, a[i+1]=1, b[i+1]=0)
            // Here a[i] == b[i+1] ('0' == '0') and a[i+1] == b[i] ('1' == '1')
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] == b[i+1] && a[i+1] == b[i]) {
                // This is a swap candidate
                cost += 1; // Cost of swapping adjacent bits is |(i+1) - i| = 1
                i += 2;    // Both bits are now fixed, move past them
            } else {
                // Cannot swap with adjacent bit to fix both, or no such adjacent bit
                // Must flip this bit
                cost += 1; // Cost of flipping is 1
                i += 1;    // This bit is fixed, move to the next
            }
        } else {
            // Bits are already the same, move to the next
            i += 1;
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will track the rightmost valid point for the current 'i'

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d
        // or until right_ptr reaches the end of the array.
        // The loop condition ensures right_ptr is always at least i.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // After the loop, right_ptr points to the first element
        // that violates the condition x[right_ptr] - x[i] <= d,
        // or it is equal to n if all remaining elements satisfy it.

        // The number of points in the valid range [x[i], ..., x[right_ptr-1]] is (right_ptr - 1) - i + 1 = right_ptr - i.
        // Let k_count be the number of points in this range, including x[i].
        // So, k_count = right_ptr - i.
        // We need to choose 3 points. x[i] is fixed as the leftmost.
        // We need to choose 2 more points from the remaining (k_count - 1) points.
        // These (k_count - 1) points are x[i+1], ..., x[right_ptr-1].
        // The number of ways to choose 2 points from (k_count - 1) points is (k_count - 1) * (k_count - 2) / 2.

        long long k_count_minus_1 = (long long)right_ptr - 1 - i; // Number of points strictly to the right of x[i] that satisfy the condition.
                                                                 // These are x[i+1], ..., x[right_ptr-1].
        if (k_count_minus_1 >= 2) {
            count += k_count_minus_1 * (k_count_minus_1 - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
