// Function to check if a sub-array is a permutation
bool is_permutation(const std::vector<int>& arr, int start, int end, int length) {
    if (length == 0) return true; // Empty sequence is vacuously a permutation
    if (length < 0) return false; // Should not happen with valid inputs

    std::vector<bool> seen(length + 1, false);
    int max_val = 0;

    for (int i = start; i < end; ++i) {
        int val = arr[i];
        if (val < 1 || val > length || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Precompute prefix permutations
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    int distinct_count_prefix = 0;
    for (int l = 1; l <= n; ++l) {
        int val = a[l - 1];
        if (val > n || seen_prefix[val]) { // val > n is an optimization, max possible length is n
            // This prefix cannot be a permutation, nor can any longer prefix
            break;
        }
        seen_prefix[val] = true;
        distinct_count_prefix++;
        if (val > current_max_prefix) {
            current_max_prefix = val;
        }
        if (distinct_count_prefix == l && current_max_prefix == l) {
            is_prefix_perm[l] = true;
        }
    }

    // Precompute suffix permutations
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    int distinct_count_suffix = 0;
    for (int l = 1; l <= n; ++l) {
        int val = a[n - l];
        if (val > n || seen_suffix[val]) { // val > n is an optimization
            // This suffix cannot be a permutation, nor can any longer suffix
            break;
        }
        seen_suffix[val] = true;
        distinct_count_suffix++;
        if (val > current_max_suffix) {
            current_max_suffix = val;
        }
        if (distinct_count_suffix == l && current_max_suffix == l) {
            is_suffix_perm[l] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, l2 must be at least 1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

