int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int current_score = 0;
        int initial_wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                initial_wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        if (initial_wins == 0) { // All 'L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 2 * k - 1 << "\n"; // Change k 'L's to 'W's, optimally consecutive
            }
            continue;
        }

        // Case: initial_wins > 0 and initial_wins + k < n
        // We have some 'W's and some 'L's, and cannot make all 'W's.
        // We want to convert 'L's to 'W's to maximize score.
        // Converting an 'L' to 'W' gives 1 point.
        // If this 'W' is adjacent to another 'W', it gives an additional 1 point.
        // So, converting an 'L' to 'W' gives 1 point, plus potentially 1 more if it connects two 'W' segments.

        std::vector<int> gaps;
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        // Collect gaps between 'W's
        int current_gap = 0;
        for (int i = first_w + 1; i < last_w; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        if (current_gap > 0) { // Last gap
            gaps.push_back(current_gap);
        }

        std::sort(gaps.begin(), gaps.end());

        int additional_score = 0;
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                additional_score += 2 * gap_len + 1; // Each L becomes W (1pt), plus 1 for connecting (1pt)
            } else {
                break;
            }
        }

        // Remaining k can be used to convert 'L's to 'W's at the ends or within existing 'W' segments.
        // Each such conversion gives 2 points (1 for the W itself, 1 for being preceded by W).
        // This is because we've already connected all possible gaps, so any remaining 'L's are either
        // at the ends (before first_w or after last_w) or within a segment of 'W's that was already connected.
        // In either case, converting an 'L' to 'W' will be adjacent to an existing 'W' (or a newly converted 'W').
        additional_score += 2 * k;

        std::cout << current_score + additional_score << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_score += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, Chanek takes 1
                    chanek_score += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd, taking N/2 leaves an odd number for opponent
                    chanek_score += n / 2;
                    n /= 2;
                } else { // N/2 is even, taking N/2 leaves an even number for opponent
                    // If Chanek takes N/2, opponent gets an even number.
                    // If Chanek takes 1, opponent gets an odd number.
                    // Chanek wants to maximize his score.
                    // Taking 1 leaves N-1 (odd) for opponent.
                    // Taking N/2 leaves N/2 (even) for opponent.
                    // If N/2 is even, and N > 2, then N/2 > 1.
                    // Taking N/2 is always better for Chanek than taking 1,
                    // because N/2 > 1 for N > 2.
                    // The opponent will also play optimally.
                    // The strategy for Chanek is to take N/2 if it's even and N > 2.
                    // This is because taking N/2 gives Chanek more coins immediately.
                    // The opponent will then face an even number of coins (N/2) and will also try to maximize.
                    // The only exception is N=2, where taking 1 is the only option that makes sense.
                    // For N > 2 and N/2 is even, Chanek takes N/2.
                    chanek_score += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, opponent takes 1
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd, opponent takes N/2
                    n /= 2;
                } else { // N/2 is even, opponent takes N/2
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_score;
}

