    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Check 'R'
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        // Check 'S'
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // Check 'P'
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        // If counts are equal, any choice among the most frequent is fine.
        // The order of if statements above implicitly prioritizes R, then S, then P.
        // This is fine as any of them will yield the same maximum average wins.

        char our_optimal_move = get_winning_move(most_frequent_bot_move);

        for (size_t i = 0; i < s.length(); ++i) {
