    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int i = n - 1;

    // Step 1: Find the longest suffix that is non-decreasing
    // This means a[i-1] <= a[i]
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // After this loop, a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.
    // If i > 0, then a[i-1] < a[i].

    // Step 2: Find the longest suffix of the remaining prefix that is non-increasing
    // This means a[i-1] >= a[i]
    // We continue from the point where the non-decreasing suffix ended.
    // The goal is to find the first element from the right that breaks the non-increasing trend.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // n=7
    // i starts at 6.
    // a[5]=5, a[6]=2. a[5] >= a[6] is false. So i remains 6.
    // This is wrong. The condition is a[i-1] >= a[i] for non-decreasing.
    // Let's re-evaluate the logic for finding the "peak".

    // The logic is: find the rightmost peak.
    // The array must look like: ... [decreasing part] [increasing part]
    // Or: ... [decreasing part]
    // Or: ... [increasing part]

    // Find the end of the non-decreasing suffix
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // n=7
    // i=6, a[6]=2
    // i=5, a[5]=3. a[5] >= a[6] (3 >= 2) is true. i becomes 5.
    // i=4, a[4]=5. a[4] >= a[5] (5 >= 3) is true. i becomes 4.
    // i=3, a[3]=4. a[3] >= a[4] (4 >= 5) is false. Loop stops.
    // So, i is 4. The suffix a[4...6] = [5, 3, 2] is non-increasing.
    // This is the first part of the "good array" structure.
    // The elements a[4], a[5], a[6] would be picked from right to left.

    // Now, from this point `i`, we need to find the start of the non-decreasing part.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // Current `i` is 4. (a[4]=5)
    // We need to find the point `j` such that a[j...i-1] is non-decreasing.
    // And a[j-1] > a[j] (if j > 0).

    // Let's restart the logic for finding the "peak".
    // We are looking for the longest suffix `a[k...n-1]` that can be formed into a non-decreasing `c`.
    // This suffix must have a structure like `[...decreasing...peak...increasing...]`
    // Or `[...decreasing...]`
    // Or `[...increasing...]`

    // Find the first element from the right that breaks the non-decreasing order.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // n=7
    // i = n-1 = 6.
    // a[6]=2
    // a[5]=5. a[5] > a[6]. (5 > 2). This is non-decreasing from right.
    // a[4]=4. a[4] < a[5]. (4 < 5). This breaks the non-decreasing from right.
    // So, the suffix [4, 5, 2] is the candidate.
    // The elements are 4, 5, 2.
    // We can pick 2, then 5, then 4. This forms [2, 5, 4] which is not non-decreasing.
    // This means the "good array" property is not just about a single peak.

    // The property of a good array `b` is that it can be split into two parts:
    // `b_1, ..., b_k` and `b_{k+1}, ..., b_m` such that
    // `b_1, ..., b_k` is non-decreasing (picked from left)
    // `b_m, b_{m-1}, ..., b_{k+1}` is non-decreasing (picked from right)
    // And `b_k <= b_{k+1}` (if both parts exist).
    // This is equivalent to saying that the array `b` must be "bitonic" if we consider the elements in the order they are picked.
    // But the problem states we can pick from either end.

    // Let's re-read the example: b = [1, 2, 3, 4, 4, 2, 1]
    // c = [1] (take b_1)
    // c = [1, 1] (take b_7)
    // c = [1, 1, 2] (take b_6)
    // c = [1, 1, 2, 2] (take b_2)
    // c = [1, 1, 2, 2, 3] (take b_3)
    // c = [1, 1, 2, 2, 3, 4] (take b_5)
    // c = [1, 1, 2, 2, 3, 4, 4] (take b_4)
    // The elements picked are: b_1, b_7, b_6, b_2, b_3, b_5, b_4.
    // Original indices: 1, 7, 6, 2, 3, 5, 4.
    // This means the elements remaining in `b` at any point form a contiguous subarray.
    // The elements picked are `b_1, b_2, ..., b_k` and `b_m, b_{m-1}, ..., b_j`.
    // The remaining elements are `b_{k+1}, ..., b_{j-1}`.
    // The elements picked from the left are `b_1, ..., b_k`.
    // The elements picked from the right are `b_m, ..., b_j`.
    // The elements `b_1, ..., b_k` must be non-decreasing.
    // The elements `b_m, ..., b_j` must be non-decreasing.
    // And the last element picked from the left (`b_k`) must be less than or equal to the first element picked from the right (`b_m`).
    // And the last element picked from the right (`b_j`) must be less than or equal to the first element picked from the left (`b_1`).
    // This is getting complicated.

    // A simpler interpretation:
    // The elements that form `c` are taken from the ends of the current `b`.
    // This means `c` is formed by some prefix `b[0...k-1]` and some suffix `b[j...m-1]`.
    // The elements `b[k...j-1]` are never picked. This is incorrect. All elements are picked.
    // The elements picked are `b_0, b_1, ..., b_L` and `b_R, b_{R-1}, ..., b_{m-1}`.
    // Where `L` is the index of the last element picked from the left, and `R` is the index of the first element picked from the right.
    // The elements `b_0, ..., b_L` are picked in increasing order of index.
    // The elements `b_R, ..., b_{m-1}` are picked in decreasing order of index.
    // The elements `b_L` and `b_R` are the "inner" elements.
    // The elements `b_0, ..., b_L` and `b_R, ..., b_{m-1}` must form a non-decreasing sequence when merged.
    // This means `b_0 <= b_1 <= ... <= b_L` and `b_{m-1} <= b_{m-2} <= ... <= b_R`.
    // And the sequence `b_0, ..., b_L, b_R, ..., b_{m-1}` must be non-decreasing.
    // This implies `b_L <= b_R`.

    // So, a good array `b` must have the property that there exists an index `k` (0 <= k <= m) such that:
    // 1. `b[0...k-1]` is non-decreasing. (If k=0, this part is empty).
    // 2. `b[k...m-1]` is non-increasing. (If k=m, this part is empty).
    // This is the "mountain" or "valley" shape.
    // If `b` is `[b_0, ..., b_{k-1}, b_k, ..., b_{m-1}]`
    // We can pick `b_0, b_1, ..., b_{k-1}` (if `b_0 <= ... <= b_{k-1}`)
    // Then pick `b_{m-1}, b_{m-2}, ..., b_k` (if `b_{m-1} <= ... <= b_k`)
    // The resulting `c` would be `[b_0, ..., b_{k-1}, b_{m-1}, ..., b_k]`.
    // For `c` to be non-decreasing, we need `b_{k-1} <= b_{m-1}`.
    // This is the condition for a "good" array.

    // Let's try this interpretation.
    // We need to find the smallest `p` such that `a[p...n-1]` is good.
    // Let `b = a[p...n-1]`.
    // We need to find `k` such that `b[0...k-1]` is non-decreasing and `b[k...m-1]` is non-increasing.
    // (where `m = n-p`).
    // This means `a[p] <= a[p+1] <= ... <= a[p+k-1]`
    // and `a[p+k] >= a[p+k+1] >= ... >= a[n-1]`.

    // Let's find the rightmost `k` such that `a[k...n-1]` is non-increasing.
    // `i` is the index of the first element of this non-increasing suffix.
    // `a[i] >= a[i+1] >= ... >= a[n-1]`
    // Example: `a = [1, 3, 1, 4, 5, 3, 2]`
    // `n=7`.
    // `i = n-1 = 6`. `a[6]=2`.
    // `i=5`. `a[5]=3`. `a[5] >= a[6]` (3 >= 2). `i` becomes 5.
    // `i=4`. `a[4]=5`. `a[4] >= a[5]` (5 >= 3). `i` becomes 4.
    // `i=3`. `a[3]=4`. `a[3] >= a[4]` (4 >= 5) is false. Loop stops.
    // So, `i` is 4. The suffix `a[4...6]` is `[5, 3, 2]`. This is non-increasing.
    // This `i` is the potential `k` in the definition `b[k...m-1]` is non-increasing.

    // Now, we need to find the rightmost `j` such that `a[j...i-1]` is non-decreasing.
    // `j` is the index of the first element of this non-decreasing part.
    // `a[j] <= a[j+1] <= ... <= a[i-1]`
    // Continuing from `i=4` (a[4]=5).
    // `j` starts at `i-1 = 3`. `a[3]=4`.
    // `j=2`. `a[2]=1`. `a[2] <= a[3]` (1 <= 4). `j` becomes 2.
    // `j=1`. `a[1]=3`. `a[1] <= a[2]` (3 <= 1) is false. Loop stops.
    // So, `j` is 2. The segment `a[2...3]` is `[1, 4]`. This is non-decreasing.
    // This `j` is the potential `p` in the definition `a[p...n-1]` is good.

    // So, for `a = [1, 3, 1, 4, 5, 3, 2]`, we found `j=2`.
    // The suffix `a[2...6]` is `[1, 4, 5, 3, 2]`.
    // This suffix has `a[2...3]` (`[1, 4]`) non-decreasing.
    // And `a[4...6]` (`[5, 3, 2]`) non-increasing.
    // This means `p=2` is the answer.
    // The length of the prefix to erase is `p = 2`.

