int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // First, handle friends with w_i = 1.
        // They should get the largest available numbers.
        // These are the friends with the largest w_i values in the sorted w array,
        // if w_i = 1.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += 2 * a[a_ptr_right];
                a_ptr_right--;
            } else {
                // Since w is sorted, all remaining w[i] will be > 1.
                // We can break here.
                break;
            }
        }

        // Now, handle friends with w_i > 1.
        // These are the friends with smaller w_i values in the sorted w array.
        // They need one largest number and one smallest number from their assigned set.
        // To maximize happiness, they should get the remaining largest numbers as their max_val.
        // And the smallest available numbers as their min_val.
        for (int i = 0; i < k; ++i) {
            if (w[i] > 1) {
                // This friend gets one of the remaining largest numbers as max_val
                total_happiness += a[a_ptr_right];
                a_ptr_right--;

                // This friend gets one of the remaining smallest numbers as min_val
                total_happiness += a[a_ptr_left];
                a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest numbers
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

