int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1000000007;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually have to pass this 'b'.
            // When an 'a' passes a 'b', it generates a new 'b'.
            // So, this 'b' effectively doubles the number of 'a's
            // that will need to pass subsequent 'b's to its right.
            // Or, more simply, it means the current 'a's (count_a)
            // will each perform an operation with this 'b'.
            // And each such operation "ab" -> "bba" generates a new 'b'.
            // This new 'b' will then also need to be passed by the
            // remaining 'a's.
            // The number of 'a's that need to pass this 'b' is `count_a`.
            // Each such pass adds `count_a` to `total_steps`.
            // And each such pass also effectively doubles the number of 'a's
            // that will need to pass any 'b's further to the left.
            // So, `count_a` itself doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to pass all 'b's that are currently to its right.
            // The number of 'b's it needs to pass is `count_a` (which
            // represents the effective number of 'b's to its right,
            // including those generated by previous operations).
            // So, this 'a' adds 1 to the count of 'a's that need to
            // pass subsequent 'b's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

