int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int x = 0; x <= 9; ++x) {
        std::string coloring(n, ' ');
        char last1 = '0' - 1; // Smallest possible char
        char last2 = '0' - 1; // Smallest possible char
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < x + '0') {
                // Must be color 1
                if (current_digit < last1) {
                    possible = false;
                    break;
                }
                coloring[i] = '1';
                last1 = current_digit;
            } else if (current_digit > x + '0') {
                // Must be color 2
                if (current_digit < last2) {
                    possible = false;
                    break;
                }
                coloring[i] = '2';
                last2 = current_digit;
            } else { // current_digit == x + '0'
                // Can be color 1 or 2
                if (current_digit >= last2) {
                    // Prefer color 2 if possible, to keep last1 small
                    coloring[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    // Otherwise, try color 1
                    coloring[i] = '1';
                    last1 = current_digit;
                } else {
                    // Cannot be colored 1 or 2
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

