int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    long long sum_r = (b - 1);
    sum_r = (sum_r * b) % MOD;

    // Modular inverse of 2 for division
    // Since MOD is prime (10^9 + 7), we can use Fermat's Little Theorem: a^(MOD-2) % MOD
    long long inv2 = 500000004; // (MOD + 1) / 2

    sum_r = (sum_r * inv2) % MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a

    long long sum_k_b_plus_1_term1 = (a * (a + 1)) % MOD;
    sum_k_b_plus_1_term1 = (sum_k_b_plus_1_term1 * inv2) % MOD;
    sum_k_b_plus_1_term1 = (sum_k_b_plus_1_term1 * b) % MOD;

    long long sum_k_b_plus_1_term2 = a % MOD;

    long long sum_k_b_plus_1 = (sum_k_b_plus_1_term1 + sum_k_b_plus_1_term2) % MOD;

    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

