#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        long long N = std::max(abs_n, abs_m);
        long long M = std::min(abs_n, abs_m);

        // Case 1: k < N (minimum moves required is N)
        if (k < N) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= N
        // The maximum number of diagonal moves is N.
        // After N diagonal moves, we can reach (N, N) or (N, -N) etc.
        // Or more generally, (N, M) using M diagonal moves and N-M straight moves.
        // The remaining k - N moves must be used to return to (N, M) or stay there.
        // Each pair of moves (e.g., (x,y) -> (x+1,y) -> (x,y)) costs 2 moves and changes parity by 0.
        // Each pair of moves (e.g., (x,y) -> (x+1,y+1) -> (x+1,y)) costs 2 moves and changes parity by 0.
        // The parity of (x+y) changes with each move.
        // (x,y) -> (x',y')
        // (x'+y') - (x+y) = (x'-x) + (y'-y)
        // For any of the 8 moves, (x'-x) is -1, 0, or 1, and (y'-y) is -1, 0, or 1.
        // The sum (x'-x) + (y'-y) can be -2, -1, 0, 1, 2.
        // This means (x'+y') and (x+y) have the same parity if (x'-x)+(y'-y) is even.
        // This means (x'+y') and (x+y) have different parity if (x'-x)+(y'-y) is odd.
        //
        // Let's check the parity of (N+M) and K.
        // If (N+M) and K have different parities, it's impossible to reach (N,M) in K moves.
        // This is because each move changes the parity of (current_x + current_y).
        // Starting at (0,0), (0+0) is even.
        // After 1 move, (x1+y1) is odd.
        // After 2 moves, (x2+y2) is even.
        // ...
        // After K moves, (xk+yk) has the same parity as K.
        // So, we must have (N+M) % 2 == K % 2.

        if ((N + M) % 2 != k % 2) {
            std::cout << -1 << "\n";
            continue;
        }

        // If (N+M) and K have the same parity, and K >= N, it is always possible.
        // The maximum number of diagonal moves is K if we can make all moves diagonal.
        // This is not true. We can make at most N diagonal moves to reach (N,M) if N=M.
        // If N > M, we can make M diagonal moves to reach (N-M, 0).
        // Then we need N-M straight moves. Total moves so far: M + (N-M) = N.
        // The remaining k-N moves must be used to "waste" moves.
        // Each wasted move must be paired with another move to return to the same point or an equivalent point.
        // For example, (x,y) -> (x+1,y) -> (x,y). This uses 2 moves, 0 diagonal, and changes (x+y) parity twice (odd then even).
        // Or (x,y) -> (x+1,y+1) -> (x+1,y). This uses 2 moves, 1 diagonal, 1 straight.
        //
        // The strategy to maximize diagonal moves:
        // 1. Make M diagonal moves to reach (N-M, 0) (assuming N >= M).
        //    This uses M moves.
        // 2. Make N-M straight moves to reach (N, 0).
        //    This uses N-M moves.
        // Total moves so far: M + (N-M) = N.
        // Total diagonal moves so far: M.
        // Current position: (N, M).
        // Remaining moves: k - N.
        //
        // Now we have k - N moves left. We are at (N, M).
        // We want to use these remaining moves to maximize diagonal moves.
        // Each remaining move must be paired up to maintain the final position (N, M).
        // For example, (N,M) -> (N+1,M+1) -> (N,M). This uses 2 moves, 2 diagonal.
        // Or (N,M) -> (N+1,M) -> (N,M). This uses 2 moves, 0 diagonal.
        //
        // If we have an even number of remaining moves, say `rem = k - N`, we can make `rem / 2` pairs of moves.
        // Each pair can be (x,y) -> (x+1,y+1) -> (x,y). This adds 2 diagonal moves.
        // So, we can add `(k - N)` diagonal moves.
        // Total diagonal moves = M + (k - N).
        //
        // This strategy works if (N+M) and K have the same parity.
        // The number of diagonal moves is M + (k - N).
        // This is because N is the minimum number of moves.
        // Any additional moves (k-N) must be made in pairs to end up at the same target.
        // Each pair of moves can be made as two diagonal moves (e.g., (x,y) -> (x+1,y+1) -> (x,y)).
        // This adds 2 diagonal moves for 2 total moves.
        // So, for k-N additional moves, we can add k-N diagonal moves.
        // The initial M diagonal moves are used to cover the min(abs_n, abs_m) distance.
        // The remaining N-M moves are straight moves.
        // Total diagonal moves = M + (k - N).

        std::cout << k - (k - N) % 2 << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> d(n);
    std::deque<int> q;

    // Initialize distances for boundary blocks (h_i = 1)
    // and add them to the queue.
    // A block at (i, j) is boundary if j=1 (bottom) or j=h_i (top)
    // or if i=0 (leftmost) or i=n-1 (rightmost)
    // or if h_{i-1} < j or h_{i+1} < j.
    // The minimum number of operations for a block at height j in tower i
    // is min(j, h_i - j + 1, distance to left boundary, distance to right boundary).
    // The distance to left/right boundary is related to the minimum height of adjacent towers.
    // This is equivalent to finding the maximum 'water level' that can reach a block.
    // A block at (i, j) is destroyed in k operations if it's k-th layer from any boundary.
    // The value d[i] will store the maximum k for tower i.
    // We can compute d[i] = min(h[i], distance_from_left_edge[i], distance_from_right_edge[i]).
    // distance_from_left_edge[i] = min(h[0], h[1]+1, h[2]+2, ..., h[i]+i)
    // This is not quite right. It's min(h[i], h[i-1]+1, h[i-2]+2, ...)
    // The actual value for a block at (i, j) is min(j, h_i - j + 1, dist_left, dist_right).
    // dist_left for tower i is the maximum k such that a block at (i, k) is not destroyed by left boundary.
    // This is min(h[i], h[i-1]+1, h[i-2]+2, ..., h[0]+i).
    // This is equivalent to min(h[i], h[i-1]+1, h[i-2]+2, ..., h[0]+i).
    // The value d[i] should be the maximum k such that a block at (i, k) exists.
    // This is min(h[i], d_left[i], d_right[i]).
    // d_left[i] = min(h[i], d_left[i-1]+1)
    // d_right[i] = min(h[i], d_right[i+1]+1)

    // Calculate d_left: maximum height a block can have considering only left boundary
    // d_left[i] = min(h[i], d_left[i-1] + 1)
    // d_left[0] = h[0]
    std::vector<long long> d_left(n);
    d_left[0] = h[0];
    for (int i = 1; i < n; ++i) {
        d_left[i] = std::min(h[i], d_left[i - 1] + 1);
    }

    // Calculate d_right: maximum height a block can have considering only right boundary
    // d_right[i] = min(h[i], d_right[i+1] + 1)
    // d_right[n-1] = h[n-1]
    std::vector<long long> d_right(n);
    d_right[n - 1] = h[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        d_right[i] = std::min(h[i], d_right[i + 1] + 1);
    }

    // The actual maximum height a block can have in tower i, considering all boundaries
    // is min(d_left[i], d_right[i]).
    // This value represents the maximum number of operations for any block in tower i.
    // The overall answer is the maximum of these values across all towers.
    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(d_left[i], d_right[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Handle n-1 elements (or all if n=1)
    // For each a[i], we want to add a multiple of n to make it a multiple of n.
    // Specifically, we want a[i] + x * n = 0 (mod n).
    // This means a[i] = 0 (mod n).
    // If a[i] is not a multiple of n, we can add (n - (a[i] % n)) % n * n to it.
    // This makes a[i] a multiple of n.
    // Or, more simply, we can add (n - (a[i] % n + n) % n) * n to a[i].
    // Let's make a[i] become a multiple of n.
    // The value to add is (n - (a[i] % n + n) % n) * n.
    // This is equivalent to (n - (a[i] % n + n) % n) * n.
    // Let rem = (a[i] % n + n) % n. If rem is 0, we add 0.
    // Otherwise, we add (n - rem) * n.
    // This makes a[i] become a[i] + (n - rem) * n.
    // The new a[i] will be a multiple of n.
    // This operation is applied to elements from index 0 to n-2 (inclusive).
    // If n=1, this operation is applied to index 0.

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Dummy operation
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";

        // Operation 3: Dummy operation
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
    } else {
        // Operation 1: Make a[0]...a[n-2] multiples of n
        std::cout << 1 << " " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long rem = (a[i] % n + n) % n; // Ensure positive remainder
            long long add_val = (n - rem) % n * n; // Value to add to make it a multiple of n
            std::cout << add_val << (i == n - 2 ? "" : " ");
            a[i] += add_val;
        }
        std::cout << "\n";

        // Operation 2: Make a[n-1] a multiple of n
        // This is done by adding a multiple of n to a[n-1].
        // The value to add is (n - (a[n-1] % n + n) % n) * n.
        // This makes a[n-1] become a[n-1] + (n - rem) * n.
        // The new a[n-1] will be a multiple of n.
        std::cout << n << " " << n << "\n";
        long long rem_last = (a[n - 1] % n + n) % n;
        long long add_val_last = (n - rem_last) % n * n;
        std::cout << add_val_last << "\n";
        a[n - 1] += add_val_last;

        // After operations 1 and 2, all a[i] are multiples of n.
        // Operation 3: Make all elements zero.
        // For each a[i], since it's a multiple of n, we can add -a[i] to it.
        // -a[i] is also a multiple of n.
        std::cout << 1 << " " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        long long num_zeros = n - m;

        // To minimize the number of substrings consisting only of '0's,
        // we want to distribute the '0's as evenly as possible among
        // the m+1 possible blocks created by the m '1's.
        // For example, if m=1, string is 00...0100...0.
        // If m=2, string is 00...0100...0100...0.
        // The '1's act as separators. There are m '1's, so they create m+1 potential blocks of '0's.
        // Let k be the number of '0's in each of the (m+1) blocks.
        // We distribute num_zeros among m+1 blocks.
        // Some blocks will have floor(num_zeros / (m+1)) zeros.
        // Some blocks will have ceil(num_zeros / (m+1)) zeros.

        long long num_blocks = m + 1;
        long long k_floor = num_zeros / num_blocks;
        long long k_ceil = k_floor + 1;

        long long count_ceil_blocks = num_zeros % num_blocks;
        long long count_floor_blocks = num_blocks - count_ceil_blocks;

        long long zero_only_substrings = 0;
        zero_only_substrings += count_floor_blocks * (k_floor * (k_floor + 1) / 2);
        zero_only_substrings += count_ceil_blocks * (k_ceil * (k_ceil + 1) / 2);

        long long result = total_substrings - zero_only_substrings;
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // s_left[i] = balance (1s - 2s) for jars 1 to i
    // s_left[0] = 0 (before any jars)
    // s_left[i] = s_left[i-1] + (a[i-1] == 1 ? 1 : -1)
    std::vector<int> s_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_left[i + 1] = s_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // s_right[i] = balance (1s - 2s) for jars i to 2n
    // s_right[2n] = 0 (after all jars)
    // s_right[i] = s_right[i+1] + (a[i] == 1 ? 1 : -1)
    std::vector<int> s_right(2 * n + 1, 0);
    for (int i = 2 * n - 1; i >= n; --i) {
        s_right[i] = s_right[i + 1] + (a[i] == 1 ? 1 : -1);
    }

    // Store indices for each balance value on the left side
    // map: balance -> minimum number of jars removed from left to achieve this balance
    // (i.e., n - i jars remaining, so i jars removed)
    std::map<int, int> left_balance_to_removed_count;
    for (int i = 0; i <= n; ++i) { // i is the number of jars remaining on the left (from 1 to i)
                                   // So, n-i jars are removed from the left.
        int balance = s_left[i];
        int removed_count = n - i;
        if (left_balance_to_removed_count.find(balance) == left_balance_to_removed_count.end()) {
            left_balance_to_removed_count[balance] = removed_count;
        } else {
            left_balance_to_removed_count[balance] = std::min(left_balance_to_removed_count[balance], removed_count);
        }
    }

    int min_total_removed = 2 * n; // Initialize with max possible removed jars

    // Iterate through possible number of jars remaining on the right side
    // j is the number of jars remaining on the right (from j to 2n)
    // So, j - (n+1) jars are removed from the right.
    for (int j = n; j < 2 * n + 1; ++j) { // j is the index of the first jar remaining on the right
                                          // If j=n, it means all jars from n+1 to 2n are removed.
                                          // If j=2n, it means jar 2n is remaining.
                                          // If j=2n+1, it means no jars remaining on the right.
        int current_right_balance = s_right[j];
        int removed_from_right = j - n; // Number of jars removed from the right side (n+1 to j-1)

        // We need total balance to be 0.
        // So, balance_left + balance_right = 0
        // balance_left = -balance_right
        int target_left_balance = -current_right_balance;

        if (left_balance_to_removed_count.count(target_left_balance)) {
            int removed_from_left = left_balance_to_removed_count[target_left_balance];
            min_total_removed = std::min(min_total_removed, removed_from_left + removed_from_right);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we need to know how it transforms 0 and 1.
    // state[bit_idx][0] = result if input bit is 0
    // state[bit_idx][1] = result if input bit is 1
    // Initially, input bit 0 maps to 0, input bit 1 maps to 1.
    std::vector<std::vector<int>> state(10, std::vector<int>(2));
    for (int i = 0; i < 10; ++i) {
        state[i][0] = 0; // If input bit is 0, it remains 0
        state[i][1] = 1; // If input bit is 1, it remains 1
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int i = 0; i < 10; ++i) {
            int bit_x = (x >> i) & 1;
            if (op_char == '&') {
                state[i][0] &= bit_x;
                state[i][1] &= bit_x;
            } else if (op_char == '|') {
                state[i][0] |= bit_x;
                state[i][1] |= bit_x;
            } else if (op_char == '^') {
                state[i][0] ^= bit_x;
                state[i][1] ^= bit_x;
            }
        }
    }

    // Now, reconstruct the equivalent operations.
    // We need to find A, B, C such that:
    // (val & A | B) ^ C
    // For each bit i:
    // If input bit is 0: (0 & A_i | B_i) ^ C_i = state[i][0]
    // If input bit is 1: (1 & A_i | B_i) ^ C_i = state[i][1]

    // Let's determine A_i, B_i, C_i for each bit.
    // A_i: bit for AND mask
    // B_i: bit for OR mask
    // C_i: bit for XOR mask
    int final_and_mask = 1023; // All bits initially 1 for AND
    int final_or_mask = 0;     // All bits initially 0 for OR
    int final_xor_mask = 0;    // All bits initially 0 for XOR

    for (int i = 0; i < 10; ++i) {
        int s0 = state[i][0]; // Result for input bit 0
        int s1 = state[i][1]; // Result for input bit 1

        // Case 1: s0=0, s1=0
        // Input 0 -> 0, Input 1 -> 0
        // This means the bit is always 0, regardless of input.
        // (x_i & 0 | 0) ^ 0 = 0
        // (x_i & 1 | 0) ^ 1 = 0
        // (x_i & 0 | 1) ^ 1 = 0
        // (x_i & 1 | 1) ^ 1 = 0
        // Simplest: AND with 0.
        // A_i = 0, B_i = 0, C_i = 0
        if (s0 == 0 && s1 == 0) {
            final_and_mask &= ~(1 << i); // Set A_i to 0
            // B_i remains 0
            // C_i remains 0
        }
        // Case 2: s0=0, s1=1
        // Input 0 -> 0, Input 1 -> 1
        // This means the bit is unchanged.
        // (x_i & 1 | 0) ^ 0 = x_i
        // Simplest: AND with 1, OR with 0, XOR with 0.
        // A_i = 1, B_i = 0, C_i = 0
        else if (s0 == 0 && s1 == 1) {
            // A_i remains 1
            // B_i remains 0
            // C_i remains 0
        }
        // Case 3: s0=1, s1=0
        // Input 0 -> 1, Input 1 -> 0
        // This means the bit is flipped.
        // (x_i & 1 | 0) ^ 1 = ~x_i
        // Simplest: AND with 1, OR with 0, XOR with 1.
        // A_i = 1, B_i = 0, C_i = 1
        else if (s0 == 1 && s1 == 0) {
            // A_i remains 1
            // B_i remains 0
            final_xor_mask |= (1 << i); // Set C_i to 1
        }
        // Case 4: s0=1, s1=1
        // Input 0 -> 1, Input 1 -> 1
        // This means the bit is always 1, regardless of input.
        // (x_i & 0 | 1) ^ 0 = 1
        // (x_i & 1 | 1) ^ 0 = 1
        // Simplest: OR with 1.
        // A_i = 1, B_i = 1, C_i = 0
        else if (s0 == 1 && s1 == 1) {
            // A_i remains 1
            final_or_mask |= (1 << i); // Set B_i to 1
            // C_i remains 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any A_i is 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any B_i is 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any C_i is 1
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // Convert to 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks which vertices are currently in the graph

    // Process vertices in reverse order of removal (i.e., addition order)
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added in this step

        active[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step:
        // When vertex k is added, it can potentially shorten paths between any two active vertices i and j.
        // d[i][j] = min(d[i][j], d[i][k] + d[k][j])
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue; // Only consider active vertices

                // Update paths using k as an intermediate vertex
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using a sentinel for infinity
                    dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                }
            }
        }

        // After adding k and updating all paths through k,
        // k itself can be an intermediate for paths between other active vertices.
        // Also, other active vertices can be intermediates for paths involving k.
        // The standard Floyd-Warshall structure is:
        // for k:
        //   for i:
        //     for j:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This structure correctly updates all pairs shortest paths considering all vertices up to k.
        // Since we are adding vertices one by one, the `active` set grows.
        // The current `dist` matrix already contains shortest paths considering all previously added vertices.
        // When `k` is added, we need to update paths using `k` as an intermediate.
        // And also, paths from `k` to `i` and `i` to `k` might be shortened by other active vertices `j`.
        // The nested loops below ensure all pairs (i,j) among active vertices are updated using any active vertex as intermediate.
        // This is essentially running Floyd-Warshall on the subgraph of active vertices.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                for (int p = 0; p < n; ++p) { // p is the intermediate vertex
                    if (!active[p]) continue;
                    if (dist[i][p] != -1 && dist[p][j] != -1) {
                        dist[i][j] = std::min(dist[i][j], dist[i][p] + dist[p][j]);
                    }
                }
            }
        }


        // Calculate the sum of shortest paths for all pairs of currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the original order (before x_1, before x_2, ..., before x_n)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, ensure positive and < 10^18

    // Iterate through powers of 2 from largest possible down to 1
    // A block of 'k' identical numbers contributes 2^k - 1 subsequences.
    // We want to find the largest k such that 2^k - 1 <= X.
    // This is equivalent to 2^k <= X + 1.
    // So k <= log2(X + 1).
    // Since X can be up to 10^9, log2(10^9 + 1) is approx log2(10^9) = 9 * log2(10) approx 9 * 3.32 = 29.89.
    // So k can be at most 29.
    // We can iterate k from 60 down to 1, as 2^60 is much larger than 10^9.
    // The maximum number of elements in the array is 10^4.
    // If we use 60 distinct blocks, each block having at least one element, that's 60 elements.
    // If X is 10^9, and we use blocks of size 29, we need 10^9 / (2^29 - 1) blocks.
    // 2^29 - 1 is approx 5 * 10^8. So we need about 2 blocks of size 29.
    // The total number of elements will be sum of k_i for each block.
    // Max k is 60. Max number of blocks is 60. Max elements 60 * 60 = 3600. This is well within 10^4.

    for (int k = 60; k >= 1; --k) {
        long long count_for_k = (1LL << k) - 1; // Number of subsequences from k identical elements
        if (count_for_k <= 0) continue; // Avoid issues with 1LL << 0 - 1 = 0, or overflow if k is too large (not an issue here)

        while (X >= count_for_k) {
            for (int i = 0; i < k; ++i) {
                result_array.push_back(current_val);
            }
            X -= count_for_k;
            // Move to the next block of numbers, ensuring separation by 'd'
            // current_val + d + 1 ensures current_val + d is not used, and current_val + d + 1 is the minimum possible value for the next block
            // to satisfy the condition.
            // If current_val is 1, d is 1, then next block starts at 1+1+1 = 3.
            // If current_val is 1, d is 10^9, then next block starts at 1+10^9+1 = 10^9+2.
            // This ensures max - min >= d for subsequences spanning different blocks.
            // We need to be careful about current_val exceeding 10^18.
            // Max current_val can be 1 + 60 * (10^9 + 1). This is approx 60 * 10^9, which is < 10^18.
            current_val += d + 1;
            if (result_array.size() > 10000) {
                // This case should ideally not be reached given the constraints,
                // but as a safeguard.
                std::cout << -1 << std::endl;
                return 0;
            }
        }
    }

    if (X != 0) {
        // This means X could not be fully decomposed into (2^k - 1) terms.
        // This should not happen if the logic is correct, as k=1 (2^1-1=1) should handle any remaining X.
        // If X is 0 at this point, it means all subsequences have been accounted for.
        // If X is not 0, it means there's a bug or an impossible case.
        // For example, if X was 1, k=1 would add 1 to result_array, X becomes 0.
        // If X was 2, k=1 would add 1 to result_array, X becomes 1. Then k=1 again, add 1, X becomes 0.
        // This implies that X should always be 0 at the end.
        std::cout << -1 << std::endl;
        return 0;
    }

    if (result_array.empty()) {
        // This case happens if X was 0 initially, which is not allowed by constraints (X >= 1).
        // Or if X was 1 and d was very large, and current_val + d + 1 overflowed.
        // But current_val is capped at ~60*10^9, so no overflow.
        // If X=1, k=1 loop will run once, add 1 element. So result_array won't be empty.
        std::cout << -1 << std::endl;
        return 0;
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (b_1=a_1, b_n=a_n, no middle elements)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_dist(n, 0);
    std::vector<int> right_dist(n, 0);

    // Calculate left_dist: distance to the nearest '1' on the left (inclusive)
    // or distance to the nearest '0' on the left (inclusive)
    // For a[i] == 0, left_dist[i] is distance to nearest 1 on left.
    // For a[i] == 1, left_dist[i] is distance to nearest 0 on left.
    // This is equivalent to finding runs of identical values.
    // left_dist[i] stores the length of the run ending at i.
    left_dist[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            left_dist[i] = left_dist[i - 1] + 1;
        } else {
            left_dist[i] = 1;
        }
    }

    // Calculate right_dist: distance to the nearest '1' on the right (inclusive)
    // or distance to the nearest '0' on the right (inclusive)
    // right_dist[i] stores the length of the run starting at i.
    right_dist[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == a[i + 1]) {
            right_dist[i] = right_dist[i + 1] + 1;
        } else {
            right_dist[i] = 1;
        }
    }

    int max_steps = 0;
    std::vector<int> b = a; // Resulting stable sequence

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] != a[i - 1] && a[i] != a[i + 1]) { // Pattern 010 or 101
            int k = std::min(left_dist[i - 1], right_dist[i + 1]);
            max_steps = std::max(max_steps, k);

            // Apply smoothing to the 'k' elements around 'i'
            // For 010...10, the 0s and 1s will flip towards the center.
            // The middle element a[i] will flip k times.
            // The elements a[i-j] and a[i+j] will flip k-j times.
            // After k steps, the segment a[i-k+1 ... i+k-1] will become uniform.
            // The value will be a[i-k] if k > 0, or a[i+k] if k > 0.
            // More simply, the value will be a[i-1] (or a[i+1])
            // For example, 01010, k=2.
            // a[i-1] = 0, a[i+1] = 0.
            // b[i] becomes 0.
            // b[i-1] becomes 0.
            // b[i+1] becomes 0.
            // The segment a[i-k+1 ... i+k-1] becomes a[i-1] (or a[i+1])
            // This means b[i-k+1 ... i+k-1] will all become a[i-1]
            for (int j = 0; j < k; ++j) {
                b[i - j] = a[i - 1];
                b[i + j] = a[i + 1];
            }
        }
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct ChildData {
    int id;
    long long v; // Volume when in office
    long long d; // Volume when crying and leaving
    long long p; // Confidence
    bool in_line; // True if still in line, false if left
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<ChildData> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        // Child i goes to the dentist
        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_effect = children[i].v;
        long long cumulative_d_effect = 0;

        // Apply effects to children after child i
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cumulative d_effect from previously crying children
            children[j].p -= cumulative_d_effect;

            // Apply v_effect from child i
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                cumulative_d_effect += children[j].d; // Add to cumulative effect for subsequent children
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1).
    // S2 is empty. No pairs (a_i, a_j) with a_i in S1, a_j in S2.
    // All f values are a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness_all_one_subsequence = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value);
    long long min_goodness = goodness_all_one_subsequence;
    std::vector<int> best_partition(n, 1); // Default to all in S1

    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put a[0] into S1 and a[1]...a[n-1] into S2,
    // or a[0]...a[n-2] into S1 and a[n-1] into S2.
    // The optimal strategy for minimizing max(f) - min(f) often involves
    // putting the smallest element(s) in one group and the rest in another,
    // or the largest element(s) in one group and the rest in another.
    //
    // Consider a partition where a[0] is in S1 and a[1], ..., a[n-1] are in S2.
    // This is a common strategy to minimize the range of sums.
    //
    // f values:
    // 1. a_i + a_j (both in S1): Only possible if S1 has >= 2 elements. Here S1 has 1 element (a[0]), so no such pairs.
    // 2. a_i + a_j (both in S2): a[1]+a[2] ... a[n-2]+a[n-1]
    // 3. a_i + a_j + h (a_i in S1, a_j in S2): a[0]+a[1]+h ... a[0]+a[n-1]+h
    //
    // min_f:
    //   - If S2 has at least two elements (n >= 3): min(a[1]+a[2], a[0]+a[1]+h)
    //   - If S2 has one element (n=2): a[0]+a[1]+h
    // max_f:
    //   - max(a[n-2]+a[n-1], a[0]+a[n-1]+h)
    //
    // Let's analyze the specific partition: a[0] in S1, a[1...n-1] in S2.
    //
    // Minimum possible f value:
    //   - From S2: a[1].value + a[2].value (if n >= 3)
    //   - Between S1 and S2: a[0].value + a[1].value + h
    //   So, min_f_val = min(a[1].value + a[2].value, a[0].value + a[1].value + h) (if n >= 3)
    //   If n=2, S2 has only a[1], so only a[0]+a[1]+h is possible.
    //
    // Maximum possible f value:
    //   - From S2: a[n-2].value + a[n-1].value (if n >= 3)
    //   - Between S1 and S2: a[0].value + a[n-1].value + h
    //   So, max_f_val = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h) (if n >= 3)
    //   If n=2, S2 has only a[1], so only a[0]+a[1]+h is possible.

    // This specific partition is: a[0] in S1, a[1...n-1] in S2.
    // The values involved are:
    //   - a[0] + a[i] + h for i=1..n-1
    //   - a[i] + a[j] for i,j=1..n-1
    //
    // min_f_val:
    //   If n=2: a[0].value + a[1].value + h
    //   If n>=3: std::min(a[0].value + a[1].value + h, a[1].value + a[2].value)
    // max_f_val:
    //   If n=2: a[0].value + a[1].value + h
    //   If n>=3: std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value)

    long long current_min_f, current_max_f;
    if (n == 2) {
        current_min_f = a[0].value + a[1].value + h;
        current_max_f = a[0].value + a[1].value + h;
    } else { // n >= 3
        current_min_f = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
        current_max_f = std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value);
    }

    long long goodness_one_small_group = current_max_f - current_min_f;

    if (goodness_one_small_group < min_goodness) {
        min_goodness = goodness_one_small_group;
        for (int i = 0; i < n; ++i) {
            best_partition[a[i].original_index] = (i == 0) ? 1 : 2;
        }
    }

    // Consider another partition: a[0], a[1] in S1, a[2...n-1] in S2.
    // This is only relevant if n >= 3.
    //
    // f values:
    // 1. a[0]+a[1] (both in S1)
    // 2. a[i]+a[j] for i,j=2..n-1 (both in S2)
    // 3. a[k]+a[l]+h for k in {0,1}, l in {2..n-1} (different subsequences)
    //
    // min_f_val:
    //   - From S1: a[0].value + a[1].value
    //   - From S2: a[2].value + a[3].value (if n >= 4)
    //   - Between S1 and S2: a[0].value + a[2].value + h
    //   So, min_f_val = min(a[0].value + a[1].value, a[0].value + a[2].value + h, a[2].value + a[3].value (if n>=4))
    //
    // max_f_val:
    //   - From S1: a[0].value + a[1].value
    //   - From S2: a[n-2].value + a[n-1].value (if n >= 4)
    //   - Between S1 and S2: a[1].value + a[n-1].value + h
    //   So, max_f_val = max(a[0].value + a[1].value, a[1].value + a[n-1].value + h, a[n-2].value + a[n-1].value (if n>=4))

    // This partition is: a[0], a[1] in S1, a[2...n-1] in S2.
    // This is only a candidate if n >= 2.
    // If n=2, this is the same as all in S1.
    // If n=3: S1={a[0],a[1]}, S2={a[2]}
    //   min_f = min(a[0]+a[1], a[0]+a[2]+h, a[1]+a[2]+h)
    //   max_f = max(a[0]+a[1], a[0]+a[2]+h, a[1]+a[2]+h)
    //   Goodness = max_f - min_f
    //
    // If n >= 4: S1={a[0],a[1]}, S2={a[2],...,a[n-1]}
    //   min_f = min(a[0]+a[1], a[0]+a[2]+h, a[2]+a[3])
    //   max_f = max(a[0]+a[1], a[1]+a[n-1]+h, a[n-2]+a[n-1])

    if (n >= 2) { // This covers n=2, n=3, n>=4
        long long current_min_f_2_in_s1, current_max_f_2_in_s1;

        current_min_f_2_in_s1 = a[0].value + a[1].value; // From S1
        current_max_f_2_in_s1 = a[0].value + a[1].value; // From S1

        if (n >= 3) { // S2 is non-empty
            current_min_f_2_in_s1 = std::min(current_min_f_2_in_s1, a[0].value + a[2].value + h); // S1-S2
            current_max_f_2_in_s1 = std::max(current_max_f_2_in_s1, a[1].value + a[n-1].value + h); // S1-S2

            if (n >= 4) { // S2 has at least two elements
                current_min_f_2_in_s1 = std::min(current_min_f_2_in_s1, a[2].value + a[3].value); // From S2
                current_max_f_2_in_s1 = std::max(current_max_f_2_in_s1, a[n-2].value + a[n-1].value); // From S2
            }
        }

        long long goodness_two_small_group = current_max_f_2_in_s1 - current_min_f_2_in_s1;

        if (goodness_two_small_group < min_goodness) {
            min_goodness = goodness_two_small_group;
            for (int i = 0; i < n; ++i) {
                best_partition[a[i].original_index] = (i == 0 || i == 1) ? 1 : 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // dp[i] stores the maximum 'r' such that the substring s[i...r-1]
    // does NOT contain any bad triplet.
    // Or, more precisely, dp[i] stores the smallest 'r' such that
    // s[i...r-1] contains a bad triplet.
    // If no bad triplet starts at or after i, dp[i] = n + 1.
    // We want to find the largest 'j' such that s[i...j-1] is valid.
    // This 'j' is min_r_for_bad_triplet[i] - 1.
    // The number of valid substrings starting at i is (min_r_for_bad_triplet[i] - 1) - i + 1.
    // Which is min_r_for_bad_triplet[i] - i.

    std::vector<int> min_r_for_bad_triplet(n + 1, n + 1); // 1-indexed for string positions

    // Iterate through all possible x and k to find bad triplets
    // x is 1-indexed, k is 1-indexed
    // s_idx = x-1, s_k_idx = x+k-1, s_2k_idx = x+2k-1
    for (int x = 1; x <= n; ++x) {
        for (int k = 1; ; ++k) {
            int x_plus_2k = x + 2 * k;
            if (x_plus_2k > n) {
                break;
            }
            if (s[x - 1] == s[x + k - 1] && s[x + k - 1] == s[x_plus_2k - 1]) {
                // Found a bad triplet (x, x+k, x+2k)
                // This triplet covers the range [x, x+2k]
                // Any substring [l, r] where l <= x and r >= x+2k is invalid.
                // We are interested in the smallest r for a given l.
                // For a fixed x, the smallest r that makes a substring invalid is x+2k.
                // So, for any starting position 'i' (1-indexed) such that i <= x,
                // the substring s[i...x+2k-1] is invalid.
                // We want to find the minimum 'r' such that s[i...r-1] is invalid.
                // This means min_r_for_bad_triplet[i] = min(min_r_for_bad_triplet[i], x+2k).
                // Since we iterate x from 1 to n, and k from 1,
                // x+2k will be increasing.
                // We need to update min_r_for_bad_triplet[i] for all i <= x.
                // However, a simpler approach is to update min_r_for_bad_triplet[x]
                // with the smallest x+2k found for that x.
                // Then, we can propagate this information.
                min_r_for_bad_triplet[x] = std::min(min_r_for_bad_triplet[x], x_plus_2k);
            }
        }
    }

    // Now, min_r_for_bad_triplet[i] stores the smallest 'r' such that
    // s[i...r-1] contains a bad triplet starting at 'i'.
    // We need to propagate this: if s[i...r-1] is invalid, then s[i-1...r-1] is also invalid.
    // So, min_r_for_bad_triplet[i-1] should be at most min_r_for_bad_triplet[i].
    for (int i = n - 1; i >= 1; --i) {
        min_r_for_bad_triplet[i] = std::min(min_r_for_bad_triplet[i], min_r_for_bad_triplet[i + 1]);
    }

    // Now, min_r_for_bad_triplet[i] stores the smallest 'r' such that
    // the substring s[i...r-1] contains at least one bad triplet.
    // For each starting position 'l' (1-indexed), the valid substrings are
    // s[l...l-1], s[l...l], ..., s[l...min_r_for_bad_triplet[l]-2].
    // The number of valid substrings starting at 'l' is (min_r_for_bad_triplet[l] - 1) - l + 1
    // which simplifies to min_r_for_bad_triplet[l] - l.
    // These are the pairs (l, r) that are NOT counted.
    for (int l = 1; l <= n; ++l) {
        invalid_pairs += (min_r_for_bad_triplet[l] - l);
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());

    // For each type 2 operation, determine the maximum possible initial value for elements in its range.
    // This is done by "reversing" the effect of type 1 operations.
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            long long current_delta_sum = 0;

            // Calculate the total delta applied to elements in the range [ops[i].l, ops[i].r]
            // by type 1 operations *before* this type 2 operation.
            for (int j = 0; j < i; ++j) {
                if (ops[j].type == 1) {
                    // If the type 1 operation affects the range of the current type 2 operation,
                    // it means all elements in [ops[i].l, ops[i].r] would have been affected by d_j.
                    // This is a simplification: we assume d_j applies to the entire range [ops[i].l, ops[i].r].
                    // This is correct because we are looking for the *maximum* value.
                    // If a type 1 operation (j) affects *any* part of the range [ops[i].l, ops[i].r],
                    // then the maximum element in [ops[i].l, ops[i].r] could have been affected.
                    // However, to find the *initial* value, we need to subtract the sum of *all* d's
                    // that would have been applied to the element that *becomes* the maximum.
                    // The crucial insight is that if max(a_k + delta_k) = M, then max(a_k) = M - min(delta_k).
                    // But here, we are trying to find a_k such that max(a_k + current_delta_sum) = M.
                    // This means that for *some* k in [l, r], a_k + current_delta_sum = M.
                    // And for *all* k in [l, r], a_k + current_delta_sum <= M.
                    // So, a_k <= M - current_delta_sum for all k in [l, r].
                    // This implies that initial_a[k] must be at most M - current_delta_sum.
                    // The current_delta_sum is the sum of d_j for type 1 operations that affect the *entire* range [ops[i].l, ops[i].r].
                    // This is not quite right. The delta sum is specific to each index.
                    // Let's re-evaluate.
                    // For a type 2 operation (l, r, m), we know that max_{k=l..r} (A_0[k] + Delta_k) = m.
                    // This implies that for all k in [l, r], A_0[k] + Delta_k <= m.
                    // So, A_0[k] <= m - Delta_k for all k in [l, r].
                    // We want to find the tightest upper bound for A_0[k].
                    // The Delta_k for a specific k is the sum of d_j for all type 1 operations (j < i) where l_j <= k <= r_j.
                    // We don't know Delta_k yet for each k.
                    // Instead, let's find the minimum possible Delta_k for k in [l, r].
                    // Let min_delta_in_range = min_{k=ops[i].l..ops[i].r} (sum of d_j for type 1 ops j<i affecting k).
                    // Then, for all k in [ops[i].l, ops[i].r], A_0[k] <= ops[i].val - min_delta_in_range.
                    // This is still not quite right.
                    // The condition is: there exists *some* k0 in [l, r] such that A_0[k0] + Delta_k0 = m.
                    // And for all k in [l, r], A_0[k] + Delta_k <= m.
                    // This means A_0[k] <= m - Delta_k for all k in [l, r].
                    // So, we can update initial_a[k] = min(initial_a[k], m - Delta_k).
                    // To do this, we need to calculate Delta_k for each k.

                    // Let's use a difference array / prefix sum approach for deltas.
                    // `delta_at_k` is the sum of `d` values applied to `a[k]` by type 1 operations *before* the current type 2 operation.
                    // We can compute `delta_at_k` for each `k` in `[ops[i].l, ops[i].r]` by simulating type 1 operations up to `i-1`.
                    // This would be O(N*M) which is too slow (5000*5000 = 2.5*10^7 per type 2 op, total M*N*M).

                    // A better approach:
                    // For each type 2 operation (l, r, m):
                    // We know that for any j in [l, r], the initial value a_j must satisfy:
                    // a_j + (sum of d's applied to j before this op) <= m.
                    // So, a_j <= m - (sum of d's applied to j before this op).
                    // We want to find the tightest upper bound for each a_j.
                    // Let `current_delta_sum_for_j` be the sum of `d` values for type 1 operations `k < i` that affect index `j`.
                    // Then, for each `j` in `[ops[i].l, ops[i].r]`, we must have `initial_a[j] <= ops[i].val - current_delta_sum_for_j`.
                    // We can compute `current_delta_sum_for_j` for all `j` in `[ops[i].l, ops[i].r]` efficiently.
                    // We can use a difference array `temp_delta` for this.
                    // `temp_delta[k]` stores the sum of `d` values for type 1 operations `op_idx < i` that affect index `k`.
                    // Initialize `temp_delta` to all zeros.
                    // For each `op_idx` from `0` to `i-1`:
                    //   If `ops[op_idx].type == 1`:
                    //     For `j` from `ops[op_idx].l` to `ops[op_idx].r`:
                    //       `temp_delta[j] += ops[op_idx].val`.
                    // This is still O(N*M) for each type 2 op.

                    // The key is that `initial_a[j]` is the *initial* value.
                    // For a type 2 operation `(l, r, m)` at index `i`:
                    // We need to find `max_{k=l..r} (initial_a[k] + \sum_{op_idx < i, type=1, l_{op_idx} \le k \le r_{op_idx}} d_{op_idx}) = m`.
                    // Let `S_k = \sum_{op_idx < i, type=1, l_{op_idx} \le k \le r_{op_idx}} d_{op_idx}`.
                    // Then `max_{k=l..r} (initial_a[k] + S_k) = m`.
                    // This implies `initial_a[k] + S_k <= m` for all `k \in [l, r]`.
                    // So, `initial_a[k] <= m - S_k` for all `k \in [l, r]`.
                    // We can update `initial_a[k] = min(initial_a[k], m - S_k)`.

                    // To compute `S_k` for all `k` in `[l, r]` efficiently for a given type 2 operation `i`:
                    // We can use a temporary difference array.
                    std::vector<long long> current_deltas(n + 1, 0);
                    for (int op_idx = 0; op_idx < i; ++op_idx) {
                        if (ops[op_idx].type == 1) {
                            current_deltas[ops[op_idx].l] += ops[op_idx].val;
                            if (ops[op_idx].r + 1 < n) {
                                current_deltas[ops[op_idx].r + 1] -= ops[op_idx].val;
                            }
                        }
                    }

                    long long current_sum_d = 0;
                    for (int k = 0; k < n; ++k) {
                        current_sum_d += current_deltas[k];
                        if (k >= ops[i].l && k <= ops[i].r) {
                            initial_a[k] = std::min(initial_a[k], ops[i].val - current_sum_d);
                        }
                    }
                }
            }
        }
    }

    // If initial_a[k] is still max_long_long, it means it was never constrained by a type 2 operation.
    // We can set it to 0, as per problem constraints (|a_i| <= 10^9).
    // Or, more safely, to a value that satisfies the constraints.
    // Since we are looking for *any* suitable array, setting unconstrained values to 0 is fine.
    // The problem states |a_i| <= 10^9. If initial_a[k] is unconstrained, it can be 0.
    // If it's constrained, it's already <= 5*10^7 - (-5*10^7) = 10^8, which is within 10^9.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0;
        }
    }

    // Now, verify if this `initial_a` works.
    // Simulate all operations with the constructed `initial_a`.
    // We need a segment tree or similar for efficient range max query and range add.
    // Since N, M <= 5000, a simple array simulation for verification is O(N*M) which is too slow.
    // We need to use a segment tree for verification.

    // Segment tree implementation
    std::vector<long long> tree(4 * n);
    std::vector<long long> lazy(4 * n, 0);

    auto build = [&](auto self, int node, int start, int end) -> void {
        if (start == end) {
            tree[node] = initial_a[start];
        } else {
            int mid = (start + end) / 2;
            self(self, 2 * node, start, mid);
            self(self, 2 * node + 1, mid + 1, end);
            tree[node] = std::max(tree[2 * node], tree[2 * node + 1]);
        }
    };

    auto push = [&](int node) -> void {
        if (lazy[node] != 0) {
            tree[2 * node] += lazy[node];
            lazy[2 * node] += lazy[node];
            tree[2 * node + 1] += lazy[node];
            lazy[2 * node + 1] += lazy[node];
            lazy[node] = 0;
        }
    };

    auto update_range = [&](auto self, int node, int start, int end, int l, int r, long long val) -> void {
        if (start > end || start > r || end < l) {
            return;
        }
        if (l <= start && end <= r) {
            tree[node] += val;
            lazy[node] += val;
            return;
        }
        push(node);
        int mid = (start + end) / 2;
        self(self, 2 * node, start, mid, l, r, val);
        self(self, 2 * node + 1, mid + 1, end, l, r, val);
        tree[node] = std::max(tree[2 * node], tree[2 * node + 1]);
    };

    auto query_range = [&](auto self, int node, int start, int end, int l, int r) -> long long {
        if (start > end || start > r || end < l) {
            return std::numeric_limits<long long>::min();
        }
        if (l <= start && end <= r) {
            return tree[node];
        }
        push(node);
        int mid = (start + end) / 2;
        long long p1 = self(self, 2 * node, start, mid, l, r);
        long long p2 = self(self, 2 * node + 1, mid + 1, end, l, r);
        return std::max(p1, p2);
    };

    build(build, 1, 0, n - 1);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            update_range(update_range, 1, 0, n - 1, ops[i].l, ops[i].r, ops[i].val);
        } else {
            long long current_max = query_range(query_range, 1, 0, n - 1, ops[i].l, ops[i].r);
            if (current_max != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.
// x can also become large, but it's primarily used for indexing or termination checks.
// The maximum value of x is n + max(a_i) which is 2*10^5 + 10^9, fits in long long.
// However, x is only used for indexing up to n, so int is fine for x if we handle the termination condition carefully.
// Let's use long long for x as well to be safe and consistent with y, especially since intermediate x values can be large.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_2, ..., a_n are given. We need to store them in a 0-indexed vector.
    // a[0] will be a_1, a[1] will be a_2, ..., a[n-1] will be a_n.
    // The input gives a_2 to a_n, so we read into a[1] to a[n-1].
    std::vector<long long> a(n);
    for (int i = 1; i < n; ++i) {
        std::cin >> a[i];
    }

    // dp[i] will store the result for a_1 = i+1.
    // dp[i] = {final_y, final_x} if terminates, or {-1, -1} if loop.
    // We need to store the final x value to reconstruct the path for memoization.
    // The state for memoization is (current_x, current_y_offset).
    // current_y_offset is the y accumulated in the current step (a_x + a_x_after_first_jump).
    // This is tricky because y accumulates.
    // A better DP state would be (current_x, current_y_offset_from_start_of_step).
    // Let's define dp[x_idx][step_type] where step_type is 0 for first jump, 1 for second jump.
    // This is still not quite right because the initial a_1 changes.

    // The problem asks for n-1 runs, each with a different a_1.
    // For each i from 1 to n-1, a_1 is set to i.
    // This suggests that we might need to compute each case independently or use DP.
    // Given N up to 2*10^5, O(N^2) is too slow. O(N log N) or O(N) is required.

    // Let's analyze the jumps.
    // From (x, y):
    // 1. x' = x + a_x, y' = y + a_x
    // 2. x'' = x' - a_x', y'' = y' + a_x'
    // The total change in y for one full cycle (step 2 then step 3) is a_x + a_x'.
    // The total change in x for one full cycle is a_x - a_x'.

    // We can use dynamic programming with memoization.
    // For a given starting a_1 (let's call it `initial_a1`), we want to find the final y.
    // The state can be (current_x, current_y_offset_from_initial_a1).
    // This is still not quite right. The `a` array is fixed except for `a_1`.

    // Let's define `memo[x_val]` as a pair {final_y_contribution, final_x_value}
    // starting from `x_val` with `y` initially 0.
    // This memoization works if `a_1` is fixed. But `a_1` changes for each query.

    // The key observation for DP is that the sequence `a_2, ..., a_n` is fixed.
    // Only `a_1` changes.
    // If `x` ever becomes `1`, the value of `a_1` matters.
    // If `x` is never `1` after the initial step, then `a_1` doesn't matter beyond the first jump.

    // Let's define `dp[k]` as the result of starting the process at `x = k+1` (0-indexed `k`).
    // `dp[k]` will store a pair: `{total_y_added, final_x_value}`.
    // This `dp` table will be computed for `k` from `1` to `n-1` (corresponding to `a_2` to `a_n`).
    // `dp[0]` is special because `a_1` changes.

    // `dp[k]` for `k` from `1` to `n-1`:
    // `x_curr = k+1` (1-indexed)
    // `y_curr = 0`
    // `val1 = a[k]`
    // `x_next1 = x_curr + val1`
    // `y_next1 = y_curr + val1`
    // If `x_next1 <= 0` or `x_next1 > n`: `dp[k] = {val1, x_next1}` (terminates)
    // Else:
    //   `val2 = a[x_next1 - 1]`
    //   `x_next2 = x_next1 - val2`
    //   `y_next2 = y_next1 + val2`
    //   If `x_next2 <= 0` or `x_next2 > n`: `dp[k] = {y_next2, x_next2}` (terminates)
    //   Else:
    //     If `x_next2 == 1`: This is the tricky part. `a_1` is unknown.
    //     Else (`x_next2 > 1`):
    //       `res = dp[x_next2 - 1]` (recursive call)
    //       If `res.first == -1`: `dp[k] = {-1, -1}` (loop)
    //       Else: `dp[k] = {y_next2 + res.first, res.second}`

    // We need to handle cycles. A `visited` array can detect cycles.
    // `visited[k]` can store `true` if currently computing `dp[k]`.
    // `memo[k]` stores the computed result.

    std::vector<std::pair<long long, long long>> memo(n + 1, {-2, -2}); // -2 indicates not computed
    std::vector<bool> visiting(n + 1, false); // true if currently in recursion stack

    // Function to compute {total_y_added, final_x_value} starting from 1-indexed `start_x`
    // `a_arr` is the full array including `a_1`.
    // This function is called for `start_x` from 2 to n.
    // For `start_x = 1`, `a_1` is variable.
    auto solve = [&](int start_x, const std::vector<long long>& a_arr, auto& self_ref) -> std::pair<long long, long long> {
        if (start_x <= 0 || start_x > n) {
            return {0, start_x}; // Base case: already out of bounds, 0 y added, x is start_x
        }

        // If we are computing for a_1, it's a special case.
        // This `solve` function is designed for `x > 1` or when `a_1` is known.
        // For the main loop, `a_1` is set to `i`.
        // When `x` becomes `1` during a jump, we need to use the `i` value.
        // This means `solve` needs to know `a_1`.

        // Let's rethink. The `a` array is fixed for `a_2` to `a_n`.
        // The only variable is `a_1`.
        // When `x` is `1`, `a_1` is used.
        // When `x` is `k > 1`, `a_k` is used.

        // We can precompute results for `x` starting from `2` to `n`.
        // Let `dp[k]` be the pair `{total_y_added, final_x_value}` if we start at `x=k` (1-indexed)
        // and `y=0`, assuming `a_1` is *not* used in this path (i.e., `x` never becomes `1`).
        // This is not quite right. `x` can become `1` and then jump to `x > 1`.

        // Let's define `dp[k]` as the result of starting at `x=k` (1-indexed)
        // and `y=0`. The result is `{total_y_added, final_x_value}`.
        // If `x` ever becomes `1`, we need to know the current `a_1`.
        // This means `dp` cannot be purely based on `k`.

        // The problem structure is: for each `i` from `1` to `n-1`, set `a_1 = i`.
        // Then run the simulation.
        // The simulation involves `x` and `y`.
        // `x` starts at `1`.
        // `y` starts at `0`.

        // Let's use a `std::vector<std::pair<long long, long long>> results(n + 1);`
        // `results[k]` stores the pair `{total_y_added, final_x_value}` if we start at `x=k`
        // and `y=0`, and `a_1` is the *current* `a_1` for the outer loop.
        // This means `results` needs to be cleared or recomputed for each `i`.
        // This would be O(N^2) in worst case.

        // The key is that `a_x` is used.
        // If `x` is `1`, `a_1` is used.
        // If `x` is `k > 1`, `a_k` is used.
        // The values `a_2, ..., a_n` are fixed.
        // The only variable is `a_1`.

        // Let's define `memo[k]` as the result of starting at `x=k` (1-indexed)
        // and `y=0`, assuming `a_1` is *not* used in this path.
        // This means if `x` ever becomes `1`, we cannot use `memo[1]`.
        // Instead, we must explicitly calculate the jump from `x=1`.

        // `memo[k]` stores `{total_y_added, final_x_value}` for `k` from `2` to `n`.
        // `memo[k]` is computed assuming `a_1` is not involved.
        // If `x` becomes `1`, we need to handle it.

        // Let's define `dp[k]` for `k` from `2` to `n`.
        // `dp[k]` stores `{total_y_added, final_x_value}` if we start at `x=k` (1-indexed)
        // and `y=0`.
        // If `x` becomes `1` during the computation of `dp[k]`, it means we need to
        // know the value of `a_1`. This is a problem.

        // The only way to make this O(N) or O(N log N) is if the path from `x=1`
        // can be broken down into parts that don't depend on `a_1`.
        // Consider the sequence of `x` values: `1 -> x_1 -> x_2 -> ...`
        // If `x_k` is `1`, then `a_1` is used again.
        // If `x_k` is `j > 1`, then `a_j` is used.

        // Let's define `dp[k]` as the pair `{total_y_added, final_x_value}`
        // when starting at `x=k` (1-indexed) and `y=0`, and `a_1` is *not* used.
        // This means if `x` ever becomes `1`, we cannot use `dp[1]`.
        // Instead, we must return a special value indicating that `a_1` is needed.

        // `dp[k]` for `k` from `2` to `n`:
        // `dp[k]` will store `{y_sum, x_final}`.
        // `y_sum` is the sum of `a_val`s encountered.
        // `x_final` is the `x` value when it terminates or becomes `1`.
        // If `x_final` is `1`, it means we need to use `a_1` next.

        // `memo[k]` stores `{y_sum, x_final}` for `k` from `2` to `n`.
        // `y_sum` is the sum of `a_val`s encountered until `x` terminates or becomes `1`.
        // `x_final` is the `x` value when it terminates or becomes `1`.
        // If `x_final == 1`, it means the path leads back to `x=1`.

        // Initialize `memo` with a special value, e.g., `{-1, -1}` for uncomputed.
        // `visiting` array to detect cycles.

        std::vector<std::pair<long long, long long>> memo_results(n + 1, {-1, -1}); // {y_sum, final_x}
        std::vector<bool> in_path(n + 1, false); // To detect cycles

        // This function computes the path starting from `x_start` (1-indexed)
        // until it terminates or reaches `x=1`.
        // It returns `{y_accumulated, final_x_value}`.
        // If a cycle is detected, it returns `{LLONG_MAX, LLONG_MAX}` to signify non-termination.
        // We only compute for `x_start >= 2`.
        std::function<std::pair<long long, long long>(int)> compute_path =
            [&](int x_start) -> std::pair<long long, long long> {
            if (x_start <= 0 || x_start > n) {
                return {0, x_start}; // Terminated
            }
            if (x_start == 1) {
                return {0, 1}; // Reached x=1, need a_1
            }

            if (memo_results[x_start].first != -1) {
                return memo_results[x_start]; // Already computed
            }
            if (in_path[x_start]) {
                return {LLONG_MAX, LLONG_MAX}; // Cycle detected
            }

            in_path[x_start] = true;

            long long current_y_sum = 0;
            long long current_x = x_start;

            // Step 2: x = x + a_x, y = y + a_x
            long long val1 = a[current_x - 1];
            current_x += val1;
            current_y_sum += val1;

            if (current_x <= 0 || current_x > n) {
                in_path[x_start] = false;
                return memo_results[x_start] = {current_y_sum, current_x};
            }

            // Step 3: y = y + a_x, x = x - a_x
            long long val2 = a[current_x - 1];
            current_y_sum += val2;
            current_x -= val2;

            if (current_x <= 0 || current_x > n) {
                in_path[x_start] = false;
                return memo_results[x_start] = {current_y_sum, current_x};
            }

            // Recursive call for the next state
            std::pair<long long, long long> next_res = compute_path(current_x);

            in_path[x_start] = false;

            if (next_res.first == LLONG_MAX) { // Cycle detected in sub-path
                return memo_results[x_start] = {LLONG_MAX, LLONG_MAX};
            } else {
                return memo_results[x_start] = {current_y_sum + next_res.first, next_res.second};
            }
        };

    // Precompute for x_start from 2 to n
    for (int k = 2; k <= n; ++k) {
        if (memo_results[k].first == -1) { // If not computed yet
            compute_path(k);
        }
    }

    // Now, for each i (1 to n-1), run the simulation with a_1 = i.
    for (int i = 1; i < n; ++i) {
        a[0] = i; // Set a_1 for the current run

        long long current_x = 1;
        long long current_y = 0;

        // Simulate the first full step (step 2 then step 3)
        // Step 2: x = x + a_x, y = y + a_x
        long long val1 = a[current_x - 1]; // a[0] is a_1
        current_x += val1;
        current_y += val1;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Step 3: y = y + a_x, x = x - a_x
        long long val2 = a[current_x - 1];
        current_y += val2;
        current_x -= val2;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now, current_x is the state after the first full step.
        // If current_x is 1, it means we are in a cycle that involves a_1.
        // This is a tricky case. If current_x becomes 1 again, and a_1 is fixed,
        // it's an infinite loop.
        if (current_x == 1) {
            std::cout << -1 << "\n"; // If x becomes 1 again, it will repeat the same jumps with the same a_1.
            continue;
        }

        // If current_x > 1, we can use the precomputed `memo_results`.
        std::pair<long long, long long> res = memo_results[current_x];

        if (res.first == LLONG_MAX) { // Cycle detected in the precomputed path
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + res.first << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // We can form s2 + s1.
    // We need s2 + s1 to be a palindrome and s2 + s1 != s.
    // Iterate through all possible cut points (1 to n-1)
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // For k=2, we need to cut s into s1, s2, s3.
    // The problem statement implies that any permutation of pieces is allowed.
    // However, the example for k=2 (nolon -> onlno) suggests a specific type of rearrangement.
    // "no|l|on, and then unite them as follows on|l|no"
    // This is s_prefix | s_middle | s_suffix -> s_suffix | s_middle | s_prefix
    // This is equivalent to cutting s into s_prefix and s_suffix, and then swapping them.
    // The middle part is just one of the pieces.
    //
    // Let's re-evaluate the problem statement:
    // "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string,
    // and then unite those pieces together to get a new string. Pieces couldn't be turned over, they could be shuffled."
    //
    // This means we can take any permutation of the k+1 pieces.
    //
    // Consider the structure of a palindrome.
    // If s is a palindrome, and we cut it into k+1 pieces, say P_0, P_1, ..., P_k.
    // The new string s' is a permutation of these pieces.
    // For s' to be a palindrome, its characters must be symmetric.
    //
    // If all characters in s are the same (e.g., "qqqq"), then any permutation of its substrings
    // will result in the same string "qqqq".
    // For example, "qqqq" cut into "q|q|q|q". Any rearrangement is "qqqq".
    // In this case, it's impossible to form a new string s' != s.
    //
    // Let's check this condition: if all characters are the same.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }
    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 must be the answer.
    // Why?
    // If s is a palindrome and not all characters are the same, then s must have at least two distinct characters.
    // Example: "abacaba"
    // If we cut s into s_prefix and s_suffix, and swap them, we get s_suffix + s_prefix.
    // This is what we checked for k=1. If it didn't work, it means for all `i`, `s.substr(i) + s.substr(0, i)` is either `s` or not a palindrome.
    //
    // Consider the case where `s` is a palindrome, and not all characters are the same.
    // Example: "nolon" (n=5)
    // k=1:
    // "o" + "nolon" -> "onolon" (not pal)
    // "lo" + "non" -> "lonon" (not pal)
    // "olo" + "no" -> "olonon" (not pal)
    // "lono" + "n" -> "lonon" (not pal)
    //
    // The example says "nolon" -> "onlno" with k=2.
    // This is "no|l|on" -> "on|l|no".
    // This is a specific permutation: P_0 P_1 P_2 -> P_2 P_1 P_0.
    //
    // The problem statement is a bit ambiguous about "minimum k".
    // If k=1 doesn't work, and not all characters are the same, then k=2 is always possible.
    //
    // Let's consider a string `s` that is a palindrome and not all characters are the same.
    // This means there exists at least one character `c` such that `s[0] != c` and `c` appears in `s`.
    // Or, more simply, `s` is not of the form `aaaa...a`.
    //
    // If `s` is not `aaaa...a`, then there must be some `s[i] != s[0]`.
    // Since `s` is a palindrome, `s[i] == s[n-1-i]`.
    //
    // Consider cutting `s` into `s[0]` and `s.substr(1, n-2)` and `s[n-1]`.
    // `s = s[0] + s.substr(1, n-2) + s[n-1]`
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    //
    // If we cut `s` into `s_prefix = s.substr(0, i)` and `s_suffix = s.substr(i, n-i)`.
    // We checked `s_suffix + s_prefix`.
    //
    // The problem statement implies that if k=1 doesn't work, k=2 is the next best.
    // The example "nolon" -> "onlno" uses 3 pieces (k=2).
    // The pieces are "no", "l", "on".
    // Original: "no" + "l" + "on"
    // New:      "on" + "l" + "no"
    // This is a specific permutation of pieces: P_0 P_1 P_2 -> P_2 P_1 P_0.
    //
    // If `s` is a palindrome and not all characters are the same, we can always find a cut that results in a new palindrome.
    // Consider `s = s_1 + s_2 + s_3` where `s_1` is the first character, `s_3` is the last character, and `s_2` is the middle part.
    // `s_1 = s[0]`, `s_3 = s[n-1]`. Since `s` is a palindrome, `s_1 == s_3`.
    // We can rearrange to `s_3 + s_2 + s_1`.
    // This new string is `s[n-1] + s.substr(1, n-2) + s[0]`.
    // Since `s[n-1] == s[0]`, this is `s[0] + s.substr(1, n-2) + s[n-1]`, which is `s`.
    // This specific rearrangement doesn't work to get a *different* string.
    //
    // The key is that we can choose *any* `k+1` pieces and permute them.
    // If `s` is a palindrome and not all characters are the same, then there must be at least two distinct characters.
    // Let `s = c_0 c_1 ... c_{n-1}`.
    // Since `s` is a palindrome, `c_i = c_{n-1-i}`.
    // Since not all characters are the same, there exists some `j` such that `c_j != c_0`.
    //
    // Consider cutting `s` into `n` pieces, each of length 1. `k = n-1`.
    // Then we can rearrange these characters.
    // If `s` is a palindrome and not all characters are the same, we can always form a new palindrome.
    // For example, if `s = "abacaba"`.
    // Cut into `a|b|a|c|a|b|a`.
    // Rearrange to `a|b|a|c|a|b|a` (same).
    //
    // The problem is asking for the minimum `k`.
    // If `k=1` doesn't work, and `s` is not `aaaa...a`, then `k=2` is the answer.
    // This is a common pattern in competitive programming problems: if the simplest case doesn't work,
    // and there's a specific "impossible" case, then the next simplest case is usually the answer for all others.
    //
    // The logic for k=2 being the answer for all other cases:
    // If `s` is a palindrome and not all characters are the same, then `s` must contain at least two distinct characters.
    // Let `s = P_0 P_1 ... P_k` be the pieces.
    // The total length of the string is `N`.
    //
    // If `s` is a palindrome and not all characters are the same, then it's always possible to make a new palindrome with 2 cuts (3 pieces).
    // Consider `s = s[0] + s.substr(1, n-2) + s[n-1]`.
    // Let `P_0 = s[0]`, `P_1 = s.substr(1, n-2)`, `P_2 = s[n-1]`.
    // We know `P_0 == P_2` because `s` is a palindrome.
    // The original string is `P_0 P_1 P_2`.
    // We can form `P_2 P_1 P_0`. This is `s[n-1] + s.substr(1, n-2) + s[0]`.
    // Since `s[n-1] == s[0]`, this is `s[0] + s.substr(1, n-2) + s[n-1]`, which is `s`.
    // This specific rearrangement doesn't yield a *different* string.
    //
    // However, the example "nolon" -> "onlno" uses `no|l|on`.
    // Here `P_0 = "no"`, `P_1 = "l"`, `P_2 = "on"`.
    // `P_0` is not equal to `P_2`.
    // `s = P_0 P_1 P_2`.
    // `s' = P_2 P_1 P_0`.
    // `s' = "on" + "l" + "no" = "onlno"`.
    // `s'` is a palindrome. `s' != s`.
    // This works.
    //
    // The crucial part is that we can choose *any* cut points.
    // If `s` is a palindrome and not all characters are the same, then there must be some `i` such that `s.substr(0, i)` is not equal to `s.substr(n-i, i)`.
    // For example, `s = "abacaba"`.
    // `i=1`: `s.substr(0,1) = "a"`, `s.substr(6,1) = "a"`. They are equal.
    // `i=2`: `s.substr(0,2) = "ab"`, `s.substr(5,2) = "ba"`. They are not equal.
    //
    // Let `i` be the smallest index such that `s.substr(0, i)` is not equal to `s.substr(n-i, i)`.
    // Such an `i` must exist if `s` is not `aaaa...a`.
    // If `s = "aaaa...a"`, then `s.substr(0,i)` is always equal to `s.substr(n-i,i)` for all `i`.
    //
    // If such an `i` exists:
    // Let `P_0 = s.substr(0, i)`.
    // Let `P_1 = s.substr(i, n - 2*i)`.
    // Let `P_2 = s.substr(n-i, i)`.
    //
    // Then `s = P_0 P_1 P_2`.
    // We know `P_0 != P_2`.
    // Consider `s' = P_2 P_1 P_0`.
    // `s'` is a palindrome if `P_2 == reverse(P_0)` and `P_1` is a palindrome.
    //
    // This is not the right way to think about it.
    // The pieces can be shuffled.
    // If `s` is a palindrome, and not all characters are the same, then `k=2` is always possible.
    // The example "nolon" -> "onlno" is a specific case.
    //
    // The problem is simpler: if `s` is a palindrome and not all characters are the same,
    // then there must be a way to cut it into 3 pieces and rearrange them to form a new palindrome.
    //
    // Consider `s = "abacaba"`.
    // `k=1` check:
    // `baca + a` -> `bacaa` (not pal)
    // `acaba + ab` -> `acabaab` (not pal)
    // ...
    //
    // If `s` is a palindrome and not all characters are the same, then `k=2` is the answer.
    // This is a known property for such problems.
    // The only case where it's impossible is when all characters are the same.
    // The only case where `k=1` works is when `s_2 + s_1` is a palindrome and `s_2 + s_1 != s`.
    // Otherwise, it's `k=2`.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

// Function to check if all target tracks can be covered within time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // current_p_idx points to the first target track that has not yet been covered
    int current_p_idx = 0;

    // Iterate through each head
    for (int i = 0; i < n; ++i) {
        // If all target tracks are already covered, we are done
        if (current_p_idx == m) {
            return true;
        }

        // Calculate the range this head can cover
        long long head_start = h[i] - t;
        long long head_end = h[i] + t;

        // If the current head cannot even reach the current target track,
        // it means this head cannot help cover p[current_p_idx].
        // We need to find a head that can cover p[current_p_idx].
        // If p[current_p_idx] is outside the range [head_start, head_end],
        // this head cannot cover it.
        // However, a head can cover a range. We need to find the first p[j]
        // that is within the range of this head.
        // The crucial part is that heads can move independently.
        // If a head is used to cover a range, it should cover as many
        // *uncovered* tracks as possible, starting from current_p_idx.

        // Find the first target track p[j] that this head can potentially cover.
        // This means p[j] must be within [h[i] - t, h[i] + t].
        // Since p is sorted, we can efficiently find this.
        // If p[current_p_idx] is already greater than head_end, this head cannot cover it.
        // If p[current_p_idx] is less than head_start, this head can cover it,
        // but it might be better to use this head for later tracks.
        // The greedy strategy is to use the current head to cover tracks starting from
        // current_p_idx, as long as they are reachable.

        // If the current head h[i] is too far to the left to cover p[current_p_idx]
        // even by moving right for 't' seconds, then this head cannot cover p[current_p_idx].
        // In this case, we must rely on a previous head (which is not possible as we iterate heads)
        // or a future head.
        // This means if h[i] + t < p[current_p_idx], this head cannot cover p[current_p_idx].
        // Since h is sorted, if this head cannot cover it, no previous head could have.
        // So, if h[i] + t < p[current_p_idx], it's impossible to cover p[current_p_idx] with this head or any previous head.
        // This is incorrect. A previous head might have been able to cover it.
        // The correct logic is: if p[current_p_idx] is not covered, we must use *some* head to cover it.
        // The current head h[i] can cover a range [h[i]-t, h[i]+t].
        // If p[current_p_idx] is within this range, we can use h[i] to cover it.
        // If p[current_p_idx] is to the right of h[i]+t, then h[i] cannot cover it.
        // If p[current_p_idx] is to the left of h[i]-t, then h[i] can cover it, but it's better to use h[i]
        // to cover tracks further to the right.

        // The greedy approach:
        // For each head h[i], we want to cover as many *uncovered* tracks as possible,
        // starting from p[current_p_idx].
        // The head h[i] can cover any track x such that |h[i] - x| <= t.
        // This means x must be in the range [h[i] - t, h[i] + t].

        // If p[current_p_idx] is to the right of what this head can reach (h[i] + t),
        // then this head cannot cover p[current_p_idx]. We move to the next head.
        // This is not quite right. We need to check if *any* head can cover p[current_p_idx].
        // The problem is about covering all p_j.

        // Let's rephrase: We need to find if there exists a mapping from heads to segments
        // such that all p_j are covered.
        // A head h_i can cover the segment [h_i - t, h_i + t].
        // We want to cover all p_j.
        // We iterate through the heads. For each head, we try to cover the leftmost
        // uncovered track p[current_p_idx].
        // If h[i] can cover p[current_p_idx] (i.e., p[current_p_idx] >= h[i] - t),
        // then this head can be used.
        // The range this head can cover is [max(p[current_p_idx], h[i] - t), h[i] + t].
        // We want to extend this coverage as far right as possible.
        // So, this head covers all p_j such that p_j <= h[i] + t and p_j >= p[current_p_idx].

        // If the current head h[i] cannot reach p[current_p_idx] even by moving right (h[i] + t < p[current_p_idx]),
        // then this head is too far left to cover p[current_p_idx].
        // Since heads are sorted, and p are sorted, this means no previous head could have covered p[current_p_idx]
        // if it was not covered by them.
        // This is the key: if h[i] + t < p[current_p_idx], then p[current_p_idx] cannot be covered by h[i]
        // or any h[k] where k < i (because h[k] <= h[i], so h[k]+t <= h[i]+t).
        // Thus, if h[i] + t < p[current_p_idx], it's impossible to cover p[current_p_idx].
        // This is the condition for failure.
        if (h[i] + t < p[current_p_idx]) {
            return false;
        }

        // If h[i] can reach p[current_p_idx] (i.e., h[i] + t >= p[current_p_idx]),
        // then this head can cover a range starting from p[current_p_idx]
        // up to h[i] + t.
        // We advance current_p_idx past all tracks covered by this head.
        // The leftmost track this head can cover is max(p[current_p_idx], h[i] - t).
        // The rightmost track this head can cover is h[i] + t.
        // We want to cover all p_j in [p[current_p_idx], h[i] + t].
        // So, we advance current_p_idx as long as p[current_p_idx] <= h[i] + t.
        while (current_p_idx < m && p[current_p_idx] <= h[i] + t) {
            current_p_idx++;
        }
    }

    // After iterating through all heads, check if all target tracks are covered.
    return current_p_idx == m;
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    // Binary search for the minimum time 't'
    long long low = 0;
    // Max possible time: difference between max p and min h, or max h and min p.
    // Max value of p_m or h_n is 10^10. So difference can be 10^10.
    long long high = 2e10; // A sufficiently large upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

