int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To maximize the binary number, we want as many '1's as possible, followed by '0's.
    // Each '1' comes from "one" (o, n, e)
    // Each '0' comes from "zero" (z, e, r, o)

    // Count how many '1's we can form.
    // 'n' is unique to "one". So, the number of '1's is limited by 'n'.
    int num_ones = count_n;

    // After forming 'num_ones' "one"s, we use up:
    // 'num_ones' 'o's
    // 'num_ones' 'n's
    // 'num_ones' 'e's

    // Remaining letters for "zero"s:
    // 'z's: count_z
    // 'e's: count_e - num_ones
    // 'r's: count_r
    // 'o's: count_o - num_ones

    // Count how many '0's we can form.
    // This is limited by the remaining 'z', 'e', 'r', 'o'.
    // Note: The problem guarantees that it's possible to form a sequence of "one"s and "zero"s.
    // This implies that after forming all possible '1's, the remaining letters will perfectly form '0's.
    // So, the number of '0's is simply the count of 'z's, as 'z' is unique to "zero".
    int num_zeros = count_z;

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

