#include <string>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_duration = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_duration += a[i];
    }

    if (total_duration % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_post_duration = total_duration / k;
    std::vector<int> s_values;
    long long current_post_sum = 0;
    int current_post_video_count = 0;
    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_video_count++;

        if (current_post_sum == target_post_duration) {
            s_values.push_back(current_post_video_count);
            current_post_sum = 0;
            current_post_video_count = 0;
            posts_formed++;
        } else if (current_post_sum > target_post_duration) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_formed == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // Since n can be up to 150000, dynamic allocation with vector is appropriate.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n == 0) { // Edge case: no days
            std::cout << 0 << "\n";
            continue;
        }
        if (n == 1) { // Edge case: only one day, no later prices to compare
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price.
        // The last price a[n-1] is never a bad price itself.
        int min_suffix = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // For each day i, we compare its price a[i] with the minimum price
        // encountered so far in the suffix a[i+1...n-1].
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                // If the current price is greater than the minimum price in the suffix,
                // it means there's a later day with a lower price, so a[i] is a bad price.
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix, it means a[i] is
                // either equal to or less than min_suffix.
                // In this case, a[i] itself becomes the new minimum for the suffix
                // starting from i.
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = -1; // Represents cell 0
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After the loop, last_r_pos is the index of the last 'R' character.
        // The gap from the last 'R' to n+1 needs to be considered.
        // The length of the string is s.length(), so the cells are 1 to s.length().
        // The target is cell s.length() + 1.
        // If last_r_pos is -1, it means there were no 'R's.
        // In this case, the frog must jump from 0 to n+1 directly.
        // The distance is (n+1) - 0 = n+1.
        // The loop correctly handles this: max_gap will be 0, and then
        // s.length() - (-1) = s.length() + 1 will be compared.
        max_gap = std::max(max_gap, (int)s.length() - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    bool n_found = false;

    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_for_i = std::max(max_val_for_i, a[i][j]);
            }
        }
        p[i] = max_val_for_i;
        if (p[i] == n - 1) {
            // This element p[i] could be n.
            // If no other element is n, then this one must be.
            // We'll check later if any p[i] is actually n.
            // For now, we tentatively assign n-1.
        }
    }

    // Check if any p[i] is actually n.
    // If max(a[i][j] for j!=i) is n-1, then p[i] could be n.
    // If no p[i] is n, it means the maximum value in the permutation (n)
    // was not captured by any min(p[i], p[j]) as n-1.
    // This happens if p[i] is the element 'n', and all other p[j] are < n.
    // In that case, max(a[i][j] for j!=i) = max(p[j] for j!=i) = n-1.
    // So, if we find an element whose max_val_for_i is n-1, it's a candidate for 'n'.
    // If no such element exists, it means 'n' was never the larger value in any pair,
    // which is impossible for a permutation of 1 to n.
    // The problem guarantees a solution exists.
    // So, if we don't find 'n' among the calculated p[i] values,
    // it means one of the p[i] values that was calculated as n-1 should actually be n.
    // We need to find one such p[i] and increment it.

    for (int i = 0; i < n; ++i) {
        if (p[i] == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found among the calculated p[i] values,
        // it means one of the p[i] values that was calculated as n-1 should actually be n.
        // This happens for the element p_k = n. For this k, max(a[k][j] for j!=k) = n-1.
        // So we find any p[i] that is n-1 and change it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; // Only one such element needs to be changed
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // With 2n students, if we sort all students, the optimal strategy
        // to minimize the difference between medians of two odd-sized classes
        // is to pick the median of the first class as a[n-1] and the median
        // of the second class as a[n].
        // This is because if we split the sorted array into two halves,
        // the "middle" elements are a[n-1] and a[n].
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // We need to form two classes, C1 and C2, each with an odd number of students.
        // Let |C1| = 2k1+1 and |C2| = 2k2+1.
        // Then (2k1+1) + (2k2+1) = 2n => 2k1 + 2k2 + 2 = 2n => k1 + k2 + 1 = n.
        // The median of C1 is its (k1+1)-th element.
        // The median of C2 is its (k2+1)-th element.
        //
        // To minimize the difference, we want the medians to be as close as possible.
        // The elements a[n-1] and a[n] are the two middle elements of the entire sorted array.
        // It can be shown that we can always construct two classes such that
        // one median is a[n-1] and the other is a[n].
        //
        // For example, let C1 contain a_0, ..., a_{n-1} (n elements).
        // If n is odd, then C1 has n elements, which is odd. Its median is a_{(n-1)/2}.
        // If n is even, then C1 has n elements, which is even. This doesn't work directly.
        //
        // The key insight is that the median of a class of size $2k+1$ is the $(k+1)$-th element.
        // If we take the $n$-th element (0-indexed $a_{n-1}$) as the median of one class,
        // and the $(n+1)$-th element (0-indexed $a_n$) as the median of the other class,
        // we can always form valid classes.
        //
        // For example, Class 1: {a_0, ..., a_{n-1}}. This class has n elements.
        // If n is odd, this is a valid class. Its median is a_{(n-1)/2}.
        // If n is even, this is not a valid class.
        //
        // The problem statement implies that the median of the first class will be a[n-1]
        // and the median of the second class will be a[n].
        // This is because if we sort all $2n$ students, the $n$-th student (0-indexed $a_{n-1}$)
        // and the $(n+1)$-th student (0-indexed $a_n$) are the two "middle" students.
        // To minimize the difference between medians, we should pick these two.
        //
        // We can form a class C1 of size $2k_1+1$ and C2 of size $2k_2+1$.
        // The total number of students is $2n$.
        // The median of C1 will be $m_1$ and C2 will be $m_2$.
        //
        // Consider the specific partition where:
        // Class 1 consists of students $a_0, a_1, \dots, a_{n-1}$. This class has $n$ students.
        // Class 2 consists of students $a_n, a_{n+1}, \dots, a_{2n-1}$. This class also has $n$ students.
        //
        // This partition is only valid if $n$ is odd.
        // If $n$ is odd, then both classes have $n$ students (odd number).
        // The median of Class 1 (sorted $a_0, \dots, a_{n-1}$) is $a_{(n-1)/2}$.
        // The median of Class 2 (sorted $a_n, \dots, a_{2n-1}$) is $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler: the minimum difference is always between $a_{n-1}$ and $a_n$.
        // We can always construct two classes such that $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other class.
        //
        // Let's make $a_{n-1}$ the median of Class 1 and $a_n$ the median of Class 2.
        // Class 1: We need $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We can pick $a_0, \dots, a_{n-1-k_1-1}$ (total $n-1-k_1$ elements)
        // and $a_{n-1+1}, \dots, a_{n-1+k_1}$ (total $k_1$ elements).
        //
        // A simpler argument:
        // The $n$-th smallest element is $a_{n-1}$.
        // The $(n+1)$-th smallest element is $a_n$.
        //
        // We can form Class 1 with $a_0, a_1, \dots, a_{n-1}$ and $n$ is odd.
        // And Class 2 with $a_n, a_{n+1}, \dots, a_{2n-1}$ and $n$ is odd.
        // This is only possible if $n$ is odd.
        //
        // The example for n=3 (2n=6 students):
        // Sorted: 1 2 3 4 5 6
        // n=3.
        // a[n-1] = a[2] = 3.
        // a[n] = a[3] = 4.
        // Difference is |4-3|=1. This matches the example output.
        //
        // Example partition:
        // Class 1: [6, 4, 2] -> sorted [2, 4, 6]. Median is 4.
        // Class 2: [5, 1, 3] -> sorted [1, 3, 5]. Median is 3.
        // Difference |4-3|=1.
        //
        // In this example, the medians are 3 and 4.
        // The elements $a_{n-1}$ and $a_n$ are $a_2=3$ and $a_3=4$.
        //
        // The problem is asking for the minimum possible absolute difference.
        // If we sort all $2n$ students, $a_0, a_1, \dots, a_{2n-1}$.
        // The $n$-th student (0-indexed $a_{n-1}$) and the $(n+1)$-th student (0-indexed $a_n$)
        // are the two students "in the middle" of the entire group.
        //
        // It is always possible to assign $a_{n-1}$ to one class as its median,
        // and $a_n$ to the other class as its median.
        //
        // Let $m_1 = a_{n-1}$ and $m_2 = a_n$.
        // We need to construct two classes $C_1$ and $C_2$ such that $m_1$ is the median of $C_1$
        // and $m_2$ is the median of $C_2$.
        //
        // For $C_1$ to have $a_{n-1}$ as its median, it must have $k_1$ elements smaller than $a_{n-1}$
        // and $k_1$ elements larger than $a_{n-1}$.
        // We have $n-1$ elements smaller than $a_{n-1}$ ($a_0, \dots, a_{n-2}$).
        // We have $n$ elements larger than or equal to $a_n$ ($a_n, \dots, a_{2n-1}$).
        //
        // Let's try to make $a_{n-1}$ the median of $C_1$ and $a_n$ the median of $C_2$.
        //
        // Class $C_1$:
        // Take $a_{n-1}$ as the median.
        // We need $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We can take $k_1$ elements from $a_0, \dots, a_{n-2}$ (there are $n-1$ such elements).
        // We can take $k_1$ elements from $a_n, \dots, a_{2n-1}$ (there are $n$ such elements).
        //
        // Class $C_2$:
        // Take $a_n$ as the median.
        // We need $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$.
        // We can take $k_2$ elements from $a_0, \dots, a_{n-1}$ (there are $n$ such elements).
        // We can take $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ (there are $n-1$ such elements).
        //
        // The total number of students is $2n$.
        // $k_1 + k_2 + 1 = n$.
        //
        // Consider the simplest case: $k_1 = 0$ and $k_2 = n-1$.
        // $C_1$ has size $2(0)+1 = 1$. Median is $a_{n-1}$.
        // $C_2$ has size $2(n-1)+1 = 2n-1$. Median is $a_n$.
        //
        // To form $C_1 = \{a_{n-1}\}$:
        // This is valid.
        //
        // To form $C_2$ with $a_n$ as median and size $2n-1$:
        // We need $n-1$ elements smaller than $a_n$ and $n-1$ elements larger than $a_n$.
        // We have $n$ elements $a_0, \dots, a_{n-1}$ that are $\le a_n$. We can pick $n-1$ of them.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ that are $\ge a_n$. We can pick all $n-1$ of them.
        //
        // So, $C_1 = \{a_{n-1}\}$.
        // $C_2 = \{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This partition uses all $2n$ students.
        // $C_1$ has 1 student (odd).
        // $C_2$ has $(n-1) + 1 + (n-1) = 2n-1$ students (odd).
        // The median of $C_1$ is $a_{n-1}$.
        // The median of $C_2$ (which is sorted as $a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}$)
        // is its $( (2n-1-1)/2 + 1 ) = (n-1)+1 = n$-th element.
        // In the sorted list of $C_2$, the elements are $a_0, \dots, a_{n-2}$ (total $n-1$ elements),
        // then $a_n$, then $a_{n+1}, \dots, a_{2n-1}$ (total $n-1$ elements).
        // The $n$-th element is $a_n$.
        //
        // So, this construction works for any $n \ge 1$.
        // The difference is $|a_n - a_{n-1}|$.
        // Since $a_{n-1}$ and $a_n$ are adjacent elements in the sorted array,
        // their difference is the smallest possible for any two distinct elements chosen from the array.
        // Any other choice of medians would involve elements further apart or equal.
        // If the medians are equal, the difference is 0. This is covered by $|a_n - a_{n-1}|$ if $a_n = a_{n-1}$.
        //
        // Therefore, the minimum absolute difference is always $a_n - a_{n-1}$.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // The remaining 'mid' spots can be filled by anyone.
            // Total students needed: 3 * mid
            // Coders available after minimum: c - mid
            // Mathematicians available after minimum: m - mid
            // Students without specialization: x
            // Total remaining students to fill 'mid' spots: (c - mid) + (m - mid) + x
            // This sum must be at least 'mid'.
            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    if (p[0] < 1 || p[0] > n) { // q_1 must be within [1, n]
        possible = false;
    } else {
        used_values.insert(p[0]);
    }

    // Determine p_i for q_i > q_{i-1}
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            p[i] = q[i];
            if (p[i] < 1 || p[i] > n || used_values.count(p[i])) {
                possible = false;
                break;
            }
            used_values.insert(p[i]);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Fill in remaining p_i where q_i == q_{i-1}
    // These p_i must be values not yet used, and less than q_i.
    std::vector<int> available_values;
    for (int i = 1; i <= n; ++i) {
        if (!used_values.count(i)) {
            available_values.push_back(i);
        }
    }
    std::sort(available_values.rbegin(), available_values.rend()); // Use largest available first

    int current_available_idx = 0;
    for (int i = 1; i < n; ++i) {
        if (q[i] == q[i-1]) {
            if (current_available_idx >= available_values.size()) { // Not enough available numbers
                possible = false;
                break;
            }
            p[i] = available_values[current_available_idx];
            if (p[i] >= q[i]) { // p_i must be strictly less than q_i (which is q_{i-1})
                possible = false;
                break;
            }
            current_available_idx++;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences using a zig-zag pattern
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k + 1) elements, just append them in increasing order
    // This will only generate difference 1, which is already among the k differences (if k >= 1)
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int current_open_count = 0;
    int current_close_count = 0;

    for (char c : s) {
        if (c == '(') {
            if (current_open_count < open_needed) {
                result += '(';
                current_open_count++;
            }
        } else { // c == ')'
            if (current_close_count < close_needed && current_open_count > current_close_count) {
                result += ')';
                current_close_count++;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This marks the end of the longest suffix that is non-decreasing.
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j] > a[j-1]
    // This marks the end of the longest suffix that is non-increasing.
    // We start from `i` because any prefix before `i` is already "broken"
    // in terms of non-decreasing order.
    // We are looking for the point where the non-increasing part ends.
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now, a[j...i-1] is non-increasing (if i > j).
    // The segment a[j...n-1] is the candidate for the "good" array.
    // The length of the prefix to erase is `j`.

    std::cout << j << std::endl;
}

