#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx = pos[1], max_idx = pos[1]. Length = 1. Max value = 1.
        // This is always beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1]...pos[m]) to max(pos[1]...pos[m]).
        // Let's maintain current_min_idx and current_max_idx as the minimum and maximum
        // indices encountered so far for numbers 1 to (m-1).
        // When considering 'm', we update these bounds to include pos[m].

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A segment [p[current_min_idx], ..., p[current_max_idx]]
        // contains all numbers from 1 to m (because we've included pos[1]...pos[m]).
        // For this segment to be a permutation of 1...m, two conditions must hold:
        // 1. Its length must be exactly m. (current_max_idx - current_min_idx + 1 == m)
        // 2. The maximum value in this segment must be m. (This is implicitly true
        //    because we are only considering numbers up to m, and we know m is present).
        //    The minimum value in this segment must be 1. (Also implicitly true).

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    std::vector<int> result_subsequence;
    result_subsequence.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a peak if p[i] > p[i-1] and p[i] > p[i+1]
        // p[i] is a valley if p[i] < p[i-1] and p[i] < p[i+1]
        bool is_peak = (p[i] > p[i-1] && p[i] > p[i+1]);
        bool is_valley = (p[i] < p[i-1] && p[i] < p[i+1]);

        if (is_peak || is_valley) {
            result_subsequence.push_back(p[i]);
        }
    }
    result_subsequence.push_back(p[n-1]);

    std::cout << result_subsequence.size() << "\n";
    for (size_t i = 0; i < result_subsequence.size(); ++i) {
        std::cout << result_subsequence[i] << (i == result_subsequence.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

