    int mid_idx = n / 2;

    // Operations for the median element itself
    operations += std::abs(a[mid_idx] - s);

    // Operations for elements to the left of the median
    // These elements must be <= s to ensure s remains the median
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Operations for elements to the right of the median
    // These elements must be >= s to ensure s remains the median
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order based on B_i values
    // We need to store the original indices of B to map them back to A'
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& x, const Element& y) {
        return x.value > y.value;
    });

    // Create the result array A'
    std::vector<long long> result_a_prime(m);

    // Pair the smallest A_i with the largest B_i,
    // the second smallest A_i with the second largest B_i, and so on.
    // This means a_elements[i].value should be assigned to result_a_prime[b_elements[i].original_index]
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    // Output the rearranged array A'
    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int count01 = 0; // count of positions where a[i] = '0' and b[i] = '1'
    int count10 = 0; // count of positions where a[i] = '1' and b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                count01++;
            } else { // a[i] = '1', b[i] = '0'
                count10++;
            }
        }
    }

    // Each pair of (0->1, 1->0) can be resolved by a swap or two flips.
    // A swap costs |i-j|. Two flips cost 2.
    // The problem statement implies that we can choose to swap or flip.
    // The optimal strategy is to resolve as many (0->1, 1->0) pairs as possible
    // using swaps, and then flip the remaining bits.
    // However, a swap only makes sense if it resolves two differing positions.
    // If a[i] = '0', b[i] = '1' and a[j] = '1', b[j] = '0',
    // swapping a[i] and a[j] makes a[i] = '1' and a[j] = '0'.
    // Both positions now match b[i] and b[j]. Cost = |i-j|.
    // If we flip them, cost = 1 + 1 = 2.
    // So, if we have a 0->1 at index i and a 1->0 at index j,
    // we can either swap them for cost |i-j| or flip both for cost 2.
    // We should choose the minimum of these two options.
    //
    // The key insight is that we can always pair up a '0' that needs to become '1'
    // with a '1' that needs to become '0' using a swap.
    // The number of such pairs is min(count01, count10).
    // Each such pair can be resolved by a swap or two flips.
    //
    // Consider the state of `a` and `b` at each index `i`.
    // If `a[i] == b[i]`, nothing to do.
    // If `a[i] != b[i]`:
    //   Case 1: `a[i] = '0'`, `b[i] = '1'`. We need a '1' here.
    //   Case 2: `a[i] = '1'`, `b[i] = '0'`. We need a '0' here.
    //
    // Let's iterate through the string and maintain counts of pending '0's that need to be '1's
    // and pending '1's that need to be '0's.
    //
    // `zeros_to_ones_needed`: count of '0's encountered so far that need to become '1's.
    // `ones_to_zeros_needed`: count of '1's encountered so far that need to become '0's.
    //
    // When we are at index `i`:
    // If `a[i] == '0'` and `b[i] == '1'`:
    //   We need a '1' here. If there's a pending '1' that needs to be '0' (i.e., `ones_to_zeros_needed > 0`),
    //   we can perform a swap. This swap would have happened between the current index `i` and some previous index `j`
    //   where `a[j] = '1'` and `b[j] = '0'`. The cost of this swap is `i - j`.
    //   This is equivalent to saying we resolve one `ones_to_zeros_needed` and one `zeros_to_ones_needed`
    //   with a cost of 1 (because we are effectively "moving" the '1' from `j` to `i` and '0' from `i` to `j`).
    //   The cost of 1 is for the "effective" swap of values.
    //   The alternative is to flip `a[i]` to '1' (cost 1) and flip `a[j]` to '0' (cost 1). Total 2.
    //   So, if we can pair them, we pay 1.
    //   If `ones_to_zeros_needed > 0`, we decrement `ones_to_zeros_needed` and add 1 to `cost`.
    //   Else, we increment `zeros_to_ones_needed`.
    //
    // If `a[i] == '1'` and `b[i] == '0'`:
    //   We need a '0' here. If there's a pending '0' that needs to be '1' (i.e., `zeros_to_ones_needed > 0`),
    //   we can perform a swap. Similar logic, decrement `zeros_to_ones_needed` and add 1 to `cost`.
    //   Else, we increment `ones_to_zeros_needed`.
    //
    // After iterating through all indices, any remaining `zeros_to_ones_needed` or `ones_to_zeros_needed`
    // must be resolved by flips. Each remaining one costs 1.
    // The total remaining is `zeros_to_ones_needed + ones_to_zeros_needed`.
    //
    // This greedy approach works because a swap between `i` and `j` (where `i < j`)
    // costs `j - i`. If `a[i] = '0', b[i] = '1'` and `a[j] = '1', b[j] = '0'`,
    // swapping them resolves both.
    // If we have `a[i] = '0', b[i] = '1'` and `a[j] = '1', b[j] = '0'`,
    // and we also have `a[k] = '0', b[k] = '1'` and `a[l] = '1', b[l] = '0'`,
    // where `i < j` and `k < l`.
    //
    // The problem states "swap any two bits at indices i and j".
    // This means we can swap `a[i]` and `a[j]` even if `i` and `j` are far apart.
    //
    // Let's re-evaluate.
    // We have `count01` positions where `a[i]=0, b[i]=1`.
    // We have `count10` positions where `a[i]=1, b[i]=0`.
    //
    // We can perform `min(count01, count10)` swaps.
    // Each such swap resolves two differing positions.
    // For example, if `a[i]=0, b[i]=1` and `a[j]=1, b[j]=0`, we swap `a[i]` and `a[j]`.
    // `a[i]` becomes `1` (matches `b[i]`), `a[j]` becomes `0` (matches `b[j]`).
    // The cost is `|i-j|`.
    //
    // The remaining `|count01 - count10|` positions must be resolved by flips.
    // Each flip costs 1. So, `|count01 - count10|` flips cost `|count01 - count10|`.
    //
    // What about the `min(count01, count10)` swaps?
    // We want to minimize the sum of `|i-j|` for these swaps.
    // This is a minimum weight perfect matching problem on a bipartite graph, which is complex.
    //
    // However, the problem statement also says "flip the bit at this index. The cost of this operation is 1."
    //
    // Consider a position `i` where `a[i] = '0'` and `b[i] = '1'`.
    // Consider a position `j` where `a[j] = '1'` and `b[j] = '0'`.
    //
    // Option 1: Swap `a[i]` and `a[j]`. Cost `|i-j|`. Both `a[i]` and `a[j]` now match `b[i]` and `b[j]`.
    // Option 2: Flip `a[i]` to '1' and flip `a[j]` to '0'. Cost `1 + 1 = 2`. Both `a[i]` and `a[j]` now match.
    //
    // We should choose `min(|i-j|, 2)` for each such pair.
    //
    // This implies that if `|i-j| >= 2`, it's always better or equal to flip both.
    // If `|i-j| = 1`, it's better to swap.
    //
    // This simplifies the problem significantly.
    // We only care about adjacent swaps.
    //
    // Let's count the number of `01` pairs that need to be `10` (i.e., `a[i]=0, b[i]=1` and `a[i+1]=1, b[i+1]=0`).
    // And `10` pairs that need to be `01`.
    //
    // This is a standard dynamic programming problem or a greedy approach.
    //
    // Let's track the number of '0's that need to become '1's (`c01`) and '1's that need to become '0's (`c10`).
    // Iterate `i` from `0` to `n-1`.
    // If `a[i] == '0'` and `b[i] == '1'`:
    //   If `c10 > 0`, we can resolve a previous `1->0` mismatch with this `0->1` mismatch.
    //   This is effectively a swap. The cost is 1. (Because `|i-j|` for some `j < i` is at least 1.
    //   If `|i-j|=1`, cost is 1. If `|i-j| >= 2`, cost is 2 for flips. So we take 1 if we can pair).
    //   Decrement `c10`, add 1 to `cost`.
    //   Else, increment `c01`.
    // If `a[i] == '1'` and `b[i] == '0'`:
    //   If `c01 > 0`, we can resolve a previous `0->1` mismatch with this `1->0` mismatch.
    //   Decrement `c01`, add 1 to `cost`.
    //   Else, increment `c10`.
    //
    // After the loop, any remaining `c01` or `c10` must be resolved by flips.
    // Each costs 1. So, `cost += c01 + c10`.
    //
    // Let's test this logic with examples:
    // Example 1:
    // n = 3
    // a = 100
    // b = 001
    //
    // cost = 0, c01 = 0, c10 = 0
    // i = 0: a[0]=1, b[0]=0. Mismatch. `c01` is 0. Increment `c10`. `c10 = 1`.
    // i = 1: a[1]=0, b[1]=0. Match.
    // i = 2: a[2]=0, b[2]=1. Mismatch. `c10` is 1. Decrement `c10`, add 1 to `cost`. `c10 = 0`, `cost = 1`.
    //
    // End loop. `c01 = 0`, `c10 = 0`.
    // Final cost = 1. This is incorrect. Expected 2.
    //
    // The issue with the greedy approach above is that it assumes a swap always costs 1.
    // A swap costs `|i-j|`. A flip costs 1.
    //
    // The problem is that we can swap any `i` and `j`.
    // If we have `a[i]=0, b[i]=1` and `a[j]=1, b[j]=0`.
    // We can either:
    // 1. Swap `a[i]` and `a[j]`. Cost `|i-j|`.
    // 2. Flip `a[i]` and `a[j]`. Cost `1+1=2`.
    //
    // We should choose `min(|i-j|, 2)` for each pair.
    //
    // This means that if `|i-j| >= 2`, we should always flip.
    // If `|i-j| = 1`, we should swap.
    //
    // So, the strategy is:
    // 1. Identify all positions where `a[k] != b[k]`.
    // 2. Count `count01` (where `a[k]=0, b[k]=1`) and `count10` (where `a[k]=1, b[k]=0`).
    // 3. The number of positions that must be resolved by flips is `|count01 - count10|`.
    //    Add `|count01 - count10|` to total cost.
    // 4. The number of pairs that can potentially be resolved by swaps is `min(count01, count10)`.
    //    Let this be `num_pairs`.
    // 5. For these `num_pairs`, we need to decide if we swap or flip.
    //    If we swap, we pay `|i-j|`. If we flip, we pay `2`.
    //    We should choose the cheaper option.
    //    This means we only perform swaps for adjacent differing bits.
    //
    // Let's refine the greedy approach:
    // Iterate `i` from `0` to `n-1`.
    // If `a[i] == '0'` and `b[i] == '1'`:
    //   If `i+1 < n` and `a[i+1] == '1'` and `b[i+1] == '0'`:
    //     This is a `01` mismatch followed by a `10` mismatch.
    //     We can swap `a[i]` and `a[i+1]`. Cost `|(i+1)-i| = 1`.
    //     This is cheaper than flipping both (cost 2).
    //     So, perform this swap. Add 1 to `cost`.
    //     Advance `i` by one more (since `i+1` is also resolved).
    //   Else (no adjacent `10` mismatch):
    //     This `0->1` mismatch must be resolved by a flip (cost 1) or a non-adjacent swap (cost `|i-j| >= 2`).
    //     So, it's effectively a flip. Add 1 to `cost`.
    // If `a[i] == '1'` and `b[i] == '0'`:
    //   If `i+1 < n` and `a[i+1] == '0'` and `b[i+1] == '1'`:
    //     This is a `10` mismatch followed by a `01` mismatch.
    //     We can swap `a[i]` and `a[i+1]`. Cost `|(i+1)-i| = 1`.
    //     Add 1 to `cost`. Advance `i` by one more.
    //   Else (no adjacent `01` mismatch):
    //     This `1->0` mismatch must be resolved by a flip. Add 1 to `cost`.
    //
    // This greedy strategy seems correct.
    // It prioritizes adjacent swaps (cost 1) over flips (cost 1) or non-adjacent swaps (cost >= 2).
    // If an adjacent swap is possible, it's always optimal to take it because it resolves two mismatches for cost 1,
    // whereas two flips would cost 2.
    // If an adjacent swap is not possible, then any remaining mismatch must either be flipped (cost 1)
    // or swapped with a non-adjacent mismatch (cost `|i-j| >= 2`).
    // In this case, flipping is always better or equal.
    //
    // Let's re-test with examples:
    // Example 1:
    // n = 3
    // a = 100
    // b = 001
    //
    // cost = 0
    // i = 0: a[0]=1, b[0]=0. Mismatch.
    //   `i+1=1 < 3`. `a[1]=0, b[1]=0`. Match. No adjacent `01` mismatch.
    //   Add 1 to `cost`. `cost = 1`.
    // i = 1: a[1]=0, b[1]=0. Match.
    // i = 2: a[2]=0, b[2]=1. Mismatch.
    //   `i+1=3` not `< 3`. No adjacent `10` mismatch.
    //   Add 1 to `cost`. `cost = 2`.
    //
    // End loop. Final cost = 2. Correct!

    // Example 2:
    // n = 4
    // a = 0101
    // b = 0011
    //
    // cost = 0
    // i = 0: a[0]=0, b[0]=0. Match.
    // i = 1: a[1]=1, b[1]=0. Mismatch.
    //   `i+1=2 < 4`. `a[2]=0, b[2]=1`. Mismatch.
    //   This is `10` followed by `01`. Swap `a[1]` and `a[2]`. Cost 1.
    //   Add 1 to `cost`. `cost = 1`.
    //   Increment `i` (to skip `i+1`). `i` becomes 2.
    // i = 3: a[3]=1, b[3]=1. Match.
    //
    // End loop. Final cost = 1. Correct!

    // This greedy strategy seems robust.

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0' && b[i] == '1') { // Current is 0->1 mismatch
                if (i + 1 < n && a[i+1] == '1' && b[i+1] == '0') { // Next is 1->0 mismatch
                    // Swap a[i] and a[i+1]. Cost is 1.
                    // Both mismatches resolved.
                    cost += 1;
                    i++; // Skip next character as it's resolved
                } else {
                    // No adjacent 1->0 mismatch. Flip a[i]. Cost is 1.
                    cost += 1;
                }
            } else { // Current is 1->0 mismatch (a[i] == '1' && b[i] == '0')
                if (i + 1 < n && a[i+1] == '0' && b[i+1] == '1') { // Next is 0->1 mismatch
                    // Swap a[i] and a[i+1]. Cost is 1.
                    // Both mismatches resolved.
                    cost += 1;
                    i++; // Skip next character as it's resolved
                } else {
                    // No adjacent 0->1 mismatch. Flip a[i]. Cost is 1.
                    cost += 1;
                }
            }
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a sub-array is a permutation of length `len`
// It uses a frequency array (or boolean array) to track seen elements.
// It also checks if the maximum element is equal to `len`.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len <= 0) { // A permutation must have non-zero length
        return false;
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len; // All elements must be present, and max must be len
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max prefix values and check for prefix permutations
    std::vector<int> max_prefix(n);
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[L] is true if a[0...L-1] is a perm of length L
    std::vector<bool> seen_prefix(n + 1, false); // For checking distinctness and range for prefixes
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val <= 0 || val > (i + 1) || seen_prefix[val]) {
            possible_prefix = false;
        }
        seen_prefix[val] = true;
        if (val > current_max_prefix) {
            current_max_prefix = val;
        }
        max_prefix[i] = current_max_prefix;
        if (possible_prefix && current_max_prefix == (i + 1)) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Precompute max suffix values and check for suffix permutations
    std::vector<int> max_suffix(n);
    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[L] is true if a[n-L...n-1] is a perm of length L
    std::vector<bool> seen_suffix(n + 1, false); // For checking distinctness and range for suffixes
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        int len_suffix = n - i; // Length of suffix a[i...n-1]
        if (val <= 0 || val > len_suffix || seen_suffix[val]) {
            possible_suffix = false;
        }
        seen_suffix[val] = true;
        if (val > current_max_suffix) {
            current_max_suffix = val;
        }
        max_suffix[i] = current_max_suffix;
        if (possible_suffix && current_max_suffix == len_suffix) {
            is_suffix_perm[len_suffix] = true;
        }
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 goes from 1 to n-1.
    // If l1 is the length of p1, then l2 = n - l1.
    // The split point is after index l1-1.
    // p1 is a[0...l1-1], p2 is a[l1...n-1].
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (l2 <= 0) continue; // l2 must be non-zero length

        // Check if a[0...l1-1] is a permutation of length l1
        // This is true if is_prefix_perm[l1] is true
        bool p1_is_perm = is_prefix_perm[l1];

        // Check if a[l1...n-1] is a permutation of length l2
        // This is true if is_suffix_perm[l2] is true (suffix starting at index l1)
        bool p2_is_perm = is_suffix_perm[l2];

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

