#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    int k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    int current_score = 0;
    int initial_losses_count = 0;

    // Calculate initial score and count initial losses
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (i == 0 || s[i-1] == 'L') {
                current_score += 1;
            } else { // s[i-1] == 'W'
                current_score += 2;
            }
        } else { // s[i] == 'L'
            initial_losses_count++;
        }
    }

    // If k is greater than or equal to the number of losses, we can turn all 'L's to 'W's.
    // In this case, the score is 1 for the first game and 2 for all subsequent games.
    if (k >= initial_losses_count) {
        if (n == 0) { // Should not happen based on constraints n >= 1
            std::cout << 0 << std::endl;
        } else {
            std::cout << 1 + (n - 1) * 2 << std::endl;
        }
        return;
    }

    // If there are no 'W's initially and k > 0, we can turn the first k games into 'W's.
    // The score will be 1 for the first 'W' and 2 for the subsequent k-1 'W's.
    // If k=0, score is 0.
    if (current_score == 0 && k > 0) {
        std::cout << 1 + (k - 1) * 2 << std::endl;
        return;
    }

    // If k is 0, no changes can be made, so the initial score is the answer.
    if (k == 0) {
        std::cout << current_score << std::endl;
        return;
    }

    // Find the first and last 'W' to identify segments of 'L's
    int first_w = -1;
    int last_w = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (first_w == -1) {
                first_w = i;
            }
            last_w = i;
        }
    }

    // Collect lengths of 'L' segments between 'W's
    std::vector<int> l_segments;
    int current_l_count = 0;
    for (int i = first_w + 1; i < last_w; ++i) {
        if (s[i] == 'L') {
            current_l_count++;
        } else { // s[i] == 'W'
            if (current_l_count > 0) {
                l_segments.push_back(current_l_count);
            }
            current_l_count = 0;
        }
    }
    if (current_l_count > 0) {
        l_segments.push_back(current_l_count);
    }

    std::sort(l_segments.begin(), l_segments.end());

    // Greedily convert 'L' segments between 'W's
    for (int segment_len : l_segments) {
        if (k >= segment_len) {
            k -= segment_len;
            current_score += segment_len * 2 + 1; // Each L becomes W, connecting two Ws, adding 2 points for each L, plus 1 for the new connection
        } else {
            break; // Cannot convert this segment
        }
    }

    // Convert remaining k 'L's. These will be from the ends (before first 'W' or after last 'W').
    // Each such 'L' converted to 'W' adds 2 points (if adjacent to an existing 'W') or 1 point (if it's the first 'W' in a new chain).
    // Since we've already handled connecting segments, any remaining k will be used to extend existing 'W' chains.
    // Each 'L' converted to 'W' will be adjacent to an existing 'W' (first_w or last_w) or will become part of a new chain.
    // If it's adjacent to an existing 'W', it adds 2 points.
    // If it's not adjacent, it adds 1 point.
    // However, since we've already processed internal segments, any remaining k will be used to extend the 'W' chain from the ends.
    // Each such 'L' will become a 'W' adjacent to an existing 'W' (first_w or last_w) or to another 'W' we just converted.
    // So, each of these k conversions will add 2 points.
    current_score += k * 2;

    std::cout << current_score << std::endl;
}

