#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end()); // Sort w in ascending order

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // First, handle friends with w_i = 1.
        // These friends get 2 * largest_available_number.
        // Since w is sorted, these are at the beginning of w.
        // We give them the largest numbers from 'a'.
        for (int i = 0; i < k; ++i) {
            if (w[i] == 1) {
                total_happiness += 2 * a[a_ptr_right];
                a_ptr_right--;
            } else {
                // All remaining w_i will be > 1 because w is sorted.
                // Break and handle them in the next loop.
                break;
            }
        }

        // Now, handle friends with w_i > 1.
        // These friends get max_val + min_val.
        // To maximize sum, give largest remaining numbers as max_val.
        // To maximize sum, give smallest remaining numbers as min_val.
        // The friends with larger w_i values consume more small numbers.
        // So, assign friends with larger w_i to consume the smallest available numbers.
        // Iterate w in descending order for w_i > 1.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_right]; // Max value for this friend
                a_ptr_right--;
                total_happiness += a[a_ptr_left]; // Min value for this friend
                a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest numbers
            } else {
                // All remaining w_i are 1, which have already been handled.
                break;
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

