    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append at most 3 elements.
        // Let S be current_sum, X be current_xor_sum.
        // We want S' = 2X'.
        // S' = S + b1 + b2 + b3
        // X' = X ^ b1 ^ b2 ^ b3

        // Strategy: Append two elements.
        // Let b1 = X.
        // New XOR sum X' = X ^ X = 0.
        // New sum S' = S + X.
        // Now we need S' = 2X' => S + X = 2 * 0 => S + X = 0.
        // This is generally not true.

        // Let's try to make the XOR sum 0.
        // Append X.
        // New XOR sum becomes X_new = X ^ X = 0.
        // New sum becomes S_new = S + X.
        // Now we need S_new = 2 * X_new, which means S + X = 2 * 0 = 0.
        // This is only true if S=0 and X=0, which is not generally the case.

        // Let's try to make the XOR sum X.
        // This is not helpful.

        // Consider the property: S - 2X.
        // We want S' - 2X' = 0.
        // Let's append two numbers: X and S+X.
        // New XOR sum: X' = X ^ X ^ (S+X) = S+X.
        // New sum: S' = S + X + (S+X) = 2S + 2X.
        // Check condition: S' = 2X'
        // 2S + 2X = 2 * (S+X)
        // This is always true!
        // So, we can always append X and S+X.
        // The number of appended elements is 2.

        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

