int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'a') {
            // If we encounter an 'a', it will eventually move past all 'b's to its right.
            // Each 'b' to its right will cause one operation.
            // The 'a' itself will then be replaced by 'b'.
            // The number of operations this 'a' contributes is equal to the current count_b.
            // After this 'a' is processed, it effectively becomes a 'b' for subsequent 'a's to its left.
            // So, we add count_b to total_steps.
            // Then, this 'a' effectively becomes a 'b' for the purpose of future 'a's.
            // The number of 'b's that this 'a' will generate for 'a's to its left is (count_b * 2) + 1.
            // This is because each 'b' it passes doubles the number of 'b's it generates,
            // and then it itself becomes a 'b'.
            // So, count_a = (count_a * 2) + 1.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2 + 1) % mod;
        } else { // s[i] == 'b'
            // If we encounter a 'b', it simply adds to the count of 'b's that 'a's to its left
            // will have to pass.
            // This 'b' is effectively a 'b' that an 'a' to its left will encounter.
            // So, we increment count_b.
            // In our logic, count_a represents the number of 'b's that an 'a' to its left
            // will effectively encounter. So, we increment count_a.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        // Chanek's turn
        if (n == 1) {
            chanek_coins += 1;
            n = 0;
        } else if (n == 2) {
            chanek_coins += 1; // Take 1, N becomes 1. Opponent takes 1. Chanek gets 1.
            n = 0;
        } else if (n == 3) {
            chanek_coins += 1; // Take 1, N becomes 2. Opponent takes 1. Chanek takes 1.
            n = 0;
        } else if (n % 2 != 0) { // N is odd and N > 3
            chanek_coins += 1;
            n -= 1;
        } else { // N is even and N > 3
            // If N is even, Chanek can take N/2 or 1.
            // Opponent will play optimally to maximize their coins.
            // Consider N/2. If N/2 is odd, opponent will take 1.
            // If N/2 is even, opponent will take (N/2)/2 = N/4.
            //
            // Strategy:
            // If N is a power of 2 (N = 2^k, k >= 2), taking N/2 is always better.
            // Example: N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3.
            // If Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+1=2.
            // So for N=4, take N/2.
            //
            // Example: N=6.
            // Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
            // Chanek: 1+2+1 = 4. Opponent: 1+1 = 2.
            // Chanek takes N/2=3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
            // Chanek: 3+1 = 4. Opponent: 1+1 = 2.
            // Both give 4.
            //
            // The key insight is that if N is even, taking N/2 is generally better or equal.
            // The only exception is when N/2 is odd, and taking 1 would lead to a better outcome.
            // If N/2 is odd, the opponent will take 1 from N/2, leaving N/2-1 (even).
            // If Chanek takes 1, N-1 is odd. Opponent takes 1, N-2 is even.
            //
            // Let's consider the opponent's turn after Chanek takes N/2.
            // If N/2 is odd, opponent takes 1. Remaining N/2-1 (even).
            // If N/2 is even, opponent takes (N/2)/2 = N/4. Remaining N/4 (even).
            //
            // The optimal strategy for Chanek when N is even:
            // If N is a power of 2 (N = 2^k), Chanek should always take N/2.
            // If N is even but not a power of 2, it means N has an odd factor.
            // Let N = 2^k * M, where M is odd and M > 1.
            // If Chanek takes N/2 = 2^(k-1) * M.
            // If Chanek takes 1, N-1 is odd.
            //
            // Consider the opponent's turn.
            // If N is even, and N/2 is odd (i.e., N = 2 * M, where M is odd).
            // Chanek takes N/2. Remaining N/2 (odd). Opponent takes 1. Remaining N/2-1 (even).
            // Chanek takes 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2 (even).
            //
            // It seems that if N is even and N/2 is odd (N = 2 * odd_number), Chanek should take 1.
            // Example: N=6. N/2=3 (odd).
            // Chanek takes 1. N=5. Chanek: 1.
            // Opponent's turn. N=5. Opponent takes 1. N=4. Opponent: 1.
            // Chanek's turn. N=4. Chanek takes 2. N=2. Chanek: 1+2=3.
            // Opponent's turn. N=2. Opponent takes 1. N=1. Opponent: 1+1=2.
            // Chanek's turn. N=1. Chanek takes 1. N=0. Chanek: 3+1=4.
            // Final: Chanek 4, Opponent 2.
            //
            // Chanek takes N/2=3. N=3. Chanek: 3.
            // Opponent's turn. N=3. Opponent takes 1. N=2. Opponent: 1.
            // Chanek's turn. N=2. Chanek takes 1. N=1. Chanek: 3+1=4.
            // Opponent's turn. N=1. Opponent takes 1. N=0. Opponent: 1+1=2.
            // Final: Chanek 4, Opponent 2.
            // In this case, both yield the same result for Chanek.

            // What if N is a power of 2? N = 2^k.
            // Chanek takes N/2. N becomes N/2.
            // Opponent takes (N/2)/2. N becomes N/4.
            // ...
            // This continues until N becomes 2.
            // Chanek takes N/2. N becomes 1.
            // Opponent takes 1. N becomes 0.
            // Chanek gets N/2 + N/8 + N/32 + ... + 1.
            // This is N * (1/2 + 1/8 + 1/32 + ...) = N * ( (1/2) / (1 - 1/4) ) = N * ( (1/2) / (3/4) ) = N * (2/3).
            // This is not quite right because the last 1 is taken by Chanek.
            // Let's trace N=4: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3.
            // N=8: Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 4+1=5.
            // N=16: Chanek takes 8. N=8. Opponent takes 4. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 8+2+1=11.
            // The pattern for N=2^k is Chanek gets 2^k - (2^k / 3) rounded down. No, it's 2^k - (2^k / 3) rounded up.
            // It's (2^k + 1) / 3 * 2 - 1 if k is odd.
            // It's (2^k + 1) / 3 * 2 - 1 if k is even.
            // It's (2^k - 1) / 3 * 2 + 1 if k is odd.
            // It's (2^k - 1) / 3 * 2 + 1 if k is even.
            // For N=2^k, Chanek gets (2^(k+1) + (-1)^k) / 3.
            // For N=4 (k=2): (2^3 + (-1)^2)/3 = (8+1)/3 = 3. Correct.
            // For N=8 (k=3): (2^4 + (-1)^3)/3 = (16-1)/3 = 5. Correct.
            // For N=16 (k=4): (2^5 + (-1)^4)/3 = (32+1)/3 = 11. Correct.
            // So if N is a power of 2, Chanek takes N/2.

            // If N is even but not a power of 2, it means N = 2^k * M where M is odd and M > 1.
            // If Chanek takes N/2, N becomes 2^(k-1) * M.
            // If Chanek takes 1, N becomes 2^k * M - 1 (odd).
            //
            // The optimal strategy for Chanek when N is even:
            // If N is a power of 2, take N/2.
            // If N is even but not a power of 2 (i.e., N has an odd factor > 1), take 1.
            // Why? If N = 2^k * M (M > 1, M odd).
            // If Chanek takes N/2, the opponent faces 2^(k-1) * M.
            // If Chanek takes 1, the opponent faces 2^k * M - 1 (odd). Opponent takes 1. Then N-2 (even).
            //
            // Let's re-evaluate the general strategy.
            // If N is odd: Chanek takes 1. N becomes N-1 (even).
            // If N is even:
            //   If N is a power of 2 (N = 2^k): Chanek takes N/2. N becomes N/2.
            //   If N is even but not a power of 2 (N = 2^k * M, M > 1, M odd): Chanek takes 1. N becomes N-1 (odd).
            //
            // Let's test this strategy.
            // N=5: Chanek takes 1. N=4. Chanek: 1.
            // Opponent's turn. N=4 (power of 2). Opponent takes 4/2=2. N=2. Opponent: 2.
            // Chanek's turn. N=2 (power of 2). Chanek takes 2/2=1. N=1. Chanek: 1+1=2.
            // Opponent's turn. N=1. Opponent takes 1. N=0. Opponent: 2+1=3.
            // Final: Chanek 2, Opponent 3. This matches example.

            // N=6: Chanek's turn. N=6 (even, not power of 2). Chanek takes 1. N=5. Chanek: 1.
            // Opponent's turn. N=5 (odd). Opponent takes 1. N=4. Opponent: 1.
            // Chanek's turn. N=4 (power of 2). Chanek takes 4/2=2. N=2. Chanek: 1+2=3.
            // Opponent's turn. N=2 (power of 2). Opponent takes 2/2=1. N=1. Opponent: 1+1=2.
            // Chanek's turn. N=1 (odd). Chanek takes 1. N=0. Chanek: 3+1=4.
            // Final: Chanek 4, Opponent 2. This matches example.

            // This strategy seems correct.
            // How to check if N is a power of 2? (N > 0) && ((N & (N - 1)) == 0).
            if ((n & (n - 1)) == 0) { // N is a power of 2
                chanek_coins += n / 2;
                n /= 2;
            } else { // N is even but not a power of 2
                chanek_coins += 1;
                n -= 1;
            }
        }

        // Opponent's turn (if N > 0)
        if (n > 0) {
            if (n == 1) {
                n = 0; // Opponent takes 1
            } else if (n % 2 != 0) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                // Opponent applies the same optimal strategy
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    n /= 2;
                } else { // N is even but not a power of 2
                    n -= 1;
                }
            }
        }
    }
    return chanek_coins;
}

