    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x-1)
            // f2: can move up (y+1)
            // f3: can move right (x+1)
            // f4: can move down (y-1)

            // If robot cannot move left (f1=0), it must end up at x >= its current x.
            // So, the target X must be >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // If robot cannot move down (f4=0), it must end up at y >= its current y.
            // So, the target Y must be >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // If robot cannot move right (f3=0), it must end up at x <= its current x.
            // So, the target X must be <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If robot cannot move up (f2=0), it must end up at y <= its current y.
            // So, the target Y must be <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a point exists, one exists within [-10^5, 10^5].
            // Our calculated min_x, max_x, min_y, max_y might exceed this range if the
            // initial coordinates are large, but we can always pick a point within the
            // intersection. For example, min_x and min_y.
            // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
            // This implies we should pick a point within the guaranteed range if possible.
            // However, the constraints on x_i, y_i are -10^5 to 10^5.
            // If min_x is, say, 100001, and max_x is 100001, then the only valid X is 100001.
            // The problem guarantees that if a solution exists, one exists with |X|, |Y| <= 10^5.
            // So, we can just output min_x and min_y, and they will be within the bounds if a solution exists.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // (b-1) * b can be large, so we need to take modulo carefully.
    // Since MOD is prime and 2 < MOD, we can use modular inverse for division by 2.
    long long sum_r_term = (b - 1);
    sum_r_term %= MOD;
    long long b_mod = b % MOD;
    sum_r_term = (sum_r_term * b_mod) % MOD;

    // Modular inverse of 2 modulo MOD (10^9 + 7)
    // Since MOD is prime, 2^(MOD-2) mod MOD is the inverse.
    // (MOD + 1) / 2 = (1000000007 + 1) / 2 = 1000000008 / 2 = 500000004
    long long inv2 = 500000004;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a

    long long sum_k_term_part1 = a;
    sum_k_term_part1 %= MOD;
    long long a_plus_1_mod = (a + 1) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * a_plus_1_mod) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * inv2) % MOD; // (a * (a+1) / 2)

    long long sum_k_term_part2 = (b % MOD);
    sum_k_term_part2 = (sum_k_term_part2 * sum_k_term_part1) % MOD; // b * (a * (a+1) / 2)

    long long sum_k_term_part3 = a % MOD; // + a

    long long sum_k_term = (sum_k_term_part2 + sum_k_term_part3) % MOD;

    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long val = h[i];
        if (!dq.empty()) {
            val = std::min(val, L[dq.back()] + (i - dq.back()));
        } else {
            val = std::min(val, (long long)i + 1);
        }
        L[i] = val;
        dq.push_back(i);
    }

    std::vector<long long> R(n);
    dq.clear();

    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long val = h[i];
        if (!dq.empty()) {
            val = std::min(val, R[dq.back()] + (dq.back() - i));
        } else {
            val = std::min(val, (long long)(n - i));
        }
        R[i] = val;
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << "1\n";
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    // If n is a perfect square, k = sqrt(n).
    // If n is not a perfect square, k = floor(sqrt(n)).
    // We want to make LIS and LDS roughly k or k+1.
    // The optimal strategy is to divide the permutation into blocks of size k.
    // The number of blocks will be ceil(n/k).
    // Let's try to make the block size k.
    // The number of blocks will be (n + k - 1) / k.

    // Example: n=4, k=2
    // Blocks: [1,2], [3,4]
    // Output: 3 4 1 2
    // Block 1: [3,4] (reversed)
    // Block 2: [1,2] (reversed)
    // This is (k*2-1) ... (k*1) (k*1-1) ... (k*0)
    // For n=4, k=2:
    // Block 2: 3 4
    // Block 1: 1 2
    // Output: 3 4 1 2

    // Example: n=9, k=3
    // Blocks: [1,2,3], [4,5,6], [7,8,9]
    // Output: 7 8 9 4 5 6 1 2 3
    // Block 3: 7 8 9
    // Block 2: 4 5 6
    // Block 1: 1 2 3

    // The general construction is to print numbers in blocks of size k,
    // but in decreasing order of blocks.
    // For each block, print numbers in increasing order.
    // The last block might be smaller than k.

    // Number of full blocks
    int num_blocks = (n + k - 1) / k;

    for (int i = num_blocks - 1; i >= 0; --i) {
        int start_val = i * k + 1;
        int end_val = std::min((i + 1) * k, n);
        for (int j = start_val; j <= end_val; ++j) {
            std::cout << j << (j == n ? "" : " ");
        }
    }
    std::cout << "\n";

    return 0;
}

