#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int val0 = 0; // Represents the state of a 0-bit after all operations
    int val1 = 1023; // Represents the state of a 1-bit after all operations (i.e., what 1023 becomes)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1 ^= x;
        }
    }

    // Now we have val0 and val1.
    // For each bit position i (0 to 9):
    // If input bit is 0, output bit is (val0 >> i) & 1.
    // If input bit is 1, output bit is (val1 >> i) & 1.

    // We want to find A, B, C such that:
    // (x & A | B) ^ C = result
    // Or a shorter sequence.

    // Let's determine the final operations.
    // We need to find a sequence of operations that transforms an input `x`
    // into `val0` if `x` is 0, and into `val1` if `x` is 1023.

    // The general form of a single bit transformation is:
    // input_bit -> (input_bit & a | b) ^ c
    //
    // For input_bit = 0: (0 & a | b) ^ c = b ^ c
    // This must equal (val0 >> i) & 1.
    //
    // For input_bit = 1: (1 & a | b) ^ c = (a | b) ^ c
    // This must equal (val1 >> i) & 1.

    // Let's find the effective AND, OR, XOR constants.
    int final_and_mask = 1023; // Bits that are forced to 0 by an AND operation
    int final_or_mask = 0;    // Bits that are forced to 1 by an OR operation
    int final_xor_mask = 0;   // Bits that are flipped by an XOR operation

    for (int i = 0; i < 10; ++i) {
        int bit0_result = (val0 >> i) & 1;
        int bit1_result = (val1 >> i) & 1;

        if (bit0_result == 0 && bit1_result == 0) {
            // Both 0 and 1 map to 0.
            // This means the bit must be forced to 0.
            // This can be achieved by `& 0` for this bit.
            final_and_mask &= ~(1 << i); // Set i-th bit of final_and_mask to 0
        } else if (bit0_result == 1 && bit1_result == 1) {
            // Both 0 and 1 map to 1.
            // This means the bit must be forced to 1.
            // This can be achieved by `| 1` for this bit.
            final_or_mask |= (1 << i); // Set i-th bit of final_or_mask to 1
        } else if (bit0_result == 0 && bit1_result == 1) {
            // 0 maps to 0, 1 maps to 1.
            // This means the bit is unchanged.
            // This can be achieved by `& 1` and `| 0` and `^ 0` for this bit.
            // No change to final_and_mask, final_or_mask, final_xor_mask for this bit.
        } else if (bit0_result == 1 && bit1_result == 0) {
            // 0 maps to 1, 1 maps to 0.
            // This means the bit is flipped.
            // This can be achieved by `^ 1` for this bit.
            final_xor_mask |= (1 << i); // Set i-th bit of final_xor_mask to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // Apply AND first
    if (final_and_mask != 1023) { // If any bit is forced to 0
        result_ops.push_back({'&', final_and_mask});
    }

    // Apply OR next
    // The OR mask should only affect bits that are not already forced to 0 by AND.
    // If a bit is forced to 0 by AND, ORing with 1 won't change it from 0.
    // So, we need to OR with bits that are 1 in final_or_mask AND 1 in final_and_mask.
    int effective_or_mask = final_or_mask & final_and_mask;
    if (effective_or_mask != 0) { // If any bit is forced to 1
        result_ops.push_back({'|', effective_or_mask});
    }

    // Apply XOR last
    // The XOR mask should only affect bits that are not already determined by AND/OR.
    // If a bit is forced to 0 by AND, or forced to 1 by OR, XORing with 1 will flip it.
    // We need to XOR with bits that are 1 in final_xor_mask.
    // The XOR operation flips the current state.
    // The current state for a 0-input bit is (0 & final_and_mask | effective_or_mask).
    // The current state for a 1-input bit is (1 & final_and_mask | effective_or_mask).
    // We need to apply XOR to achieve the final bit_result.
    // The final_xor_mask already captures the bits that need to be flipped.
    if (final_xor_mask != 0) { // If any bit needs to be flipped
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
        // This is achieved by making the blocks of '0's as equal in length as possible.
        // There are m '1's. These '1's divide the string into m+1 potential blocks of '0's.
        // For example, 10101 has 3 '1's and 4 blocks of '0's (including empty ones).
        // The '1's are fixed, so we have n - m '0's to distribute into m+1 blocks.

        long long num_zeros = n - m;

        // If num_zeros is 0, then all characters are '1's.
        // In this case, there are no substrings of '0's, so N_zeros = 0.
        // f(s) = total_substrings.
        if (num_zeros == 0) {
            std::cout << total_substrings << "\n";
            continue;
        }

        // Distribute num_zeros into m+1 blocks as evenly as possible.
        // Let k be the number of '0's in each block.
        // There will be (m+1) blocks.
        // Some blocks will have floor(num_zeros / (m+1)) zeros.
        // Some blocks will have ceil(num_zeros / (m+1)) zeros.

        long long k_small = num_zeros / (m + 1);
        long long k_large = k_small + 1;

        // Number of blocks with k_large zeros
        long long count_large_blocks = num_zeros % (m + 1);
        // Number of blocks with k_small zeros
        long long count_small_blocks = (m + 1) - count_large_blocks;

        long long sum_zeros_substrings = 0;

        // Contribution from blocks with k_small zeros
        sum_zeros_substrings += count_small_blocks * (k_small * (k_small + 1) / 2);

        // Contribution from blocks with k_large zeros
        sum_zeros_substrings += count_large_blocks * (k_large * (k_large + 1) / 2);

        std::cout << total_substrings - sum_zeros_substrings << "\n";
    }
    return 0;
}

