#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance for the whole row
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Store balances for prefixes of the left half (jars 1 to n)
    // and suffixes of the right half (jars n+1 to 2n)
    // The map will store balance -> minimum number of jars removed to achieve that balance
    std::map<int, int> left_balances;
    left_balances[0] = 0; // 0 jars removed from left, balance 0

    int current_balance = 0;
    for (int i = n - 1; i >= 0; --i) { // Iterate from n-1 down to 0 (jars n, n-1, ..., 1)
        if (a[i] == 1) {
            current_balance++;
        } else {
            current_balance--;
        }
        int jars_removed = n - i; // Number of jars removed from the left (jars 1 to i)
                                  // This is equivalent to removing jars from index 0 to i-1
                                  // If i=n-1, we remove 1 jar (jar n). Jars_removed = 1.
                                  // If i=0, we remove n jars (jars 1 to n). Jars_removed = n.
        if (left_balances.find(current_balance) == left_balances.end()) {
            left_balances[current_balance] = jars_removed;
        }
    }

    // Find the minimum total jars removed
    int min_total_removed = 2 * n; // Max possible jars removed

    // Case 1: No jars removed from the right side (R=0)
    // We need the remaining balance to be 0.
    // The initial balance of the whole array is `initial_balance`.
    // If we remove `L` jars from the left, the balance changes by `current_balance` (from `left_balances`).
    // The remaining balance will be `initial_balance - current_balance`.
    // We need `initial_balance - current_balance = 0`, so `current_balance = initial_balance`.
    if (left_balances.count(initial_balance)) {
        min_total_removed = std::min(min_total_removed, left_balances[initial_balance]);
    }

    // Iterate through suffixes of the right half (jars n+1 to 2n)
    current_balance = 0;
    for (int i = n; i < 2 * n; ++i) { // Iterate from n up to 2n-1 (jars n+1, n+2, ..., 2n)
        if (a[i] == 1) {
            current_balance++;
        } else {
            current_balance--;
        }
        int jars_removed_right = i - n + 1; // Number of jars removed from the right (jars 2n down to i+1)
                                            // This is equivalent to removing jars from index 2n-1 down to i
                                            // If i=n, we remove 1 jar (jar n+1). Jars_removed_right = 1.
                                            // If i=2n-1, we remove n jars (jars n+1 to 2n). Jars_removed_right = n.

        // We need the final balance to be 0.
        // The initial balance of the whole array is `initial_balance`.
        // If we remove `L` jars from the left (with balance `bal_L`) and `R` jars from the right (with balance `bal_R`),
        // the remaining balance is `initial_balance - bal_L - bal_R`.
        // We need `initial_balance - bal_L - bal_R = 0`, so `bal_L = initial_balance - bal_R`.
        int target_left_balance = initial_balance - current_balance;
        if (left_balances.count(target_left_balance)) {
            min_total_removed = std::min(min_total_removed, left_balances[target_left_balance] + jars_removed_right);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

