        //
        // Here, k is the node being added.
        // We need to update all pairs (i, j) using k as an intermediate.
        // And also update paths from i to k, and k to j, using other active nodes as intermediates.
        // The most robust way is to iterate over all active nodes for i, j, and the new k.

        // Re-evaluate all pairs (i, j) using all active nodes as intermediates.
        // This is the full Floyd-Warshall step for the current set of active nodes.
        // Since k is the newest active node, we can optimize by only considering k as the intermediate
        // for paths between *already* active nodes, and then considering *all* active nodes
        // for paths involving k as an endpoint.
        // The previous loop `for i, for j` already handles `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.
        // We also need to update `dist[i][k]` and `dist[k][j]` using other active nodes.
        // This is implicitly handled by the full Floyd-Warshall structure if we consider k as the outermost loop variable.
        // The current structure is:
        // k is the node being added.
        // For all active i, j:
        //   dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //   dist[i][k] = min(dist[i][k], dist[i][p] + dist[p][k]) for all active p
        //   dist[k][j] = min(dist[k][j], dist[k][p] + dist[p][j]) for all active p
        //
        // The following three nested loops achieve this for the current set of active nodes.
        // The order of loops matters for correctness.
        // The standard Floyd-Warshall order is `k, i, j`.
        // Here, `k` is the node just added.
        // We need to update all `dist[i][j]` for active `i, j` using `k` as an intermediate.
        // And also update `dist[i][k]` and `dist[k][j]` using other active nodes as intermediates.
        // The most straightforward way to ensure all shortest paths are correct after adding `k`
        // is to run the Floyd-Warshall update step where `k` is the intermediate node.
        // This means, for every pair of *currently active* nodes `i` and `j`,
        // we check if `dist[i][k] + dist[k][j]` is shorter than `dist[i][j]`.
        // This is what the first set of nested loops does.
        // However, `dist[i][k]` and `dist[k][j]` themselves might need to be updated
        // using other *already active* nodes as intermediates.
        // So, the full update for adding node `k` should be:
        // 1. For all active `i`, `p`: `dist[i][k] = min(dist[i][k], dist[i][p] + dist[p][k])`
        // 2. For all active `p`, `j`: `dist[k][j] = min(dist[k][j], dist[k][p] + dist[p][j])`
        // 3. For all active `i`, `j`: `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        //
        // Combining these, we can just iterate over all active nodes `p`, `i`, `j`
        // and apply the Floyd-Warshall update.
        // Since `k` is the *newest* active node, we can use `k` as the intermediate for the outermost loop.
        // This is exactly what the standard Floyd-Warshall algorithm does.
        // The `k` in `dist[i][k] + dist[k][j]` is the intermediate node.
        // The `k_idx` loop variable corresponds to the intermediate node in Floyd-Warshall.
        // So, the current `k` (from `x[k_idx]`) is the intermediate node.
        // The loops should be:
        // for (int i = 0; i < n; ++i) {
        //     if (!active_nodes[i]) continue;
        //     for (int j = 0; j < n; ++j) {
        //         if (!active_nodes[j]) continue;
        //         dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
        //     }
        // }
        // This is correct. The `dist[i][k]` and `dist[k][j]` values used here
        // are the ones that were already computed considering all nodes that were active *before* `k`.
        // When `k` becomes active, it can now serve as an intermediate.
        // The `dist` matrix always holds the shortest paths considering all nodes that have been
        // processed as intermediate nodes up to that point.
        // So, when `k` is processed, `dist[i][k]` and `dist[k][j]` already reflect shortest paths
        // using intermediates from `x[k_idx+1], ..., x[n-1]`.
        // The current loop correctly updates `dist[i][j]` using `k` as an intermediate.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;
                if (i == j) continue; // Sum for v != u
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were collected)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    // Use a vector of indices to represent the current line
    // This allows efficient removal by marking children as not in line
    // and iterating over the original children vector.
    // The `current_line_indices` will store the original indices (0 to n-1)
    // of children still in line.
    std::vector<int> current_line_indices(n);
    std::iota(current_line_indices.begin(), current_line_indices.end(), 0);

    int current_line_head_idx = 0; // Index in current_line_indices

    while (current_line_head_idx < current_line_indices.size()) {
        int child_original_idx = current_line_indices[current_line_head_idx];

        // This child goes to the doctor
        cured_children_ids.push_back(children[child_original_idx].id);
        children[child_original_idx].in_line = false; // Mark as treated

        long long office_cry_volume = children[child_original_idx].v;
        long long hall_cry_sum_d = 0; // Accumulates d_j from children leaving the line

        // Apply office cry volume to subsequent children
        // Iterate through children *after* the one just treated
        for (int i = current_line_head_idx + 1; i < current_line_indices.size(); ++i) {
            int subsequent_child_original_idx = current_line_indices[i];

            // Apply accumulated hall cry volume first
            children[subsequent_child_original_idx].p -= hall_cry_sum_d;

            // Apply office cry volume
            if (office_cry_volume > 0) {
                children[subsequent_child_original_idx].p -= office_cry_volume;
                office_cry_volume--;
            }

            // Check if this child leaves due to low confidence
            if (children[subsequent_child_original_idx].p < 0 && children[subsequent_child_original_idx].in_line) {
                children[subsequent_child_original_idx].in_line = false; // Mark as left
                hall_cry_sum_d += children[subsequent_child_original_idx].d;
            }
        }

        // Rebuild current_line_indices to remove children who left
        std::vector<int> next_line_indices;
        for (int i = current_line_head_idx + 1; i < current_line_indices.size(); ++i) {
            if (children[current_line_indices[i]].in_line) {
                next_line_indices.push_back(current_line_indices[i]);
            }
        }
        current_line_indices = std::move(next_line_indices);
        current_line_head_idx = 0; // Reset head index for the new line
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a_min = elements[0].value;
    long long a_max = elements[n - 1].value;
    long long a_second_min = elements[1].value;
    long long a_second_max = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., S1 is empty or S2 is empty)
    // All f values are a_i + a_j.
    // Min f = a_min + a_second_min
    // Max f = a_max + a_second_max
    // Goodness = (a_max + a_second_max) - (a_min + a_second_min)
    long long goodness1 = (a_max + a_second_max) - (a_min + a_second_min);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put a_min into S1 and a_max into S2.
    // The remaining elements can be distributed.
    // To minimize max_f - min_f, we want to make the range of f values as small as possible.
    // The values are:
    // 1. a_i + a_j (same subsequence)
    // 2. a_i + a_j + h (different subsequences)

    // Consider the partition where a_min is in S1 and a_max is in S2.
    // The smallest possible sum of two elements in the same subsequence is a_min + a_second_min.
    // The largest possible sum of two elements in the same subsequence is a_max + a_second_max.
    // The smallest possible sum of two elements in different subsequences is a_min + a_min_other + h.
    // The largest possible sum of two elements in different subsequences is a_max + a_max_other + h.

    // Let's try a specific partition:
    // Put a_min in S1.
    // Put a_max in S2.
    // Put all other elements (a_second_min to a_second_max) into S1.
    // So S1 = {a_min, a_second_min, ..., a_second_max}
    //    S2 = {a_max}
    // This is effectively putting all elements except a_max into S1, and a_max into S2.
    // This is equivalent to putting a_min into S1 and all other elements into S2.
    // S1 = {a_min}
    // S2 = {a_second_min, ..., a_max}
    //
    // Let's analyze this partition:
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    //
    // Min f:
    //   - From S1: No pairs if S1 has 1 element.
    //   - From S2: elements[1].value + elements[2].value (if n >= 3)
    //   - Between S1 and S2: elements[0].value + elements[1].value + h
    // So, min_f = min(elements[1].value + elements[2].value (if n>=3), elements[0].value + elements[1].value + h)
    //
    // Max f:
    //   - From S1: No pairs if S1 has 1 element.
    //   - From S2: elements[n-1].value + elements[n-2].value
    //   - Between S1 and S2: elements[0].value + elements[n-1].value + h
    // So, max_f = max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)

    // Let's consider two specific partitions for Case 2:
    // Partition A: elements[0] in S1, all others in S2.
    // Partition B: elements[n-1] in S2, all others in S1.
    // These are symmetric. Let's just consider one:
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    //
    // Min_f_A:
    //   If n=2: S1={a_min}, S2={a_max}. Only one f value: a_min + a_max + h. Min_f_A = Max_f_A = a_min + a_max + h. Goodness = 0.
    //   If n>=3:
    //     Pairs within S2: min sum is elements[1].value + elements[2].value
    //     Pairs between S1 and S2: min sum is elements[0].value + elements[1].value + h
    //     So, min_f_A = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // Max_f_A:
    //   If n=2: (handled above)
    //   If n>=3:
    //     Pairs within S2: max sum is elements[n-1].value + elements[n-2].value
    //     Pairs between S1 and S2: max sum is elements[0].value + elements[n-1].value + h
    //     So, max_f_A = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    // Goodness_A = max_f_A - min_f_A

    long long goodness2 = -1;
    std::vector<int> partition2(n);

    if (n == 2) {
        // If n=2, there's only one pair (a_0, a_1).
        // If they are in the same subsequence: f = a_0 + a_1. Goodness = 0.
        // If they are in different subsequences: f = a_0 + a_1 + h. Goodness = 0.
        // So, for n=2, goodness is always 0.
        // The problem statement says "difference between maximum value of function f and minimum value of function f".
        // If there's only one pair, there's only one f value, so max_f = min_f, difference is 0.
        // This is true for both partition types.
        // We can just use partition1 (all 1s) or partition2 (1 2).
        goodness2 = 0;
        partition2[elements[0].original_index] = 1;
        partition2[elements[1].original_index] = 2;
    } else { // n >= 3
        long long min_f_A = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        long long max_f_A = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
        goodness2 = max_f_A - min_f_A;

        partition2[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition2[elements[i].original_index] = 2;
        }
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, subsequent values will be current_val + d + 1

    // Iterate through powers of 2, from largest possible down to 1
    // A block of 'k' identical numbers contributes 2^k - 1 subsequences.
    // We want to represent X as a sum of (2^k - 1) terms.
    // This is equivalent to representing X+1 as a sum of 2^k terms.
    // Or, more simply, if we have a block of 'k' identical numbers, it contributes 2^k-1 to the count.
    // If we have a block of 'k' numbers, and then a new number far away,
    // the new number starts a new "group" of subsequences.
    // The total count is the sum of (2^k - 1) for each block.
    // This is not quite right.
    //
    // Let's re-evaluate:
    // If we have an array `[A, A, ..., A (k times), B, B, ..., B (m times), C, ...]`,
    // where `B - A >= d` and `C - B >= d`.
    // The subsequences from the first block `[A, ..., A]` are `2^k - 1`.
    // The subsequences from the second block `[B, ..., B]` are `2^m - 1`.
    // And so on.
    // The total count `X` is the sum of `(2^k - 1)` for each block.
    //
    // This means we need to decompose `X` into a sum of `(2^k - 1)` terms.
    // `X = (2^k1 - 1) + (2^k2 - 1) + ...`
    // This is equivalent to `X + N = 2^k1 + 2^k2 + ...` where N is the number of blocks.
    //
    // A simpler approach:
    // We want to represent X as a sum of `(2^k - 1)` values.
    // We can greedily pick the largest `k` such that `2^k - 1 <= X`.
    //
    // Example: X = 10, d = 5
    // Largest k such that 2^k - 1 <= 10 is k=3 (2^3 - 1 = 7).
    // Add 3 copies of `current_val` (e.g., 1). `result_array = [1, 1, 1]`. `X = 10 - 7 = 3`.
    // `current_val` becomes `1 + 5 + 1 = 7`.
    // Largest k such that 2^k - 1 <= 3 is k=2 (2^2 - 1 = 3).
    // Add 2 copies of `current_val` (e.g., 7). `result_array = [1, 1, 1, 7, 7]`. `X = 3 - 3 = 0`.
    // `current_val` becomes `7 + 5 + 1 = 13`.
    // X is 0, stop.
    // Final array: `[1, 1, 1, 7, 7]`. Size 5.
    //
    // Let's check the example `X=10, d=5`. Output: `6 \n 5 50 7 15 6 100`.
    // This output has distinct numbers.
    // The problem statement says "removed all the subsequences in which Maximum_element_of_the_subsequence - Minimum_element_of_subsequence >= d".
    // This means only subsequences where `max - min < d` remain.
    //
    // If we have an array `[a_1, a_2, ..., a_n]` where all `a_i` are distinct and `a_i+1 - a_i >= d`.
    // Then only single-element subsequences `[a_i]` satisfy `max - min < d`.
    // The count would be `n`.
    // So if `X` is small, we can just output `X` distinct numbers.
    // For `X=10, d=5`, `[1, 10, 20, 30, 40, 50, 60, 70, 80, 90]` would work.
    //
    // The example output `[5, 50, 7, 15, 6, 100]` for `X=10, d=5`.
    // Let's sort it: `[5, 6, 7, 15, 50, 100]`.
    // Valid subsequences:
    // `[5]`
    // `[6]`
    // `[7]`
    // `[15]`
    // `[50]`
    // `[100]`
    // `[5, 6]` (max-min=1 < 5)
    // `[5, 7]` (max-min=2 < 5)
    // `[6, 7]` (max-min=1 < 5)
    // `[5, 6, 7]` (max-min=2 < 5)
    // Total 10.
    //
    // This means we need to group numbers such that `max - min < d` within a group,
    // and `max_group1 - min_group2 >= d` if group1 and group2 are different.
    //
    // Let's use the strategy of creating blocks of identical numbers.
    // If we have `k` identical numbers, say `[A, A, ..., A]`, this block contributes `2^k - 1` valid subsequences.
    // If we then add a number `B` such that `B - A >= d`, then `B` starts a new block.
    // The total count `X` is the sum of `(2^k - 1)` for each block.
    //
    // We need to decompose `X` into a sum of `(2^k - 1)` terms.
    // `X = (2^k1 - 1) + (2^k2 - 1) + ... + (2^kN - 1)`
    // This is equivalent to `X + N = 2^k1 + 2^k2 + ... + 2^kN`.
    //
    // Let's try to find the binary representation of `X + N`.
    // No, this is not `X+N`.
    //
    // Consider `X`. We want to find `k_i` such that `X = sum(2^k_i - 1)`.
    // This is equivalent to finding `k_i` such that `X + count_of_blocks = sum(2^k_i)`.
    //
    // Let's try a greedy approach:
    // Start with `current_val = 1`.
    // While `X > 0`:
    //   Find the largest `k` such that `2^k - 1 <= X`.
    //   If no such `k` exists (i.e., `X < 1`), we are done.
    //   Add `k` copies of `current_val` to `result_array`.
    //   Subtract `2^k - 1` from `X`.
    //   Update `current_val = current_val + d + 1`.
    //
    // Let's trace `X=10, d=5`:
    // 1. `X=10`. Largest `k` such that `2^k - 1 <= 10` is `k=3` (`2^3 - 1 = 7`).
    //    Add 3 copies of `1`. `result_array = [1, 1, 1]`.
    //    `X = 10 - 7 = 3`.
    //    `current_val = 1 + 5 + 1 = 7`.
    // 2. `X=3`. Largest `k` such that `2^k - 1 <= 3` is `k=2` (`2^2 - 1 = 3`).
    //    Add 2 copies of `7`. `result_array = [1, 1, 1, 7, 7]`.
    //    `X = 3 - 3 = 0`.
    //    `current_val = 7 + 5 + 1 = 13`.
    // 3. `X=0`. Stop.
    //
    // Final array: `[1, 1, 1, 7, 7]`. Size 5.
    // This array has `max_n = 10^4` elements.
    // The maximum value of `X` is `10^9`.
    // The maximum `k` for `2^k - 1 <= 10^9` is `k=29` (`2^29 - 1` is approx `5 * 10^8`).
    // `2^30 - 1` is approx `10^9`.
    // So `k` can be up to 30.
    //
    // How many blocks can there be?
    // If `X = 10^9`, and we always pick `k=1` (`2^1 - 1 = 1`), then we would have `10^9` blocks.
    // This would mean `10^9` elements, which is too many.
    //
    // We need to ensure `n <= 10^4`.
    // The number of elements `n = sum(k_i)`.
    // The number of blocks `N`.
    //
    // The greedy strategy of picking the largest `k` for `2^k - 1 <= X` is essentially finding the "binary representation" of `X` in terms of `(2^k - 1)`.
    // This is not standard binary representation.
    //
    // Let's consider the binary representation of `X`.
    // `X = sum(b_i * 2^i)`.
    // If `X = 10 = 1010_2`.
    // `10 = 8 + 2`.
    // If we have `k` elements, they contribute `2^k - 1` subsequences.
    //
    // Let's try to represent `X` as `sum_{i=1 to N} (2^{k_i} - 1)`.
    // This is equivalent to `X + N = sum_{i=1 to N} 2^{k_i}`.
    //
    // Consider the binary representation of `X`.
    // `X = (b_m b_{m-1} ... b_1 b_0)_2`.
    // If `b_i = 1`, it means `2^i` is part of `X`.
    //
    // Let's try a different approach.
    // We want to construct an array `a` such that `X` subsequences satisfy the condition.
    //
    // If we have `k` identical numbers `A, A, ..., A`, they contribute `2^k - 1` subsequences.
    // If we have `k` numbers `A, A+1, ..., A+k-1` where `k-1 < d`, they contribute `2^k - 1` subsequences.
    //
    // The problem statement implies that the elements in the array can be arbitrary.
    // The example `[5, 50, 7, 15, 6, 100]` for `X=10, d=5` is interesting.
    // Sorted: `[5, 6, 7, 15, 50, 100]`.
    // Group 1: `[5, 6, 7]`. Max-min = 2 < 5. This group contributes `2^3 - 1 = 7` subsequences.
    // Group 2: `[15]`. Max-min = 0 < 5. This group contributes `2^1 - 1 = 1` subsequence.
    // Group 3: `[50]`. Max-min = 0 < 5. This group contributes `2^1 - 1 = 1` subsequence.
    // Group 4: `[100]`. Max-min = 0 < 5. This group contributes `2^1 - 1 = 1` subsequence.
    // Total = `7 + 1 + 1 + 1 = 10`.
    //
    // This means we can form "groups" of numbers.
    // Each group `G_j = [g_{j,1}, g_{j,2}, ..., g_{j,k_j}]` must satisfy `max(G_j) - min(G_j) < d`.
    // And for any two numbers `x` from `G_j` and `y` from `G_p` where `j != p`, we must have `|x - y| >= d`.
    //
    // If we construct such groups, then any valid subsequence must be entirely contained within one group.
    // If a subsequence contains elements from two different groups, say `x` from `G_j` and `y` from `G_p`,
    // then `max(s) - min(s) >= |x - y| >= d`, making it invalid.
    //
    // So, the total number of valid subsequences `X` is the sum of `(2^{k_j} - 1)` for each group `G_j`.
    // Here `k_j` is the size of group `G_j`.
    //
    // This is exactly the decomposition `X = sum(2^k - 1)`.
    //
    // Let's use the greedy strategy:
    // `current_val = 1`.
    // While `X > 0`:
    //   Find largest `k` such that `2^k - 1 <= X`.
    //   If `k=0` (i.e., `2^0 - 1 = 0`), this means `X` is 0, so we stop.
    //   Add `k` elements to `result_array`. These elements will be `current_val, current_val+1, ..., current_val+k-1`.
    //   This ensures `max - min = (current_val+k-1) - current_val = k-1`.
    //   We need `k-1 < d`. So `k < d+1`.
    //   If `k` is chosen such that `k >= d+1`, then `max - min >= d`, and this group would not contribute `2^k - 1` valid subsequences.
    //   It would contribute fewer.
    //
    // So, the `k` we choose must also satisfy `k-1 < d`.
    // This means `k <= d`.
    //
    // So, the strategy is:
    // `current_val = 1`.
    // While `X > 0`:
    //   Find largest `k` such that `2^k - 1 <= X` AND `k <= d`.
    //   If no such `k` exists (e.g., `X=0` or `X` is too small for any `k>=1` and `k<=d`), then something is wrong or `X` is 0.
    //   For `k=1`, `2^1 - 1 = 1`. So if `X >= 1`, we can always pick `k=1` (assuming `d >= 1`).
    //   Add `k` elements: `current_val, current_val+1, ..., current_val+k-1` to `result_array`.
    //   `X = X - (2^k - 1)`.
    //   `current_val = current_val + d + 1`. (This ensures the next group is far enough).
    //
    // Let's trace `X=10, d=5`:
    // 1. `X=10, current_val=1`.
    //    Largest `k` such that `2^k - 1 <= 10` AND `k <= 5`.
    //    `k=1: 2^1-1=1 <= 10, 1 <= 5` (valid)
    //    `k=2: 2^2-1=3 <= 10, 2 <= 5` (valid)
    //    `k=3: 2^3-1=7 <= 10, 3 <= 5` (valid)
    //    `k=4: 2^4-1=15 > 10` (invalid)
    //    So, `k=3`.
    //    Add `1, 2, 3` to `result_array`. `result_array = [1, 2, 3]`.
    //    `X = 10 - 7 = 3`.
    //    `current_val = 1 + 5 + 1 = 7`.
    // 2. `X=3, current_val=7`.
    //    Largest `k` such that `2^k - 1 <= 3` AND `k <= 5`.
    //    `k=1: 2^1-1=1 <= 3, 1 <= 5` (valid)
    //    `k=2: 2^2-1=3 <= 3, 2 <= 5` (valid)
    //    `k=3: 2^3-1=7 > 3` (invalid)
    //    So, `k=2`.
    //    Add `7, 8` to `result_array`. `result_array = [1, 2, 3, 7, 8]`.
    //    `X = 3 - 3 = 0`.
    //    `current_val = 7 + 5 + 1 = 13`.
    // 3. `X=0`. Stop.
    //
    // Final array: `[1, 2, 3, 7, 8]`. Size 5.
    // This is a valid array. The example output is different but also valid.
    // This strategy seems robust.

    // Max array size check:
    // `n = sum(k_i)`.
    // Smallest `k` we can pick is `k=1`.
    // If `d=1`, then `k` can only be `1`.
    // `X = sum(2^1 - 1) = sum(1) = N`. So `n = N = X`.
    // If `X = 10^9`, then `n = 10^9`, which is too large (`10^4`).
    //
    // This means the strategy of `k <= d` is problematic if `d` is small.
    // If `d=1`, then `k` must be `1`.
    // `X = 10^9, d=1`.
    // `k=1` is the only choice. `2^1 - 1 = 1`.
    // We add `1` element, `X` decreases by `1`.
    // This will add `X` elements to the array. `n = X`.
    // If `X > 10^4`, this strategy fails.
    //
    // The problem states `1 <= X, d <= 10^9`.
    // If `X > 10^4` and `d=1`, then `n` will be `X`, which is too large.
    // In this case, no answer is possible.
    //
    // What if `d` is large? Say `d = 10^9`.
    // Then `k` can be up to `30` (since `2^30 - 1` is approx `10^9`).
    // If `X = 10^9`, we pick `k=30`. `n=30`. This is fine.
    //
    // The constraint `n <= 10^4` is critical.
    // The total number of elements added is `sum(k_i)`.
    // We are decomposing `X` into `sum(2^k_i - 1)`.
    //
    // Let `X_rem = X`.
    // `n_total = 0`.
    // `current_val = 1`.
    // While `X_rem > 0`:
    //   Find largest `k` such that `(1LL << k) - 1 <= X_rem`.
    //   If `k > d`, we must cap `k` at `d`.
    //   So, `k_actual = min(k_found, d)`.
    //   If `k_actual == 0`, this means `d=0` (not possible as `d>=1`) or `X_rem=0`.
    //   If `k_actual == 0` and `X_rem > 0`, it means `d=0` or `X_rem` is too small for `k=1`.
    //   Since `d >= 1`, `k_actual` will be at least `1` if `X_rem >= 1`.
    //   So, `k_actual` will be at least `1`.
    //
    //   Add `k_actual` elements. `n_total += k_actual`.
    //   If `n_total > 10000`, then no solution. Print -1.
    //
    //   For `j` from `0` to `k_actual - 1`:
    //     Add `current_val + j` to `result_array`.
    //   `X_rem -= ((1LL << k_actual) - 1)`.
    //   `current_val += (d + 1)`.
    //
    // Let's re-trace `X=10, d=5`:
    // 1. `X_rem=10, current_val=1, n_total=0`.
    //    Largest `k` such that `(1LL << k) - 1 <= 10` is `k=3`.
    //    `k_actual = min(3, d=5) = 3`.
    //    `n_total = 0 + 3 = 3`. (`3 <= 10000`, OK).
    //    Add `1, 2, 3`. `result_array = [1, 2, 3]`.
    //    `X_rem = 10 - ((1LL << 3) - 1) = 10 - 7 = 3`.
    //    `current_val = 1 + (5 + 1) = 7`.
    // 2. `X_rem=3, current_val=7, n_total=3`.
    //    Largest `k` such that `(1LL << k) - 1 <= 3` is `k=2`.
    //    `k_actual = min(2, d=5) = 2`.
    //    `n_total = 3 + 2 = 5`. (`5 <= 10000`, OK).
    //    Add `7, 8`. `result_array = [1, 2, 3, 7, 8]`.
    //    `X_rem = 3 - ((1LL << 2) - 1) = 3 - 3 = 0`.
    //    `current_val = 7 + (5 + 1) = 13`.
    // 3. `X_rem=0`. Stop.
    //
    // This seems correct and handles the `k <= d` constraint.
    //
    // What about the `n <= 10^4` constraint?
    // The maximum value of `k` is `d`.
    // The maximum value of `k` is also `~60` (for `2^60 - 1` to fit in `long long`).
    // So `k_actual = min(k_found, d, 60)`.
    //
    // Let's consider the worst case for `n_total`.
    // `X = 10^9`.
    // If `d` is very small, say `d=1`.
    // Then `k_actual` will always be `1`.
    // `X_rem` decreases by `1` in each step.
    // `n_total` increases by `1` in each step.
    // So `n_total` will reach `X`. If `X > 10^4`, it will exceed the limit.
    //
    // So, if `d=1` and `X > 10000`, output -1.
    // More generally, if `X` is large, and `d` is small, we might exceed `10000`.
    //
    // The number of elements added in one step is `k_actual`.
    // The number of subsequences accounted for is `(1LL << k_actual) - 1`.
    //
    // We need `sum(k_actual_i) <= 10000`.
    //
    // Let's analyze the loop:
    // `k_actual` is `min(k_found, d)`.
    // `k_found` is `floor(log2(X_rem + 1))`.
    //
    // If `d` is small, say `d=1`. Then `k_actual` is always `1`.
    // `X_rem` decreases by `1`. `n_total` increases by `1`.
    // If `X > 10000`, `n_total` will exceed `10000`.
    //
    // If `d` is large, say `d=10^9`. Then `k_actual` is `k_found`.
    // `k_found` is at most `~60`.
    // `X_rem` decreases by `(1LL << k_found) - 1`.
    // `n_total` increases by `k_found`.
    // The maximum `k_found` is `~30` for `X=10^9`.
    // If `X = 10^9`, `k_found = 30`. `n_total = 30`.
    // `X_rem = 10^9 - (2^30 - 1)`.
    // Next `k_found` will be smaller.
    // The sum of `k_found` values will be small.
    // For example, `X = 2^30 - 1`. `n_total = 30`.
    // `X = (2^30 - 1) + (2^29 - 1) + ... + (2^1 - 1)`.
    // This is `X = sum_{i=1 to 30} (2^i - 1)`.
    // `n_total = sum_{i=1 to 30} i = 30 * 31 / 2 = 465`. This is well within `10^4`.
    //
    // The problem arises when `d` is small, forcing `k_actual` to be small, even if `X_rem` is large.
    //
    // Example: `X = 100000, d = 2`.
    // `k_actual = min(k_found, 2)`.
    // `k_found` can be up to `~16` for `X=100000`.
    // But `k_actual` will be capped at `2`.
    // So in each step, `k_actual = 2`.
    // `X_rem` decreases by `(2^2 - 1) = 3`.
    // `n_total` increases by `2`.
    // Number of steps = `X / 3 = 100000 / 3 = 33333`.
    // `n_total = 2 * 33333 = 66666`. This is `> 10000`.
    // So, for `X=100000, d=2`, it should output -1.
    //
    // The condition for outputting -1:
    // If `X` is large, and `d` is small, the number of elements `n` can exceed `10^4`.
    // The minimum number of elements to represent `X` is when `k` is maximized in each step.
    // This happens when `d` is large enough not to cap `k`.
    // The maximum `k` is `~30` for `X=10^9`.
    // The minimum `n` is `~30` (if `X` is a power of 2 minus 1).
    // The maximum `n` is `~465` (if `X` is `sum(2^i - 1)` for `i=1..30`).
    //
    // The maximum number of elements `n` is `10^4`.
    // In each step, we add `k_actual` elements and reduce `X` by `(2^k_actual - 1)`.
    // The ratio `k_actual / (2^k_actual - 1)` is minimized when `k_actual` is small.
    // For `k_actual = 1`, ratio is `1/1 = 1`.
    // For `k_actual = 2`, ratio is `2/3`.
    // For `k_actual = 3`, ratio is `3/7`.
    // For `k_actual = 4`, ratio is `4/15`.
    // The ratio `k / (2^k - 1)` decreases as `k` increases.
    //
    // So, if `d` is small, `k_actual` will be small.
    // The worst case for `n_total` is when `k_actual` is always `1`.
    // This happens when `d=1`. Then `n_total = X`.
    // So if `d=1` and `X > 10000`, output -1.
    //
    // What if `d=2`? `k_actual` is at most `2`.
    // `X_rem` decreases by at least `(2^1 - 1) = 1`.
    // `X_rem` decreases by at most `(2^2 - 1) = 3`.
    // `n_total` increases by at least `1`.
    // `n_total` increases by at most `2`.
    //
    // If `k_actual` is always `2`, then `n_total` is `2 * (X / 3)`.
    // If `2 * X / 3 > 10000`, then output -1.
    // `X > 15000`.
    //
    // Let's refine the check for `n > 10000`.
    // We can simply check `result_array.size()` at the end.
    // Or, check `n_total` inside the loop.
    //
    // `current_val` can grow large. `1 + (10^4) * (10^9 + 1)`. This exceeds `10^18`.
    // `current_val` is `1 + N * (d+1)`.
    // `N` is the number of blocks.
    // Max `N` is `X` (when `k_actual=1` always).
    // If `X=10^4`, `d=1`. `N=10^4`. `current_val = 1 + 10^4 * 2 = 20001`. This is fine.
    // If `X=10^9`, `d=1`. This case is already handled by `n > 10^4`.
    //

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, 0); // Initial array values, to be determined
    std::vector<long long> current_a(n); // Array state after applying operations

    // Initialize b with a very large value for type 2 operations
    // This is because for a type 2 operation (l, r, m), we know that
    // b[j] + sum_d_j <= m for all j in [l, r].
    // So, b[j] <= m - sum_d_j. We want to find the largest possible b[j]
    // that satisfies all constraints.
    // For type 2 operations, we can set an upper bound for b[j].
    // For type 1 operations, they don't directly constrain b[j] but affect sum_d_j.
    // We initialize b[j] to a large value and then reduce it based on type 2 constraints.
    for (int i = 0; i < n; ++i) {
        b[i] = 1000000000LL; // Max allowed initial value is 10^9
    }

    // Iterate through operations in reverse to determine upper bounds for b[j]
    // When processing in reverse, 'sum_d_j' represents the sum of 'd' values
    // from operations *after* the current one in the original sequence.
    // This is because if we are at operation k (original index), and we are
    // calculating b[j], then b[j] + (sum of d's from ops 0 to k-1) + (sum of d's from ops k to m-1)
    // is the value of a[j] at the end.
    // If we want to find b[j] such that b[j] + (sum of d's from ops 0 to k-1) <= m_k,
    // then b[j] <= m_k - (sum of d's from ops 0 to k-1).
    // This is equivalent to:
    // b[j] + (sum of d's from ops 0 to m-1) - (sum of d's from ops k to m-1) <= m_k
    // Let S_total[j] be the total sum of d's affecting j over all operations.
    // Let S_suffix[j][k] be the sum of d's affecting j from operations k to m-1.
    // Then, at operation k, the value of a[j] is b[j] + S_total[j] - S_suffix[j][k].
    // So, for a type 2 operation (l, r, m_k) at index k:
    // b[j] + S_total[j] - S_suffix[j][k] <= m_k for j in [l, r].
    // b[j] <= m_k - S_total[j] + S_suffix[j][k].
    //
    // A simpler approach:
    // Let `delta[j]` be the total sum of `d` values applied to `a[j]` up to the current point in the reverse iteration.
    // When we process an operation `k` (from `m-1` down to `0`):
    // If `ops[k]` is type 1 (`l, r, d`):
    //   This `d` value was applied *before* this point in the original sequence.
    //   So, it contributes to the `delta` for elements `j` in `[l, r]`.
    //   We add `d` to `delta[j]` for `j` in `[l, r]`.
    // If `ops[k]` is type 2 (`l, r, m`):
    //   For all `j` in `[l, r]`, we know that `b[j] + delta[j]` must be less than or equal to `m`.
    //   So, `b[j] <= m - delta[j]`. We update `b[j] = min(b[j], m - delta[j])`.
    // This `delta[j]` accumulates the `d` values from operations `k` to `m-1`.
    // This is not quite right. `delta[j]` should be the sum of `d` values from operations *before* `k` in the original sequence.
    //
    // Let's redefine `b[i]` as the initial value.
    // Let `diff[i]` be the total sum of `d` values applied to `a[i]` by all type 1 operations.
    // `a[i]` at the end of all operations is `b[i] + diff[i]`.
    //
    // The problem is that `m_i` is the maximum *at the time of the query*.
    // So, `m_i = max_{j=l_i}^{r_i} (b[j] + sum_of_d_up_to_op_i_for_j)`.
    //
    // Let `initial_a[j]` be the value we are trying to find.
    // Let `current_add[j]` be the sum of `d` values applied to `j` so far.
    //
    // For type 2 operations, `m_i = max_{j=l_i}^{r_i} (initial_a[j] + current_add[j])`.
    // This implies `initial_a[j] + current_add[j] <= m_i` for all `j` in `[l_i, r_i]`.
    // So, `initial_a[j] <= m_i - current_add[j]`.
    //
    // We can iterate operations in reverse.
    // Let `max_val_at_end[j]` be the maximum possible value for `initial_a[j]` such that all type 2 constraints are met.
    // Initialize `max_val_at_end[j] = 10^9` for all `j`.
    //
    // `current_d_sum[j]` will store the sum of `d` values from operations *after* the current one (in original order).
    // When processing `ops[k]` from `m-1` down to `0`:
    // If `ops[k]` is type 1 (`l, r, d`):
    //   This `d` value will be applied. It affects `initial_a[j]` for `j` in `[l, r]` by adding `d`.
    //   So, for `j` in `[l, r]`, `initial_a[j]` effectively needs to be `initial_a[j] - d` to achieve the same final value.
    //   This means `max_val_at_end[j]` should be reduced by `d`.
    //   `max_val_at_end[j] -= d`.
    // If `ops[k]` is type 2 (`l, r, m`):
    //   For all `j` in `[l, r]`, we know that `initial_a[j]` (after all subsequent `d`s are applied) must be `<= m`.
    //   So, `max_val_at_end[j] = min(max_val_at_end[j], m)`.
    //
    // This logic is for finding `initial_a[j]` such that `initial_a[j] + (sum of all d's affecting j) <= m_k`.
    // This is not quite right. The `m_k` is for `a[j]` at operation `k`.
    //
    // Let's use the `b[i]` array to store the initial values we are trying to find.
    // Initialize `b[i]` to a large value (e.g., 10^9).
    // We also need an array `delta[i]` to store the sum of `d` values that have been applied to `a[i]` *after* the current operation in the reverse pass.
    //
    // `delta` array for range updates:
    // `delta_diff[i]` stores `delta[i] - delta[i-1]`.
    // When we add `d` to `delta[j]` for `j` in `[l, r]`:
    // `delta_diff[l] += d`
    // `delta_diff[r+1] -= d`
    //
    // Iterate `k` from `m-1` down to `0`:
    //   If `ops[k]` is type 1 (`l, r, d`):
    //     `delta_diff[l] += d`
    //     `delta_diff[r+1] -= d`
    //   If `ops[k]` is type 2 (`l, r, m`):
    //     Calculate `current_delta[j]` for `j` in `[l, r]` using `delta_diff`.
    //     `current_delta[j] = sum_{p=0 to j} delta_diff[p]`.
    //     For each `j` in `[l, r]`:
    //       `b[j] = min(b[j], m - current_delta[j])`.
    //
    // This approach requires calculating `current_delta[j]` for ranges, which is slow if done naively.
    // We can use a segment tree or Fenwick tree for `delta_diff` to query `current_delta[j]` efficiently.
    // Or, since `n` is up to 5000, we can afford `O(N)` for each type 2 operation to calculate `current_delta[j]` for the range.
    //
    // Let's refine the reverse pass:
    // `b[i]` stores the initial value. Initialize `b[i] = 10^9`.
    // `current_d_effect[i]` stores the sum of `d` values from operations *after* the current one (in original order) that affect index `i`.
    //
    // `current_d_effect` can be maintained using a difference array.
    // `diff_array[i]` stores `current_d_effect[i] - current_d_effect[i-1]`.
    //
    // For `k` from `m-1` down to `0`:
    //   If `ops[k]` is type 1 (`l, r, d`):
    //     `diff_array[l] += d`
    //     `diff_array[r+1] -= d` (if `r+1 < n`)
    //   If `ops[k]` is type 2 (`l, r, m`):
    //     `current_sum_d = 0`
    //     For `j` from `0` to `n-1`:
    //       `current_sum_d += diff_array[j]`
    //       If `j` is in `[l, r]`:
    //         `b[j] = std::min(b[j], ops[k].val - current_sum_d)`
    //
    // This is `O(M * N)` for the reverse pass, which is `5000 * 5000 = 2.5 * 10^7`, potentially too slow.
    // We need to optimize the type 2 operation in the reverse pass.
    //
    // The `current_sum_d` is effectively `delta[j]` from the previous thought.
    // For a type 2 operation `(l, r, m)` at index `k` (original order):
    // We need `b[j] + (sum of d's from ops 0 to k-1 affecting j) <= m` for `j` in `[l, r]`.
    //
    // Let `initial_a[j]` be the value we are solving for.
    // Let `total_d_applied[j]` be the sum of all `d` values from type 1 operations that affect `j`.
    //
    // The final value of `a[j]` is `initial_a[j] + total_d_applied[j]`.
    //
    // Let's try a different perspective.
    // For each `j`, `initial_a[j]` must satisfy:
    // 1. `|initial_a[j]| <= 10^9`
    // 2. For every type 2 operation `(l_i, r_i, m_i)`:
    //    `initial_a[j] + (sum of d's from ops 0 to i-1 affecting j) <= m_i` for all `j` in `[l_i, r_i]`.
    //    And `max_{j=l_i}^{r_i} (initial_a[j] + (sum of d's from ops 0 to i-1 affecting j)) == m_i`.
    //
    // The first part (`<= m_i`) gives an upper bound for `initial_a[j]`.
    // Let `S_i[j]` be the sum of `d` values from operations `0` to `i-1` that affect `j`.
    // Then `initial_a[j] <= m_i - S_i[j]` for `j` in `[l_i, r_i]`.
    // So, `initial_a[j] <= min(10^9, min_{all type 2 ops (l_k, r_k, m_k) where j in [l_k, r_k]} (m_k - S_k[j]))`.
    // Let `b[j]` be this calculated upper bound for `initial_a[j]`.
    //
    // How to calculate `S_k[j]` efficiently for all `k` and `j`?
    // We can precompute `S_k[j]` for all `k` and `j`.
    // `S_0[j] = 0`.
    // For `k` from `0` to `m-1`:
    //   `S_{k+1}[j] = S_k[j]` for all `j`.
    //   If `ops[k]` is type 1 (`l, r, d`):
    //     For `j` in `[l, r]`, `S_{k+1}[j] += d`.
    // This is `O(M * N)` to precompute all `S_k[j]`.
    // Then, for each `j`, iterate through all type 2 operations to find `b[j]`. This is `O(N * M)`.
    // Total `O(M * N)`. This should be acceptable. `5000 * 5000 = 2.5 * 10^7`.

    std::vector<std::vector<long long>> S(m + 1, std::vector<long long>(n, 0));

    for (int k = 0; k < m; ++k) {
        for (int j = 0; j < n; ++j) {
            S[k+1][j] = S[k][j];
        }
        if (ops[k].type == 1) {
            for (int j = ops[k].l; j <= ops[k].r; ++j) {
                S[k+1][j] += ops[k].val;
            }
        }
    }

    // Initialize b[j] with the maximum allowed value
    for (int j = 0; j < n; ++j) {
        b[j] = 1000000000LL;
