                    last1 = current_digit; // last1 becomes k
                } else { // Must be color 2
                    // current_digit (k) < last1. So it cannot be color 1.
                    // It must be color 2.
                    // Check if it maintains non-decreasing property for S2.
                    // current_digit (k) must be >= last2.
                    // last2 is initialized to k, and only increases. So k >= last2 is always true here.
                    result[i] = '2';
                    last2 = current_digit; // last2 becomes k
                }
            }
        }

        if (possible_k) {
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

