int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To form "one", we need 'o', 'n', 'e'.
    // The number of '1's is limited by the minimum of these counts.
    // However, 'o' and 'e' are also used by "zero".
    // The problem guarantees that it's possible to form a sequence of "one"s and "zero"s.
    // To maximize the number, we want to prioritize '1's.
    // Each '1' uses one 'n', one 'o', one 'e'.
    // Each '0' uses one 'z', one 'e', one 'r', one 'o'.

    // The number of 'n's directly tells us how many "one"s we can form,
    // as 'n' is unique to "one".
    int num_ones = count_n;

    // The number of 'z's directly tells us how many "zero"s we can form,
    // as 'z' is unique to "zero".
    int num_zeros = count_z;

    // The total count of 'e's and 'o's must be sufficient for both.
    // The problem guarantees this is possible.
    // So, we just need to count the unique letters.

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

