        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // Each coal costs y sticks. So, k coal costs k * y sticks.
        // Total sticks required for crafting and buying coal: k * y + k.
        // We start with 1 stick.
        // So, we need to acquire (k * y + k) - 1 additional sticks.
        // Let's call this amount 'sticks_to_generate'.
        long long sticks_to_generate = k * y + k - 1;

        // Each trade of type 1 (1 stick -> x sticks) effectively gives us x - 1 net sticks.
        // We need to find how many such trades are needed to get 'sticks_to_generate'.
        // Number of stick trades = ceil(sticks_to_generate / (x - 1))
        // Using integer division: (A + B - 1) / B for ceil(A / B)
        long long num_stick_trades = (sticks_to_generate + (x - 1) - 1) / (x - 1);

        // Number of coal trades is simply k, as each coal requires 1 trade.
        long long num_coal_trades = k;

        // Total trades = num_stick_trades + num_coal_trades
        long long total_trades = num_stick_trades + num_coal_trades;

        std::cout << total_trades << "\n";
    }
    return 0;
}

