    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only numbers up to 2048 are useful for forming 2048
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the contribution of 'val' to the current_sum.
        // Each 'val' contributes 'val * count' to the total sum,
        // but we only care about the sum up to 2048.
        // If current_sum already exceeds 2048, further additions won't change the outcome
        // for reaching exactly 2048.
        if (current_sum < 2048) {
            current_sum += val * count;
        }
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

