    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point (cell 0)

        // Iterate through the string s (cells 1 to n)
        for (int i = 0; i < s.length(); ++i) {
            // If s[i] is 'R', it means the frog can jump to the right from cell i+1.
            // The current cell is i+1 (1-indexed).
            // The previous 'R' or start was at last_R_pos.
            // The distance needed to jump from last_R_pos to i+1 is (i+1) - last_R_pos.
            // We need to find the maximum such distance.
            if (s[i] == 'R') {
                max_dist = std::max(max_dist, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current cell (i+1)
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R'
        // (or cell 0 if no 'R's) to the target cell n+1.
        // The distance from last_R_pos to n+1 is (s.length() + 1) - last_R_pos.
        max_dist = std::max(max_dist, (static_cast<int>(s.length()) + 1) - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and all other elements are smaller.
    // If so, it means the actual value for that p[i] should be n.
    // This happens if p[i] is the largest element in the permutation.
    bool n_found = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n - 1) {
            bool is_largest_candidate = true;
            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                if (p[j] > n - 1) { // If some other p[j] is already n, then this p[i] cannot be n.
                    is_largest_candidate = false;
                    break;
                }
            }
            if (is_largest_candidate) {
                p[i] = n;
                n_found = true;
                break; // Only one element can be n
            }
        }
    }

    // If no element was found to be n-1 and promoted to n, it means n was never
    // the maximum in any row (i.e., it was never p[i] for any i).
    // This implies that the actual maximum value n was never present in the 'a' matrix
    // as a min(p_i, p_j) value. This can only happen if n was the value of p_i
    // for some i, and all other p_j were smaller than n.
    // In this case, max_val_in_row for that i would be n-1.
    // The logic above should have caught this.
    // However, if all p[i] are distinct and range from 1 to n-1,
    // it means the value 'n' is missing.
    // This scenario implies that the element 'n' was never the maximum of any pair,
    // which is impossible if 'n' is part of the permutation.
    // The only way 'n' is not found is if the max_val_in_row for the element 'n'
    // was already 'n'. But this would mean that 'n' was not the largest element.
    // The problem guarantees a solution exists.
    // The logic `p[i] = max_val_in_row` correctly identifies `p[i]` unless `p[i]` is `n`.
    // If `p[i] = n`, then `max_val_in_row` for that `i` will be `n-1`.
    // So, if `n_found` is false after the loop, it means no `p[i]` was `n-1`.
    // This implies that all `p[i]` were already correctly determined as `max_val_in_row`.
    // But then the set of values in `p` would be `{1, ..., n-1}`.
    // This means `n` is missing.
    // This can only happen if `n` was the value of some `p[k]`, and for all `j != k`,
    // `min(p[k], p[j]) = p[j]`. So `max(a[k][j] for j != k)` would be `n-1`.
    // This `p[k]` would be set to `n-1` initially.
    // The `n_found` logic should always find it.
    // If `n_found` is still false, it means `n` was not assigned.
    // This implies that all `p[i]` are less than `n`.
    // This can only happen if `n` was not in the permutation, which contradicts the problem.
    // The only remaining case is if all `p[i]` are already `n` (e.g., `n=1`, but `n>=2`).
    // Or if `n` is the value of some `p[k]`, and `max_val_in_row` for `k` was `n-1`.
    // If `n_found` is false, it means that no `p[i]` was `n-1`.
    // This implies that all `p[i]` are either `< n-1` or `== n`.
    // If all `p[i]` are `< n-1`, then `n` is missing.
    // If some `p[i]` is `n`, then `n_found` would be true.
    // The only way `n_found` is false is if all `p[i]` are already correct and `n` is not present.
    // This means the set of values in `p` is `{1, ..., n-1}`.
