            // The `used_numbers` set already tracks what's used.
            // We need to find the largest `x` in `[1, q[i]-1]` that is NOT in `used_numbers`.
            int candidate_p_i = -1;
            for (int k = q[i] - 1; k >= 1; --k) {
                if (!used_numbers.count(k)) {
