#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right ends of the range [1, k+1]
    // Example: k=4. Range [1,5].
    // 1st diff: 5-1=4. Sequence: 1, 5
    // 2nd diff: 5-2=3. Sequence: 1, 5, 2
    // 3rd diff: 4-2=2. Sequence: 1, 5, 2, 4
    // 4th diff: 4-3=1. Sequence: 1, 5, 2, 4, 3
    // The numbers used are 1, 2, 3, 4, 5. The differences are 4, 3, 2, 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            p[i] = left;
            left++;
        } else { // Odd index, take from right
            p[i] = right;
            right--;
        }
    }

    // For the remaining n - (k+1) elements, just append them in increasing order
    // starting from the next available number (which is 'left' after the loop)
    // This ensures all subsequent differences are 1, and don't introduce new distinct differences.
    for (int i = k + 1; i < n; ++i) {
        p[i] = left;
        left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    result.reserve(n);

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1, min is 1, max is 1. So m=1 is always beautiful.
        if (m == 1) {
            result += '1';
            continue;
        }

        // For m > 1, we need to expand the segment to include m.
        // The segment must contain 1, and its elements must be 1...m.
        // This means the current segment [p[current_min_idx]...p[current_max_idx]]
        // must be expanded to include m.
        // The new element m must be at pos[m].
        // We update current_min_idx and current_max_idx to cover the range
        // from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx ... current_max_idx]
        // is a permutation of 1...m.
        // This requires two conditions:
        // 1. Its length must be exactly m.
        // 2. It must contain 1 (which it does by construction, as current_min_idx/max_idx
        //    are initialized with pos[1] and then expanded).
        // 3. It must contain m (which it does by construction, as pos[m] is included).
        // If the length is m, and it contains 1 and m, and all numbers are distinct
        // (because p is a permutation), then it must be a permutation of 1...m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

