int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            // Mismatch found at index i
            // Check if there's an adjacent mismatch at i+1 that can be swapped
            if (i + 1 < n && a[i+1] != b[i+1]) {
                // Both a[i] != b[i] and a[i+1] != b[i+1]
                // Check if they are '01' and '10' types respectively, or vice versa
                // i.e., a[i] == b[i+1] and a[i+1] == b[i]
                if (a[i] == b[i+1] && a[i+1] == b[i]) {
                    // Example: a = "01", b = "10"
                    // a[i] = '0', b[i] = '1'
                    // a[i+1] = '1', b[i+1] = '0'
                    // Swapping a[i] and a[i+1] makes a = "10", which matches b.
                    // Cost is |i - (i+1)| = 1.
                    total_cost += 1;
                    // Both positions are now resolved, skip i+1 in the next iteration
                    i++; 
                    continue; // Move to the next i after incrementing
                }
            }
            // If no adjacent swap is possible or beneficial, flip a[i]
            // This covers cases like:
            // - a[i] != b[i] but i+1 is out of bounds
            // - a[i] != b[i] but a[i+1] == b[i+1]
            // - a[i] != b[i] and a[i+1] != b[i+1] but they are of the same type
            //   (e.g., a="00", b="11" -> a[i]='0', b[i]='1' and a[i+1]='0', b[i+1]='1')
            // In all these cases, flipping a[i] is the optimal choice for a[i].
            total_cost += 1;
        }
    }

    std::cout << total_cost << std::endl;

    return 0;
}

