// Function to determine if a box can be the special box
void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    long long total_toys = A + B + C + D;

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
    } else {
        // Possibility for Box 1: (-inf, -1]
        // Final product must be negative and magnitude >= 1
        // For negative: odd number of initial negative toys (A+B)
        // For magnitude >= 1:
        //   Need at least one toy from Box 1 or Box 4 (magnitude >= 1)
        //   OR (A+D) == 0, and (B+C) > 0, and (B+C) >= 2, and (B+C) is even (for magnitude >= 1)
        //   This last condition is impossible for magnitude >= 1.
        //   If all initial toys are from B and C, the product magnitude will always be < 1.
        //   So, we must have at least one toy from A or D.

        // Condition for negative final product: (A + B) % 2 == 1
        // Condition for magnitude >= 1: A + D > 0
        if ((A + B) % 2 == 1 && (A + D > 0)) {
            ans1 = "Ya";
        }

        // Possibility for Box 2: (-1, 0)
        // Final product must be negative and magnitude < 1
        // For negative: odd number of initial negative toys (A+B)
        // For magnitude < 1:
        //   Need at least one toy from Box 2 or Box 3 (magnitude < 1)
        //   OR (A+D) == 0, and (B+C) > 0 (all toys from B and C, product magnitude < 1)
        //   OR (A+D) > 0, and (B+C) > 0, and (A+D) + (B+C) >= 2 (can achieve magnitude < 1)
        //   The only way to guarantee magnitude < 1 is if A+D=0.
        //   If A+D > 0, it's possible to get magnitude < 1 if B+C > 0.
        //   The only case where magnitude < 1 is impossible is if B+C=0 and A+D>0.
        //   So, magnitude < 1 is possible if B+C > 0 OR (A+D > 0 AND B+C > 0).
        //   This simplifies to B+C > 0.

        // Condition for negative final product: (A + B) % 2 == 1
        // Condition for magnitude < 1: B + C > 0
        if ((A + B) % 2 == 1 && (B + C > 0)) {
            ans2 = "Ya";
        }

        // Possibility for Box 3: (0, 1)
        // Final product must be positive and magnitude < 1
        // For positive: even number of initial negative toys (A+B)
        // For magnitude < 1: B + C > 0
        if ((A + B) % 2 == 0 && (B + C > 0)) {
            ans3 = "Ya";
        }

        // Possibility for Box 4: [1, inf)
        // Final product must be positive and magnitude >= 1
        // For positive: even number of initial negative toys (A+B)
        // For magnitude >= 1: A + D > 0
        if ((A + B) % 2 == 0 && (A + D > 0)) {
            ans4 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

