    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Operations for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Operations for elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Operations for elements to the right of the median
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<ElementB> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareElementA);
    std::sort(b_elements.begin(), b_elements.end(), compareElementB);

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (b_elements[i].value) should be paired with
        // the (m-1-i)-th smallest A value (a_elements[m-1-i].value)
        // to maximize F(A', B) = B / (A' + 1) * (A' + 1 - B) / (B + 1)
        // which simplifies to B / (B + 1) * (A' + 1 - B)
        // or more simply, B / (B + 1) * (A' - B + 1)
        // The term (A' - B + 1) needs to be maximized for a given B.
        // So, for the smallest B, we want the largest A'.
        // For the largest B, we want the smallest A'.
        // This means sorting A in descending order and B in ascending order,
        // then pairing them up.
        result_a_prime[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

