// Function to check if a sub-array forms a permutation
// `arr` is the original array, `start_idx` is 0-based start, `len` is length
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem constraints say l1, l2 >= 1
    }
    if (len > arr.size() - start_idx) {
        return false; // Not enough elements
    }

    std::vector<bool> seen(len + 1, false); // To track numbers from 1 to len
    int max_val = 0;

    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len) {
            return false; // Value out of range [1, len]
        }
        if (seen[val]) {
            return false; // Duplicate value
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // After iterating, check if all numbers from 1 to len were seen
    // and if the maximum value is indeed len.
    // The `seen` array check already covers all numbers from 1 to len being present.
    // If max_val is not len, it means some number in [1, len] is missing.
    // Example: [1, 2, 4] for len=3. max_val=4, but len=3.
    // Example: [1, 2] for len=3. max_val=2, but len=3.
    // The `seen` array check `seen[val]` for `val > len` already handles `max_val > len`.
    // The `seen` array check for `val < 1` already handles `min_val < 1`.
    // So, we just need to ensure all `seen[1...len]` are true.
    for (int i = 1; i <= len; ++i) {
        if (!seen[i]) {
            return false;
        }
    }

    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max_prefix[i] = max(a[0]...a[i-1])
    // Precompute max_suffix[i] = max(a[i]...a[n-1])
    std::vector<int> max_prefix(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        max_prefix[i + 1] = std::max(max_prefix[i], a[i]);
    }

    std::vector<int> max_suffix(n + 1, 0);
    for (int i = n - 1; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i + 1], a[i]);
    }

    // Precompute counts for prefix and suffix
    std::vector<int> prefix_counts(n + 1, 0);
    std::vector<int> suffix_counts(n + 1, 0);

    // Check for prefix permutation property
    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool prefix_valid = true;
    for (int l1 = 1; l1 <= n; ++l1) {
        int val = a[l1 - 1];
        if (val < 1 || val > l1 || seen_prefix[val]) {
            prefix_valid = false;
        }
        seen_prefix[val] = true;
        current_max_prefix = std::max(current_max_prefix, val);

        if (prefix_valid && current_max_prefix == l1) {
            is_prefix_perm[l1] = true;
        } else {
            is_prefix_perm[l1] = false;
        }
    }

    // Check for suffix permutation property
    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool suffix_valid = true;
    for (int l2 = 1; l2 <= n; ++l2) {
        int val = a[n - l2];
        if (val < 1 || val > l2 || seen_suffix[val]) {
            suffix_valid = false;
        }
        seen_suffix[val] = true;
        current_max_suffix = std::max(current_max_suffix, val);

        if (suffix_valid && current_max_suffix == l2) {
            is_suffix_perm[l2] = true;
        } else {
            is_suffix_perm[l2] = false;
        }
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

