#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (wins == 0) { // All 'L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 2 * k - 1 << "\n"; // k wins, first is 1, rest k-1 are 2s
            }
            continue;
        }

        // If there are wins, we can only improve by converting L to W.
        // We want to fill gaps between Ws first, then extend from ends.

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // Collect gaps between Ws
        int current_gap = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        if (current_gap > 0) { // Last gap if any
            gaps.push_back(current_gap);
        }
        std::sort(gaps.begin(), gaps.end());

        int current_k = k;
        int score_increase = 0;

        // Fill internal gaps
        for (int gap_len : gaps) {
            if (current_k >= gap_len) {
                current_k -= gap_len;
                score_increase += 2 * gap_len + 1; // Each L becomes W, connects two Ws, adds 2 points per L, plus 1 for connecting
            } else {
                score_increase += 2 * current_k; // Can't connect, just add 2 points for each new W
                current_k = 0;
                break;
            }
        }

        // Extend from ends
        // Left side: from 0 to first_W-1
        int left_L = first_W;
        score_increase += std::min(current_k, left_L) * 2;
        current_k -= std::min(current_k, left_L);

        // Right side: from last_W+1 to n-1
        int right_L = n - 1 - last_W;
        score_increase += std::min(current_k, right_L) * 2;

        std::cout << initial_score + score_increase << "\n";
    }
    return 0;
}

