    while (T--) {
        long long N;
        std::cin >> N;
        long long chanek_score = 0;
        long long opponent_score = 0;
        bool chanek_turn = true;

        while (N > 0) {
            if (N % 2 == 1) { // N is odd
                if (chanek_turn) {
                    chanek_score += 1;
                } else {
                    opponent_score += 1;
                }
                N -= 1;
            } else { // N is even
                if (N == 2) { // Special case for N=2, always take 1
                    if (chanek_turn) {
                        chanek_score += 1;
                    } else {
                        opponent_score += 1;
                    }
                    N -= 1;
                } else if ((N / 2) % 2 == 1) { // N/2 is odd
                    if (chanek_turn) {
                        chanek_score += N / 2;
                    } else {
                        opponent_score += N / 2;
                    }
                    N /= 2;
                } else { // N/2 is even
                    if (chanek_turn) {
                        chanek_score += 1;
                    } else {
                        opponent_score += 1;
                    }
                    N -= 1;
                }
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_score << "\n";
