void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'i' such that a[i] < a[i-1]
    // This 'i' is the start of the potential suffix that is non-increasing.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index 'j' such that a[j] > a[j-1]
    // This 'j' is the start of the potential suffix that is non-decreasing.
    // We are looking for the first element from the right that breaks the non-increasing sequence.
    // So, we want to find the first index 'j' from the right such that a[j] > a[j+1].
    // Or, more simply, find the longest suffix that is non-increasing.
    // Let's rephrase: find the first index 'j' from the right such that a[j] < a[j+1].
    // The elements a[j+1], ..., a[n-1] form a non-increasing sequence.

    // Let's find the rightmost index `p` such that `a[p] < a[p-1]`.
    // The suffix `a[p...n-1]` is non-decreasing.
    // Example: [1, 2, 3, 4] -> p=0
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // n-1=6, a[6]=2
    // i=6: a[5]=5 >= a[6]=2. i=5.
    // i=5: a[4]=4 < a[5]=5. Stop. i=5.
    // So, a[5...6] = [5, 2] is not non-decreasing.
    // The logic for `i` above is correct: `i` is the first index from the left of the suffix `a[i...n-1]` that is non-decreasing.
    // Example: [1, 2, 3, 4] -> i=0
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // i=6 (a[6]=2)
    // i=5 (a[5]=5) a[5] >= a[6] is false (5 >= 2 is true). i becomes 5.
    // i=4 (a[4]=4) a[4] >= a[5] is false (4 >= 5 is false). Loop stops. i is 5.
    // So, a[5...n-1] = [5, 2] is the suffix. This is not non-decreasing.
    // The problem states "non-decreasing array c".
    // The suffix `a[i...n-1]` must be non-decreasing.
    // Let's re-evaluate the `i` definition.
    // `i` should be the first index from the right such that `a[i] < a[i-1]`.
    // If we iterate from `n-1` down to `1`:
    // `i = n-1`. While `i > 0` and `a[i-1] >= a[i]`, decrement `i`.
    // This finds the longest suffix `a[i...n-1]` that is non-decreasing.
    // Example: [1, 2, 3, 4]
    // i=3. a[2]=3 >= a[3]=4 is false. Loop stops. i=3.
    // This is wrong. It should be i=0.
    // The condition for `i` is: `a[i...n-1]` is non-decreasing.
    // So, `i` is the smallest index such that `a[i...n-1]` is non-decreasing.
    // Let's find the largest `k` such that `a[k...n-1]` is non-decreasing.
    // `k = n-1`. While `k > 0` and `a[k-1] <= a[k]`, decrement `k`.
    // Example: [1, 2, 3, 4]
    // k=3. a[2]=3 <= a[3]=4. k=2.
    // k=2. a[1]=2 <= a[2]=3. k=1.
    // k=1. a[0]=1 <= a[1]=2. k=0.
    // k=0. Loop ends. `k=0`. So `a[0...n-1]` is non-decreasing. This is correct.

    // Example: [4, 3, 3, 8, 4, 5, 2]
    // k=6 (a[6]=2)
    // k=5 (a[5]=5). a[5]=5 <= a[6]=2 is false. Loop ends. `k=5`.
    // So, `a[5...n-1]` = `[5, 2]` is the longest non-decreasing suffix. This is wrong.
    // It should be `a[k...n-1]` is non-decreasing.
    // The example says `[4, 5, 2]` is good.
    // `[4, 5, 2]` -> `c=[2, 4, 5]`
    // This means `a[k...n-1]` must be a "good" array.

    // Let's re-read the definition of "good" array.
    // An array `b` is good if you can obtain a non-decreasing array `c` from it
    // by repeatedly taking either the first or the last element of `b`.
    // This implies that the elements of `b` must form a "valley" or "mountain" shape.
    // Specifically, `b` must be representable as `[X_1, X_2, ..., X_k, Y_j, ..., Y_2, Y_1]`
    // where `X_1 <= X_2 <= ... <= X_k` and `Y_1 <= Y_2 <= ... <= Y_j`.
    // And `X_k` and `Y_j` are the largest elements, and `X_1` and `Y_1` are the smallest.
    // The elements are picked from ends.
    // The smallest elements must be at the ends of `b`.
    // The largest elements must be in the middle of `b`.
    // So, `b` must be non-decreasing up to some peak, then non-increasing.
    // OR, non-increasing down to some valley, then non-decreasing.
    // The example `[1, 2, 3, 4, 4, 2, 1]` is good.
    // This is a "mountain" shape: increasing then decreasing.
    // `[4, 5, 2]` is good. This is increasing then decreasing.
    // `[1, 1, 2, 2, 3, 4, 4]` is obtained.
    // The elements picked are `b_0, b_m, b_{m-1}, b_1, b_2, b_{m-2}, b_{m-3}`.
    // This means the elements are picked from the ends, and they must be non-decreasing.
    // So, `min(b_0, b_{m-1})` is picked first.
    // Then `min(b_1, b_{m-2})` is picked (from the remaining array).
    // This implies that the array `b` must be "bitonic" (first increasing, then decreasing)
    // OR "anti-bitonic" (first decreasing, then increasing).
    // No, this is not correct. The example `[1, 2, 3, 4, 4, 2, 1]` is bitonic.
    // The example `[4, 5, 2]` is not bitonic. It's `4, 5` (increasing) then `5, 2` (decreasing).
    // The elements picked are `2, 4, 5`.
    // `b = [4, 5, 2]`
    // Pick `2` (last). `b = [4, 5]`, `c = [2]`
    // Pick `4` (first). `b = [5]`, `c = [2, 4]`
    // Pick `5` (first/last). `b = []`, `c = [2, 4, 5]`
    // This works.

    // The property of a "good" array `b` is that it can be split into two parts:
    // `b = [b_0, ..., b_k, b_{k+1}, ..., b_{m-1}]`
    // such that `b_0 <= b_1 <= ... <= b_k` and `b_{m-1} <= b_{m-2} <= ... <= b_{k+1}`.
    // This means the array `b` must be non-decreasing from left to `k`, and non-decreasing from right to `k+1`.
    // The elements `b_0, ..., b_k` are picked from the left.
    // The elements `b_{m-1}, ..., b_{k+1}` are picked from the right.
    // The elements `c` are formed by picking `min(b_left, b_right)` at each step.
    // This means the array `b` must be "V-shaped" or "U-shaped".
    // `b_0 >= b_1 >= ... >= b_k <= b_{k+1} <= ... <= b_{m-1}`.
    // The smallest element is `b_k`.
    // Example: `[1, 2, 3, 4, 4, 2, 1]`
    // This is not V-shaped. It's `1,2,3,4` then `4,2,1`.
    // The example explanation for `[1, 2, 3, 4, 4, 2, 1]` is:
    // 1. Take first (1). `b=[2,3,4,4,2,1]`, `c=[1]`
    // 2. Take last (1). `b=[2,3,4,4,2]`, `c=[1,1]`
    // 3. Take last (2). `b=[2,3,4,4]`, `c=[1,1,2]`
    // 4. Take first (2). `b=[3,4,4]`, `c=[1,1,2,2]`
    // 5. Take first (3). `b=[4,4]`, `c=[1,1,2,2,3]`
    // 6. Take last (4). `b=[4]`, `c=[1,1,2,2,3,4]`
    // 7. Take first (4). `b=[]`, `c=[1,1,2,2,3,4,4]`
    // This sequence of operations means that the elements are picked in a specific order.
    // The elements picked are `a_0, a_{n-1}, a_{n-2}, a_1, a_2, a_{n-3}, a_{n-4}`.
    // The elements are picked from the ends.
    // The crucial property is that the remaining elements always form a contiguous subarray.
    // Let the current subarray be `a[L...R]`. We pick either `a[L]` or `a[R]`.
    // To form a non-decreasing `c`, we must always pick `min(a[L], a[R])` if `a[L] != a[R]`.
    // If `a[L] == a[R]`, we can pick either.
    // This implies that the array `b` must be "anti-bitonic" (decreasing then increasing).
    // `b_0 >= b_1 >= ... >= b_k <= b_{k+1} <= ... <= b_{m-1}`.
    // The smallest element is `b_k`.
    // Example: `[4, 5, 2]`
    // This is not anti-bitonic. `4 < 5`, then `5 > 2`.
    // The example `[1, 2, 3, 4, 4, 2, 1]` is bitonic.
    // The example `[4, 5, 2]` is not bitonic nor anti-bitonic.

    // Let's reconsider the definition of "good array" from the problem statement.
    // "select either the first or the last element of b, remove it from b, and append it to the end of the array c."
    // This means that the elements that are *not* removed must form a contiguous block.
    // The elements that are removed form a sequence `c`.
    // The elements of `c` must be non-decreasing.
    // Let the suffix we are considering be `a[k...n-1]`.
    // We need to find the smallest `k` such that `a[k...n-1]` is good.
    // Let `b = a[k...n-1]`.
    // The elements of `b` are `b_0, b_1, ..., b_{m-1}` where `m = n-k`.
    // The elements of `c` are `c_0, c_1, ..., c_{m-1}`.
    // `c_0 <= c_1 <= ... <= c_{m-1}`.
    // The elements `c_j` are taken from `b`'s ends.
    // This means that the elements `b_0, ..., b_{m-1}` must be such that
    // if we remove elements from both ends, the remaining elements are always greater than or equal to the last element added to `c`.
    // This implies that the array `b` must be "anti-bitonic".
    // `b_0 >= b_1 >= ... >= b_p <= b_{p+1} <= ... <= b_{m-1}` for some `p`.
    // The smallest element is `b_p`.
    // We can pick `b_0` or `b_{m-1}`.
    // If `b_0 < b_{m-1}`, we pick `b_0`.
    // If `b_{m-1} < b_0`, we pick `b_{m-1}`.
    // If `b_0 == b_{m-1}`, we can pick either.
    // This strategy ensures `c` is non-decreasing if `b` is anti-bitonic.
    // Example: `b = [5, 4, 3, 2, 3]`
    // `p=3`, `b_3=2`. `5 >= 4 >= 3 >= 2 <= 3`. This is anti-bitonic.
    // Pick `2` (from `b_3`). No, this is not how it works. We pick from ends.
    // `b = [5, 4, 3, 2, 3]`
    // `min(5, 3) = 3`. Pick `3` (last). `b = [5, 4, 3, 2]`, `c = [3]`
    // `min(5, 2) = 2`. Pick `2` (last). `b = [5, 4, 3]`, `c = [3, 2]`. This is not non-decreasing.
    // So the anti-bitonic property is not sufficient.

    // The example `[1, 2, 3, 4, 4, 2, 1]` is good.
    // It is bitonic: `1 <= 2 <= 3 <= 4` and `4 >= 2 >= 1`.
    // The elements picked are `1, 1, 2, 2, 3, 4, 4`.
    // This means the elements are picked from the ends, and they must be non-decreasing.
    // This implies that the array `b` must be "bitonic" (first increasing, then decreasing).
    // `b_0 <= b_1 <= ... <= b_p >= b_{p+1} >= ... >= b_{m-1}`.
    // The largest element is `b_p`.
    // Example: `[4, 5, 2]`
    // `4 <= 5` and `5 >= 2`. This is bitonic with peak at `5`.
    // `b = [4, 5, 2]`
    // `min(4, 2) = 2`. Pick `2` (last). `b = [4, 5]`, `c = [2]`
    // `min(4, 5) = 4`. Pick `4` (first). `b = [5]`, `c = [2, 4]`
    // Pick `5`. `b = []`, `c = [2, 4, 5]`. This works!

    // So, the condition for a "good" array `b` is that it must be bitonic.
    // `b_0 <= b_1 <= ... <= b_p >= b_{p+1} >= ... >= b_{m-1}` for some `p`.
    // This means we need to find the shortest prefix to remove such that the remaining suffix `a[k...n-1]` is bitonic.

    // Let's find the longest suffix `a[k...n-1]` that is bitonic.
    // A single element array is bitonic (peak is itself).
    // Two elements `[x, y]` is bitonic (peak is `max(x,y)`).
    // `[x, y, z]` is bitonic if `x <= y >= z` or `x >= y >= z` or `x <= y <= z`.
    // No, it must be `x <= y` and `y >= z`.
    // So, `a[k...n-1]` must be `a_k <= a_{k+1} <= ... <= a_p >= a_{p+1} >= ... >= a_{n-1}`.

    // We need to find the smallest `k` such that `a[k...n-1]` is bitonic.
    // This is equivalent to finding the largest `k` such that `a[k...n-1]` is NOT bitonic, and then `k+1` is the answer.
    // Or, find the smallest `k` such that `a[k...n-1]` is bitonic.
    // We can iterate `k` from `0` to `n-1`.
    // For each `k`, check if `a[k...n-1]` is bitonic. The first `k` for which it is, is the answer.
    // This is `O(N^2)` in worst case. `N=2e5`, so `N^2` is too slow.

    // Let's find the rightmost index `p` such that `a[p] < a[p-1]`.
    // This `p` marks the start of the non-increasing part from the right.
    // `a[p...n-1]` is non-increasing.
    // Example: `[4, 3, 3, 8, 4, 5, 2]`
    // `n-1=6`.
    // `i=6`. `a[6]=2`.
    // `i=5`. `a[5]=5`. `a[5] < a[6]` (5 < 2) is false.
    // `i=4`. `a[4]=4`. `a[4] < a[5]` (4 < 5) is true. So `p=4`.
    // `a[4...n-1]` = `[4, 5, 2]`. This is the suffix we are interested in.
    // This suffix `[4, 5, 2]` is bitonic. Peak at `5`.
    // So, `k=4` is the answer. Length of prefix to remove is `4`.

    // Let's try this strategy:
    // 1. Find the longest suffix that is non-increasing.
    //    Let `idx1` be the starting index of this suffix.
    //    `idx1 = n-1`. While `idx1 > 0` and `a[idx1-1] >= a[idx1]`, decrement `idx1`.
    //    Now, `a[idx1...n-1]` is non-increasing.
    //    Example: `[4, 3, 3, 8, 4, 5, 2]`
    //    `idx1=6`. `a[5]=5 >= a[6]=2`. `idx1=5`.
    //    `idx1=5`. `a[4]=4 >= a[5]=5` is false. Loop stops. `idx1=5`.
    //    So, `a[5...6]` = `[5, 2]` is the non-increasing suffix. This is correct.

    // 2. From `idx1`, find the longest suffix that is non-decreasing.
    //    Let `idx2` be the starting index of this suffix.
    //    `idx2 = idx1`. While `idx2 > 0` and `a[idx2-1] <= a[idx2]`, decrement `idx2`.
    //    Now, `a[idx2...idx1-1]` is non-decreasing.
    //    The final answer is `idx2`.

    // Let's trace `[4, 3, 3, 8, 4, 5, 2]`
    // `n=7`.
    // Step 1: Find `idx1`.
    // `idx1 = 6`.
    // `idx1=6`: `a[5]=5 >= a[6]=2` (true). `idx1` becomes `5`.
    // `idx1=5`: `a[4]=4 >= a[5]=5` (false). Loop terminates.
    // So, `idx1 = 5`. The suffix `a[5...6]` is `[5, 2]`. This is the non-increasing part.

    // Step 2: Find `idx2`.
    // `idx2 = idx1 = 5`.
    // `idx2=5`: `a[4]=4 <= a[5]=5` (true). `idx2` becomes `4`.
    // `idx2=4`: `a[3]=8 <= a[4]=4` (false). Loop terminates.
    // So, `idx2 = 4`. The suffix `a[4...6]` is `[4, 5, 2]`. This is the bitonic suffix.
    // The length of prefix to remove is `idx2 = 4`. This matches the example output.

    // Let's trace `[1, 2, 3, 4]`
    // `n=4`.
    // Step 1: Find `idx1`.
    // `idx1 = 3`.
    // `idx1=3`: `a[2]=3 >= a[3]=4` (false). Loop terminates.
    // So, `idx1 = 3`. The suffix `a[3...3]` is `[4]`. This is non-increasing.

    // Step 2: Find `idx2`.
    // `idx2 = idx1 = 3`.
    // `idx2=3`: `a[2]=3 <= a[3]=4` (true). `idx2` becomes `2`.
    // `idx2=2`: `a[1]=2 <= a[2]=3` (true). `idx2` becomes `1`.
    // `idx2=1`: `a[0]=1 <= a[1]=2` (true). `idx2` becomes `0`.
    // `idx2=0`: Loop terminates.
    // So, `idx2 = 0`. The suffix `a[0...3]` is `[1, 2, 3, 4]`. This is bitonic.
    // The length of prefix to remove is `idx2 = 0`. This matches the example output.

    // Let's trace `[1, 1, 1]`
    // `n=3`.
    // Step 1: Find `idx1`.
    // `idx1 = 2`.
    // `idx1=2`: `a[1]=1 >= a[2]=1` (true). `idx1` becomes `1`.
    // `idx1=1`: `a[0]=1 >= a[1]=1` (true). `idx1` becomes `0`.
    // `idx1=0`: Loop terminates.
    // So, `idx1 = 0`. The suffix `a[0...2]` is `[1, 1, 1]`. This is non-increasing.

    // Step 2: Find `idx2`.
    // `idx2 = idx1 = 0`.
    // `idx2=0`: Loop terminates.
    // So, `idx2 = 0`. The suffix `a[0...2]` is `[1, 1, 1]`. This is bitonic.
    // The length of prefix to remove is `idx2 = 0`. This matches the example output.

    // Let's trace `[1, 3, 1, 4, 5, 3, 2]`
    // `n=7`.
    // Step 1: Find `idx1`. (Longest non-increasing suffix)
    // `idx1 = 6`. `a[6]=2`.
    // `idx1=6`: `a[5]=3 >= a[6]=2` (true). `idx1` becomes `5`.
    // `idx1=5`: `a[4]=5 >= a[5]=3` (true). `idx1` becomes `4`.
    // `idx1=4`: `a[3]=4 >= a[4]=5` (false). Loop terminates.
    // So, `idx1 = 4`. The suffix `a[4...6]` is `[5, 3, 2]`. This is non-increasing.

    // Step 2: Find `idx2`. (Longest non-decreasing suffix ending at `idx1-1`)
    // `idx2 = idx1 = 4`.
    // `idx2=4`: `a[3]=4 <= a[4]=5` (true). `idx2` becomes `3`.
    // `idx2=3`: `a[2]=1 <= a[3]=4` (true). `idx2` becomes `2`.
    // `idx2=2`: `a[1]=3 <= a[2]=1` (false). Loop terminates.
    // So, `idx2 = 2`. The suffix `a[2...6]` is `[1, 4, 5, 3, 2]`. This is bitonic.
    // The length of prefix to remove is `idx2 = 2`. This matches the example output.

    // Let's trace `[5, 4, 3, 2, 3]`
    // `n=5`.
    // Step 1: Find `idx1`. (Longest non-increasing suffix)
    // `idx1 = 4`. `a[4]=3`.
    // `idx1=4`: `a[3]=2 >= a[4]=3` (false). Loop terminates.
    // So, `idx1 = 4`. The suffix `a[4...4]` is `[3]`. This is non-increasing.

    // Step 2: Find `idx2`. (Longest non-decreasing suffix ending at `idx1-1`)
    // `idx2 = idx1 = 4`.
    // `idx2=4`: `a[3]=2 <= a[4]=3` (true). `idx2` becomes `3`.
    // `idx2=3`: `a[2]=3 <= a[3]=2` (false). Loop terminates.
    // So, `idx2 = 3`. The suffix `a[3...4]` is `[2, 3]`. This is bitonic.
    // The length of prefix to remove is `idx2 = 3`. This matches the example output.

    // The logic seems correct.
    // The algorithm is:
    // 1. Find the rightmost index `idx1` such that `a[idx1...n-1]` is non-increasing.
    //    This means `a[idx1-1] < a[idx1]` (if `idx1 > 0`).
    //    Iterate `idx1` from `n-1` down to `1`. If `a[idx1-1] < a[idx1]`, stop.
    //    The `idx1` found is the start of the non-increasing part.
    // 2. From this `idx1`, find the rightmost index `idx2` such that `a[idx2...idx1-1]` is non-decreasing.
    //    This means `a[idx2-1] > a[idx2]` (if `idx2 > 0`).
    //    Iterate `idx2` from `idx1` down to `1`. If `a[idx2-1] > a[idx2]`, stop.
    //    The `idx2` found is the start of the non-decreasing part.
    // The final answer is `idx2`.

    // Let's refine step 1:
    // `idx1 = n - 1;`
    // `while (idx1 > 0 && a[idx1-1] >= a[idx1]) { idx1--; }`
    // This finds the start of the longest non-increasing suffix.
    // Example: `[1, 2, 3, 4, 4, 2, 1]`
    // `idx1=6`. `a[5]=2 >= a[6]=1` (true). `idx1=5`.
    // `idx1=5`. `a[4]=4 >= a[5]=2` (true). `idx1=4`.
    // `idx1=4`. `a[3]=4 >= a[4]=4` (true). `idx1=3`.
    // `idx1=3`. `a[2]=3 >= a[3]=4` (false). Loop stops. `idx1=3`.
    // So, `a[3...6]` = `[4, 4, 2, 1]` is the non-increasing suffix.

    // Let's refine step 2:
    // `idx2 = idx1;`
    // `while (idx2 > 0 && a[idx2-1] <= a[idx2]) { idx2--; }`
    // This finds the start of the longest non-decreasing prefix *before* `idx1`.
    // Example: `[1, 2, 3, 4, 4, 2, 1]`
    // `idx1=3`.
    // `idx2=3`.
    // `idx2=3`: `a[2]=3 <= a[3]=4` (true). `idx2=2`.
    // `idx2=2`: `a[1]=2 <= a[2]=3` (true). `idx2=1`.
    // `idx2=1`: `a[0]=1 <= a[1]=2` (true). `idx2=0`.
    // `idx2=0`: Loop stops. `idx2=0`.
    // So, `a[0...6]` is the bitonic array. Answer is `0`. This matches the example.

    // This two-pass approach seems to correctly identify the shortest prefix to remove.
    // The first pass finds the end of the "decreasing" part of the bitonic sequence.
    // The second pass finds the start of the "increasing" part of the bitonic sequence.
    // The elements `a[idx2...n-1]` form the bitonic sequence.
    // The length of the prefix to remove is `idx2`.

    int idx1 = n - 1;
    while (idx1 > 0 && a[idx1-1] >= a[idx1]) {
        idx1--;
    }

    int idx2 = idx1;
    while (idx2 > 0 && a[idx2-1] <= a[idx2]) {
        idx2--;
    }

    std::cout << idx2 << std::endl;
}

