int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1000000007;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually have to jump over this 'b'.
            // Each such jump costs 1 step and effectively doubles the number of 'a's
            // that need to jump over subsequent 'b's (because 'ab' -> 'bba' creates a new 'b').
            // So, if there are 'count_a' 'a's to the left that need to jump over this 'b',
            // it adds 'count_a' steps.
            // After this 'b' is processed, it effectively becomes two 'b's for the 'a's
            // further to the left. This is implicitly handled by the doubling of 'count_a'
            // for the next 'b' encountered.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually need to jump
            // over all 'b's to its right.
            // It contributes to the 'count_a' for 'b's further to its left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    int k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends who get w_i = 1 integers:
    // These friends should get the largest available numbers, as their happiness is 2 * number.
    // Since w is sorted, these are the first elements in w.
    // The largest numbers in 'a' are at the end.
    int a_ptr_end = n - 1;
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_end];
            a_ptr_end--;
        } else {
            // All remaining w_i will be > 1. Break and handle them.
            // This relies on w being sorted.
            break;
        }
    }

    // Friends who get w_i > 1 integers:
    // These friends should get the largest available number as their max,
    // and the smallest available number as their min.
    // To maximize sum(max + min), we pair the largest remaining 'a' with the smallest remaining 'a'.
    // The largest w_i values (which are at the end of the sorted w array)
    // should be given to friends who receive the largest 'max' values.
    // The largest w_i values mean these friends will consume more of the smallest 'a' values.

    int a_ptr_start = 0;
    // Iterate w from largest w_i to smallest w_i (that are > 1)
    // The largest w_i values are at the end of the sorted w array.
    // The smallest w_i values (that are > 1) are after the w_i=1 group.
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            // This friend gets w[i] integers.
            // Their max integer should be one of the largest remaining.
            // Their min integer should be one of the smallest remaining.
            total_happiness += a[a_ptr_end]; // Max element
            a_ptr_end--;

            // This friend needs w[i] - 1 more integers.
            // These w[i] - 1 integers will be consumed from the smallest available numbers.
            // The smallest available number will be their min.
            total_happiness += a[a_ptr_start]; // Min element
            a_ptr_start += (w[i] - 1); // Consume w[i] - 1 smallest elements
        } else {
            // All remaining w_i are 1, which have already been processed.
            break;
        }
    }

    std::cout << total_happiness << std::endl;
}

