    // Total time = (n-1 - correct_consecutive_pairs) + (n-k - correct_consecutive_pairs)
    //            = n - 1 - correct_consecutive_pairs + n - k - correct_consecutive_pairs
    //            = 2*n - k - 1 - 2*correct_consecutive_pairs

    long long result = (long long)2 * n - k - 1 - (long long)2 * correct_consecutive_pairs;
    std::cout << result << std::endl;

