                last2 = digit;
            } else { // digit == p + '0'
                // Can be color 1 or 2. Try to put in color 2 if possible, otherwise color 1.
                // This greedy choice for 'p' digits is crucial.
                // If we put 'p' into color 2, it must be >= last2.
                // If we put 'p' into color 1, it must be >= last1.
                // To maximize chances for future digits, it's better to keep last1 as small as possible.
                // So, if 'p' can go into color 2, put it there.
                if (digit >= last2) { // Can put 'p' into color 2
                    current_result[i] = '2';
                    last2 = digit;
                } else if (digit >= last1) { // Cannot put into color 2, try color 1
                    current_result[i] = '1';
                    last1 = digit;
                } else { // Cannot put into either
                    valid_p = false;
                    break;
                }
            }
        }

        if (valid_p) {
            // After assigning all digits, check the final condition: last(S1) <= first(S2)
            // This is implicitly handled by the `last1` and `last2` tracking.
            // If a digit `d_i` is colored '1', then `d_i >= last1` (previous '1' digit).
            // If a digit `d_i` is colored '2', then `d_i >= last2` (previous '2' digit).
            // The critical point is the transition from S1 to S2.
            // The `last1` variable tracks the maximum digit assigned to color 1 so far.
            // The `last2` variable tracks the maximum digit assigned to color 2 so far.
            // If we assign a digit `d_i` to color 1, it must be >= `last1`.
            // If we assign a digit `d_i` to color 2, it must be >= `last2`.
            // The condition `last(S1) <= first(S2)` is satisfied if `last1 <= first_digit_in_S2`.
            // Our greedy choice for `p` digits ensures this.
            // If a digit `d_i = p` is colored '1', then `d_i >= last1`.
            // If a digit `d_i = p` is colored '2', then `d_i >= last2`.
            // The `last1` and `last2` variables correctly track the non-decreasing property within each color.
            // The overall non-decreasing property of S1+S2 is guaranteed if `last1 <= first_digit_in_S2`.
            // The way we assign `p` digits (preferring color 2 if `p >= last2`) ensures that `last1` remains as small as possible.
            // If `last1` is the largest digit in S1, and `first_digit_in_S2` is the smallest in S2,
            // then `last1 <= p` (because all digits > p are in S2, and some p's might be in S1).
            // And `p <= first_digit_in_S2` (because all digits < p are in S1, and some p's might be in S2).
            // So `last1 <= p <= first_digit_in_S2` is implicitly maintained.

            possible = true;
            result = current_result;
            break;
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

