#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate constraints s[i] == s[i+k]
    // This means s[i], s[i+k], s[i+2k], ... must all be the same character.
    // We can iterate through the first k characters and ensure consistency
    // for each "chain" s[i], s[i+k], s[i+2k], ...
    for (int i = 0; i < k; ++i) {
        char fixed_char = '?';
        for (int j = i; j < n; j += k) {
            if (s[j] != '?') {
                if (fixed_char == '?') {
                    fixed_char = s[j];
                } else if (fixed_char != s[j]) {
                    // Conflict found: s[j] is different from a previously seen char in this chain
                    std::cout << "NO\n";
                    return;
                }
            }
        }
        // If a fixed_char was found, apply it to all '?' in this chain
        if (fixed_char != '?') {
            for (int j = i; j < n; j += k) {
                s[j] = fixed_char;
            }
        }
    }

    // Step 2: Check if the first k characters can form a k/2 balanced substring
    // After propagation, the first k characters s[0...k-1] are either '0', '1', or '?'.
    // Any '?' in s[0...k-1] can be replaced by '0' or '1' freely,
    // as long as it doesn't violate the k/2 balance.
    // The propagation step ensures that if s[j] is '0' or '1', then s[j+k], s[j+2k], etc.
    // are also '0' or '1' respectively.
    // So, if s[0...k-1] can be made k/2 balanced, the entire string can be.
    int count0 = 0;
    int count1 = 0;
    int countQ = 0;

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            count0++;
        } else if (s[i] == '1') {
            count1++;
        } else { // s[i] == '?'
            countQ++;
        }
    }

    int target_half = k / 2;

    // Check if it's possible to assign '?'s to meet the target_half counts
    // We need (target_half - count0) zeros and (target_half - count1) ones.
    // These must be non-negative.
    // The sum of these needed counts must be equal to countQ.
    if (count0 > target_half || count1 > target_half) {
        std::cout << "NO\n";
        return;
    }

    int needed0 = target_half - count0;
    int needed1 = target_half - count1;

    if (needed0 + needed1 == countQ) {
        std::cout << "YES\n";
    } else {
        // This case should ideally not happen if count0 <= target_half and count1 <= target_half
        // and needed0 + needed1 == countQ is the only condition.
        // However, if needed0 + needed1 < countQ, it means we have too many '?'s
        // to fill exactly the remaining slots.
        // If needed0 + needed1 > countQ, it means we don't have enough '?'s.
        // Both are covered by the equality check.
        std::cout << "NO\n";
    }
}

