int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum_k = sum_{k=1 to a} k
    // Sum_k = a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = (sum_k * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum_r = sum_{r=1 to b-1} r
    // Sum_r = (b-1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = (sum_r * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum_total = sum_{k=1 to a} sum_{r=1 to b-1} (r * (k * b + 1))
    // Sum_total = sum_{k=1 to a} sum_{r=1 to b-1} (r * k * b + r)
    // Sum_total = sum_{k=1 to a} (k * b * sum_{r=1 to b-1} r + sum_{r=1 to b-1} r)
    // Sum_total = sum_{k=1 to a} ((k * b + 1) * sum_{r=1 to b-1} r)
    // Sum_total = (sum_{r=1 to b-1} r) * sum_{k=1 to a} (k * b + 1)
    // Sum_total = (sum_{r=1 to b-1} r) * (b * sum_{k=1 to a} k + sum_{k=1 to a} 1)
    // Sum_total = (sum_{r=1 to b-1} r) * (b * sum_{k=1 to a} k + a)

    long long term_b_sum_k = (b % MOD * sum_k) % MOD;
    long long term_a = a % MOD;

    long long sum_k_b_plus_1 = (term_b_sum_k + term_a) % MOD;

    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

