#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_L = (dq.empty() ? 0 : L[dq.back()]);
        long long prev_h = (dq.empty() ? 0 : h[dq.back()]);

        L[i] = std::min(h[i], prev_max_L + (i - (dq.empty() ? -1 : dq.back())));
        dq.push_back(i);
    }

    std::vector<long long> R(n);
    dq.clear();

    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_R = (dq.empty() ? 0 : R[dq.back()]);
        long long prev_h = (dq.empty() ? 0 : h[dq.back()]);

        R[i] = std::min(h[i], prev_max_R + ((dq.empty() ? n : dq.back()) - i));
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

