int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operation 2: Do nothing
        std::cout << "1 1\n";
        std::cout << "0\n";
        // Operation 3: Do nothing
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Operation 1: Make a[0]...a[n-2] divisible by n
        // For each a[i] (0 <= i < n-1), we want to add x_i such that (a[i] + x_i) % n == 0.
        // x_i must be a multiple of n.
        // So, x_i = (n - (a[i] % n)) % n. If a[i] % n == 0, this is 0.
        // If a[i] is negative, a[i] % n might be negative.
        // A safe way to get a positive remainder: (a[i] % n + n) % n.
        // Then, x_i = (n - ((a[i] % n + n) % n)) % n.
        // This x_i is a multiple of n.
        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = (a[i] % n + n) % n;
            long long add_val = (n - remainder) % n;
            std::cout << add_val << (i == n - 2 ? "" : " ");
            a[i] += add_val; // Update a[i]
        }
        std::cout << "\n";

        // Operation 2: Make a[n-1] divisible by n
        // For a[n-1], we want to add x_{n-1} such that (a[n-1] + x_{n-1}) % n == 0.
        // x_{n-1} must be a multiple of n.
        // Same logic as above.
        std::cout << n << " " << n << "\n";
        long long remainder_last = (a[n - 1] % n + n) % n;
        long long add_val_last = (n - remainder_last) % n;
        std::cout << add_val_last << "\n";
        a[n - 1] += add_val_last; // Update a[n-1]

        // After operations 1 and 2, all a[i] are multiples of n.
        // Operation 3: Make all a[i] zero.
        // Select segment [1, n]. Length is n.
        // For each a[i], it's a multiple of n. We want to add -a[i].
        // -a[i] is also a multiple of n. This is valid.
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix balances for the left side (jars 1 to n)
    // and suffix balances for the right side (jars n+1 to 2n)
    // relative to the middle point.

    // Balances for the left side (jars n down to 1)
    // `left_balances[k]` stores the balance of jars `n-k+1` to `n`.
    // `left_balances[0]` is balance of empty set (0 jars removed from left)
    // `left_balances[1]` is balance of jar `n`
    // `left_balances[k]` is balance of jars `n-k+1, ..., n`
    std::map<int, int> left_balances; // balance -> count of jars removed from left
    left_balances[0] = 0; // 0 jars removed, balance 0

    int current_balance = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_balance++;
        } else {
            current_balance--;
        }
        // Store the minimum number of jars removed to achieve this balance
        // (i.e., the maximum number of jars remaining on the left side)
        // The number of jars removed is (n - i)
        if (left_balances.find(current_balance) == left_balances.end()) {
            left_balances[current_balance] = n - i;
        }
    }

    // Balances for the right side (jars n+1 up to 2n)
    // `right_balances[k]` stores the balance of jars `n+1` to `n+k`.
    // `right_balances[0]` is balance of empty set (0 jars removed from right)
    // `right_balances[1]` is balance of jar `n+1`
    // `right_balances[k]` is balance of jars `n+1, ..., n+k`
    std::map<int, int> right_balances; // balance -> count of jars removed from right
    right_balances[0] = 0; // 0 jars removed, balance 0

    current_balance = 0;
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            current_balance++;
        } else {
            current_balance--;
        }
        // Store the minimum number of jars removed to achieve this balance
        // (i.e., the maximum number of jars remaining on the right side)
        // The number of jars removed is (i - n + 1)
        if (right_balances.find(current_balance) == right_balances.end()) {
            right_balances[current_balance] = i - n + 1;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through all possible balances from the left side
    // For each left_balance, find if there's a corresponding right_balance
    // such that their sum is 0 (meaning the total remaining balance is 0).
    // If left_balance is `b_L` (from removing `k_L` jars from left),
    // we need a right_balance `b_R = -b_L` (from removing `k_R` jars from right).
    // Total jars removed = `k_L + k_R`.
    for (auto const& [b_L, k_L] : left_balances) {
        int target_b_R = -b_L;
        if (right_balances.count(target_b_R)) {
            int k_R = right_balances[target_b_R];
            min_removed_jars = std::min(min_removed_jars, k_L + k_R);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

