    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we track how the output bit depends on the input bit.
    // There are 4 possibilities for each bit:
    // 0: output bit is always 0, regardless of input bit
    // 1: output bit is always 1, regardless of input bit
    // 2: output bit is the same as input bit (x)
    // 3: output bit is the inverse of input bit (~x)
    // Initially, output bit is the same as input bit for all positions.
    std::vector<int> bit_state(10, 2); // 2 means 'x'

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int j = 0; j < 10; ++j) {
            int bit_val = (val >> j) & 1; // j-th bit of the constant 'val'
            int current_state = bit_state[j];

            if (op_char == '&') {
                if (bit_val == 0) {
                    bit_state[j] = 0; // x & 0 = 0, ~x & 0 = 0, 0 & 0 = 0, 1 & 0 = 0
                } else { // bit_val == 1
                    // x & 1 = x, ~x & 1 = ~x, 0 & 1 = 0, 1 & 1 = 1
                    // State remains unchanged
                }
            } else if (op_char == '|') {
                if (bit_val == 1) {
                    bit_state[j] = 1; // x | 1 = 1, ~x | 1 = 1, 0 | 1 = 1, 1 | 1 = 1
                } else { // bit_val == 0
                    // x | 0 = x, ~x | 0 = ~x, 0 | 0 = 0, 1 | 0 = 1
                    // State remains unchanged
                }
            } else if (op_char == '^') {
                if (bit_val == 1) {
                    // x ^ 1 = ~x, ~x ^ 1 = x, 0 ^ 1 = 1, 1 ^ 1 = 0
                    if (current_state == 0) bit_state[j] = 1;
                    else if (current_state == 1) bit_state[j] = 0;
                    else if (current_state == 2) bit_state[j] = 3; // x -> ~x
                    else if (current_state == 3) bit_state[j] = 2; // ~x -> x
                } else { // bit_val == 0
                    // x ^ 0 = x, ~x ^ 0 = ~x, 0 ^ 0 = 0, 1 ^ 0 = 1
                    // State remains unchanged
                }
            }
        }
    }

    // Reconstruct the operations
    int and_val = 1023; // All bits 1
    int or_val = 0;     // All bits 0
    int xor_val = 0;    // All bits 0

    for (int j = 0; j < 10; ++j) {
        if (bit_state[j] == 0) { // Output bit is always 0
            and_val &= ~(1 << j); // Force this bit to 0 using AND
        } else if (bit_state[j] == 1) { // Output bit is always 1
            or_val |= (1 << j);   // Force this bit to 1 using OR
        } else if (bit_state[j] == 3) { // Output bit is ~x
            xor_val |= (1 << j);  // Invert this bit using XOR
        }
        // If bit_state[j] == 2 (output bit is x), no action needed for this bit
        // with respect to and_val, or_val, xor_val.
        // and_val will keep it 1, or_val will keep it 0, xor_val will keep it 0.
    }

    std::vector<std::pair<char, int>> result_ops;
    if (or_val != 0) {
        result_ops.push_back({'|', or_val});
    }
    if (xor_val != 0) {
        result_ops.push_back({'^', xor_val});
    }
    if (and_val != 1023) { // Only add if it actually changes bits (i.e., not all 1s)
        result_ops.push_back({'&', and_val});
    }

    // The order of operations matters for the final result.
    // The order should be OR, then XOR, then AND.
    // This is because:
    // (x | A) ^ B & C
    // If we apply AND first: (x & C) | A ^ B. This is not equivalent.
    // If we apply XOR first: (x ^ B) | A & C. This is not equivalent.
    //
    // Let's verify the order:
    // For a bit 'j':
    // If bit_state[j] == 0:
    //   or_val_j = 0, xor_val_j = 0, and_val_j = 0
    //   (x_j | 0) ^ 0 & 0 = x_j ^ 0 & 0 = x_j & 0 = 0. Correct.
    // If bit_state[j] == 1:
    //   or_val_j = 1, xor_val_j = 0, and_val_j = 1
    //   (x_j | 1) ^ 0 & 1 = 1 ^ 0 & 1 = 1 & 1 = 1. Correct.
    // If bit_state[j] == 2:
    //   or_val_j = 0, xor_val_j = 0, and_val_j = 1
    //   (x_j | 0) ^ 0 & 1 = x_j ^ 0 & 1 = x_j & 1 = x_j. Correct.
    // If bit_state[j] == 3:
    //   or_val_j = 0, xor_val_j = 1, and_val_j = 1
    //   (x_j | 0) ^ 1 & 1 = x_j ^ 1 & 1 = (~x_j) & 1 = ~x_j. Correct.

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        long long num_zeros = n - m;

        // To minimize substrings of all zeros, we want to make the blocks of zeros
        // as small as possible. This means distributing the 'm' ones to break up
        // the 'n-m' zeros into 'm+1' blocks (some of which might be empty).
        // The most even distribution is to have 'm' blocks of size k and
        // 'm+1 - m' = 1 block of size k+1, or similar.
        // More precisely, 'm+1' blocks of zeros.
        // Let k be the minimum size of a block of zeros.
        // Let r be the number of blocks of size k+1.
        // Then (m+1 - r) blocks have size k.
        // Total zeros: (m+1 - r) * k + r * (k+1) = num_zeros
        // (m+1) * k + r = num_zeros
        // k = num_zeros / (m+1)
        // r = num_zeros % (m+1)

        long long k = num_zeros / (m + 1);
        long long r = num_zeros % (m + 1);

        // Number of blocks of zeros of size k+1 is r.
        // Number of blocks of zeros of size k is (m+1 - r).

        long long substrings_all_zeros = 0;

        // Substrings from blocks of size k+1
        substrings_all_zeros += r * (k + 1) * (k + 2) / 2;

        // Substrings from blocks of size k
        substrings_all_zeros += (m + 1 - r) * k * (k + 1) / 2;

        long long max_f_s = total_substrings - substrings_all_zeros;

        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal (i.e., in order of addition)
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added to the graph

        active_vertices[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step:
        // When vertex k is added, it can potentially shorten paths between any two active vertices i and j.
        // d[i][j] = min(d[i][j], d[i][k] + d[k][j])
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                    if (dist[i][j] == -1 || dist[i][j] > dist[i][k] + dist[k][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // After adding vertex k and updating all-pairs shortest paths considering k,
        // calculate the sum of shortest paths between all *currently active* pairs.
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j]) {
                        current_sum += dist[i][j];
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first removal to last)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    while (X > 0) {
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to finding largest k such that 2^k <= X + 1
        // k = floor(log2(X + 1))
        long long k = 0;
        if (X + 1 > 0) { // Ensure X+1 is positive for log2
            k = static_cast<long long>(std::log2(static_cast<double>(X + 1)));
        }

        // If k is 0, it means X+1 is 1, so X is 0. But loop condition is X > 0.
        // If X=1, X+1=2, log2(2)=1, k=1. 2^1-1 = 1.
        // If X=2, X+1=3, log2(3)=1.something, k=1. 2^1-1 = 1.
        // If X=3, X+1=4, log2(4)=2, k=2. 2^2-1 = 3.
        // So, if 2^k - 1 > X, we need to decrease k.
        // The largest power of 2 less than or equal to X+1 is 2^k.
        // The number of subsequences is 2^k - 1.
        // If X is 1, k=1. 2^1-1 = 1.
        // If X is 2, k=1. 2^1-1 = 1.
        // If X is 3, k=2. 2^2-1 = 3.
        // If X is 4, k=2. 2^2-1 = 3.
        // So, we need to find the largest k such that 2^k - 1 <= X.
        // This is equivalent to finding the largest k such that 2^k <= X + 1.
        // The `std::log2` approach might be off by 1 for edge cases due to floating point precision.
        // A safer way is to iterate or use bit manipulation.

        long long num_elements_for_this_block = 0;
        if (X == 1) {
            num_elements_for_this_block = 1;
        } else {
            // Find largest k such that 2^k - 1 <= X
            // This is equivalent to finding largest k such that 2^k <= X + 1
            // We can find the highest set bit in X+1.
            // For example, if X=1, X+1=2 (10_2), highest bit is 1st (0-indexed), so k=1.
            // If X=2, X+1=3 (11_2), highest bit is 1st, so k=1.
            // If X=3, X+1=4 (100_2), highest bit is 2nd, so k=2.
            // If X=4, X+1=5 (101_2), highest bit is 2nd, so k=2.
            // So k is the position of the most significant bit of (X+1) if X+1 is a power of 2,
            // or floor(log2(X+1)) otherwise.
            // In C++20, std::log2p1 is available, but we are using C++23.
            // std::bit_width(X+1) gives k if X+1 is a power of 2, or k+1 otherwise.
            // std::countr_zero(X+1) for power of 2.
            // std::log2(X+1) is generally fine for large numbers.
            // Let's use a loop to be safe.
            long long temp_X_plus_1 = X + 1;
            long long current_power_of_2 = 1;
            num_elements_for_this_block = 0;
            while (current_power_of_2 <= temp_X_plus_1) {
                current_power_of_2 <<= 1;
                num_elements_for_this_block++;
            }
            num_elements_for_this_block--; // This gives k such that 2^k is the smallest power of 2 >= X+1
                                            // We need 2^k <= X+1, so we might need to decrement.
            if ((1LL << num_elements_for_this_block) > (X + 1)) {
                num_elements_for_this_block--;
            }
            if (num_elements_for_this_block == 0 && X > 0) { // Special case for X=1, X+1=2, loop gives 1.
                num_elements_for_this_block = 1;
            }
        }

        for (int i = 0; i < num_elements_for_this_block; ++i) {
            result_array.push_back(current_val);
        }
        X -= ((1LL << num_elements_for_this_block) - 1);
        current_val += d; // Ensure new block elements are sufficiently far from previous ones
        current_val += 1000000000LL; // Add a large constant to ensure max-min >= d
                                     // This ensures that subsequences mixing elements from different blocks are removed.
                                     // The problem states d <= 10^9. So adding d is not enough.
                                     // Adding d + 1 is enough to make max-min >= d.
                                     // Adding 10^9 is a safe bet.
    }

    if (result_array.size() > 10000) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_ones(n, 0);
    std::vector<int> right_ones(n, 0);

    // Calculate left_ones: distance to the nearest 1 on the left (inclusive)
    // If a[i] is 1, left_ones[i] = 0. If a[i] is 0, left_ones[i] = left_ones[i-1] + 1.
    // If no 1 on left, it's effectively infinity.
    if (a[0] == 1) {
        left_ones[0] = 0;
    } else {
        left_ones[0] = n + 1; // Represents infinity
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = 0;
        } else {
            left_ones[i] = left_ones[i - 1] + 1;
        }
    }

    // Calculate right_ones: distance to the nearest 1 on the right (inclusive)
    // If a[i] is 1, right_ones[i] = 0. If a[i] is 0, right_ones[i] = right_ones[i+1] + 1.
    // If no 1 on right, it's effectively infinity.
    if (a[n - 1] == 1) {
        right_ones[n - 1] = 0;
    } else {
        right_ones[n - 1] = n + 1; // Represents infinity
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = 0;
        } else {
            right_ones[i] = right_ones[i + 1] + 1;
        }
    }

    int max_dist = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            // For a 0 at index i, it will become 1 if it's "covered" by two 1s.
            // The distance to the nearest 1 on the left is left_ones[i].
            // The distance to the nearest 1 on the right is right_ones[i].
            // The 0 at index i will become 1 if it's within 1 step of a 1 on both sides,
            // or more generally, if it's within k steps of a 1 on both sides.
            // The number of steps for a 0 to become 1 is ceil(min(left_ones[i], right_ones[i]) / 2.0)
            // This is equivalent to (min(left_ones[i], right_ones[i]) + 1) / 2 using integer division.
            // We are interested in the maximum such steps for any 0.
            max_dist = std::max(max_dist, (std::min(left_ones[i], right_ones[i]) + 1) / 2);
        }
    }

    std::cout << max_dist << std::endl;

    std::vector<int> result(n);
    result[0] = a[0];
    result[n - 1] = a[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 1) {
            result[i] = 1; // 1s never change to 0s
        } else { // a[i] == 0
            // A 0 at index i becomes 1 if it's "close enough" to 1s on both sides.
            // It becomes 1 if min(left_ones[i], right_ones[i]) <= 2 * max_dist.
            // This is because after max_dist steps, all 0s that are within 2*max_dist distance
            // from a 1 on both sides will have turned into 1s.
            // More precisely, a 0 at index i becomes 1 if its distance to the nearest 1 on the left
            // and its distance to the nearest 1 on the right are both greater than max_dist.
            // No, this is wrong.
            // A 0 at index i becomes 1 if it's "filled in" by the expansion of 1s.
            // The condition for a[i] to become 1 in the stable state is that it's closer to a 1
            // than max_dist steps from both sides.
            // If left_ones[i] <= max_dist and right_ones[i] <= max_dist, then it becomes 1.
            // Otherwise, it remains 0.
            if (left_ones[i] <= max_dist && right_ones[i] <= max_dist) {
                result[i] = 1;
            } else {
                result[i] = 0;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    std::vector<long long> min_val_at_idx(n + 1, std::numeric_limits<long long>::max()); // Stores max_val_at_idx[i] = m_k - sum_d_k_for_i
    std::vector<long long> current_delta(n + 1, 0); // Stores sum of d for type 1 operations

    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        if (ops[i].type == 2) {
            // For a type 2 operation (l, r, m), we know that for any j in [l, r],
            // initial_a[j] + current_delta[j] <= m.
            // So, initial_a[j] <= m - current_delta[j].
            // We want to find the largest possible initial_a[j] that satisfies all constraints.
            // Thus, initial_a[j] <= min(m_k - current_delta_k[j]) over all type 2 ops k affecting j.
            // We initialize min_val_at_idx[j] to a very large value and update it.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_val_at_idx[j] = std::min(min_val_at_idx[j], ops[i].val - current_delta[j]);
            }
        } else { // type 1 operation
            // Update current_delta for subsequent type 2 operations
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        }
    }

    // Initialize the candidate array `a`
    std::vector<long long> a(n + 1);
    for (int i = 1; i <= n; ++i) {
        if (min_val_at_idx[i] == std::numeric_limits<long long>::max()) {
            // If no type 2 operation constrained this element, we can set it to 0.
            // Or any value within [-10^9, 10^9]. 0 is simplest.
            a[i] = 0;
        } else {
            a[i] = min_val_at_idx[i];
        }
    }

    // Verify the constructed array `a`
    std::vector<long long> current_arr_values = a; // This will store a_j + sum_d_k_for_j
    bool possible = true;

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_arr_values[j] += ops[i].val;
            }
        } else { // type 2 operation
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, current_arr_values[j]);
            }
            if (max_val_in_range != ops[i].val) {
                possible = false;
                break;
            }
        }
    }

    if (possible) {
        std::cout << "YES\n";
        for (int i = 1; i <= n; ++i) {
            std::cout << a[i] << (i == n ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_in_line;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_in_line.push_back({i + 1, v_val, d_val, p_val});
    }

    std::vector<int> treated_children_ids;

    while (!children_in_line.empty()) {
        Child current_child = children_in_line.front();
        children_in_line.pop_front();
        treated_children_ids.push_back(current_child.id);

        long long v_cry_volume = current_child.v;
        long long d_cry_sum = 0; // Accumulates d_j from children running away

        // Apply v_cry_volume to children in line
        auto it = children_in_line.begin();
        long long current_v_reduction = v_cry_volume;
        while (it != children_in_line.end() && current_v_reduction > 0) {
            it->p -= current_v_reduction;
            current_v_reduction--;
            ++it;
        }

        // Process chain reactions from d_cry_sum and children whose confidence dropped below zero
        // This loop continues as long as new children run away
        bool chain_reaction_occurred;
        do {
            chain_reaction_occurred = false;
            it = children_in_line.begin();
            while (it != children_in_line.end()) {
                it->p -= d_cry_sum; // Apply accumulated d_cry_sum from previous step

                if (it->p < 0) {
                    d_cry_sum += it->d; // Add this child's d_j to the sum
                    it = children_in_line.erase(it); // Remove child from line
                    chain_reaction_occurred = true; // A child ran away, so another pass might be needed
                } else {
                    ++it;
                }
            }
            d_cry_sum = 0; // Reset d_cry_sum for the next iteration of the outer loop, as it's applied
                           // and new d_cry_sum will be accumulated if more children run away.
                           // The logic is that d_cry_sum is applied to *all* children currently in line.
                           // If a child runs away, its d_j is added to d_cry_sum, and this new d_cry_sum
                           // will be applied to the *remaining* children in the next pass.
                           // So, if chain_reaction_occurred is true, we need to re-evaluate all remaining children.
        } while (chain_reaction_occurred);
    }

    std::cout << treated_children_ids.size() << "\n";
    for (size_t i = 0; i < treated_children_ids.size(); ++i) {
        std::cout << treated_children_ids[i] << (i == treated_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9
// and y can accumulate multiple such values.
// x can also become large, but it's an index, so it's checked against n.
// The values in a_i are also large, so the array should store long long.

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // The input array a_2, ..., a_n.
    // We'll store it in a 0-indexed vector for convenience,
    // so a_2 will be at index 0, a_3 at index 1, etc.
    // This means a_k is stored at `given_a[k-2]`.
    std::vector<long long> given_a(n - 1);
    for (int k = 0; k < n - 1; ++k) {
        std::cin >> given_a[k];
    }

    // dp_y[k] will store the final y value if the program starts with x=k, y=0
    // and the first step is step 2 (x = x + A[x], y = y + A[x]).
    // dp_y[k] stores the total y accumulated from that point onwards.
    // dp_y[k] is initialized to -2 to indicate not computed yet.
    // -1 means infinite loop.
    std::vector<long long> dp_y(n + 1, -2);

    // dp_x_final[k] will store the final x value if the program starts with x=k, y=0
    // and the first step is step 2.
    // This is needed to determine if the program terminates or loops.
    std::vector<long long> dp_x_final(n + 1, -2);

    // dp_visited[k] is used to detect cycles during DFS-like computation.
    // 0: not visited
    // 1: currently in recursion stack (visiting)
    // 2: finished visiting (computed)
    std::vector<int> dp_visited(n + 1, 0);

    // Lambda function to solve for a given starting x_start.
    // This function computes dp_y[x_start] and dp_x_final[x_start].
    // It takes the current value of A[x_start] as a parameter.
    auto solve = [&](int x_start, long long a_x_start, auto& self) -> void {
        // Mark as currently visiting
        dp_visited[x_start] = 1;

        long long current_x = x_start;
        long long current_y_accum = 0; // y accumulated from this point onwards

        // Step 2: x = x + A[x], y = y + A[x]
        long long val_ax_step2 = a_x_start;
        current_x += val_ax_step2;
        current_y_accum += val_ax_step2;

        // Check termination after step 2
        if (current_x <= 0 || current_x > n) {
            dp_y[x_start] = current_y_accum;
            dp_x_final[x_start] = current_x;
            dp_visited[x_start] = 2; // Mark as computed
            return;
        }

        // Step 3: x = x - A[x], y = y + A[x]
        // A[x] here refers to A[current_x] *after* step 2.
        long long val_ax_step3;
        if (current_x == 1) { // This case is for the initial 'i' value
            // This should not happen if we are computing dp_y[k] for k > 1.
            // If current_x becomes 1, it means we are in a path that leads back to A[1].
            // However, A[1] is variable. So, we cannot use dp_y[1] directly.
            // This path should be handled by the main loop for each 'i'.
            // For dp_y[k] where k > 1, A[k] is fixed.
            // If current_x becomes 1, it means we are trying to use A[1] which is not fixed.
            // This implies that the path from x_start (where x_start > 1) leads to x=1.
            // This is an infinite loop for the purpose of precomputation,
            // because A[1] is not fixed.
            // Or, it means the path from x_start leads to x=1, and then the program
            // will use the specific 'i' value for A[1].
            // This is a tricky part. The problem states "Suppose for each i (1 <= i <= n - 1)
            // we run the program on the sequence i, a_2, a_3, ..., a_n."
            // This means A[1] is 'i' for *each* run.
            // So, if current_x becomes 1, we cannot use precomputed dp values.
            // This means any path that leads to x=1 from x > 1 is effectively a "restart"
            // with a new A[1] value.
            // This implies that the precomputation should only be for paths that *don't*
            // hit x=1.
            // Let's re-evaluate the DP state.
            // dp_y[k] and dp_x_final[k] should represent the outcome if the program
            // starts at x=k, and A[k] is fixed (i.e., k > 1).
            // If current_x becomes 1, it means we are in a cycle that involves A[1].
            // This is an infinite loop for the precomputation.
            // So, if current_x == 1, it's an infinite loop for the precomputation.
            dp_y[x_start] = -1;
            dp_x_final[x_start] = -1;
            dp_visited[x_start] = 2;
            return;
        } else {
            val_ax_step3 = given_a[current_x - 2]; // A[current_x]
        }

        current_x -= val_ax_step3;
        current_y_accum += val_ax_step3;

        // Check termination after step 3
        if (current_x <= 0 || current_x > n) {
            dp_y[x_start] = current_y_accum;
            dp_x_final[x_start] = current_x;
            dp_visited[x_start] = 2;
            return;
        }

        // Now, current_x is the new starting point for the next iteration of (step 2, step 3).
        // We need to get A[current_x] for the next iteration.
        long long next_a_val;
        if (current_x == 1) {
            // If current_x becomes 1, it means we are trying to use A[1] which is variable.
            // This path is effectively an infinite loop for precomputation.
            dp_y[x_start] = -1;
            dp_x_final[x_start] = -1;
            dp_visited[x_start] = 2;
            return;
        } else {
            next_a_val = given_a[current_x - 2];
        }

        // Check if we've already computed this state
        if (dp_visited[current_x] == 2) { // Already computed
            if (dp_y[current_x] == -1) { // It leads to an infinite loop
                dp_y[x_start] = -1;
                dp_x_final[x_start] = -1;
            } else {
                dp_y[x_start] = current_y_accum + dp_y[current_x];
                dp_x_final[x_start] = dp_x_final[current_x];
            }
        } else if (dp_visited[current_x] == 1) { // Cycle detected
            dp_y[x_start] = -1;
            dp_x_final[x_start] = -1;
        } else { // Not visited, recurse
            self(current_x, next_a_val, self);
            if (dp_y[current_x] == -1) {
                dp_y[x_start] = -1;
                dp_x_final[x_start] = -1;
            } else {
                dp_y[x_start] = current_y_accum + dp_y[current_x];
                dp_x_final[x_start] = dp_x_final[current_x];
            }
        }
        dp_visited[x_start] = 2; // Mark as computed
    };

    // Precompute for x_start from 2 to n.
    // A[1] is variable, so we cannot precompute for x_start = 1.
    for (int k = 2; k <= n; ++k) {
        if (dp_visited[k] == 0) { // If not yet computed
            solve(k, given_a[k - 2], solve);
        }
    }

    // Now, for each i from 1 to n-1, run the program.
    for (int i = 1; i < n; ++i) {
        long long current_x = 1;
        long long current_y = 0;
        long long a_1_val = i; // A[1] is 'i' for this run

        // First iteration of (step 2, step 3)
        // Step 2: x = x + A[x], y = y + A[x]
        long long val_ax_step2 = a_1_val; // A[1] is 'i'
        current_x += val_ax_step2;
        current_y += val_ax_step2;

        // Check termination after step 2
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Step 3: x = x - A[x], y = y + A[x]
        // A[x] here refers to A[current_x] *after* step 2.
        long long val_ax_step3;
        if (current_x == 1) { // If x becomes 1 again, it's an infinite loop
            std::cout << -1 << "\n";
            continue;
        } else {
            val_ax_step3 = given_a[current_x - 2]; // A[current_x]
        }

        current_x -= val_ax_step3;
        current_y += val_ax_step3;

        // Check termination after step 3
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now, current_x is the new starting point for the next iteration of (step 2, step 3).
        // We can use precomputed DP values if current_x > 1.
        if (current_x == 1) { // If x becomes 1 again, it's an infinite loop
            std::cout << -1 << "\n";
        } else {
            if (dp_y[current_x] == -1) { // Precomputed path leads to infinite loop
                std::cout << -1 << "\n";
            } else {
                std::cout << current_y + dp_y[current_x] << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = std::numeric_limits<long long>::max();
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all in subsequence 1)
    // This means all f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    if (n >= 2) { // Need at least two elements to form a pair
        long long current_goodness = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                best_partition[a[i].original_index] = 1;
            }
        }
    } else { // n=1, no pairs, goodness is 0. But problem states n >= 2.
        min_goodness = 0; // Should not happen based on constraints
        best_partition[a[0].original_index] = 1;
    }


    // Case 2: Partition into two non-empty subsequences.
    // Consider placing a[0] in S1 and a[1] in S2.
    // The minimum possible sum for elements in different subsequences is a[0] + a[1] + h.
    // The minimum possible sum for elements in the same subsequence is a[0] + a[2] (if a[2] is in S1) or a[1] + a[2] (if a[2] is in S2).
    // The maximum possible sum for elements in the same subsequence is a[n-1] + a[n-2].
    // The maximum possible sum for elements in different subsequences is a[n-1] + a[n-2] + h.

    // Strategy: Put a[0] in S1, and all other elements (a[1]...a[n-1]) in S2.
    // This ensures a[0] is in a different subsequence from all a[i] for i > 0.
    // S1 = {a[0]}
    // S2 = {a[1], a[2], ..., a[n-1]}

    // Minimum f value:
    // If S2 has at least two elements (n-1 >= 2, i.e., n >= 3):
    //   min_f = min(a[0] + a[1] + h, a[1] + a[2])
    // If S2 has only one element (n-1 == 1, i.e., n == 2):
    //   min_f = a[0] + a[1] + h (no pairs within S2)
    // If S2 is empty (n-1 == 0, i.e., n == 1):
    //   This case is covered by Case 1 (all in S1).

    // Maximum f value:
    // max_f = max(a[0] + a[n-1] + h, a[n-1] + a[n-2]) (if n >= 3)
    // max_f = a[0] + a[1] + h (if n == 2)

    long long current_min_f, current_max_f;
    if (n == 2) {
        current_min_f = a[0].value + a[1].value + h;
        current_max_f = a[0].value + a[1].value + h;
    } else { // n >= 3
        current_min_f = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
        current_max_f = std::max(a[0].value + a[n - 1].value + h, a[n - 1].value + a[n - 2].value);
    }

    long long current_goodness = current_max_f - current_min_f;

    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        best_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // last_bad[i] stores the largest j < i such that s[j...i] contains a bad pattern.
    // A bad pattern is s[x] = s[x+k] = s[x+2k] for some x, k.
    // We are interested in the smallest x such that x+2k = i.
    // So, last_bad[i] will store the smallest x for the pattern ending at i.
    // If no such pattern ends at i, last_bad[i] is 0.
    std::vector<int> last_bad_start(n + 1, 0); // 1-indexed for convenience

    for (int i = 1; i <= n; ++i) { // i is the 1-indexed end of the potential pattern (x+2k)
        // Check for k=1: s[i-2] = s[i-1] = s[i]
        if (i >= 3 && s[i-3] == s[i-2] && s[i-2] == s[i-1]) {
            last_bad_start[i] = std::max(last_bad_start[i], i - 2);
        }
        // Check for k=2: s[i-4] = s[i-2] = s[i]
        if (i >= 5 && s[i-5] == s[i-3] && s[i-3] == s[i-1]) {
            last_bad_start[i] = std::max(last_bad_start[i], i - 4);
        }
        // Check for k=3: s[i-6] = s[i-3] = s[i]
        if (i >= 7 && s[i-7] == s[i-4] && s[i-4] == s[i-1]) {
            last_bad_start[i] = std::max(last_bad_start[i], i - 6);
        }
    }

    // Now, calculate the number of "good" pairs (l, r)
    // A pair (l, r) is good if s[l...r] does NOT contain any triple pattern.
    // This means for all x, k such that l <= x and x+2k <= r, s[x], s[x+k], s[x+2k] are not all equal.
    // Equivalently, for any i from l+2 to r, last_bad_start[i] must be < l.

    // Iterate through all possible right endpoints r (1-indexed)
    for (int r = 1; r <= n; ++r) {
        // max_start_idx_for_r is the maximum starting index x (1-indexed)
        // such that s[x...r] contains a triple pattern.
        // If no such pattern exists ending at or before r, it's 0.
        int max_start_idx_for_r = 0;
        for (int i = 1; i <= r; ++i) {
            max_start_idx_for_r = std::max(max_start_idx_for_r, last_bad_start[i]);
        }

        // If max_start_idx_for_r is 0, it means no triple pattern exists in s[1...r].
        // All pairs (l, r) for 1 <= l <= r are good. There are r such pairs.
        // If max_start_idx_for_r > 0, it means there is at least one triple pattern
        // s[x...x+2k] where x+2k <= r, and the smallest x for such a pattern is max_start_idx_for_r.
        // Any l such that l <= max_start_idx_for_r will make (l, r) a bad pair.
        // So, for a fixed r, the good pairs (l, r) are those where l > max_start_idx_for_r.
        // The number of such l's is r - max_start_idx_for_r.
        // If max_start_idx_for_r >= r, it means all l's (1 to r) would make (l,r) a bad pair.
        // In this case, r - max_start_idx_for_r would be <= 0, correctly counting 0 good pairs.
        bad_pairs += max_start_idx_for_r;
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1 (one cut)
    // Cut s into s1 and s2. Rearrange to s2 + s1.
    // s1 = s.substr(0, i), s2 = s.substr(i, n-i)
    // New string s' = s.substr(i, n-i) + s.substr(0, i)
    // We need s' to be a palindrome and s' != s.
    for (int i = 1; i < n; ++i) { // i is the length of s1, so s1 is s[0...i-1]
                                  // s2 is s[i...n-1]
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (is_palindrome(s_prime) && s_prime != s) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2 (two cuts)
    // This means 3 pieces: s1, s2, s3.
    // s = s1 + s2 + s3
    // The problem statement implies that if a solution exists, k=1 or k=2 will be sufficient.
    // If k=1 doesn't work, it means no single cut and swap creates a new palindrome.
    // This implies that for any cut point i, s[i...n-1] + s[0...i-1] is either not a palindrome
    // or it is equal to s.
    //
    // Consider the structure of s. Since s is a palindrome, s[j] == s[n-1-j].
    // If all characters in s are the same (e.g., "aaaaa"), then any rearrangement of pieces
    // will result in the same string "aaaaa". In this case, it's impossible.
    // We can check this by counting unique characters. If there's only one unique character,
    // and n > 1, it's impossible. If n=1, it's also impossible.
    //
    // If not all characters are the same, then there must be at least two distinct characters.
    // Example: "nolon" -> 'n', 'o', 'l'.
    //
    // If k=1 doesn't work, it means that for any split s = A + B, B + A is either not a palindrome
    // or B + A == s.
    //
    // Let's consider the case where s has at least two distinct characters.
    // If s has at least two distinct characters, and n > 1, then it's always possible to make 2 cuts.
    //
    // Example: "nolon"
    // n=5
    // k=1 checks:
    // i=1: s1="n", s2="olon". s'="olonn". Not palindrome.
    // i=2: s1="no", s2="lon". s'="lonno". Not palindrome.
    // i=3: s1="nol", s2="on". s'="onnol". Not palindrome.
    // i=4: s1="nolo", s2="n". s'="nnolo". Not palindrome.
    // So k=1 is not possible for "nolon".
    //
    // For "nolon", k=2:
    // Cut: no|l|on. Pieces: "no", "l", "on".
    // Rearrange: "on", "l", "no". New string: "onlno". This is a palindrome and != "nolon".
    // So k=2 is the answer.
    //
    // The only case where k=2 might not work is if all characters are the same.
    // If all characters are the same, e.g., "qqqq", then any rearrangement of pieces
    // will result in "qqqq".
    //
    // Let's check if all characters in s are the same.
    bool all_same = true;
    if (n > 0) {
        char first_char = s[0];
        for (int i = 1; i < n; ++i) {
            if (s[i] != first_char) {
                all_same = false;
                break;
            }
        }
    } else { // Empty string, though constraints say 1 <= |s|
        all_same = true;
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work, then k=2 must be the answer.
        // This is because we can always make 2 cuts to get 3 pieces.
        // For example, take s = A B C, where A is the first character, C is the last character,
        // and B is the middle part.
        // Since s is a palindrome, A == C.
        // If not all characters are the same, then there must be some character in B that is
        // different from A (and C).
        //
        // Consider cutting s into s[0...i-1], s[i...j-1], s[j...n-1].
        // If n is odd, say n = 2m + 1. s = s[0...m-1] + s[m] + s[m+1...2m].
        // Let s1 = s[0...m-1], s2 = s[m], s3 = s[m+1...2m].
        // Since s is a palindrome, s1 is the reverse of s3.
        // If we rearrange to s3 + s2 + s1, this will be a palindrome.
        // Example: "nolon". n=5, m=2.
        // s1="no", s2="l", s3="on".
        // s3 + s2 + s1 = "on" + "l" + "no" = "onlno". This is a palindrome and != "nolon".
        // This works if s1 is not empty. If s1 is empty (n=1), then all_same would be true.
        //
        // What if n is even, say n = 2m. s = s[0...m-1] + s[m...2m-1].
        // Let s1 = s[0...m-1], s2 = s[m...2m-1].
        // s1 is the reverse of s2.
        // If we cut s1 into s1_a and s1_b, and s2 into s2_a and s2_b.
        // This is getting complicated.
        //
        // The problem statement implies that if a solution exists, k=1 or k=2 will be sufficient.
        // The logic is:
        // 1. If all characters are the same (e.g., "aaaa"), it's impossible.
        // 2. Otherwise, there are at least two distinct characters.
        // 3. Try k=1. If it works, output 1.
        // 4. If k=1 doesn't work, it means for any split s=A+B, B+A is either not a palindrome or B+A=s.
        //    In this specific scenario (s is a palindrome, not all chars are same, k=1 fails),
        //    it can be proven that k=2 will always work.
        //    A simple way to achieve k=2 is to cut s into s[0], s[1...n-2], s[n-1].
        //    Let s1 = s[0], s2 = s[1...n-2], s3 = s[n-1].
        //    Since s is a palindrome, s[0] == s[n-1], so s1 == s3.
        //    Rearrange to s3 + s2 + s1. This will be a palindrome.
        //    s3 + s2 + s1 = s[n-1] + s[1...n-2] + s[0].
        //    This new string is a palindrome because s[n-1] == s[0] and s[1...n-2] is a palindrome
        //    (since s is a palindrome).
        //    Is s3 + s2 + s1 != s?
        //    s = s[0] + s[1...n-2] + s[n-1].
        //    s' = s[n-1] + s[1...n-2] + s[0].
        //    Since s[0] == s[n-1], s' is identical to s. This specific cut doesn't work.
        //
        // The example "nolon" -> 2.
        // s1="no", s2="l", s3="on". Rearrange to "on", "l", "no" -> "onlno".
        // This is achieved by cutting at index 2 and index 3.
        // s.substr(0,2), s.substr(2,1), s.substr(3,2)
        // Pieces: "no", "l", "on".
        // Rearranged: "on", "l", "no".
        //
        // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2 is the answer.
        // The only "Impossible" case is when all characters are the same.
        // So, if we reach here, it means not all characters are the same, and k=1 failed.
        // Therefore, the answer must be 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    int h_idx = 0; // Current head index

    while (p_idx < m && h_idx < n) {
        // Find the first target track p[p_idx] that is reachable by h[h_idx]
        // A head h[h_idx] can reach tracks in [h[h_idx] - T, h[h_idx] + T]
        // If p[p_idx] is too far to the left for h[h_idx], move to the next head.
        if (p[p_idx] < h[h_idx] - T) {
            // This p[p_idx] cannot be covered by h[h_idx] (or any subsequent head, as h is sorted)
            // This logic is incorrect. A head h[h_idx] might be able to cover p[p_idx] if it moves left.
            // The problem is to cover ALL p_i.
            // We need to assign heads to cover tracks.
            // A greedy approach:
            // For the current head h[h_idx], find the rightmost track it can cover.
            // Then advance p_idx past all tracks covered by this head.
            // If p_idx reaches m, then all tracks are covered.

            // Let's re-think the greedy strategy for check(T).
            // We want to cover all p_i using n heads, each moving at most T.
            // Iterate through the heads. For each head, try to cover as many *uncovered* tracks as possible,
            // starting from the leftmost uncovered track.

            // p_idx points to the first *uncovered* track.
            // h_idx points to the current head we are considering.

            // If the current head h[h_idx] cannot reach p[p_idx] (even by moving left by T),
            // then this configuration is impossible.
            // This means p[p_idx] < h[h_idx] - T.
            // However, this is not necessarily true. We can use h[h_idx] to cover p[p_idx] if
            // h[h_idx] - T <= p[p_idx] <= h[h_idx] + T.
            // If p[p_idx] is to the left of h[h_idx] - T, then h[h_idx] cannot cover it.
            // But we are iterating through heads. If h[h_idx] cannot cover p[p_idx], then no h[k] with k > h_idx can either,
            // because h[k] > h[h_idx]. So p[p_idx] would be uncovered.
            // This means if p[p_idx] < h[h_idx] - T, then it's impossible.
            // This is the condition for failure.

            // If h[h_idx] can reach p[p_idx] (i.e., p[p_idx] >= h[h_idx] - T),
            // then we use h[h_idx] to cover p[p_idx] and potentially subsequent tracks.
            // The rightmost track h[h_idx] can cover is h[h_idx] + T.
            // So, we advance p_idx past all tracks that are <= h[h_idx] + T.
            // After covering, we move to the next head.
            // This greedy strategy works because heads are sorted and tracks are sorted.
            // Assigning h[h_idx] to cover p[p_idx] and its right neighbors is optimal
            // because h[h_idx] cannot cover anything to the left of p[p_idx] (which would have been covered by previous heads).
