            }

            // If p[p_idx] is reachable by h[h_idx], then h[h_idx] can cover tracks up to h[h_idx] + T.
            long long current_head_reach_right = h[h_idx] + T;
            while (p_idx < m && p[p_idx] <= current_head_reach_right) {
                p_idx++; // This track is covered
            }
            h_idx++; // Move to the next head
        }
    }

    // If all target tracks are covered (p_idx == m), return true.
    return p_idx == m;
