#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick n even numbers starting from 2n+2,
        // specifically 2n+2, 2n+4, ..., 4n.
        // This sequence has (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n numbers.
        // All numbers are even, so gcd(a,b) >= 2.
        // For any a, b in this set, a = 2k, b = 2j.
        // If a divides b, then 2k divides 2j, which means k divides j.
        // The numbers are 2n+2, 2n+4, ..., 4n.
        // The corresponding k values are n+1, n+2, ..., 2n.
        // For any k_i, k_j from {n+1, ..., 2n}, if k_i divides k_j,
        // then k_j must be at least 2 * k_i.
        // The smallest k_i is n+1. The largest k_j is 2n.
        // If k_i divides k_j, then k_j >= 2 * k_i.
        // But 2 * k_i = 2 * (n+1) = 2n+2.
        // Since k_j <= 2n, it's impossible for k_j to be >= 2n+2.
        // Therefore, no k_i divides k_j (and vice versa) for distinct k_i, k_j.
        // This means no 2k_i divides 2k_j (and vice versa).
        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (n + 1 + i) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

