    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int num_ones = 0;
    if (counts['o'] > 0 && counts['n'] > 0 && counts['e'] > 0) {
        num_ones = std::min({counts['o'], counts['n'], counts['e']});
    }

    // After forming 'num_ones' "one"s, update counts for remaining letters
    counts['o'] -= num_ones;
    counts['n'] -= num_ones;
    counts['e'] -= num_ones;

    int num_zeros = 0;
    if (counts['z'] > 0 && counts['e'] > 0 && counts['r'] > 0 && counts['o'] > 0) {
        num_zeros = std::min({counts['z'], counts['e'], counts['r'], counts['o']});
    }

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

