#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for coal and torches = k * y + k.
        // We start with 1 stick.
        // The number of additional sticks we need to acquire is (k * y + k) - 1.
        long long sticks_to_acquire = k * y + k - 1;

        // Each trade of type 1 (1 stick for x sticks) effectively gives us x - 1 net sticks.
        // We need to find how many such trades are needed to get 'sticks_to_acquire' sticks.
        // Let 'num_stick_trades' be the number of times we use the 1 stick -> x sticks trade.
        // Each such trade costs 1 trade.
        // The total number of sticks we have after 'num_stick_trades' is 1 + num_stick_trades * (x - 1).
        // We need 1 + num_stick_trades * (x - 1) >= sticks_to_acquire + 1 (since we start with 1 stick).
        // Or, more simply, we need to generate 'sticks_to_acquire' sticks using the (x-1) net gain.
        // num_stick_trades = ceil(sticks_to_acquire / (x - 1))
        long long num_stick_trades = (sticks_to_acquire + (x - 1) - 1) / (x - 1);

        // Total trades = num_stick_trades (for acquiring sticks) + k (for acquiring k coal).
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << std::endl;
    }
    return 0;
}

