int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is 0, it means all other elements in the row are 0.
        // This can only happen if n=2 and p[i]=1, p[j]=0 (not possible as p is 1 to n)
        // or if p[i]=1 and all other p[j] are also 1 (not possible as p is a permutation).
        // The only way max_val_in_row can be 0 is if n=1, but n >= 2.
        // So max_val_in_row will be at least 1.
        // If max_val_in_row is less than n, then p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row < n) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

