#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks to partition 2n students into two classes,
        // each with an odd number of students.
        // Let the sorted skill levels be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the smallest possible odd class size, which is 1.
        // If one class has size 1, its median is its only element.
        // The other class would have size 2n-1.
        //
        // Let's analyze the median for a class of size 2k+1.
        // The median is the (k+1)-th element (0-indexed: k-th element).
        //
        // If we sort all 2n students, a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the partition where the first class consists of students
        // with skill levels a_0, ..., a_{n-1} and the second class consists of
        // students with skill levels a_n, ..., a_{2n-1}.
        //
        // This partition is not valid because both classes would have size n.
        // If n is even, this is not allowed. If n is odd, it is allowed.
        //
        // However, the problem statement implies that we can choose any odd sizes
        // for the classes.
        //
        // Let's consider the specific case where the first class has students
        // a_0, ..., a_{n-1} and the second class has students a_n, ..., a_{2n-1}.
        //
        // If n is odd, then both classes have size n (odd).
        // The median of the first class (a_0, ..., a_{n-1}) would be a_{(n-1)/2}.
        // The median of the second class (a_n, ..., a_{2n-1}) would be a_{n + (n-1)/2}.
        // The difference would be |a_{n + (n-1)/2} - a_{(n-1)/2}|.
        //
        // If n is even, this partition is not valid.
        //
        // The key insight for this problem is that to minimize the difference between medians,
        // we should try to make the medians as close as possible.
        //
        // If we sort all students, a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the two "middle" elements: a_{n-1} and a_n.
        //
        // If we can make a_{n-1} the median of one class and a_n the median of the other class,
        // then the difference would be |a_n - a_{n-1}|.
        //
        // Can we always achieve this?
        //
        // Let's try to construct two classes such that a_{n-1} is the median of the first class
        // and a_n is the median of the second class.
        //
        // For a_{n-1} to be the median of a class of size 2k_1+1, there must be k_1 elements
        // less than or equal to a_{n-1} and k_1 elements greater than or equal to a_{n-1}.
        //
        // For a_n to be the median of a class of size 2k_2+1, there must be k_2 elements
        // less than or equal to a_n and k_2 elements greater than or equal to a_n.
        //
        // Consider the partition where:
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // Each class has exactly n students.
        // If n is odd, this is a valid partition.
        // The median of Class 1 is a_{(n-1)/2}.
        // The median of Class 2 is a_{n + (n-1)/2}.
        // The difference is |a_{n + (n-1)/2} - a_{(n-1)/2}|.
        //
        // The problem statement implies that the minimum difference is always achieved
        // by taking the two middle elements of the *sorted full array* as the medians
        // of the two classes.
        //
        // Let's verify this.
        // The elements are sorted: a_0, a_1, ..., a_{2n-1}.
        //
        // The median of the first class will be some a_i.
        // The median of the second class will be some a_j.
        //
        // To minimize |a_j - a_i|, we want a_i and a_j to be as close as possible.
        //
        // Consider the elements a_{n-1} and a_n.
        //
        // If we make a_{n-1} the median of the first class, and a_n the median of the second class.
        //
        // Class 1: We need to pick k_1 elements from {a_0, ..., a_{n-2}} and k_1 elements from {a_n, ..., a_{2n-1}}
        // along with a_{n-1} to form Class 1.
        // This is not how it works. The elements are chosen from the original set.
        //
        // The problem is simpler than that.
        // The minimum possible difference between the medians of two classes, each of odd size,
        // is always achieved by taking the difference between the two middle elements
        // of the *entire sorted array*.
        //
        // That is, if the sorted array is $a_0, a_1, \dots, a_{2n-1}$,
        // the minimum difference is $|a_n - a_{n-1}|$.
        //
        // Let's prove this.
        // Suppose we have two classes $C_1$ and $C_2$ with medians $m_1$ and $m_2$.
        // Let $m_1$ be the $k_1$-th element in sorted $C_1$ and $m_2$ be the $k_2$-th element in sorted $C_2$.
        //
        // The total number of elements is $2n$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // The median of any class must be one of the $a_i$.
        //
        // Let $m_1$ be the median of the first class and $m_2$ be the median of the second class.
        // Without loss of generality, assume $m_1 \le m_2$.
        //
        // For $m_1$ to be the median of its class, there must be at least $(|C_1|-1)/2$ elements
        // in $C_1$ that are less than or equal to $m_1$.
        // For $m_2$ to be the median of its class, there must be at least $(|C_2|-1)/2$ elements
        // in $C_2$ that are greater than or equal to $m_2$.
        //
        // The total number of elements less than or equal to $m_1$ is at least $(|C_1|-1)/2 + 1$.
        // The total number of elements greater than or equal to $m_2$ is at least $(|C_2|-1)/2 + 1$.
        //
        // Summing these up:
        // Number of elements $\le m_1$ + Number of elements $\ge m_2$
        // $\ge ((|C_1|-1)/2 + 1) + ((|C_2|-1)/2 + 1)$
        // $= (|C_1|+|C_2|)/2 - 1/2 - 1/2 + 2$
        // $= (2n)/2 - 1 + 2 = n+1$.
        //
        // This means there are at least $n+1$ elements that are either $\le m_1$ or $\ge m_2$.
        //
        // In the sorted array $a_0, \dots, a_{2n-1}$:
        // The elements $a_0, \dots, a_{n-1}$ are $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are $n$ elements.
        //
        // If $m_1$ is $a_i$ and $m_2$ is $a_j$.
        //
        // The number of elements $\le a_{n-1}$ is $n$.
        // The number of elements $\ge a_n$ is $n$.
        //
        // If $m_1 < a_{n-1}$, then $m_1$ is one of $a_0, \dots, a_{n-2}$.
        // If $m_2 > a_n$, then $m_2$ is one of $a_{n+1}, \dots, a_{2n-1}$.
        //
        // The crucial observation is that the $n$-th element (0-indexed $a_{n-1}$) and the $(n+1)$-th element (0-indexed $a_n$)
        // are the "middle" two elements of the entire sorted array.
        //
        // We can always form two classes such that $a_{n-1}$ is the median of one and $a_n$ is the median of the other.
        //
        // Example:
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // If n is odd, this is a valid partition.
        // Median of Class 1 is a_{(n-1)/2}.
        // Median of Class 2 is a_{n + (n-1)/2}.
        // The difference is |a_{n + (n-1)/2} - a_{(n-1)/2}|.
        // This is not necessarily |a_n - a_{n-1}|.
        //
        // The problem is simpler:
        // The minimum difference is always achieved by taking the difference between $a_{n-1}$ and $a_n$.
        //
        // Why?
        // Let $m_1$ and $m_2$ be the medians of the two classes, with $m_1 \le m_2$.
        //
        // The first class has size $2k_1+1$. It contains $k_1$ elements $\le m_1$ and $k_1$ elements $\ge m_1$.
        // The second class has size $2k_2+1$. It contains $k_2$ elements $\le m_2$ and $k_2$ elements $\ge m_2$.
        //
        // The total number of elements $\le m_1$ in the entire set is at least $k_1+1$.
        // The total number of elements $\ge m_2$ in the entire set is at least $k_2+1$.
        //
        // The total number of elements is $2n$.
        // The number of elements strictly between $m_1$ and $m_2$ is $2n - (\text{count of } \le m_1) - (\text{count of } \ge m_2 \text{ excluding } m_1 \text{ if } m_1=m_2)$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // The $n$-th element (0-indexed $a_{n-1}$) is the largest among the first $n$ elements.
        // The $(n+1)$-th element (0-indexed $a_n$) is the smallest among the last $n$ elements.
        //
        // It is always possible to construct two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // For example, let Class 1 be $\{a_0, a_1, \dots, a_{n-1}\}$ and Class 2 be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is a valid partition if $n$ is odd.
        // In this case, the medians are $a_{(n-1)/2}$ and $a_{n+(n-1)/2}$.
        //
        // The problem is simpler: the minimum difference is always $a_n - a_{n-1}$.
        // This is a known property for this type of problem.
        //
        // Let's confirm with examples:
        // n=1, 2n=2. a = [1, 1]. Sorted: [1, 1].
        // a_{n-1} = a_0 = 1. a_n = a_1 = 1. Difference = |1-1| = 0. Correct.
        //
        // n=3, 2n=6. a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // a_{n-1} = a_2 = 3. a_n = a_3 = 4. Difference = |4-3| = 1. Correct.
        //
        // n=5, 2n=10. a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16].
        // Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // a_{n-1} = a_4 = 8. a_n = a_5 = 13. Difference = |13-8| = 5. Correct.
        //
        // The solution is simply to sort the array and take the absolute difference
        // between the element at index n-1 and the element at index n.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
