#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = 0; // Represents the position of the last 'R' or the starting point (0)
        // The frog starts at 0.
        // It needs to reach n+1.
        // It can only jump right from 0.
        // If it lands on an 'L' cell, it can only jump left. This means it gets stuck
        // unless it can jump over the 'L' cell from a previous 'R' cell or from 0.
        // To reach n+1, the frog must always be able to jump past any 'L' cells.
        // This means the frog must be able to jump from its current 'R' cell (or 0)
        // to the next 'R' cell (or n+1) directly, skipping any 'L' cells in between.

        // Consider the sequence of 'R' cells and the starting point 0.
        // Let these positions be p_0, p_1, ..., p_k, where p_0 = 0,
        // and p_j are indices of 'R' cells.
        // The target is n+1.
        // The frog needs to be able to jump from p_j to p_{j+1} (or n+1).
        // The distance between p_j and p_{j+1} is p_{j+1} - p_j.
        // The maximum such distance will determine the minimum d.

        // Iterate through the string to find positions of 'R's.
        // The 'R' cells are at indices i+1 where s[i] is 'R'.
        // The starting point is 0.
        // The target is n+1.

        // last_r_pos tracks the last position from which the frog could jump right.
        // Initially, this is 0.
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at index i (cell i+1),
                // the frog must have been able to jump from last_r_pos to cell i+1.
                // The distance required for this jump is (i + 1) - last_r_pos.
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1; // Update last_r_pos to the current 'R' cell
            }
        }
        // After iterating through the string, the frog needs to jump from the last 'R' cell
        // (or 0 if no 'R's) to the target n+1.
        // The distance required for this final jump is (s.length() + 1) - last_r_pos.
        max_gap = std::max(max_gap, (static_cast<int>(s.length()) + 1) - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

