    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents 2^0, 2^1, 2^2, ...
        while (true) {
            // Cost of a nice staircase with (2^k - 1) stairs
            // is (2^k - 1) * (2^k) / 2
            // which is (2^k - 1) * 2^(k-1)
            // Let m = 2^k - 1. The cost is m * (m+1) / 2.
            // The problem states the cost is (2^k - 1) * 2^(k-1)
            // Let's verify:
            // For k=1, m=1. Cost = 1 * 2^0 = 1. (1 * 2 / 2 = 1)
            // For k=2, m=3. Cost = 3 * 2^1 = 6. (3 * 4 / 2 = 6)
            // For k=3, m=7. Cost = 7 * 2^2 = 28. (7 * 8 / 2 = 28)
            // This formula is correct.

            // The cost of the next nice staircase is (2*k - 1) * k
            // where k here is 2^(i-1) from the derivation.
            // Let's use `val` for the current `k` in the sequence 1, 2, 4, 8, ...
            // The number of stairs is `2*val - 1`.
            // The cost is `(2*val - 1) * val`.

            long long stairs_count = 2 * k - 1;
            long long cost_of_this_staircase = stairs_count * k;

            if (current_cost + cost_of_this_staircase <= x) {
                current_cost += cost_of_this_staircase;
                count++;
                k *= 2; // Next staircase will have 2*(2k)-1 stairs, and cost (2*(2k)-1)*(2k)
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

