#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    bool possible = true;

    // Determine p_i for indices where q_i > q_{i-1}
    // These p_i values must be q_i
    p[0] = q[0];
    if (p[0] < 1 || p[0] > n) { // p_1 must be within [1, n]
        possible = false;
    } else {
        used_values.insert(p[0]);
    }

    for (int i = 1; i < n; ++i) {
        if (!possible) break;
        if (q[i] > q[i-1]) {
            p[i] = q[i];
            if (p[i] < 1 || p[i] > n || used_values.count(p[i])) {
                possible = false;
            } else {
                used_values.insert(p[i]);
            }
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Fill in remaining p_i values
    // These p_i values must be less than q_i and not yet used.
    // To maximize chances of success, use the smallest available unused values.
    std::vector<int> available_values;
    for (int i = 1; i <= n; ++i) {
        if (used_values.find(i) == used_values.end()) {
            available_values.push_back(i);
        }
    }
    std::reverse(available_values.begin(), available_values.end()); // Use largest available first for greedy strategy

    for (int i = 1; i < n; ++i) {
        if (q[i] == q[i-1]) {
            if (available_values.empty()) { // No values left to assign
                possible = false;
                break;
            }
            int val_to_assign = available_values.back();
            available_values.pop_back();

            if (val_to_assign > q[i]) { // p_i must be <= q_i
                possible = false;
                break;
            }
            p[i] = val_to_assign;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

