    // The remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order.
    // This will produce differences of 1, which is already one of the k distinct differences (the smallest one).
    // So, no new distinct differences are introduced.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

