#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // For m > 1, we extend the current segment [min_idx...max_idx]
        // to include the number m.
        // The new segment must span from min(current_min_idx, pos[m])
        // to max(current_max_idx, pos[m]).
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if there exists a subsegment [l, r]
        // such that it contains 1, 2, ..., m and nothing else.
        // This implies:
        // 1. The length of the subsegment (r - l + 1) must be m.
        // 2. The minimum value in the subsegment must be 1.
        // 3. The maximum value in the subsegment must be m.
        //
        // By maintaining current_min_idx and current_max_idx, we are tracking
        // the smallest possible range [current_min_idx, current_max_idx]
        // that contains all numbers from 1 to m.
        //
        // If this range [current_min_idx, current_max_idx] has length m,
        // then it means all numbers from 1 to m are present in this range,
        // and no other numbers are present (because its length is exactly m).
        // The minimum value in this range is 1 (by construction, as we include pos[1]).
        // The maximum value in this range is m (by construction, as we include pos[m] and all values up to m).
        //
        // So, m is beautiful if and only if (current_max_idx - current_min_idx + 1) == m.
        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

