        // i=0: a[0]=-1, b[0]=-1. Equal. OK.
        //      has_one_prefix = false
        //      has_minus_one_prefix = true
        //
        // i=1: a[1]=0, b[1]=-41. a[1] > b[1]. Need to decrease.
        //      has_minus_one_prefix is true. Possible. OK.
        //      has_one_prefix = false
        //      has_minus_one_prefix = true
        //
        // Result: YES. Matches example.

