        // If `a[0] > b[0]`, `!has_minus_one_prefix` is true, so `possible = false`.
        // If `a[0] == b[0]`, it continues. This is correct.

        // The solution seems robust under the simple interpretation.
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
