int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int count01 = 0; // count of positions where a[i] = '0' and b[i] = '1'
    int count10 = 0; // count of positions where a[i] = '1' and b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                count01++;
            } else { // a[i] = '1', b[i] = '0'
                count10++;
            }
        }
    }

    // The number of pairs of (0->1) and (1->0) that can be resolved by swaps
    // is min(count01, count10).
    // Each such swap effectively resolves two mismatches.
    // The cost of such a swap is 1 (because we can always find adjacent ones or use flips).
    // However, the problem states cost is |i-j|.
    // Let's re-evaluate.

    // Consider the state of the string `a` as we iterate.
    // `diff_01_needed`: number of '0's in `a` that need to become '1's.
    // `diff_10_needed`: number of '1's in `a` that need to become '0's.
    // These are the counts of `a[i] = '0', b[i] = '1'` and `a[i] = '1', b[i] = '0'` respectively.

    // We can process the string from left to right.
    // `current_01_available`: number of '0's encountered so far that need to become '1's.
    // `current_10_available`: number of '1's encountered so far that need to become '0's.

    int current_01_available = 0;
    int current_10_available = 0;

    for (int i = 0; i < n; ++i) {
        if (a[i] == '0' && b[i] == '1') { // This '0' needs to become '1'
            if (current_10_available > 0) { // We have an available '1' that needs to become '0'
                // We can swap this '0' with that '1'. Cost is 1.
                // This resolves both mismatches.
                current_10_available--;
                cost++;
            } else {
                // No '1' available to swap with. This '0' must wait or be flipped.
                // We count it as an available '0' that needs to become '1'.
                current_01_available++;
            }
        } else if (a[i] == '1' && b[i] == '0') { // This '1' needs to become '0'
            if (current_01_available > 0) { // We have an available '0' that needs to become '1'
                // We can swap this '1' with that '0'. Cost is 1.
                // This resolves both mismatches.
                current_01_available--;
                cost++;
            } else {
                // No '0' available to swap with. This '1' must wait or be flipped.
                // We count it as an available '1' that needs to become '0'.
                current_10_available++;
            }
        }
        // If a[i] == b[i], nothing needs to be done at this position.
        // The available counts remain unchanged.
    }

    // After iterating through the string, any remaining `current_01_available`
    // or `current_10_available` must be resolved by flips.
    // Each remaining mismatch requires one flip.
    cost += current_01_available;
    cost += current_10_available;

    std::cout << cost << std::endl;

    return 0;
}

