// Function to check if a sub-array is a permutation of length 'len'
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) { // A permutation of length 0 is vacuously true, but problem states non-zero lengths
        return false; // Based on problem constraints l1, l2 >= 1
    }
    if (len > arr.size() - start_idx) { // Not enough elements for the given length
        return false;
    }

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;

    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    return max_val == len; // All numbers from 1 to len must be present, and max must be len
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix maximums and suffix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute prefix distinct counts and suffix distinct counts
    std::vector<int> prefix_distinct_count(n);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_distinct_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] <= n && !seen_prefix[a[i]]) { // a[i] can be up to n-1, so n+1 size is fine
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        prefix_distinct_count[i] = current_distinct_prefix;
    }

    std::vector<int> suffix_distinct_count(n);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_distinct_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] <= n && !seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        suffix_distinct_count[i] = current_distinct_suffix;
    }

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1 (inclusive)
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check conditions for p1 (first l1 elements)
        // 1. Max element in p1 must be l1
        // 2. Number of distinct elements in p1 must be l1
        bool p1_is_perm = (prefix_max[l1 - 1] == l1) && (prefix_distinct_count[l1 - 1] == l1);

        // Check conditions for p2 (last l2 elements)
        // 1. Max element in p2 must be l2
        // 2. Number of distinct elements in p2 must be l2
        bool p2_is_perm = (suffix_max[l1] == l2) && (suffix_distinct_count[l1] == l2);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

