int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int current_score = 0;
        int initial_wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                initial_wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (initial_wins == 0) { // All 'L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // If we change k 'L's to 'W's, we get k wins.
                // The best way is to make them consecutive: WW...W (k times)
                // Score: 1 (for first W) + 2*(k-1) (for subsequent Ws)
                // If k=0, score is 0. If k=1, score is 1.
                // This can be simplified to 2*k - 1, but only if k >= 1.
                // If k=0, it's 0. If k=1, it's 1. If k=2, it's 3.
                // The formula 2*k - 1 works for k >= 1.
                std::cout << std::max(0, 2 * k - 1) << "\n";
            }
            continue;
        }

        // If there are initial wins, we can improve the score.
        // Each 'L' converted to 'W' costs 1 k.
        // It adds 1 point if it's isolated or next to an 'L'.
        // It adds 2 points if it connects two 'W' segments or extends a 'W' segment.
        // The most efficient way to use k is to fill gaps between 'W's.
        // Filling a gap of length `len` costs `len` changes and adds `2*len` points.
        // Converting an 'L' at the start/end or an isolated 'L' costs 1 change and adds 1 point.

        std::vector<int> gap_lengths;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        // Collect gap lengths between 'W's
        int current_gap = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gap_lengths.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        if (current_gap > 0) { // Last gap before last_W
            gap_lengths.push_back(current_gap);
        }
        std::sort(gap_lengths.begin(), gap_lengths.end());

        // Fill gaps
        for (int gap_len : gap_lengths) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len; // Each L in gap becomes W, adds 2 points
            } else {
                // Not enough k to fill this gap, fill partially
                current_score += 2 * k;
                k = 0;
                break;
            }
        }

        // Use remaining k to convert 'L's at the ends or isolated 'L's
        // Each such conversion adds 1 point.
        // We can convert at most `n - initial_wins` 'L's.
        // The number of 'L's we can convert is `k`.
        // Each such conversion adds 1 point.
        current_score += std::min(k, n - initial_wins);

        std::cout << current_score << "\n";
    }
    return 0;
}

