// Function to determine if a box can be the special box
// Returns a tuple of four booleans: {can_be_box1, can_be_box2, can_be_box3, can_be_box4}
std::vector<bool> solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    if (total_toys == 1) {
        return {A == 1, B == 1, C == 1, D == 1};
    }

    // Initialize possibilities for each box
    bool can_be_box1 = false; // (-inf, -1]
    bool can_be_box2 = false; // (-1, 0)
    bool can_be_box3 = false; // (0, 1)
    bool can_be_box4 = false; // [1, inf)

    // Case 1: Final product is positive
    // This happens if the number of negative toys multiplied is even.
    // The number of negative toys can be changed by multiplying two negative toys (N*N -> P)
    // or by multiplying a negative and a positive toy (N*P -> N).
    // The parity of negative toys can be flipped if we have at least one negative toy and at least one positive toy.
    // If we only have negative toys, the parity is fixed.
    // If we only have positive toys, the parity is fixed (0, even).

    // Let's consider the parity of negative numbers.
    // Initial negative count: A + B
    // If A+B is even, the final product can be positive.
    // If A+B is odd, the final product can be negative.
    // However, we can change the parity of negative numbers if we have at least one negative toy and at least one positive toy.
    // E.g., if A+B is odd, and we have C+D > 0, we can multiply a negative toy with a positive toy.
    // This results in a negative toy. The count of negative toys remains odd.
    // If we multiply two negative toys, the count of negative toys decreases by 2 (odd -> odd, even -> even).
    // If we multiply two positive toys, the count of negative toys remains the same.
    // So, the parity of negative toys is invariant unless we consider the "effective" parity.

    // A simpler approach:
    // The final product can be positive if:
    // 1. The initial number of negative toys (A+B) is even.
    // 2. The initial number of negative toys (A+B) is odd, AND we can perform an odd number of N*P multiplications.
    //    This is equivalent to saying we can choose to have an even number of negative factors in the final product.
    //    This is possible if we have at least one negative toy (A+B > 0) and at least one positive toy (C+D > 0).
    //    If A+B is odd, and C+D > 0, we can always make the final product negative (by ensuring an odd number of N*P ops).
    //    If A+B is odd, and C+D > 0, we can also make the final product positive (by ensuring an even number of N*P ops).
    //    This is because we can always pair up negative numbers if there are enough positive numbers to "absorb" them.
    //    Example: N1, N2, N3, P1, P2. (3 neg, 2 pos). N1*P1 -> N'. N', N2, N3, P2. (3 neg, 1 pos). N'*P2 -> N''. N'', N2, N3. (3 neg). N''*N2 -> P'''. P''', N3. (1 neg). Final is negative.
    //    Example: N1, N2, N3, P1, P2. N1*N2 -> P'. P', N3, P1, P2. (1 neg, 3 pos). P'*P1 -> P''. P'', N3, P2. (1 neg, 2 pos). P''*P2 -> P'''. P''', N3. (1 neg). Final is negative.
    //    The parity of the number of negative factors in the final product is fixed by (A+B) % 2, unless we have both negative and positive numbers.
    //    If A+B > 0 and C+D > 0, we can choose the final sign.
    //    If A+B == 0, final sign is positive.
    //    If C+D == 0, final sign is negative if A+B is odd, positive if A+B is even.

    bool can_be_positive_final = false;
    bool can_be_negative_final = false;

    if (A + B == 0) { // All positive toys
        can_be_positive_final = true;
    } else if (C + D == 0) { // All negative toys
        if ((A + B) % 2 == 0) {
            can_be_positive_final = true;
        } else {
            can_be_negative_final = true;
        }
    } else { // Mixed positive and negative toys
        can_be_positive_final = true;
        can_be_negative_final = true;
    }

    // Now consider magnitude relative to 1.
    // Let's count the number of toys that are "magnitude >= 1" (Box 1 and Box 4)
    // and "magnitude < 1" (Box 2 and Box 3).
    long long num_mag_ge_1 = A + D;
    long long num_mag_lt_1 = B + C;

    // A toy with magnitude >= 1 is called a "large" toy.
    // A toy with magnitude < 1 is called a "small" toy.

    // If we multiply two large toys, the result is large. (L*L -> L)
    // If we multiply a large and a small toy, the result can be large or small. (L*S -> L or S)
    // If we multiply two small toys, the result is small. (S*S -> S)

    // The final product can be large if:
    // 1. There is at least one large toy (A+D > 0).
    // 2. We can always ensure that the final product is large by strategically multiplying large toys together.
    //    If A+D > 0, we can always make the final product large.
    //    Example: L, S1, S2. L*S1 -> L' (if S1 is close to 1). L'*S2 -> L'' (if S2 is close to 1).
    //    This is because we can choose the actual fun values.
    //    If we have at least one large toy, we can make the final product large.
    //    E.g., if we have L, S1, S2, ..., Sk. We can pick L to be very large (e.g., 100).
    //    Then L * S1 * S2 * ... * Sk can be made > 1 if S_i are close to 1.
    //    For example, if L=100, S_i=0.9. 100 * (0.9)^k. This can be > 1 for small k.
    //    But what if k is large? 100 * (0.9)^100 is very small.
    //    The problem states "you don't know their fun values". This implies we should consider all possibilities.
    //    So, if it's possible to pick values such that the final product is large, then it can be large.

    // Let's re-evaluate the magnitude.
    // The final product can be >= 1 if:
    // 1. There is at least one toy in Box 1 or Box 4 (A+D > 0).
    //    And we can choose values such that the product of all toys is >= 1.
    //    This is always possible if A+D > 0. We can pick one toy in Box 1 or Box 4 to have a very large magnitude (e.g., 10^9).
    //    And all other toys to have magnitudes close to 1 (e.g., 0.999 or 1.001).
    //    Then the product will be dominated by the very large magnitude toy.
    //    Example: A=1, B=1, C=1, D=1. Toys: -10, -0.5, 0.5, 10.
    //    (-10) * (-0.5) * (0.5) * (10) = 25. This is >= 1.
    //    So, if A+D > 0, it's possible for the final product to have magnitude >= 1.

    // The final product can be < 1 if:
    // 1. There is at least one toy in Box 2 or Box 3 (B+C > 0).
    //    And we can choose values such that the product of all toys is < 1.
    //    This is always possible if B+C > 0. We can pick one toy in Box 2 or Box 3 to have a very small magnitude (e.g., 0.001).
    //    And all other toys to have magnitudes close to 1 (e.g., 0.999 or 1.001).
    //    Then the product will be dominated by the very small magnitude toy.
    //    Example: A=1, B=1, C=1, D=1. Toys: -1.1, -0.01, 0.01, 1.1.
    //    (-1.1) * (-0.01) * (0.01) * (1.1) = 0.000121. This is < 1.
    //    So, if B+C > 0, it's possible for the final product to have magnitude < 1.

    bool can_be_mag_ge_1 = false;
    bool can_be_mag_lt_1 = false;

    if (A + D > 0) {
        can_be_mag_ge_1 = true;
    }
    if (B + C > 0) {
        can_be_mag_lt_1 = true;
    }

    // Special case: If all toys are in Box 1 or Box 4 (A+D > 0 and B+C == 0), then the magnitude must be >= 1.
    if (B + C == 0) {
        can_be_mag_lt_1 = false;
    }
    // Special case: If all toys are in Box 2 or Box 3 (A+D == 0 and B+C > 0), then the magnitude must be < 1.
    if (A + D == 0) {
        can_be_mag_ge_1 = false;
    }

    // Combine sign and magnitude possibilities
    if (can_be_negative_final) {
        if (can_be_mag_ge_1) {
            can_be_box1 = true;
        }
        if (can_be_mag_lt_1) {
            can_be_box2 = true;
        }
    }
    if (can_be_positive_final) {
        if (can_be_mag_lt_1) {
            can_be_box3 = true;
        }
        if (can_be_mag_ge_1) {
            can_be_box4 = true;
        }
    }

    // Edge case: If A+B+C+D == 0, this case is excluded by problem constraints (A+B+C+D > 0).

    // Another edge case: What if A+D=0 and B+C=0? This means total_toys=0, which is excluded.

    // Consider the case where A+D=0 (all toys are small magnitude)
    // Then can_be_mag_ge_1 must be false.
    // If A+D=0, then A=0, D=0. All toys are in B or C.
    // If B+C > 0, then can_be_mag_lt_1 is true.
    // So, if A+D=0, only Box 2 and Box 3 are possible.
    if (A + D == 0) {
        can_be_box1 = false;
        can_be_box4 = false;
    }

    // Consider the case where B+C=0 (all toys are large magnitude)
    // Then can_be_mag_lt_1 must be false.
    // If B+C=0, then B=0, C=0. All toys are in A or D.
    // If A+D > 0, then can_be_mag_ge_1 is true.
    // So, if B+C=0, only Box 1 and Box 4 are possible.
    if (B + C == 0) {
        can_be_box2 = false;
        can_be_box3 = false;
    }

    return {can_be_box1, can_be_box2, can_be_box3, can_be_box4};
}

