int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1000000007;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually need to pass this 'b'.
            // Each 'a' to the left of this 'b' will contribute to the steps.
            // The number of 'a's currently accumulated (count_a)
            // represents the 'a's that are to the left of this 'b'
            // and have not yet been processed (i.e., moved past a 'b').
            // When an 'a' moves past a 'b', it generates a new 'b'.
            // So, for each 'a' that passes this 'b', it adds 1 step,
            // and effectively doubles the number of 'a's that will
            // need to pass subsequent 'b's (because the original 'a'
            // is still there, and a new 'b' is generated).
            // This means the current count_a 'a's will each contribute
            // to moving past this 'b', and then each of them will
            // effectively double the 'a's that need to pass the next 'b'.
            // So, total_steps += count_a, and count_a *= 2.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now
            // available to move past any 'b's to its right.
            // So, we increment our count of 'a's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
