#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // If the array is already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // We need to append elements x, y, z such that:
    // (current_sum + x + y + z) = 2 * (current_xor_sum ^ x ^ y ^ z)

    // Strategy: Append two elements.
    // Let the first appended element be X_initial (current_xor_sum).
    // New XOR sum becomes X_initial ^ X_initial = 0.
    // New sum becomes S_initial + X_initial.
    // Now we need to append one more element, say P, such that:
    // (S_initial + X_initial + P) = 2 * (0 ^ P)
    // (S_initial + X_initial + P) = 2 * P
    // S_initial + X_initial = P
    // So, P = S_initial + X_initial.

    // The three elements to append would be:
    // 1. current_xor_sum
    // 2. current_sum + current_xor_sum
    // This strategy uses 2 elements.

    // Let's verify this strategy:
    // Initial: S_initial, X_initial
    // Append x1 = X_initial
    // New sum S' = S_initial + X_initial
    // New XOR sum X' = X_initial ^ X_initial = 0
    // Now we need to append x2 such that S' + x2 = 2 * (X' ^ x2)
    // S_initial + X_initial + x2 = 2 * (0 ^ x2)
    // S_initial + X_initial + x2 = 2 * x2
    // S_initial + X_initial = x2
    // So, x2 = S_initial + X_initial.

    // The two elements to append are current_xor_sum and (current_sum + current_xor_sum).
    // Let's call them val1 and val2.
    long long val1 = current_xor_sum;
    long long val2 = current_sum + current_xor_sum;

    std::cout << 2 << std::endl;
    std::cout << val1 << " " << val2 << std::endl;
}

