#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends who receive w_i = 1:
    // These friends get 2 * largest_available_number.
    // We assign the largest numbers from 'a' to these friends.
    int a_ptr_max = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_max];
            a_ptr_max--;
        } else {
            // Since w is sorted, all remaining w[i] will be > 1.
            // We can break here.
            break;
        }
    }

    // Friends who receive w_i > 1:
    // These friends get the largest available number as their max,
    // and the smallest available number as their min.
    // To maximize sum, we give the largest remaining numbers from 'a'
    // as max_val to these friends.
    // We give the smallest remaining numbers from 'a' as min_val to these friends.
    // The w_i values determine how many intermediate numbers are "skipped".

    // Assign max_val for friends with w_i > 1
    // These are the remaining largest numbers from 'a'.
    // The loop for w_i = 1 above stopped at index `i` such that w[i] > 1.
    // So we continue from that index downwards.
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_max]; // This is the max_val for this friend
            a_ptr_max--;
        } else {
            // All remaining w[i] are 1, already processed.
            break;
        }
    }

    // Assign min_val for friends with w_i > 1
    // These are the smallest numbers from 'a'.
    // The smallest numbers are taken from the beginning of the sorted 'a' array.
    int a_ptr_min = 0;
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_min]; // This is the min_val for this friend
            a_ptr_min += (w[i] - 1); // Skip w_i - 1 intermediate numbers
            a_ptr_min++; // Move to the next available smallest number for the next friend
        } else {
            // All remaining w[i] are 1, already processed.
            // Since w is sorted, these are the smallest w_i values.
            // We already handled w_i=1 friends by giving them 2*max_val.
            // The smallest w_i values are at the beginning of the sorted w array.
            // If w[i] == 1, it means we've processed all w_i > 1.
            break;
        }
    }

    std::cout << total_happiness << std::endl;
}

