// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // This means we need to remove factors from p such that x is no longer divisible by q.
        // To maximize x, we should remove as few factors as possible, or rather,
        // remove factors in a way that results in the largest possible x.
        // The strategy is to iterate through prime factors of q.
        // For each prime factor f of q, we find the largest divisor of p that is not divisible by q.
        // This is done by dividing p by f until it's no longer divisible by q.
        // The maximum of these candidates will be the answer.

        std::vector<long long> prime_factors_q = get_prime_factors(q);
        long long max_x = 1;

        for (long long factor_q : prime_factors_q) {
            long long current_p = p;
            // Divide current_p by factor_q until current_p is no longer divisible by q
            // or until current_p is no longer divisible by factor_q.
            // The goal is to make current_p not divisible by q.
            // We do this by removing factor_q from current_p.
            while (current_p % factor_q == 0) {
                if ((current_p / factor_q) % q != 0) {
                    // If dividing by factor_q makes it not divisible by q,
                    // then current_p / factor_q is a candidate for x.
                    max_x = std::max(max_x, current_p / factor_q);
                    break; // We found the largest such x for this factor_q
                }
                current_p /= factor_q;
            }
            // If after the loop, current_p is still divisible by q, it means
            // removing all occurrences of factor_q from p still leaves a number divisible by q.
            // This case is handled by other prime factors of q.
            // The loop ensures we find the largest x by removing minimal factor_q powers.
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;
    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::string colors(n, ' ');
        int last1 = -1; // Last digit assigned to color 1
        int first2 = 10; // First digit assigned to color 2

        bool possible_p = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                colors[i] = '1';
                if (d[i] < last1) { // S1 must be non-decreasing
                    possible_p = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > p) {
                colors[i] = '2';
                if (d[i] < first2) { // S2 must be non-decreasing
                    possible_p = false;
                    break;
                }
                first2 = d[i];
            }
        }

        if (!possible_p) {
            continue;
        }

        // Now handle digits equal to p
        // Digits d_i == p that appear before the first d_j > p must be 1
        // Digits d_i == p that appear after the last d_j < p must be 2
        // This is not quite right. The rule is:
        // All d_i == p that are colored 1 must appear before all d_j == p that are colored 2.
        // And all d_i == p colored 1 must be >= last1.
        // And all d_j == p colored 2 must be <= first2.

        // Strategy: assign '1' to d_i == p if it appears before the first '2' (from d_j > p)
        // and '2' to d_i == p if it appears after the last '1' (from d_j < p).
        // This is equivalent to finding the split point for 'p' digits.
        // All 'p's before a certain index get '1', all 'p's after get '2'.

        int split_idx = -1; // Index of the first 'p' that will be colored '2'
        // Find the first 'p' that can be colored '2' without violating S2 non-decreasing
        for (int i = 0; i < n; ++i) {
            if (d[i] == p) {
                if (p <= first2) { // If this 'p' can be the first '2'
                    split_idx = i;
                    break;
                }
            }
        }

        // If no 'p' can be colored '2' (e.g., first2 is already smaller than p),
        // then all 'p's must be '1'.
        if (split_idx == -1) {
            for (int i = 0; i < n; ++i) {
                if (d[i] == p) {
                    colors[i] = '1';
                    if (p < last1) { // Check if this 'p' violates S1 non-decreasing
                        possible_p = false;
                        break;
                    }
                    last1 = p;
                }
            }
        } else {
            // Assign '1' to 'p's before split_idx, '2' to 'p's at/after split_idx
            for (int i = 0; i < n; ++i) {
                if (d[i] == p) {
                    if (i < split_idx) {
                        colors[i] = '1';
                        if (p < last1) {
                            possible_p = false;
                            break;
                        }
                        last1 = p;
                    } else {
                        colors[i] = '2';
                        if (p < first2) {
                            possible_p = false;
                            break;
                        }
                        first2 = p;
                    }
                }
            }
        }

        if (!possible_p) {
            continue;
        }

        // Final check: last1 <= first2
        if (last1 > first2) {
            continue;
        }

        // If we reached here, a valid coloring is found for pivot p
        std::cout << colors << "\n";
        return;
    }

    std::cout << "-\n";
}

