int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_operations = 0;
    int consecutive_count = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (m > 0) {
            // Check for the chain starting with 1 and continuing consecutively
            if (chain[0] == 1) {
                int current_val = 1;
                for (int j = 0; j < m; ++j) {
                    if (chain[j] == current_val) {
                        consecutive_count++;
                        current_val++;
                    } else {
                        break; // Consecutive sequence broken
                    }
                }
            }
        }
    }

    // Total operations needed for the final chain 1->2->...->n is n-1.
    // Each existing nesting relationship in the initial chains that is NOT part of the 1->2->...->n sequence
    // must be undone (1 operation) and then a new one created (1 operation).
    // Each existing nesting relationship that IS part of the 1->2->...->n sequence
    // does not need to be undone or recreated.

    // The number of dolls that are part of the 1->2->...->n sequence and are already correctly nested
    // is `consecutive_count - 1`. (e.g., 1->2->3 has 2 such nestings: 1->2 and 2->3)
    // These `consecutive_count - 1` nestings do not require any operations.

    // Total nestings required for 1->...->n is n-1.
    // Number of nestings already correctly in place: `consecutive_count - 1`.
    // Number of new nestings to be created: `(n - 1) - (consecutive_count - 1)` = `n - consecutive_count`.

    // Total dolls to be moved out of their current (incorrect) nesting:
    // Each chain of length `m_i` has `m_i - 1` internal nestings.
    // Total initial nestings: `sum(m_i - 1)` = `n - k`.
    // Number of initial nestings that are *not* part of the 1->...->n sequence:
    // `(n - k) - (consecutive_count - 1)`.
    // These must be undone. Each undo operation costs 1 second.
    // So, `(n - k) - (consecutive_count - 1)` undo operations.

    // Total operations = (undo operations) + (new put operations)
    // Total operations = `((n - k) - (consecutive_count - 1))` + `(n - consecutive_count)`
    // Total operations = `n - k - consecutive_count + 1 + n - consecutive_count`
    // Total operations = `2*n - k - 2*consecutive_count + 1`

    // Let's re-evaluate.
    // Total dolls: n.
    // Total target nestings: n-1.
    // Number of dolls that are part of the 1->2->...->consecutive_count sequence: `consecutive_count`.
    // These `consecutive_count` dolls form `consecutive_count - 1` correct nestings.
    // These `consecutive_count - 1` nestings don't need to be touched.

    // All other `n - consecutive_count` dolls must be moved.
    // To move a doll, it must first be taken out of any nesting it's in.
    // If it's the outermost doll of a chain, it's not nested.
    // If it's nested, it needs to be taken out.
    // The number of dolls that are NOT 1, 2, ..., consecutive_count is `n - consecutive_count`.
    // Each of these `n - consecutive_count` dolls will eventually be placed into its correct position.
    // This requires `n - consecutive_count` "put" operations.

    // Now consider "take out" operations.
    // There are `k` chains initially.
    // The chain containing 1, 2, ..., consecutive_count has `consecutive_count - 1` internal nestings that are correct.
    // The remaining `(m_i - 1) - (consecutive_count - 1)` nestings in that chain (if any) must be undone.
    // For all other `k-1` chains, all `m_j - 1` nestings must be undone.
    // Total initial nestings: `n - k`.
    // Number of correct initial nestings: `consecutive_count - 1`.
    // Number of incorrect initial nestings that must be undone: `(n - k) - (consecutive_count - 1)`.
    // Each undo operation costs 1 second.

    // Total time = (number of dolls to be put into place) + (number of dolls to be taken out of incorrect places)
    // Number of dolls to be put into place: `n - consecutive_count`. (These are dolls `consecutive_count+1` to `n`)
    // Number of dolls to be taken out of incorrect places: `(n - k) - (consecutive_count - 1)`.
    // This is equivalent to: `(n - k)` total initial nestings.
    // `consecutive_count - 1` of these are correct.
    // So, `(n - k) - (consecutive_count - 1)` nestings must be broken.
    // Each broken nesting is 1 "take out" operation.

    // Total operations = (number of "take out" operations) + (number of "put" operations)
    // Total operations = `((n - k) - (consecutive_count - 1))` + `(n - consecutive_count)`
    // Total operations = `n - k - consecutive_count + 1 + n - consecutive_count`
    // Total operations = `2 * n - k - 2 * consecutive_count + 1`

    // Example 1: n=3, k=2. Chains: 2 1 2, 1 3.
    // consecutive_count = 2 (from 1->2).
    // Total operations = 2*3 - 2 - 2*2 + 1 = 6 - 2 - 4 + 1 = 1. Correct.

    // Example 2: n=7, k=3. Chains: 3 1 3 7, 2 2 5, 2 4 6.
    // consecutive_count = 1 (only doll 1 is correct, 1 is not nested in 2).
    // Total operations = 2*7 - 3 - 2*1 + 1 = 14 - 3 - 2 + 1 = 10. Correct.

    total_operations = (long long)2 * n - k - (long long)2 * consecutive_count + 1;

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?');
    bool possible = true;

    for (int i = 0; i < n; ++i) {
        char current_char = s[i];
        int remainder = i % k;

        if (current_char != '?') {
            if (fixed_chars[remainder] == '?') {
                fixed_chars[remainder] = current_char;
            } else if (fixed_chars[remainder] != current_char) {
                possible = false;
                break;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    int zeros = 0;
    int ones = 0;
    int question_marks = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            zeros++;
        } else if (fixed_chars[i] == '1') {
            ones++;
        } else {
            question_marks++;
        }
    }

    if (zeros > k / 2 || ones > k / 2) {
        possible = false;
    } else {
        // We need k/2 zeros and k/2 ones.
        // We have 'zeros' fixed zeros and 'ones' fixed ones.
        // We need (k/2 - zeros) more zeros and (k/2 - ones) more ones.
        // The remaining question_marks must be able to cover these.
        // (k/2 - zeros) + (k/2 - ones) = k - (zeros + ones)
        // This sum must be equal to question_marks.
        // Since zeros <= k/2 and ones <= k/2, (k/2 - zeros) >= 0 and (k/2 - ones) >= 0.
        // The total number of characters needed from '?' is (k/2 - zeros) + (k/2 - ones).
        // This sum is exactly k - (zeros + ones), which is question_marks.
        // So, if zeros <= k/2 and ones <= k/2, it's always possible to fill the '?'s.
        possible = true;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

