#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This part is constant for the inner sum
    long long sum_r_term;
    if (b % 2 == 0) {
        sum_r_term = (b - 1) % MOD * (b / 2 % MOD) % MOD;
    } else {
        sum_r_term = (b / 2 % MOD) * (b % MOD) % MOD;
        sum_r_term = (b - 1) % MOD * sum_r_term % MOD; // This is wrong. (b-1) * (b/2) * b is not right.
                                                        // It should be (b-1) * b / 2
                                                        // (b-1) * (b/2) % MOD is wrong if b is odd.
                                                        // (b-1) % MOD * (b/2) % MOD is wrong if b is odd.
                                                        // Correct: (b-1) * b / 2
                                                        // (b-1) % MOD * (b % MOD) * (MOD + 1) / 2 % MOD
        long long b_minus_1_mod = (b - 1) % MOD;
        long long b_mod = b % MOD;
        long long inv2 = (MOD + 1) / 2; // Modular inverse of 2
        sum_r_term = b_minus_1_mod * b_mod % MOD * inv2 % MOD;
    }


    // Sum of (k * b + 1) for k from 1 to a
    // = sum(k*b) + sum(1)
    // = b * sum(k) + sum(1)
    // = b * (a * (a+1) / 2) + a
    long long sum_k_b_plus_1_term;
    long long a_mod = a % MOD;
    long long b_mod = b % MOD;
    long long inv2 = (MOD + 1) / 2; // Modular inverse of 2

    long long sum_k = a_mod * ((a_mod + 1) % MOD) % MOD * inv2 % MOD;
    long long term1 = b_mod * sum_k % MOD;
    long long term2 = a_mod;
    sum_k_b_plus_1_term = (term1 + term2) % MOD;

    long long total_sum = sum_r_term * sum_k_b_plus_1_term % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

