int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operations 2 and 3: Do nothing
        std::cout << "1 1\n";
        std::cout << "0\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] multiples of n
    // Select segment [1, n-1] (0-indexed: [0, n-2])
    // Length is n-1.
    // For each a[i] in this segment, we want to add b[i] such that (a[i] + b[i]) % n == 0.
    // b[i] must be a multiple of (n-1).
    // We need a[i] + b[i] = k * n for some integer k.
    // We also need b[i] = m * (n-1) for some integer m.
    // So a[i] + m * (n-1) = k * n
    // a[i] + m * n - m = k * n
    // a[i] - m = (k - m) * n
    // This means (a[i] - m) must be a multiple of n.
    // So a[i] % n == m % n.
    // We can choose m = a[i] % n.
    // If a[i] % n is negative, add n to make it positive.
    // Then b[i] = (a[i] % n) * (n-1).
    // This makes a[i] + b[i] = a[i] + (a[i] % n) * (n-1)
    // = a[i] + (a[i] % n) * n - (a[i] % n)
    // = (a[i] - (a[i] % n)) + (a[i] % n) * n
    // Since (a[i] - (a[i] % n)) is a multiple of n, the whole sum is a multiple of n.
    // This works for a[i] in [0, n-2].

    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = a[i] % n;
        if (remainder < 0) { // Handle negative remainders
            remainder += n;
        }
        long long add_val = remainder * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] a multiple of n
    // Select segment [n, n] (0-indexed: [n-1, n-1])
    // Length is 1.
    // For a[n-1], we want to add b[n-1] such that (a[n-1] + b[n-1]) % n == 0.
    // b[n-1] must be a multiple of 1.
    // We can choose b[n-1] = -a[n-1]. This makes a[n-1] zero.
    // But we need to make it a multiple of n, not necessarily zero yet.
    // We can add b[n-1] = (n - (a[n-1] % n)) % n * n. This makes it a multiple of n.
    // Or simpler: we want a[n-1] + b[n-1] = k*n.
    // b[n-1] must be a multiple of 1.
    // We can choose b[n-1] = -a[n-1]. This makes a[n-1] zero, which is a multiple of n.
    // This is the simplest way to make a[n-1] a multiple of n.
    // The problem statement says "add a multiple of len". -a[n-1] is a multiple of 1.

    std::cout << n << " " << n << "\n";
    long long add_val_n_minus_1 = -a[n - 1];
    std::cout << add_val_n_minus_1 << "\n";
    a[n - 1] += add_val_n_minus_1; // a[n-1] is now 0

    // After operations 1 and 2:
    // a[0], ..., a[n-2] are all multiples of n.
    // a[n-1] is 0 (which is also a multiple of n).
    // Now all elements are multiples of n.

    // Operation 3: Make all elements zero.
    // Select segment [1, n] (0-indexed: [0, n-1])
    // Length is n.
    // For each a[i], we want to add b[i] such that a[i] + b[i] = 0.
    // b[i] must be a multiple of n.
    // Since a[i] is already a multiple of n, we can choose b[i] = -a[i].
    // -a[i] will also be a multiple of n.

    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

