int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two values: one starting with all bits 0, one with all bits 1.
    // We only care about bits 0-9, so 0 and 1023 are good representatives.
    int val0 = 0;    // Represents the state of a bit that was initially 0
    int val1 = 1023; // Represents the state of a bit that was initially 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1 ^= x;
        }
    }

    // Now, for each bit position j (0 to 9):
    // If the j-th bit of val0 is 0 and j-th bit of val1 is 0, then the final j-th bit is always 0.
    // If the j-th bit of val0 is 1 and j-th bit of val1 is 1, then the final j-th bit is always 1.
    // If the j-th bit of val0 is 0 and j-th bit of val1 is 1, then the final j-th bit is the original j-th bit.
    // If the j-th bit of val0 is 1 and j-th bit of val1 is 0, then the final j-th bit is the NOT of the original j-th bit.

    // We need to find constants for at most 3 operations: AND, OR, XOR.
    // Let's define the target constants for these operations.
    int and_const = 1023; // Initially, ANDing with 1023 (all 1s) doesn't change bits.
    int or_const = 0;     // Initially, ORing with 0 (all 0s) doesn't change bits.
    int xor_const = 0;    // Initially, XORing with 0 (all 0s) doesn't change bits.

    for (int j = 0; j < 10; ++j) {
        int bit_val0 = (val0 >> j) & 1;
        int bit_val1 = (val1 >> j) & 1;

        if (bit_val0 == 0 && bit_val1 == 0) {
            // Original bit becomes 0. This means we must AND with 0 at this position.
            and_const &= ~(1 << j); // Set j-th bit of and_const to 0
        } else if (bit_val0 == 1 && bit_val1 == 1) {
            // Original bit becomes 1. This means we must OR with 1 at this position.
            or_const |= (1 << j); // Set j-th bit of or_const to 1
        } else if (bit_val0 == 1 && bit_val1 == 0) {
            // Original bit becomes NOT of itself. This means we must XOR with 1 at this position.
            xor_const |= (1 << j); // Set j-th bit of xor_const to 1
        }
        // If bit_val0 == 0 && bit_val1 == 1, original bit remains itself.
        // This is achieved by ANDing with 1, ORing with 0, XORing with 0.
        // Our initial constants already satisfy this for these bits.
    }

    std::vector<std::pair<char, int>> result_ops;
    if (or_const != 0) {
        result_ops.push_back({'|', or_const});
    }
    if (and_const != 1023) {
        result_ops.push_back({'&', and_const});
    }
    if (xor_const != 0) {
        result_ops.push_back({'^', xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

