void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance for the whole array
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Calculate prefix balances for the left half (jars 1 to n)
    // and suffix balances for the right half (jars n+1 to 2n)
    // The balance is (count of 1s) - (count of 2s)

    // Balances for the left part (jars 1 to n)
    // left_balances[k] stores the balance of jars [n-k+1, n]
    // i.e., if k jars are kept from the right end of the left half.
    // k=0: empty set, balance 0
    // k=1: jar n, balance a[n-1]
    // k=2: jars n-1, n, balance a[n-2] + a[n-1]
    std::map<int, int> left_balances; // balance -> number of jars kept from left half
    left_balances[0] = 0; // 0 jars kept, balance 0

    int current_balance_left = 0;
    for (int k = 1; k <= n; ++k) {
        int jar_idx = n - k; // 0-indexed
        if (a[jar_idx] == 1) {
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        // We only care about the first time a balance is achieved
        // because we want to minimize jars removed, which means maximizing jars kept.
        // For a given balance, keeping more jars means removing fewer.
        // Here, k is the number of jars kept.
        if (left_balances.find(current_balance_left) == left_balances.end()) {
            left_balances[current_balance_left] = k;
        }
    }

    // Balances for the right part (jars n+1 to 2n)
    // right_balances[k] stores the balance of jars [n+1, n+k]
    // i.e., if k jars are kept from the left end of the right half.
    // k=0: empty set, balance 0
    // k=1: jar n+1, balance a[n]
    // k=2: jars n+1, n+2, balance a[n] + a[n+1]
    std::map<int, int> right_balances; // balance -> number of jars kept from right half
    right_balances[0] = 0; // 0 jars kept, balance 0

    int current_balance_right = 0;
    for (int k = 1; k <= n; ++k) {
        int jar_idx = n + k - 1; // 0-indexed
        if (a[jar_idx] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }
        if (right_balances.find(current_balance_right) == right_balances.end()) {
            right_balances[current_balance_right] = k;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removed jars

    // Iterate through all possible balances from the left part
    // Let 'bal_L' be the balance of jars kept from the left half (k_L jars)
    // Let 'bal_R' be the balance of jars kept from the right half (k_R jars)
    // The total balance of remaining jars is bal_L + bal_R.
    // We need bal_L + bal_R = 0. So, bal_R = -bal_L.
    // The number of jars kept is k_L + k_R.
    // The number of jars removed is 2*n - (k_L + k_R).
    // We want to minimize 2*n - (k_L + k_R), which is equivalent to maximizing k_L + k_R.

    for (auto const& [bal_L, k_L] : left_balances) {
        int target_bal_R = -bal_L;
        if (right_balances.count(target_bal_R)) {
            int k_R = right_balances[target_bal_R];
            int jars_kept = k_L + k_R;
            min_removed = std::min(min_removed, 2 * n - jars_kept);
        }
    }

    std::cout << min_removed << std::endl;
}

