    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    // Total number of substrings in a string of length n is n * (n + 1) / 2.
    long long total_substrings = n * (n + 1) / 2;

    // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
    // This is achieved by distributing the '0's as evenly as possible into m+1 blocks.
    // The number of '0's is n - m.
    long long num_zeros = n - m;

    // We want to minimize sum(z_i * (z_i + 1) / 2) where sum(z_i) = num_zeros and there are m+1 blocks.
    // This is minimized when z_i are as equal as possible.
    // Let k be the number of blocks of zeros. k = m + 1.
    long long k = m + 1;

    // Number of zeros in each block will be num_zeros / k or num_zeros / k + 1.
    long long base_zeros_per_block = num_zeros / k;
    long long num_blocks_with_extra_zero = num_zeros % k; // These blocks will have base_zeros_per_block + 1 zeros.
    long long num_blocks_with_base_zeros = k - num_blocks_with_extra_zero; // These blocks will have base_zeros_per_block zeros.

    long long min_zero_substrings = 0;

    // Calculate substrings from blocks with base_zeros_per_block zeros
    min_zero_substrings += num_blocks_with_base_zeros * (base_zeros_per_block * (base_zeros_per_block + 1) / 2);

    // Calculate substrings from blocks with base_zeros_per_block + 1 zeros
    long long zeros_plus_one = base_zeros_per_block + 1;
    min_zero_substrings += num_blocks_with_extra_zero * (zeros_plus_one * (zeros_plus_one + 1) / 2);

    return total_substrings - min_zero_substrings;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> adj_matrix(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> adj_matrix[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false); // Initially no vertices are active

    // Process vertices in reverse of removal order
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = removal_order[k_idx]; // The vertex being added in this step
        active_vertices[k] = true;    // Mark it as active

        // Update shortest paths using vertex k as an intermediate node
        // Floyd-Warshall update step: d[i][j] = min(d[i][j], d[i][k] + d[k][j])
        // Only consider active vertices for i, j, and k
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (adj_matrix[i][k] + adj_matrix[k][j] < adj_matrix[i][j]) {
                    adj_matrix[i][j] = adj_matrix[i][k] + adj_matrix[k][j];
                }
            }
        }

        // After updating paths using k as an intermediate,
        // k itself can be a source or destination for other active vertices.
        // So, we need to re-run the Floyd-Warshall update for all pairs
        // considering k as an intermediate for *all* currently active vertices.
        // This is the standard Floyd-Warshall structure where k is the "pivot" vertex.
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (adj_matrix[i][k] + adj_matrix[k][j] < adj_matrix[i][j]) {
                    adj_matrix[i][j] = adj_matrix[i][k] + adj_matrix[k][j];
                }
            }
        }

        // Calculate the sum of shortest paths for all currently active pairs
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                current_sum += adj_matrix[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were collected)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

