#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_index;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_index);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_v_reduction = children[i].v;
        long long hall_cry_reduction_sum = 0; // Sum of d_j from children leaving due to chain reaction

        // Apply v_i reduction to children after child i
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply hall_cry_reduction_sum first
            if (hall_cry_reduction_sum > 0) {
                children[j].p -= hall_cry_reduction_sum;
            }

            // Apply current_v_reduction
            if (current_v_reduction > 0) {
                children[j].p -= current_v_reduction;
                current_v_reduction = std::max(0LL, current_v_reduction - 1);
            }

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                hall_cry_reduction_sum += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

