#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

// Function to check if all tracks can be read within time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // dp[j] stores the minimum index of head_i required to cover p[0...j-1]
    // dp[j] = k means heads h[0...k-1] can cover p[0...j-1]
    // We want to find if dp[m] <= n

    // dp[j] will store the minimum index `k` such that `h[0...k-1]` can cover `p[0...j-1]`.
    // If `p[0...j-1]` cannot be covered by any `k` heads, we can use `n+1` to denote this.
    std::vector<int> dp(m + 1, n + 1);
    dp[0] = 0; // 0 heads can cover 0 tracks

    for (int j = 0; j < m; ++j) { // Iterate through target tracks p[j]
        if (dp[j] > n) { // If p[0...j-1] cannot be covered, then p[0...j] also cannot be covered
            continue;
        }

        // Option 1: Use an existing head (h[dp[j]-1]) to extend coverage to p[j]
        // If dp[j] > 0, it means h[dp[j]-1] is the rightmost head used to cover p[0...j-1].
        // We can try to extend its coverage to p[j].
        if (dp[j] > 0) {
            long long rightmost_covered_by_prev_heads = h[dp[j]-1] + t;
            if (p[j] <= rightmost_covered_by_prev_heads) {
                dp[j+1] = std::min(dp[j+1], dp[j]);
            }
        }

        // Option 2: Use a new head (h[dp[j]]) to cover p[j]
        // This means we use h[0...dp[j]] to cover p[0...j].
        // The new head is h[dp[j]].
        if (dp[j] < n) { // Check if there's an available head h[dp[j]]
            long long current_head_pos = h[dp[j]];
            long long min_reach = current_head_pos - t;
            long long max_reach = current_head_pos + t;

            // Find the furthest track p[k-1] that h[dp[j]] can cover, starting from p[j]
            // We need to cover p[j] first.
            if (p[j] >= min_reach && p[j] <= max_reach) {
                // h[dp[j]] can cover p[j]. Now find how far it can cover.
                // We need to find the largest k such that p[k-1] is covered by h[dp[j]]
                // and p[j...k-1] are all covered by h[dp[j]]

                // Binary search for the maximum k such that p[k-1] <= max_reach
                // and p[j] >= min_reach (already checked)
                int low = j + 1, high = m, k_max = j + 1;
                while (low <= high) {
                    int mid = low + (high - low) / 2;
                    if (mid > j && p[mid-1] <= max_reach) {
                        k_max = mid;
                        low = mid + 1;
                    } else {
                        high = mid - 1;
                    }
                }

                // For all k from j+1 to k_max, we can potentially update dp[k]
                // using h[0...dp[j]] (which is dp[j]+1 heads)
                for (int k = j + 1; k <= k_max; ++k) {
                    dp[k] = std::min(dp[k], dp[j] + 1);
                }
            }
        }
    }

    return dp[m] <= n;
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between p_i and h_i is ~10^10.
                               // A head might need to move from 1 to 10^10, so 10^10 time.
                               // 2e10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

