int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int q;
    std::cin >> q; // Read the number of queries.

    while (q--) {
        std::string s, t;
        std::cin >> s >> t; // Read the two strings for the current query.

        // A boolean flag to track if a common character is found.
        bool possible = false;

        // Iterate through all possible lowercase Latin letters ('a' to 'z').
        for (char c = 'a'; c <= 'z'; ++c) {
            // Check if character 'c' exists in string s.
            bool s_has_c = false;
            for (char sc : s) {
                if (sc == c) {
                    s_has_c = true;
                    break;
                }
            }

            // Check if character 'c' exists in string t.
            bool t_has_c = false;
            for (char tc : t) {
                if (tc == c) {
                    t_has_c = true;
                    break;
                }
            }

            // If 'c' is present in both strings, then it's possible to transform
            // both strings into a string consisting entirely of 'c's.
            // For example, if 's' has 'c', it can become "ccc...c".
            // If 't' has 'c', it can also become "ccc...c".
            // Thus, s can be transformed into t (via "ccc...c").
            if (s_has_c && t_has_c) {
                possible = true;
                break; // Found a common character, no need to check further.
            }
        }

        // Print the result for the current query.
        if (possible) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0; // Indicate successful execution.
}

