int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is equal to n. If not, it means n is not present in any min(p_i, p_j)
    // which implies n must be the value of some p_i that is always greater than other p_j's it's compared with.
    // In this case, the max_val_in_row for that p_i would be n-1 (if n-1 is the largest value it's compared to).
    // So, if n is not found in p, it means one of the p[i] values should be n.
    // The one that should be n is the one whose max_val_in_row is n-1 (or the largest value among all max_val_in_rows).
    // This is because if p[i] = n, then for all j != i, min(p[i], p[j]) = min(n, p[j]) = p[j].
    // So, max_{j!=i} (a[i][j]) = max_{j!=i} (p[j]).
    // If p is a permutation of 1..n, then max_{j!=i} (p[j]) must be n-1.
    // So, we look for an element whose p[i] (calculated as max_val_in_row) is n-1.
    // If such an element exists, and n is not present in the current p, we change that p[i] to n.

    bool n_is_present = false;
    for (int val : p) {
        if (val == n) {
            n_is_present = true;
            break;
        }
    }

    if (!n_is_present) {
        // Find the maximum value in the current p. This should be n-1.
        // There might be multiple elements with value n-1. Any one of them can be changed to n.
        // The problem guarantees a solution exists, so there will be exactly one such element
        // that should be n, and its calculated p[i] would be n-1.
        // We can just find the first occurrence of n-1 and change it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

