void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_values.insert(p[0]);

    // Determine p_i for i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (used_values.count(p[i])) {
                // This should not happen if q is valid, as q_i is a new max
                // and values 1..n are distinct. But good to check.
                possible = false;
                break;
            }
            used_values.insert(p[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be some value less than q_i
            // and not yet used. We need to pick the largest available value
            // that is less than q_i to maximize chances of finding a solution.
            // However, the problem asks for *any* possible permutation.
            // A simpler strategy is to pick the smallest available value.
            // Let's find the smallest unused value.
            // We need to fill these 'gaps' with unused numbers.
            // The numbers that are not in `q` (specifically, not `q_i` when `q_i > q_{i-1}`)
            // are candidates for `p_i` when `q_i == q_{i-1}`.
            // We can collect all numbers from 1 to n that are not in `used_values`
            // and assign them in increasing order.
            p[i] = 0; // Placeholder, will be filled later
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    std::vector<int> available_nums;
    for (int i = 1; i <= n; ++i) {
        if (used_values.find(i) == used_values.end()) {
            available_nums.push_back(i);
        }
    }

    // Check if we have enough available numbers for the remaining slots
    int available_idx = 0;
    for (int i = 1; i < n; ++i) {
        if (p[i] == 0) { // This is a slot where q_i == q_{i-1}
            if (available_idx >= available_nums.size()) {
                possible = false; // Not enough numbers to fill the gaps
                break;
            }
            p[i] = available_nums[available_idx];
            if (p[i] > q[i]) { // The chosen number must not exceed q_i
                possible = false;
                break;
            }
            available_idx++;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

