    int low = 1;
    int high = k + 1; // The largest number we'll use for the 'k' distinct differences

    // Construct the first k+1 elements to generate k distinct differences
    // The pattern is low, high, low+1, high-1, low+2, high-2, ...
    // This generates differences: high-low, high-(low+1), (low+1)-(high-1), ...
    // Or more simply: k, k-1, k-2, ..., 1

    // Example: n=5, k=3. low=1, high=4.
    // 1, 4, 2, 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1.
    // This generates k distinct differences: k, k-1, ..., 1.

