            std::cout << high--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k+1) elements, just append them in increasing order.
    // This ensures the differences are always 1, which is already covered by the first k+1 elements
    // (since k >= 1, difference 1 is always generated).
    for (int i = k + 1; i < n; ++i) {
        std::cout << low++; // low now holds the next available number
