    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int current_balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
                current_balance++;
            }
        } else { // c == ')'
            // We can only add a ')' if it doesn't make the balance negative
            // AND we still need closing brackets AND we have enough open brackets
            // to potentially match this closing bracket later.
            // The condition `current_balance > 0` ensures it doesn't go negative.
            // The condition `close_needed > 0` ensures we don't exceed k/2 closing brackets.
            // The condition `current_balance > open_needed` is implicitly handled by the greedy choice
            // of prioritizing open brackets first.
            // A simpler condition: if we have an open bracket to match (current_balance > 0)
            // and we still need closing brackets.
            if (current_balance > 0 && close_needed > 0) {
                result += ')';
                close_needed--;
                current_balance--;
            }
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
