void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of the suffix that is decreasing
    // i.e., find the largest k such that a[k] < a[k-1]
    // The suffix a[k...n-1] is non-increasing.
    int k = n - 1;
    while (k > 0 && a[k-1] >= a[k]) {
        k--;
    }
    // Now a[k...n-1] is non-increasing.
    // If k is 0, the whole array is non-increasing.

    // From this point k, find the rightmost peak of the suffix that is increasing
    // i.e., find the largest j such that a[j] > a[j-1]
    // The suffix a[j...k-1] is non-decreasing.
    while (k > 0 && a[k-1] <= a[k]) {
        k--;
    }
    // Now a[k...n-1] is a good array.
    // The elements a[k...n-1] form a "valley" shape:
    // a[k] <= a[k+1] <= ... <= a[p] >= a[p+1] >= ... >= a[n-1]
    // for some p in [k, n-1].
    // This is the longest suffix that is good.

    std::cout << k << std::endl;
}

