        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
                         // More precisely, k is the 'n' in the formula for cells: (2^k - 1) * (2^k) / 2
                         // No, k is the number of stairs, which is 2^p - 1.
                         // The sequence of nice staircases has n = 1, 3, 7, 15, ...
                         // For n=1, cells = 1.
                         // For n=3, cells = 6.
                         // For n=7, cells = 28.
                         // For n=15, cells = 120.
                         // The number of cells for a nice staircase with 2^p - 1 stairs is (2^p - 1) * (2^p) / 2.
                         // Let's use the formula derived: (2^p - 1) * 2^p / 2.
                         // p=1: (2^1 - 1) * 2^1 / 2 = 1 * 2 / 2 = 1.
                         // p=2: (2^2 - 1) * 2^2 / 2 = 3 * 4 / 2 = 6.
                         // p=3: (2^3 - 1) * 2^3 / 2 = 7 * 8 / 2 = 28.
                         // p=4: (2^4 - 1) * 2^4 / 2 = 15 * 16 / 2 = 120.
                         // The sequence of cells is 1, 6, 28, 120, 496, 2016, ...
                         // The next term is (2 * current_stair_cells + 1) * 2.
                         // No, this is not correct.
                         // The next term is (2 * current_stair_cells + 1) * (2 * current_stair_cells + 2) / 2.
                         // Let's use the formula for the number of cells for a nice staircase with `n` stairs, where `n = 2^p - 1`.
                         // The number of cells is `(2^p - 1) * 2^p / 2`.
                         // Let `N_p = 2^p - 1`. The cells are `N_p * (N_p + 1) / 2`.
                         // The sequence of `N_p` is 1, 3, 7, 15, 31, 63, ...
                         // The sequence of cells is 1, 6, 28, 120, 496, 2016, ...
                         // Let `n_val` be the number of stairs (1, 3, 7, ...).
                         // Let `cells_needed` be the total cells for that staircase.

        long long n_val = 1; // Current number of stairs (1, 3, 7, ...)
        long long cells_needed = 1; // Cells for n_val stairs

        while (x >= cells_needed) {
            count++;
            x -= cells_needed;

            // Calculate the next nice staircase size
            // The next n_val is 2 * n_val + 1
            // The next cells_needed is (2 * n_val + 1) * (2 * n_val + 2) / 2
            // This can be simplified.
            // Let current n_val be N. Next n_val is 2N+1.
            // Cells for N: N*(N+1)/2
            // Cells for 2N+1: (2N+1)*(2N+2)/2 = (2N+1)*(N+1)
            // This is not correct. The formula for cells is (2^p - 1) * 2^p / 2.
            // Let's use the derived recurrence:
            // C_p = (2^p - 1) * 2^p / 2
            // C_{p+1} = (2^{p+1} - 1) * 2^{p+1} / 2
            // C_{p+1} = (2 * (2^p) - 1) * (2 * (2^p)) / 2
