int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        int horizontal_pairs = std::min(counts['L'], counts['R']);
        int vertical_pairs = std::min(counts['U'], counts['D']);

        std::string result = "";
        if (horizontal_pairs == 0 && vertical_pairs == 0) {
            // No moves possible, length 0
        } else if (horizontal_pairs == 0) { // Only vertical moves possible
            result = "UD"; // Must be U then D to return to (0,0)
            if (vertical_pairs == 0) { // Should not happen if horizontal_pairs == 0 and vertical_pairs == 0 is handled
                result = "";
            }
        } else if (vertical_pairs == 0) { // Only horizontal moves possible
            result = "LR"; // Must be L then R to return to (0,0)
            if (horizontal_pairs == 0) { // Should not happen
                result = "";
            }
        } else {
            // Both horizontal and vertical moves are possible.
            // The optimal strategy is to perform all 'U' moves, then all 'L' moves,
            // then all 'R' moves, then all 'D' moves (or any permutation that keeps
            // U/D and L/R paired and separated).
            // Example: U...UL...LR...RD...D
            // This ensures no intermediate cell is revisited.
            // The path would be: (0,0) -> (0,1) -> ... -> (0,V) -> (-1,V) -> ... -> (-H,V) ->
            // (-H,V-1) -> ... -> (-H,0) -> (-H+1,0) -> ... -> (0,0)
            // This is not correct. The path must be simple.
            // A simple path that returns to (0,0) and uses both H and V moves
            // must be of the form U...UL...LR...RD...D or L...LR...RU...UD...D
            // The simplest valid path is U...UL...LR...RD...D
            // U...U (vertical up)
            // L...L (horizontal left)
            // R...R (horizontal right)
            // D...D (vertical down)
            // This path would be:
            // (0,0) -> (0,1) -> ... -> (0,V)
            // (0,V) -> (-1,V) -> ... -> (-H,V)
            // (-H,V) -> (-H+1,V) -> ... -> (0,V)
            // (0,V) -> (0,V-1) -> ... -> (0,0)
            // This path revisits (0,V) if H > 0. This is invalid.

            // The only way to use both horizontal and vertical moves without revisiting
            // intermediate cells (other than (0,0)) is to form a rectangle.
            // For example, U...UL...LD...DR...R
            // (0,0) -> (0,1) -> ... -> (0,V)
            // (0,V) -> (-1,V) -> ... -> (-H,V)
            // (-H,V) -> (-H,V-1) -> ... -> (-H,0)
            // (-H,0) -> (-H+1,0) -> ... -> (0,0)
            // This path is valid.
            // It uses V 'U's, H 'L's, V 'D's, H 'R's.
            // Total length: 2*H + 2*V.
            // The number of 'U's must equal 'D's, and 'L's must equal 'R's.
            // So we use `vertical_pairs` 'U's, `vertical_pairs` 'D's,
            // `horizontal_pairs` 'L's, `horizontal_pairs` 'R's.

            for (int i = 0; i < vertical_pairs; ++i) result += 'U';
            for (int i = 0; i < horizontal_pairs; ++i) result += 'L';
            for (int i = 0; i < vertical_pairs; ++i) result += 'D';
            for (int i = 0; i < horizontal_pairs; ++i) result += 'R';
        }

        std::cout << result.length() << "\n";
        std::cout << result << "\n";
    }
    return 0;
}

