void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the number 1 is always beautiful.
    // The subsegment is just p[pos[1]] which is [1].
    // So, min_idx = pos[1], max_idx = pos[1].
    // Current range for 1..k is [min_idx, max_idx].
    int min_idx = pos[1];
    int max_idx = pos[1];
    result[0] = '1'; // m=1 is 0-indexed in result string

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // To check if m is beautiful, we need to extend the current range [min_idx, max_idx]
        // to include the number m.
        // The number m is at pos[m].

        // Update min_idx and max_idx to cover the range [1, m]
        // This means the new range must span from min(current_min_idx, pos[m])
        // to max(current_max_idx, pos[m]).
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // A number m is beautiful if the subsegment p[min_idx...max_idx]
        // is a permutation of 1, 2, ..., m.
        // This requires two conditions:
        // 1. The subsegment must contain all numbers from 1 to m. (Guaranteed by how min_idx/max_idx are updated)
        // 2. The length of the subsegment must be exactly m.
        // The length of the subsegment p[min_idx...max_idx] is (max_idx - min_idx + 1).
        if ((max_idx - min_idx + 1) == m) {
            result[m - 1] = '1'; // m is beautiful, mark it (m-1 is 0-indexed)
        }
    }
    std::cout << result << "\n";
}

