    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This will be 'k' in the explanation, or the rightmost point in the valid window

    for (int i = 0; i < n; ++i) { // 'i' is the leftmost point of the triplet
        // Advance right_ptr until x[right_ptr] - x[i] > d
        // or right_ptr reaches the end of the array.
        // All points from x[i+1] to x[right_ptr-1] are valid candidates for the middle point 'j'
        // and the rightmost point 'k' (where k > j).
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }

        // At this point, all points x[i], x[i+1], ..., x[right_ptr-1] form a valid window
        // where the difference between the maximum and minimum is <= d.
        // We need to choose two more points from x[i+1], ..., x[right_ptr-1]
        // to form a triplet with x[i].
        // The number of points available for 'j' and 'k' (where i < j < k) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. This is the number of points strictly to the right of x[i]
        // that are within distance d from x[i].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m is m * (m - 1) / 2.

        long long m = right_ptr - 1 - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

