int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int count01 = 0; // count of indices i where a[i] = '0' and b[i] = '1'
    int count10 = 0; // count of indices i where a[i] = '1' and b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] == '0' && b[i] == '1') {
            // This is a 0->1 mismatch
            if (count10 > 0) {
                // We have a pending 1->0 mismatch. We can swap a '1' from a[j] (where b[j]='0')
                // with a '0' from a[i] (where b[i]='1').
                // This fixes both a[i] and a[j] with a cost of |i-j|.
                // Since we process from left to right, we always pair the current 0->1 with the
                // most recent 1->0. The cost is 1 for each such pair.
                // This is equivalent to saying we fix one 1->0 and one 0->1 mismatch.
                cost += 1;
                count10--; // One 1->0 mismatch is resolved
            } else {
                // No pending 1->0 mismatch. This 0->1 mismatch is now pending.
                count01++;
            }
        } else if (a[i] == '1' && b[i] == '0') {
            // This is a 1->0 mismatch
            if (count01 > 0) {
                // We have a pending 0->1 mismatch. We can swap a '0' from a[j] (where b[j]='1')
                // with a '1' from a[i] (where b[i]='0').
                // This fixes both a[i] and a[j] with a cost of |i-j|.
                // Cost is 1 for each such pair.
                cost += 1;
                count01--; // One 0->1 mismatch is resolved
            } else {
                // No pending 0->1 mismatch. This 1->0 mismatch is now pending.
                count10++;
            }
        }
    }

    // After iterating through all indices, any remaining pending mismatches (count01 or count10)
    // cannot be resolved by a swap operation with another mismatch of the opposite type.
    // These remaining mismatches must be resolved by flip operations.
    // Each flip operation costs 1.
    cost += (long long)count01;
    cost += (long long)count10;

    std::cout << cost << std::endl;

    return 0;
}

