    // If A+D > 0, we can still make magnitude < 1 by multiplying with many small numbers.
    if ((A + B) % 2 == 0) { // Even number of initial negative toys
        ans3 = "Ya";
    } else { // Odd number of initial negative toys
        // If (A+B) is odd, final product must be negative. So Box 3 is impossible.
    }

    // Case 4: Final toy in Box 4 (x >= 1)
    // Requires an even number of negative factors.
    // Requires magnitude >= 1.
    // If A+D == 0, all initial toys have magnitude < 1. Product will have magnitude < 1.
    // So if A+D == 0, Box 4 is impossible.
    if (A + D > 0) { // At least one initial toy has magnitude >= 1
        if ((A + B) % 2 == 0) { // Even number of initial negative toys
            ans4 = "Ya";
        } else { // Odd number of initial negative toys
            // If (A+B) is odd, final product must be negative. So Box 4 is impossible.
        }
    }

    // Special case: If A+D == 0, all initial toys have magnitude < 1.
    // The product of any number of such toys will always have magnitude < 1.
    // So, Box 1 and Box 4 are impossible if A+D == 0.
    if (A + D == 0) {
        ans1 = "Tidak";
        ans4 = "Tidak";
    }

    // The logic for sign is: (A+B) % 2 == 1 means final product is negative.
    // (A+B) % 2 == 0 means final product is positive.
    // This means if (A+B) is even, ans1 and ans2 must be "Tidak".
    // If (A+B) is odd, ans3 and ans4 must be "Tidak".

    if ((A + B) % 2 == 0) { // Final product must be positive
        ans1 = "Tidak";
        ans2 = "Tidak";
    } else { // Final product must be negative
        ans3 = "Tidak";
        ans4 = "Tidak";
    }

    // Re-evaluate based on the combined logic:
    // Box 1: Negative, magnitude >= 1
    // Possible if (A+B) is odd AND (A+D > 0)
    if ((A + B) % 2 == 1 && (A + D > 0)) {
        ans1 = "Ya";
    } else {
        ans1 = "Tidak";
    }

    // Box 2: Negative, magnitude < 1
    // Possible if (A+B) is odd
    if ((A + B) % 2 == 1) {
        ans2 = "Ya";
    } else {
        ans2 = "Tidak";
    }

    // Box 3: Positive, magnitude < 1
    // Possible if (A+B) is even
    if ((A + B) % 2 == 0) {
        ans3 = "Ya";
    } else {
        ans3 = "Tidak";
    }

    // Box 4: Positive, magnitude >= 1
    // Possible if (A+B) is even AND (A+D > 0)
    if ((A + B) % 2 == 0 && (A + D > 0)) {
        ans4 = "Ya";
    } else {
        ans4 = "Tidak";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

