// Function to check if a sub-array is a permutation
// This version is optimized for checking prefixes and suffixes efficiently.
// It relies on precomputed maximums and frequency counts.
bool is_permutation(int length, int max_val, const std::vector<int>& counts) {
    if (max_val != length) {
        return false;
    }
    for (int i = 1; i <= length; ++i) {
        if (counts[i] != 1) {
            return false;
        }
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums and suffix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute prefix frequency counts
    std::vector<std::vector<int>> prefix_counts(n + 1, std::vector<int>(n + 1, 0));
    std::vector<bool> prefix_has_duplicates(n + 1, false);
    std::vector<int> current_counts_p(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || current_counts_p[a[i]] > 0) {
            prefix_has_duplicates[i + 1] = true;
        }
        current_counts_p[a[i]]++;
        if (i > 0) {
            prefix_has_duplicates[i + 1] = prefix_has_duplicates[i + 1] || prefix_has_duplicates[i];
        }
    }

    // Precompute suffix frequency counts
    std::vector<bool> suffix_has_duplicates(n + 1, false);
    std::vector<int> current_counts_s(n + 1, 0);
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || current_counts_s[a[i]] > 0) {
            suffix_has_duplicates[i] = true;
        }
        current_counts_s[a[i]]++;
        if (i < n - 1) {
            suffix_has_duplicates[i] = suffix_has_duplicates[i] || suffix_has_duplicates[i + 1];
        }
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 is the length of the first permutation, so it ranges from 1 to n-1
    // The split point is after index l1-1.
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if prefix a[0...l1-1] is a permutation of length l1
        bool p1_is_perm = true;
        if (prefix_max[l1 - 1] != l1) {
            p1_is_perm = false;
        } else {
            // Check for duplicates in prefix
            std::vector<int> temp_counts(l1 + 1, 0);
            for (int i = 0; i < l1; ++i) {
                if (a[i] > l1 || temp_counts[a[i]] > 0) {
                    p1_is_perm = false;
                    break;
                }
                temp_counts[a[i]]++;
            }
        }

        // Check if suffix a[l1...n-1] is a permutation of length l2
        bool p2_is_perm = true;
        if (suffix_max[l1] != l2) {
            p2_is_perm = false;
        } else {
            // Check for duplicates in suffix
            std::vector<int> temp_counts(l2 + 1, 0);
            for (int i = l1; i < n; ++i) {
                if (a[i] > l2 || temp_counts[a[i]] > 0) {
                    p2_is_perm = false;
                    break;
                }
                temp_counts[a[i]]++;
            }
        }

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

