int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int num_wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                num_wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (num_wins == 0) { // All L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // Change k L's to W's.
                // The first W gives 1 point, subsequent k-1 W's give 2 points each.
                // Total: 1 + 2*(k-1) = 2k - 1.
                // If k=1, score is 1. This formula works: 2*1 - 1 = 1.
                std::cout << std::max(0, 2 * k - 1) << "\n";
            }
            continue;
        }

        // If there are initial wins, we can potentially improve the score.
        // We want to fill gaps of L's between W's first, as they give 2 points per L.
        // Then, we extend streaks of W's at the ends, as they also give 2 points per L.

        std::vector<int> gap_lengths;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // Collect lengths of L-segments between W's
        int current_gap = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gap_lengths.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        if (current_gap > 0) { // Last gap before last_W
            gap_lengths.push_back(current_gap);
        }

        std::sort(gap_lengths.begin(), gap_lengths.end());

        int score_increase = 0;
        int remaining_k = k;

        // Fill internal gaps
        for (int gap_len : gap_lengths) {
            if (remaining_k >= gap_len) {
                score_increase += 2 * gap_len; // Each L becomes W, connecting two W's, so 2 points per L
                remaining_k -= gap_len;
            } else {
                score_increase += 2 * remaining_k;
                remaining_k = 0;
                break;
            }
        }

        // Extend streaks at ends
        // Left end: from 0 to first_W-1
        score_increase += std::min(remaining_k, first_W) * 2;
        remaining_k -= std::min(remaining_k, first_W);

        // Right end: from last_W+1 to n-1
        score_increase += std::min(remaining_k, n - 1 - last_W) * 2;
        // remaining_k -= std::min(remaining_k, n - 1 - last_W); // Not strictly needed as we are done with k

        std::cout << initial_score + score_increase << "\n";
    }
    return 0;
}

