    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_idx = n - 1; // Pointer for largest elements in 'a'

        // First, handle friends who get w_i = 1.
        // These friends get 2 * largest_available_number.
        // They should get the largest available numbers.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += a[a_idx] * 2;
                a_idx--;
            } else {
                // Since w is sorted, all remaining w[i] will be > 1
                break;
            }
        }

        // Now, handle friends who get w_i > 1.
        // These friends get max_val + min_val.
        // The max_val should be the largest remaining available numbers.
        // The min_val should be the smallest available numbers.
        int current_a_min_idx = 0; // Pointer for smallest elements in 'a'
        for (int i = 0; i < k; ++i) {
            if (w[i] > 1) {
                // Assign the largest remaining number as max_val
                total_happiness += a[a_idx];
                a_idx--;

                // Assign the smallest available number as min_val
                // This friend needs w[i] - 1 additional numbers,
                // which will be discarded from the smallest end.
                total_happiness += a[current_a_min_idx];
                current_a_min_idx += (w[i] - 1);
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

