int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We want S' = 2 * X'
        // Current state: current_sum, current_xor_sum
        // If current_sum == 2 * current_xor_sum, array is already good.
        // We can append 0 elements.
        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
            continue;
        }

        // Otherwise, we need to append elements.
        // Let's try to append two elements.
        // We need to find b1, b2 such that:
        // (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)

        // A simple strategy is to append current_xor_sum and then current_sum + current_xor_sum.
        // Let b1 = current_xor_sum.
        // New sum_1 = current_sum + current_xor_sum
        // New xor_1 = current_xor_sum ^ current_xor_sum = 0

        // Now we need to append b2 such that:
        // (new_sum_1 + b2) = 2 * (new_xor_1 ^ b2)
        // (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2)
        // (current_sum + current_xor_sum + b2) = 2 * b2
        // current_sum + current_xor_sum = b2

        // So, b2 = current_sum + current_xor_sum.
        // Let's verify this.
        // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum.
        // Final sum S' = current_sum + b1 + b2
        // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S' = 2 * current_sum + 2 * current_xor_sum

        // Final XOR sum X' = current_xor_sum ^ b1 ^ b2
        // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X' = 0 ^ (current_sum + current_xor_sum)
        // X' = current_sum + current_xor_sum

        // Check condition: S' = 2 * X'
        // (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum)
        // This is true.

        // The number of elements to append is 2.
        // The elements are current_xor_sum and current_sum + current_xor_sum.
        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_operations = 0;
    int consecutive_count = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Calculate operations for this chain
        // Each chain starts with m-1 existing nestings.
        // To break these, we need m-1 "get out" operations.
        // These m-1 operations free up m dolls.
        // The first doll in the chain (chain[0]) is special.
        // If chain[0] is 1, it means the chain starts with 1.
        // We want to find the longest sequence 1, 2, 3, ... that is already formed.

        if (chain[0] == 1) {
            // This chain starts with 1.
            // We count how many consecutive numbers starting from 1 are present.
            int current_consecutive = 0;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == j + 1) {
                    current_consecutive++;
                } else {
                    break;
                }
            }
            consecutive_count = current_consecutive;
            // For the dolls 1, 2, ..., consecutive_count, they are already correctly nested.
            // We don't need to break these specific nestings.
            // The remaining (m - consecutive_count) dolls in this chain need to be freed.
            // This means (m - consecutive_count) "get out" operations.
            // Each "get out" operation frees one doll.
            // The number of nestings to break is (m - consecutive_count).
            total_operations += (m - consecutive_count);
        } else {
            // This chain does not start with 1.
            // All m-1 nestings in this chain must be broken.
            // This requires m-1 "get out" operations.
            total_operations += (m - 1);
        }
    }

    // Total operations = (operations to break existing chains) + (operations to form the final chain)
    // Operations to form the final chain:
    // We need to form n-1 nestings (1 into 2, 2 into 3, ..., n-1 into n).
    // The first (consecutive_count - 1) nestings (1->2, ..., (consecutive_count-1)->consecutive_count)
    // are already correctly formed and don't need to be re-done.
    // So, we need to perform (n - 1) - (consecutive_count - 1) new "put in" operations.
    // This simplifies to n - consecutive_count.
    total_operations += (n - consecutive_count);

    std::cout << total_operations << std::endl;

    return 0;
}

