#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>
#include <numeric>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    if (temp_q > 1) { // temp_q is a prime factor itself
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= temp_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

