#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    int p = -1; // The split point: digits before p are candidates for color 1, after p for color 2.
                // Specifically, digits d_i <= d_p are color 1, d_i > d_p are color 2.
                // If d_i == d_p, it can be either.

    // Find the optimal split point 'p'
    // Iterate through possible split digits 'k' from 0 to 9.
    // For a given 'k', all digits < k must be color 1.
    // All digits > k must be color 2.
    // Digits == k can be either.
    // We want to find the largest index 'p' such that d_p = k and all d_i for i < p are <= k.
    // And all d_i for i > p are >= k.
    // This is equivalent to finding the first digit 'k' such that the sequence of digits
    // d_1...d_n can be partitioned into (digits <= k) and (digits > k)
    // such that the first part is non-decreasing and the second part is non-decreasing,
    // and the last digit of the first part <= first digit of the second part.

    // A simpler approach:
    // Iterate through all possible split values `k` from 0 to 9.
    // For a fixed `k`:
    //   Assign color 1 to all `d_i` such that `d_i < k`.
    //   Assign color 2 to all `d_i` such that `d_i > k`.
    //   For `d_i == k`:
    //     Assign color 1 if `d_i` appears before the first `d_j > k`.
    //     Assign color 2 if `d_i` appears after or at the first `d_j > k`.
    // This strategy ensures that all digits colored 1 are <= k, and all digits colored 2 are >= k.
    // The "split point" for digits equal to k is crucial.
    // Let's find the first index `idx_gt_k` where `d_idx_gt_k > k`.
    // All `d_i == k` for `i < idx_gt_k` are colored 1.
    // All `d_i == k` for `i >= idx_gt_k` are colored 2.

    for (int k = 0; k <= 9; ++k) {
        std::string current_result(n, ' ');
        int last1 = -1;
        int last2 = -1;
        bool possible_k = true;

        // Find the first index where a digit is strictly greater than k
        int first_gt_k_idx = n;
        for (int i = 0; i < n; ++i) {
            if ((s[i] - '0') > k) {
                first_gt_k_idx = i;
                break;
            }
        }

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < k) {
                current_result[i] = '1';
                if (digit < last1) {
                    possible_k = false;
                    break;
                }
                last1 = digit;
            } else if (digit > k) {
                current_result[i] = '2';
                if (digit < last2) {
                    possible_k = false;
                    break;
                }
                last2 = digit;
            } else { // digit == k
                if (i < first_gt_k_idx) {
                    current_result[i] = '1';
                    if (digit < last1) {
                        possible_k = false;
                        break;
                    }
                    last1 = digit;
                } else {
                    current_result[i] = '2';
                    if (digit < last2) {
                        possible_k = false;
                        break;
                    }
                    last2 = digit;
                }
            }
        }

        if (possible_k) {
            // Check the final condition: last1 <= first digit of S2
            // This is implicitly handled by the construction:
            // All digits colored 1 are <= k.
            // All digits colored 2 are >= k.
            // So, last1 (which is <= k) will always be <= first digit of S2 (which is >= k).
            // The only edge case is if S1 is empty or S2 is empty.
            // If S1 is empty, last1 remains -1.
            // If S2 is empty, last2 remains -1.
            // The construction ensures that if S1 is non-empty, last1 is the last digit of S1.
            // If S2 is non-empty, the first digit of S2 is >= k.
            // Since last1 <= k, the condition last1 <= first_S2 is always met if both are non-empty.
            // If S1 is empty, the condition is trivially met.
            // If S2 is empty, the condition is trivially met.

            result = current_result;
            std::cout << result << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate constraints based on s[i] == s[i+k]
    // If s[i] is '0' or '1', then s[i+k], s[i+2k], ... must be the same.
    // If s[i] is '?', it can be determined by s[i+k] or s[i-k].
    // If there's a conflict (e.g., s[i] = '0' and s[i+k] = '1'), it's impossible.
    for (int i = 0; i < n - k; ++i) {
        if (s[i] != '?' && s[i+k] != '?' && s[i] != s[i+k]) {
            std::cout << "NO\n";
            return;
        }
        if (s[i] != '?' && s[i+k] == '?') {
            s[i+k] = s[i];
        } else if (s[i] == '?' && s[i+k] != '?') {
            s[i] = s[i+k];
        }
    }

    // Step 2: Check the first k characters for balance
    // After propagation, the first k characters s[0...k-1] are as constrained as possible.
    // Any remaining '?' in s[0...k-1] can be chosen freely to satisfy the k/2 balance.
    // We count fixed '0's and '1's in s[0...k-1].
    int count0 = 0;
    int count1 = 0;
    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            count0++;
        } else if (s[i] == '1') {
            count1++;
        }
    }

    // If the number of fixed '0's or '1's already exceeds k/2, it's impossible.
    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we can satisfy the balance for s[0...k-1], then all other k-length substrings
    // will also be balanced because s[i] == s[i+k] implies they have the same counts.
    // The remaining '?'s in s[0...k-1] can be filled to achieve k/2 balance.
    // The number of '?'s is k - count0 - count1.
    // We need (k/2 - count0) '0's and (k/2 - count1) '1's from the '?'s.
    // The total number of '?'s must be exactly (k/2 - count0) + (k/2 - count1).
    // This is equivalent to checking if count0 <= k/2 and count1 <= k/2.
    // The sum of '?'s is k - count0 - count1.
    // The required '?'s for 0s is k/2 - count0.
    // The required '?'s for 1s is k/2 - count1.
    // If (k/2 - count0) + (k/2 - count1) == (k - count0 - count1), then it's possible.
    // This condition is always true if count0 <= k/2 and count1 <= k/2.
    // So, if we reach here, it's always possible.

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This sum needs to be modulo MOD.
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to handle division by 2.
    // (b-1) * b / 2 mod MOD = ((b-1) mod MOD * (b mod MOD) mod MOD * (2^-1 mod MOD)) mod MOD
    // 2^-1 mod 1000000007 is 500000004.
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9 + 7
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum of (k * b + 1) from k=1 to a:
    // sum_{k=1}^{a} (k * b + 1) = b * sum_{k=1}^{a} k + sum_{k=1}^{a} 1
    // = b * (a * (a + 1) / 2) + a
    // This sum also needs to be modulo MOD.
    long long sum_k_term_part1 = (a % MOD);
    sum_k_term_part1 = (sum_k_term_part1 * ((a + 1) % MOD)) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * inv2) % MOD; // (a * (a+1) / 2) mod MOD
    sum_k_term_part1 = (sum_k_term_part1 * (b % MOD)) % MOD; // b * (a * (a+1) / 2) mod MOD

    long long sum_k_term_part2 = (a % MOD); // a mod MOD

    long long sum_k_term = (sum_k_term_part1 + sum_k_term_part2) % MOD;

    // Total sum = (sum_k_term * sum_r_term) mod MOD
    long long total_sum = (sum_k_term * sum_r_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

