    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_val = current_val;
        int block_end_idx = std::min(i + k, n);
        for (int j = i; j < block_end_idx; ++j) {
            p[j] = block_start_val - (j - i);
        }
        current_val -= k;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

