        if ((k - abs_n) % 2 != 0) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it's possible.
        // We have `abs_n` moves to reach (abs_n, abs_m).
        // `abs_m` of these moves can be diagonal (e.g., (1,1)).
        // `abs_n - abs_m` of these moves must be straight (e.g., (1,0)).
        // This gives `abs_m` diagonal moves.
        //
        // We have `remaining_moves = k - abs_n` moves left.
        // Since `remaining_moves` is even, we can use all of them to make pairs of moves that cancel out.
        // Each such pair of moves (e.g., (1,0) then (-1,0)) uses 2 moves.
        // We want to maximize diagonal moves.
        // A pair of moves like (1,1) then (-1,-1) uses 2 moves and contributes 2 diagonal moves.
        // A pair of moves like (1,0) then (-1,0) uses 2 moves and contributes 0 diagonal moves.
        //
        // To maximize diagonal moves, we should use the `remaining_moves` to make as many (1,1) then (-1,-1) pairs as possible.
        // Each such pair adds 2 diagonal moves.
        // So, `remaining_moves` / 2 pairs, each adding 2 diagonal moves.
        // Total additional diagonal moves = `remaining_moves`.
        //
        // Total diagonal moves = (initial `abs_m` diagonal moves) + (`remaining_moves` additional diagonal moves).
        long long max_diagonal_moves = abs_m + remaining_moves;

        std::cout << max_diagonal_moves << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance of the whole array
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Calculate prefix balances for the left side (jars 1 to n)
    // balance_left[i] = balance of jars 1 to i
    std::vector<int> balance_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        balance_left[i + 1] = balance_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix balances for the right side (jars n+1 to 2n)
    // balance_right[i] = balance of jars i to 2n
    // We are interested in the balance of jars 2n-k_R+1 to 2n
    // Let's define balance_right_suffix[k] as the balance of the last k jars (2n-k+1 to 2n)
    std::vector<int> balance_right_suffix(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        balance_right_suffix[i + 1] = balance_right_suffix[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum k_L for each balance_left value
    // map: balance_value -> min_k_L
    std::map<int, int> min_k_L_for_balance;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_balance = balance_left[k_L];
        if (min_k_L_for_balance.find(current_balance) == min_k_L_for_balance.end()) {
            min_k_L_for_balance[current_balance] = k_L;
        } else {
            min_k_L_for_balance[current_balance] = std::min(min_k_L_for_balance[current_balance], k_L);
        }
    }

    int min_jars_emptied = 2 * n; // Initialize with max possible

    // Iterate through all possible k_R values (0 to n)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int balance_eaten_right = balance_right_suffix[k_R];
        int target_balance_eaten_left = initial_balance - balance_eaten_right;

        if (min_k_L_for_balance.count(target_balance_eaten_left)) {
            int k_L = min_k_L_for_balance[target_balance_eaten_left];
            min_jars_emptied = std::min(min_jars_emptied, k_L + k_R);
        }
    }

    std::cout << min_jars_emptied << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    // Total number of substrings in a string of length n is n*(n+1)/2
    long long total_substrings = n * (n + 1) / 2;

    // We want to maximize f(s), which means minimizing the number of substrings consisting only of '0's.
    // This is achieved by distributing the '0's as evenly as possible.
    // The m '1's divide the string into m+1 potential blocks of '0's.
    // Let k be the number of '0's. k = n - m.
    long long num_zeros = n - m;

    // If m '1's are placed, they create m+1 potential segments for '0's.
    // For example, _1_1_..._1_ where _ are segments of '0's.
    // We distribute num_zeros among these m+1 segments as evenly as possible.
    // This means some segments will have floor(num_zeros / (m+1)) zeros,
    // and others will have ceil(num_zeros / (m+1)) zeros.

    long long num_segments = m + 1;
    long long q = num_zeros / num_segments; // floor(num_zeros / num_segments)
    long long r = num_zeros % num_segments; // number of segments with q+1 zeros

    // r segments will have q+1 zeros.
    // (num_segments - r) segments will have q zeros.

    long long substrings_from_zeros = 0;

    // Contribution from segments with q+1 zeros
    if (q + 1 > 0) { // Only add if segment length is positive
        substrings_from_zeros += r * (q + 1) * (q + 2) / 2;
    }

    // Contribution from segments with q zeros
    if (q > 0) { // Only add if segment length is positive
        substrings_from_zeros += (num_segments - r) * q * (q + 1) / 2;
    }

    return total_substrings - substrings_from_zeros;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

