#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Iterate through the deletion sequence in reverse
    // This means we are adding vertices back to the graph one by one
    // and calculating APSP sum for the current set of active vertices.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back

        active_vertices[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step for the newly added vertex k
        // For all pairs (i, j) among currently active vertices,
        // check if path i -> k -> j is shorter than current i -> j.
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                // Update paths involving k as an intermediate vertex
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After updating paths using k as an intermediate,
        // also update paths where k is an endpoint.
        // This is crucial because k itself might be part of a shorter path
        // for other active vertices.
        // The previous loop only considers k as an intermediate.
        // We need to ensure all pairs (i,j) among active vertices
        // have their shortest paths updated, including those where i or j is k.
        // The standard Floyd-Warshall structure handles this naturally.
        // The above loop is equivalent to the k-th iteration of Floyd-Warshall
        // if k is the k-th vertex considered.
        // The full Floyd-Warshall update for vertex k as an intermediate:
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Sum for v != u
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, then before x_2, ...)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

