struct Result {
    long long y_val;
    int next_x;
};

std::vector<long long> a_arr;
std::vector<Result> memo;
std::vector<bool> visited;
std::vector<bool> in_stack; // To detect cycles

Result solve(int current_x_idx) {
    // current_x_idx is 1-based
    if (current_x_idx <= 0 || current_x_idx > a_arr.size() - 1) {
        return {0, current_x_idx}; // Base case for termination
    }

    if (visited[current_x_idx]) {
        if (in_stack[current_x_idx]) {
            return {-1, 0}; // Cycle detected, return -1 for y_val
        }
        return memo[current_x_idx]; // Already computed
    }

    visited[current_x_idx] = true;
    in_stack[current_x_idx] = true;

    long long val_a_x = a_arr[current_x_idx];

    // Step 2: x = x + a_x, y = y + a_x
    int x_after_step2 = current_x_idx + val_a_x;
    long long y_after_step2 = val_a_x;

    // Check termination after step 2
    if (x_after_step2 <= 0 || x_after_step2 > a_arr.size() - 1) {
        in_stack[current_x_idx] = false;
        memo[current_x_idx] = {y_after_step2, x_after_step2};
        return memo[current_x_idx];
    }

    // Step 3: x = x - a_x_new, y = y + a_x_new
    // Here a_x_new is a_arr[x_after_step2]
    long long val_a_x_new = a_arr[x_after_step2];
    int x_after_step3 = x_after_step2 - val_a_x_new;
    long long y_after_step3 = y_after_step2 + val_a_x_new;

    // Check termination after step 3
    if (x_after_step3 <= 0 || x_after_step3 > a_arr.size() - 1) {
        in_stack[current_x_idx] = false;
        memo[current_x_idx] = {y_after_step3, x_after_step3};
        return memo[current_x_idx];
    }

    // Recursive call for the next state
    Result next_res = solve(x_after_step3);

    in_stack[current_x_idx] = false;

    if (next_res.y_val == -1) {
        memo[current_x_idx] = {-1, 0}; // Propagate cycle detection
    } else {
        memo[current_x_idx] = {y_after_step3 + next_res.y_val, next_res.next_x};
    }
    return memo[current_x_idx];
