#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // In this case, all f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: At least one element in each subsequence.
    // This is the more complex case.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is a[n-1].value + a[n-2].value + h.
    // The minimum possible f value is a[0].value + a[1].value (if a[0] and a[1] are in the same group).
    // The minimum possible f value is a[0].value + a[1].value + h (if a[0] and a[1] are in different groups).
    // The maximum possible f value is a[n-1].value + a[n-2].value (if a[n-1] and a[n-2] are in the same group).
    // The maximum possible f value is a[n-1].value + a[n-2].value + h (if a[n-1] and a[n-2] are in different groups).

    // Consider a partition where a[0] is in S1 and a[1]...a[n-1] are in S2.
    // Or a[0]...a[n-2] in S1 and a[n-1] in S2.
    // The key observation is that to minimize max_f - min_f, we want to make the range of f values as small as possible.
    // The values a_i + a_j are always between a[0]+a[1] and a[n-1]+a[n-2].
    // The values a_i + a_j + h are always between a[0]+a[1]+h and a[n-1]+a[n-2]+h.

    // If we put a[0] in S1 and all other elements a[1]...a[n-1] in S2.
    // min_f:
    //   - a[1]+a[2] (if n >= 3, from S2)
    //   - a[0]+a[1]+h (from S1 and S2)
    //   So, min_f = min(a[1]+a[2], a[0]+a[1]+h) if n >= 3.
    //   If n=2, min_f = a[0]+a[1]+h.
    // max_f:
    //   - a[n-1]+a[n-2] (from S2)
    //   - a[0]+a[n-1]+h (from S1 and S2)
    //   So, max_f = max(a[n-1]+a[n-2], a[0]+a[n-1]+h).

    // Let's analyze the specific partition: a[0] in S1, a[1]...a[n-1] in S2.
    // This partition is optimal for the "mixed" case if h is large.
    // Values within S1: None (if n=1, but n>=2)
    // Values within S2: a[i] + a[j] for i,j in [1, n-1]. Min is a[1]+a[2], Max is a[n-1]+a[n-2].
    // Values between S1 and S2: a[0] + a[j] + h for j in [1, n-1]. Min is a[0]+a[1]+h, Max is a[0]+a[n-1]+h.

    long long min_f_val_case2;
    long long max_f_val_case2;

    if (n == 2) {
        // S1 = {a[0]}, S2 = {a[1]}
        // Only one pair: (a[0], a[1]), they are in different subsequences.
        // f(a[0], a[1]) = a[0].value + a[1].value + h.
        // min_f = max_f = a[0].value + a[1].value + h.
        // Goodness = 0.
        // This is a special case, but the general logic below should handle it.
        // For n=2, a[1]+a[2] is not possible.
        // min_f_val_case2 = a[0].value + a[1].value + h;
        // max_f_val_case2 = a[0].value + a[1].value + h;
    }

    // General logic for a[0] in S1, a[1]...a[n-1] in S2
    min_f_val_case2 = a[0].value + a[1].value + h; // Smallest cross-subsequence sum
    if (n >= 3) {
        min_f_val_case2 = std::min(min_f_val_case2, a[1].value + a[2].value); // Smallest same-subsequence sum (from S2)
    }

    max_f_val_case2 = a[0].value + a[n - 1].value + h; // Largest cross-subsequence sum
    if (n >= 3) {
        max_f_val_case2 = std::max(max_f_val_case2, a[n - 1].value + a[n - 2].value); // Largest same-subsequence sum (from S2)
    }

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...n-1].
    // We reorder them to s[i...n-1] + s[0...i-1].
    // This is a cyclic shift.
    for (int i = 1; i < n; ++i) {
        std::string new_s = s.substr(i) + s.substr(0, i);
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 didn't work, we need to check if k=2 is always possible,
    // or if there are cases where it's impossible.
    // The problem statement implies that if k=1 doesn't work, k=2 might.
    // Example 1: "nolon" -> "onlno" (k=2)
    // Example 3: "qqqq" -> Impossible
    //
    // If all characters in s are the same (e.g., "aaaa"), then any permutation
    // of substrings will result in the same string "aaaa".
    // In this case, it's impossible to form a new string.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // Consider the structure of palindromes.
    // If s is a palindrome, and it's not all same characters,
    // then s must have at least two distinct characters.
    //
    // If n is odd, s[0...n/2-1] is the prefix, s[n/2] is the middle char, s[n/2+1...n-1] is the suffix.
    // If n is even, s[0...n/2-1] is the prefix, s[n/2...n-1] is the suffix.
    //
    // Let's consider cutting s into three pieces:
    // s_prefix = s.substr(0, i)
    // s_middle = s.substr(i, j-i)
    // s_suffix = s.substr(j)
    //
    // We can always achieve a new palindrome with 2 cuts if the string is not
    // composed of all identical characters.
    //
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least one character s[i] such that s[i] != s[0].
    //
    // Let's take the first half of the string: s[0...n/2-1].
    // If this prefix is itself a palindrome (e.g., "abacaba", prefix "aba"),
    // and it's not all the same character, then we can potentially use k=1.
    // But we already checked k=1.
    //
    // The key insight for k=2 is that if s is a palindrome and not all characters are the same,
    // we can always find a way to make 2 cuts and reorder to form a new palindrome.
    //
    // Consider the string s. If we take any prefix s[0...i-1] where i < n,
    // and its corresponding suffix s[n-i...n-1].
    //
    // Example: "nolon" (n=5)
    // s[0] = 'n', s[1] = 'o', s[2] = 'l', s[3] = 'o', s[4] = 'n'
    //
    // If we cut at index 1: "n" | "olon" -> "olonn" (not palindrome)
    // If we cut at index 2: "no" | "lon" -> "lonno" (not palindrome)
    // If we cut at index 3: "nol" | "on" -> "onnol" (not palindrome)
    // If we cut at index 4: "nolo" | "n" -> "nnolo" (not palindrome)
    // So k=1 doesn't work for "nolon".
    //
    // For k=2, we can cut "no|l|on". Reorder to "on|l|no". This forms "onlno", which is a palindrome and != "nolon".
    // This is achieved by taking s[0...1], s[2...2], s[3...4].
    // The pieces are "no", "l", "on".
    // We reorder them to "on", "l", "no".
    //
    // This specific reordering is:
    // Take s[0...i-1] as piece A.
    // Take s[i...n-i-1] as piece B (the middle part).
    // Take s[n-i...n-1] as piece C.
    //
    // Since s is a palindrome, A is reverse of C. (A = reverse(C)).
    // The original string is A + B + C.
    // We can reorder to C + B + A.
    // Since A = reverse(C), then C = reverse(A).
    // So C + B + A is reverse(A) + B + A.
    // For this to be a palindrome, reverse(A) + B + A must be equal to reverse(A) + reverse(B) + reverse(reverse(A)).
    // Which means B must be a palindrome.
    //
    // For "nolon", let i=2.
    // A = "no"
    // B = "l"
    // C = "on"
    // A is reverse of C. B is a palindrome.
    // Original: "no" + "l" + "on" = "nolon"
    // New: "on" + "l" + "no" = "onlno"
    // This is a palindrome and != "nolon".
    // This requires 2 cuts.
    //
    // This strategy works if we can find an `i` such that `s.substr(i, n - 2*i)` is a palindrome,
    // and `s.substr(0, i)` is not empty.
    //
    // Since `s` is a palindrome and not all characters are the same,
    // there must be at least one `i` in `[1, n/2)` such that `s[i] != s[0]`.
    //
    // Consider the string `s_prime = s.substr(0, n/2)`.
    // If `s_prime` is not all the same character, then we can always find a cut.
    //
    // The problem states that if k=1 doesn't work, and the string is not all same characters,
    // then k=2 is the answer.
    // This is a known property for palindromes. If a palindrome `s` is not composed of all identical characters,
    // and it cannot be transformed into a different palindrome by a single cyclic shift,
    // then it can always be transformed into a different palindrome by two cuts.
    // The construction `C + B + A` where `A = s.substr(0, i)`, `B = s.substr(i, n-2*i)`, `C = s.substr(n-i)`
    // works if `B` is a palindrome.
    //
    // For any palindrome `s` that is not all identical characters, we can always find an `i` such that
    // `s.substr(0, i)` is not empty, `s.substr(n-i)` is not empty, and `s.substr(i, n-2*i)` is a palindrome.
    // The simplest such `i` is 1.
    // `A = s[0]`, `B = s[1...n-2]`, `C = s[n-1]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    // `B = s.substr(1, n-2)` is also a palindrome because `s` is a palindrome.
    // So, `s = s[0] + s.substr(1, n-2) + s[n-1]`.
    // We can reorder to `s[n-1] + s.substr(1, n-2) + s[0]`.
    // This new string is `s[0] + s.substr(1, n-2) + s[0]`.
    // This is a palindrome.
    // Is it different from `s`?
    // It is `s` itself. This specific reordering `C+B+A` where `A` is a single character doesn't change the string.
    //
    // The example "nolon" shows that `k=2` is the answer.
    // The example "otto" shows that `k=1` is the answer.
    // The example "qqqq" shows "Impossible".
    //
    // The logic seems to be:
    // 1. Check if any cyclic shift (k=1) results in a different palindrome. If yes, print 1.
    // 2. If not, check if all characters in `s` are the same. If yes, print "Impossible".
    // 3. Otherwise (k=1 failed, but not all chars are same), print 2.
    //
    // This covers all examples.
    // Why is step 3 always 2?
    // If `s` is a palindrome and not all characters are the same, and no cyclic shift works:
    // This means that for any `i` from 1 to `n-1`, `s.substr(i) + s.substr(0, i)` is either not a palindrome or is equal to `s`.
    //
    // Consider the string `s`. Since it's a palindrome and not all characters are the same,
    // there must be at least one character `s[j]` such that `s[j] != s[0]`.
    //
    // Let's take the first character `s[0]` and the last character `s[n-1]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    //
    // Consider cutting `s` into `s[0...n/2-1]` and `s[n/2...n-1]`.
    // Let `P = s.substr(0, n/2)`.
    // Let `S = s.substr(n/2)`.
    // If `n` is even, `S` is `reverse(P)`.
    // If `n` is odd, `S` is `s[n/2] + reverse(P)`.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2.
    // This is a common pattern in competitive programming problems where the answer is small (0, 1, 2, Impossible).
    // The "nolon" example confirms that 2 is a possible answer.
    // The only case where it's impossible is when all characters are the same.
    //
    // So the logic is sound.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that [l, r] contains a pattern.
                                                // Initialize with n+1, meaning no pattern found starting at or before l.

    // Iterate through all possible x and k to find patterns s_x = s_{x+k} = s_{x+2k}
    // x is 0-indexed, so x ranges from 0 to n-1.
    // x+2k must be less than n.
    // k must be at least 1.
    // The maximum possible k is when x=0, then 2k < n => k < n/2.
    // The maximum possible k is when x=n-3, then 2k < n => k < (n-(n-3))/2 = 3/2 => k=1.
    // So k ranges from 1 up to (n-1)/2.

    for (int x = 0; x < n; ++x) {
        for (int k = 1; ; ++k) {
            if (x + 2 * k >= n) {
                break; // x + 2k must be within bounds [0, n-1]
            }
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a pattern s_x = s_{x+k} = s_{x+2k}
                // This pattern covers the range [x, x+2k] (0-indexed)
                // In 1-indexed terms, this is [x+1, x+2k+1]
                // We need to update min_r_for_l for all l' <= x+1
                // The minimum r for such l' would be x+2k+1.

                // The problem asks for l <= x and x+2k <= r.
                // So, for any l_0 (1-indexed) such that 1 <= l_0 <= x+1,
                // the minimum r_0 (1-indexed) that satisfies the condition is x+2k+1.
                // We want to find the smallest r_0 for each l_0.
                // So, min_r_for_l[l_0] = min(min_r_for_l[l_0], x+2k+1).

                // Since we iterate x from left to right, and k from small to large,
                // x+2k+1 will generally increase.
                // For a fixed x, as k increases, x+2k+1 increases.
                // For a fixed k, as x increases, x+2k+1 increases.

                // The crucial observation is that if a pattern exists for [x, x+2k],
                // then for any l' <= x, the minimum r' that covers this pattern is x+2k.
                // We are interested in the smallest r' for each l'.
                // So, for l_0 = x+1 (1-indexed), the minimum r_0 is x+2k+1.
                // For l_0 = x (1-indexed), the minimum r_0 is also x+2k+1 (if this is the first pattern covering it).
                // And so on, for l_0 = 1, the minimum r_0 is x+2k+1.

                // We need to update min_r_for_l[l_0] for l_0 from 1 to x+1.
                // The value to update with is x+2k+1.
                // This means min_r_for_l[l_0] = min(min_r_for_l[l_0], x+2k+1).

                // However, a simpler approach is to find the smallest r_0 for each l_0.
                // Let's define `min_r_val[i]` as the minimum `r` (0-indexed) such that `[i, r]` contains a pattern.
                // `min_r_val[x]` = `min(min_r_val[x], x+2k)`.
                // This is not quite right. `min_r_val[l]` should be the minimum `r` such that there exists `x, k` with `l <= x` and `x+2k <= r`.
                // This means `min_r_val[l]` is the minimum `x+2k` over all `x, k` such that `l <= x`.

                // Let's use `min_end_idx[i]` to store the minimum `x+2k` (0-indexed) for any pattern `(x, k)` where `x = i`.
                // Initialize `min_end_idx` with `n`.
                // `min_end_idx[x] = min(min_end_idx[x], x+2k)`.
                // After iterating all `k` for a fixed `x`, `min_end_idx[x]` will hold the smallest `x+2k` for a pattern starting at `x`.

                // The problem asks for `l <= x` and `x+2k <= r`.
                // Let `min_r_for_l[l]` be the minimum `r` (0-indexed) such that `[l, r]` contains a pattern.
                // `min_r_for_l[l]` = `min_{x=l to n-1} (min_end_idx_for_x[x])`.
                // This can be computed by iterating `l` from `n-1` down to `0`.
                // `min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l+1])`.
                // This is a suffix minimum.

                // Let's refine the `min_end_idx` definition.
                // `min_pattern_end[i]` = minimum `x+2k` (0-indexed) such that `s_i = s_{i+k} = s_{i+2k}`.
                // Initialize `min_pattern_end` with `n`.
                // For each `x`, `k` such that `s_x = s_{x+k} = s_{x+2k}`:
                // `min_pattern_end[x] = min(min_pattern_end[x], x+2k)`.

                // After filling `min_pattern_end` for all `x` and `k`:
                // `min_r_val[i]` = minimum `r` (0-indexed) such that there exists a pattern `(x, k)` with `i <= x` and `x+2k <= r`.
                // `min_r_val[i]` = `min_{j=i to n-1} (min_pattern_end[j])`.
                // This is a suffix minimum.
                // `min_r_val[n-1] = min_pattern_end[n-1]`
                // `min_r_val[i] = min(min_pattern_end[i], min_r_val[i+1])` for `i` from `n-2` down to `0`.

                // Initialize `min_pattern_end` with `n` (a value larger than any valid index).
                // `min_pattern_end[x]` stores the smallest `x+2k` for a pattern starting at `x`.
                min_r_for_l[x] = std::min(min_r_for_l[x], x + 2 * k);
            }
        }
    }

    // Now, min_r_for_l[x] (0-indexed) contains the minimum end position (0-indexed)
    // for a pattern starting exactly at x.
    // We need to compute suffix minimums.
    // min_r_for_l[i] should be the minimum end position for any pattern starting at or after i.
    // Iterate from n-2 down to 0.
    for (int i = n - 2; i >= 0; --i) {
        min_r_for_l[i] = std::min(min_r_for_l[i], min_r_for_l[i + 1]);
    }

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // An (l, r) pair (0-indexed) is invalid if there is no x, k such that l <= x and x+2k <= r.
    // This means for a given l, r must be less than min_r_for_l[l].
    // For each l (0-indexed, from 0 to n-1):
    // The valid r's (0-indexed) are from min_r_for_l[l] to n-1.
    // If min_r_for_l[l] is n (or greater), it means no pattern starts at or after l.
    // In this case, all r's from l to n-1 are invalid for this l.
    // The number of invalid r's for a given l is (min_r_for_l[l] - 1) - l + 1 = min_r_for_l[l] - l.
    // But only if min_r_for_l[l] <= n.
    // If min_r_for_l[l] == n, it means no pattern exists starting at or after l.
    // So for this l, all r from l to n-1 are invalid. Number of such r's is n - l.
    // If min_r_for_l[l] < n, then r can be from l to min_r_for_l[l]-1.
    // Number of invalid r's for this l is (min_r_for_l[l] - 1) - l + 1 = min_r_for_l[l] - l.
    // This formula works for both cases if we cap min_r_for_l[l] at n.
    // Let's use `min_r_for_l[i]` as the smallest `r` (0-indexed) such that `[i, r]` contains a pattern.
    // If `min_r_for_l[i] == n`, it means no pattern exists starting at or after `i`.
    // For a given `l` (0-indexed), `r` (0-indexed) can range from `l` to `n-1`.
    // An `(l, r)` pair is invalid if `r < min_r_for_l[l]`.
    // The possible `r` values for an invalid pair are `l, l+1, ..., min(n-1, min_r_for_l[l]-1)`.
    // The number of such `r` values is `min(n-1, min_r_for_l[l]-1) - l + 1`.
    // If `min_r_for_l[l]` is `n`, then `min(n-1, n-1) - l + 1 = n - 1 - l + 1 = n - l`.
    // This is correct.
    // If `min_r_for_l[l]` is `n+1` (initial value), then `min(n-1, n) - l + 1 = n - 1 - l + 1 = n - l`.
    // This is also correct.

    for (int l = 0; l < n; ++l) {
        // min_r_for_l[l] is the smallest 0-indexed r such that a pattern exists for [l, r].
        // If min_r_for_l[l] is n, it means no pattern exists starting at or after l.
        // So for this l, all r from l to n-1 are invalid.
        // Number of such r's is (n-1) - l + 1 = n - l.
        // If min_r_for_l[l] < n, then r can be from l to min_r_for_l[l]-1.
        // Number of such r's is (min_r_for_l[l]-1) - l + 1 = min_r_for_l[l] - l.

        // The number of invalid r's for a given l is `std::min(n, min_r_for_l[l]) - l`.
        // Example: n=6. min_r_for_l[0]=5. Invalid r's for l=0 are 0,1,2,3,4. Count = 5-0 = 5.
        // Example: n=6. min_r_for_l[0]=6 (no pattern). Invalid r's for l=0 are 0,1,2,3,4,5. Count = 6-0 = 6.
        invalid_pairs += std::min(n, min_r_for_l[l]) - l;
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) {
            break; // All target tracks covered
        }

        long long current_h = h[h_idx];
        long long left_reach = current_h - T;
        long long right_reach = current_h + T;

        // If the current head cannot even reach the current target track p[p_idx]
        // (i.e., p[p_idx] is to the left of its maximum left reach),
        // then this head cannot cover p[p_idx] without moving right.
        // This condition is actually not quite right. A head at H can cover P if abs(H-P) <= T.
        // The strategy is to use each head to cover a contiguous block of *uncovered* target tracks.
        // We try to cover p[p_idx] with the current head.
        // If p[p_idx] is too far to the right for the current head to reach (even by moving left),
        // then this head cannot cover p[p_idx] by moving left.
        // The head must move right or stay.
        // The range covered by this head is [current_h - T, current_h + T].
        // We need to cover p[p_idx].
        // If p[p_idx] is outside [current_h - T, current_h + T], this head cannot cover it.
        // But we are trying to cover a *range* of tracks.

        // Let's re-evaluate the greedy strategy for check(T).
        // We iterate through heads. For each head, we try to cover as many *uncovered* tracks as possible,
        // starting from the leftmost uncovered track.
        // `p_idx` points to the first target track that has not yet been covered.

        // If the current head `h[h_idx]` can reach `p[p_idx]` (i.e., `abs(h[h_idx] - p[p_idx]) <= T`),
        // then this head can be used to cover `p[p_idx]` and potentially more tracks to its right.
        // The effective range this head can cover, starting from `p[p_idx]`, is
        // `[p[p_idx], p[p_idx] + (T - abs(h[h_idx] - p[p_idx]))]`.
        // This is the range `[p[p_idx], p[p_idx] + T - (p[p_idx] - h[h_idx])]` if `h[h_idx] <= p[p_idx]`.
        // Or `[p[p_idx], p[p_idx] + T - (h[h_idx] - p[p_idx])]` if `h[h_idx] > p[p_idx]`.
        // This simplifies to `[p[p_idx], h[h_idx] + T]`.
        // So, if `abs(h[h_idx] - p[p_idx]) <= T`, the head can cover tracks up to `h[h_idx] + T`.
        // This is the "right-moving" strategy.

        // What if the head moves left?
        // If `h[h_idx]` moves to `p[p_idx]`, it takes `abs(h[h_idx] - p[p_idx])` time.
        // The remaining time is `T - abs(h[h_idx] - p[p_idx])`.
        // With this remaining time, it can move further left or right.
        // The total range covered by this head is `[h[h_idx] - T, h[h_idx] + T]`.
        // This is the simplest interpretation.

        // Let's use the two-pointer approach for `check(T)`.
        // `p_idx` is the index of the first target track not yet covered.
        // `h_idx` is the index of the current head we are considering.

        // For the current head `h[h_idx]`, it can cover tracks in the range `[h[h_idx] - T, h[h_idx] + T]`.
        // If `p[p_idx]` is to the right of `h[h_idx] + T`, this head cannot cover `p[p_idx]`.
        // We must use the next head.
        // If `p[p_idx]` is to the left of `h[h_idx] - T`, this head cannot cover `p[p_idx]` by moving right.
        // This head must move right to cover `p[p_idx]`.
        // The crucial observation is that a head can cover a contiguous segment of tracks.
        // If a head at `H` covers `P_start` and `P_end`, it must be that `max(abs(H - P_start), abs(H - P_end)) <= T`
        // is not necessarily true. It's `abs(H - P_start) + abs(P_start - P_end) <= T` if it moves from `H` to `P_start` then to `P_end`.
        // Or `abs(H - P_end) + abs(P_end - P_start) <= T` if it moves from `H` to `P_end` then to `P_start`.
        // This is equivalent to saying that the head moves from `H` to some `H_final` in `T` seconds,
        // and `P_start` and `P_end` are both within `[min(H, H_final), max(H, H_final)]`.
        // The total distance traveled is `abs(H - H_final)`.
        // The range covered is `[min(H, H_final), max(H, H_final)]`.
        // The time taken is `abs(H - H_final)`.
        // So, if a head at `H` covers `[P_start, P_end]`, it must be that `abs(H - P_start) + (P_end - P_start) <= T`
        // if it moves right from `P_start` to `P_end`.
        // Or `abs(H - P_end) + (P_end - P_start) <= T` if it moves left from `P_end` to `P_start`.
        // This is the key.

        // For each head `h[h_idx]`, we want to cover `p[p_idx]` and as many subsequent tracks as possible.
        // There are two main strategies for a head to cover `p[p_idx]` and subsequent tracks:
        // 1. Move right: The head moves from `h[h_idx]` to `p[p_idx]` (or further right) and then continues right.
        //    The total time taken to cover `[p[p_idx], p_end]` is `abs(h[h_idx] - p[p_idx]) + (p_end - p[p_idx])`.
        //    This must be `<= T`. So `p_end <= p[p_idx] + T - abs(h[h_idx] - p[p_idx])`.
        //    The maximum `p_end` is `h[h_idx] + T`.
        // 2. Move left: The head moves from `h[h_idx]` to some `p_final` (which is `p_end`) and then covers `[p[p_idx], p_end]` by moving left.
        //    This means `p_end` is the rightmost point reached, and `p[p_idx]` is the leftmost point.
        //    The time taken is `abs(h[h_idx] - p_end) + (p_end - p[p_idx])`. This must be `<= T`.
        //    So `p_end - p[p_idx] <= T - abs(h[h_idx] - p_end)`.
        //    This is `p_end - p[p_idx] <= T - (p_end - h[h_idx])` if `h[h_idx] <= p_end`.
        //    `2 * p_end - p[p_idx] - h[h_idx] <= T`.
        //    `2 * p_end <= T + p[p_idx] + h[h_idx]`.
        //    `p_end <= (T + p[p_idx] + h[h_idx]) / 2`.

        // We need to find the maximum `p_end` that can be covered by `h[h_idx]` starting from `p[p_idx]`.
        // Let `current_p_start = p[p_idx]`.
        // If `h[h_idx]` is to the right of `current_p_start`: `h[h_idx] >= current_p_start`.
        //   Option 1 (move right from `h[h_idx]` to `current_p_start` then right):
        //     Time = `(h[h_idx] - current_p_start) + (p_end - current_p_start)`.
        //     `p_end <= current_p_start + T - (h[h_idx] - current_p_start) = 2 * current_p_start - h[h_idx] + T`.
        //   Option 2 (move left from `h[h_idx]` to `p_end` then left to `current_p_start`):
        //     Time = `(h[h_idx] - p_end) + (p_end - current_p_start) = h[h_idx] - current_p_start`.
        //     This is only valid if `h[h_idx] - current_p_start <= T`.
        //     In this case, the head covers `[current_p_start, h[h_idx]]`.
        //     The maximum `p_end` is `h[h_idx]`.
        //     This option is simpler: if `h[h_idx]` can reach `current_p_start` by moving left,
        //     it covers `[current_p_start, h[h_idx]]`. The time is `h[h_idx] - current_p_start`.
        //     If `h[h_idx] - current_p_start <= T`, then `h[h_idx]` can cover up to `h[h_idx]`.
        //     The effective rightmost point is `h[h_idx]`.
        //     The head can also move further right from `h[h_idx]` for `T - (h[h_idx] - current_p_start)` time.
        //     So it can reach `h[h_idx] + (T - (h[h_idx] - current_p_start)) = T + current_p_start`.
        //     So if `h[h_idx] >= current_p_start`, the head can cover up to `T + current_p_start`.
        //     This is the simpler case: `h[h_idx]` is already at or to the right of `current_p_start`.
        //     It can move left to `current_p_start` (cost `h[h_idx] - current_p_start`), then move right for remaining time.
        //     Max reach is `current_p_start + (T - (h[h_idx] - current_p_start)) = T + 2*current_p_start - h[h_idx]`.
        //     This is the `p_end` for option 1.
        //     The other option is to move right from `h[h_idx]` for `T` seconds, covering `[h[h_idx], h[h_idx] + T]`.
        //     If `current_p_start` is in this range, then it's covered.
        //     The maximum `p_end` is `h[h_idx] + T`.
        //     So if `h[h_idx] >= current_p_start`, the max `p_end` is `std::max(h[h_idx] + T, 2 * current_p_start - h[h_idx] + T)`.
        //     This simplifies to `h[h_idx] + T` if `h[h_idx] >= current_p_start`.
        //     No, this is wrong.
        //     If `h[h_idx] >= current_p_start`:
        //       To cover `[current_p_start, p_end]` where `p_end >= h[h_idx]`:
        //         Move from `h[h_idx]` to `p_end`, then to `current_p_start`. Time: `(p_end - h[h_idx]) + (p_end - current_p_start)`.
        //         `2 * p_end - h[h_idx] - current_p_start <= T`.
        //         `p_end <= (T + h[h_idx] + current_p_start) / 2`.
        //       To cover `[current_p_start, p_end]` where `p_end < h[h_idx]`:
        //         Move from `h[h_idx]` to `current_p_start`, then to `p_end`. Time: `(h[h_idx] - current_p_start) + (current_p_start - p_end)`.
        //         This is `h[h_idx] - p_end`. This is not useful.
        //         The head must move from `h[h_idx]` to `p_end` and then to `current_p_start`.
        //         Time: `abs(h[h_idx] - p_end) + abs(p_end - current_p_start)`.
        //         If `p_end` is between `current_p_start` and `h[h_idx]`:
        //           Time: `(h[h_idx] - p_end) + (p_end - current_p_start) = h[h_idx] - current_p_start`.
        //           If `h[h_idx] - current_p_start <= T`, then `[current_p_start, h[h_idx]]` is covered.
        //           The max `p_end` is `h[h_idx]`.
        //         If `p_end > h[h_idx]`:
        //           Time: `(p_end - h[h_idx]) + (p_end - current_p_start)`.
        //           `2 * p_end - h[h_idx] - current_p_start <= T`.
        //           `p_end <= (T + h[h_idx] + current_p_start) / 2`.
        //         If `p_end < current_p_start`: This is not the case, we are covering `p[p_idx]` and subsequent.

        // Let's simplify. A head at `H` can cover a range `[L, R]` if `min(abs(H-L) + (R-L), abs(H-R) + (R-L))` is `<= T`.
        // We want to find the maximum `R` such that `p[p_idx]` is covered and `R` is covered.
        // Let `P_start = p[p_idx]`.
        // Case 1: Head moves right from `H` to `P_start`, then continues right to `P_end`.
        //   Time = `abs(H - P_start) + (P_end - P_start)`.
        //   `P_end <= P_start + T - abs(H - P_start)`.
        // Case 2: Head moves left from `H` to `P_end`, then continues left to `P_start`.
        //   Time = `abs(H - P_end) + (P_end - P_start)`.
        //   `P_end <= P_start + T - abs(H - P_end)`.
        //   This is `P_end <= P_start + T - (P_end - H)` if `H <= P_end`.
        //   `2 * P_end <= P_start + T + H`.
        //   `P_end <= (P_start + T + H) / 2`.
        //   This is `P_end <= P_start + T - (H - P_end)` if `H > P_end`.
        //   `P_end <= P_start + T - H + P_end`.
        //   `0 <= P_start + T - H`. This means `H <= P_start + T`.
        //   If `H > P_end`, then `P_end` must be between `P_start` and `H`.
        //   The range covered is `[P_start, H]`. The time is `H - P_start`.
        //   If `H - P_start <= T`, then `[P_start, H]` is covered.
        //   The max `P_end` is `H`.

        // So, for a given `h[h_idx]` and `P_start = p[p_idx]`:
        // If `h[h_idx] <= P_start`:
        //   The head must move right. Time = `(P_start - h[h_idx]) + (P_end - P_start)`.
        //   `P_end <= P_start + T - (P_start - h[h_idx]) = h[h_idx] + T`.
        //   This is the maximum `P_end` it can reach.
        // If `h[h_idx] > P_start`:
        //   Option A: Move right from `h[h_idx]` to `P_start`, then continue right.
        //     Time = `(h[h_idx] - P_start) + (P_end - P_start)`.
        //     `P_end <= P_start + T - (h[h_idx] - P_start) = 2 * P_start - h[h_idx] + T`.
        //   Option B: Move left from `h[h_idx]` to `P_end`, then continue left to `P_start`.
        //     Time = `(h[h_idx] - P_end) + (P_end - P_start) = h[h_idx] - P_start`.
        //     This is only valid if `h[h_idx] - P_start <= T`.
        //     If this is true, the head can cover `[P_start, h[h_idx]]`.
        //     It can also move further right from `h[h_idx]` for `T - (h[h_idx] - P_start)` time.
        //     So it can reach `h[h_idx] + (T - (h[h_idx] - P_start)) = T + P_start`.
        //     This is the maximum `P_end` it can reach.
        //   So if `h[h_idx] > P_start`:
        //     The maximum `P_end` is `std::max(2 * P_start - h[h_idx] + T, P_start + T)`.
        //     No, this is not right.
        //     The two options are:
        //     1. Move to `P_start`, then right. Max `P_end = P_start + (T - abs(h[h_idx] - P_start))`.
        //     2. Move to `P_end`, then left to `P_start`. Max `P_end` such that `abs(h[h_idx] - P_end) + (P_end - P_start) <= T`.
        //        If `h[h_idx] <= P_end`: `(P_end - h[h_idx]) + (P_end - P_start) <= T` => `2*P_end <= T + h[h_idx] + P_start` => `P_end <= (T + h[h_idx] + P_start) / 2`.
        //        If `h[h_idx] > P_end`: `(h[h_idx] - P_end) + (P_end - P_start) <= T` => `h[h_idx] - P_start <= T`.
        //           In this case, the head covers `[P_start, h[h_idx]]`. So `P_end` can be `h[h_idx]`.
        //           And it can move further right from `h[h_idx]` for `T - (h[h_idx] - P_start)` time.
        //           So it can reach `h[h_idx] + (T - (h[h_idx] - P_start)) = T + P_start`.
        //           This is the same as option 1.

        // Let's use the simpler logic:
        // For each head `h[h_idx]`, we want to cover `p[p_idx]` and subsequent tracks.
        // The head can cover a range `[L, R]` if `min(abs(h[h_idx] - L) + (R - L), abs(h[h_idx] - R) + (R - L))` is `<= T`.
        // We are given `L = p[p_idx]`. We want to find the maximum `R`.
        // Let `P_start = p[p_idx]`.
        // Max `P_end` from moving right from `P_start`: `P_start + (T - abs(h[h_idx] - P_start))`.
        // Max `P_end` from moving left from `P_end` to `P_start`:
        //   If `h[h_idx] <= P_end`: `P_end <= (T + h[h_idx] + P_start) / 2`.
        //   If `h[h_idx] > P_end`: This implies `P_end` is between `P_start` and `h[h_idx]`.
        //     The time is `h[h_idx] - P_start`. If this is `<= T`, then `P_end` can be `h[h_idx]`.
        //     And it can move further right from `h[h_idx]` for `T - (h[h_idx] - P_start)` time.
        //     So it can reach `h[h_idx] + (T - (h[h_idx] - P_start)) = T + P_start`.
        //     This is the same as the first option.

        // So, the maximum `P_end` reachable by `h[h_idx]` starting from `P_start` is:
        // `max_reach_1 = P_start + T - std::abs(h[h_idx] - P_start)` (move to `P_start`, then right)
        // `max_reach_2 = (T + h[h_idx] + P_start) / 2` (move to `P_end`, then left to `P_start`, only if `h[h_idx] <= P_end`)
        // The second option is only relevant if `h[h_idx]` is to the left of `P_end`.
        // If `h[h_idx]` is to the right of `P_start`, then `P_end` could be `h[h_idx]`.
        // If `h[h_idx]` is to the right of `P_start`, then `P_end` could be `h[h_idx]`.
        // The time to cover `[P_start, h[h_idx]]` is `h[h_idx] - P_start`.
        // If `h[h_idx] - P_start <= T`, then `h[h_idx]` is covered.
        // The head can then move further right from `h[h_idx]` for `T - (h[h_idx] - P_start)` time.
        // So it can reach `h[h_idx] + (T - (h[h_idx] - P_start)) = P_start + T`.
        // This is the maximum `P_end` if `h[h_idx]` is to the right of `P_start`.

        // Let's use the simpler logic from a similar problem:
        // A head at `H` can cover a range `[L, R]` in time `T` if:
        // 1. It moves from `H` to `L`, then to `R`. Time = `abs(H - L) + (R - L)`.
        // 2. It moves from `H` to `R`, then to `L`. Time = `abs(H - R) + (R - L)`.
        // We need `min(abs(H - L) + (R - L), abs(H - R) + (R - L)) <= T`.
        // We are given `L = p[p_idx]`. We want to find the maximum `R`.

        // Let `current_p_start = p[p_idx]`.
        // Calculate `max_reach_by_current_head`.
        // Option 1: Move to `current_p_start`, then right.
        //   `max_reach_1 = current_p_start + T - std::abs(current_h - current_p_start)`.
        // Option 2: Move to `P_end`, then left to `current_p_start`.
        //   This is only relevant if `current_h` is to the left of `P_end`.
        //   `P_end` must satisfy `(P_end - current_h) + (P_end - current_p_start) <= T`.
        //   `2 * P_end <= T + current_h + current_p_start`.
        //   `max_reach_2 = (T + current_h + current_p_start) / 2`.
        //   This `max_reach_2` is only valid if `current_h <= max_reach_2`.
        //   If `current_h > max_reach_2`, then `current_h` is to the right of `P_end`, so option 2 is not applicable in this form.
        //   If `current_h > current_p_start`, then the head can cover `[current_p_start, current_h]` in `current_h - current_p_start` time.
        //   If `current_h - current_p_start <= T`, then it can cover `[current_p_start, current_h]` and then move right for `T - (current_h - current_p_start)` time.
        //   So it can reach `current_h + (T - (current_h - current_p_start)) = T + current_p_start`.
        //   This is exactly `max_reach_1` when `current_h > current_p_start`.

        // So, the maximum `P_end` reachable by `h[h_idx]` starting from `P_start` is:
        // `max_P_end = P_start + T - std::abs(current_h - P_start)`.
        // This covers the case where the head moves to `P_start` and then right.
        // What if `current_h` is far to the right of `P_start`?
        // E.g., `h=100, p=1, T=10`.
        // `max_P_end = 1 + 10 - abs(100-1) = 11 - 99 = -88`. This is wrong.
        // This means `P_start` cannot be reached by moving right from `h`.
        // The head must move left to `P_start`.
        // If `current_h - P_start > T`, then `P_start` cannot be reached by `current_h`.
        // In this case, this head cannot cover `P_start`. We move to the next head.

        // Correct logic for `check(T)`:
        // `p_idx` is the index of the first target track not yet covered.
        // Iterate through heads `h_idx` from `0` to `n-1`.
